    let dialogResolve = null;
    function showDialog(opts) {
        return new Promise(resolve => {
            dialogResolve = resolve;
            dialogTitle.textContent = opts.title || 'AETHER';
            dialogMessage.textContent = opts.message || '';
            dialogInputContainer.style.display = opts.type === 'prompt' ? 'block' : 'none';
            if (opts.type === 'prompt') dialogInput.value = opts.default || '';
            dialogCancel.style.display = opts.type === 'alert' ? 'none' : 'block';
            dialogModal.classList.remove('hidden');
        });
    }
    dialogOk.addEventListener('click', () => {
        dialogModal.classList.add('hidden');
        if (dialogResolve) dialogResolve(dialogInputContainer.style.display === 'block' ? dialogInput.value : true);
    });
    dialogCancel.addEventListener('click', () => { dialogModal.classList.add('hidden'); if (dialogResolve) dialogResolve(false); });
    dialogClose.addEventListener('click', () => { dialogModal.classList.add('hidden'); if (dialogResolve) dialogResolve(null); });
    window.alert   = msg => showDialog({ title: 'Alert',   message: msg, type: 'alert' });
    window.confirm = msg => showDialog({ title: 'Confirm', message: msg, type: 'confirm' });
    window.prompt  = (msg, def) => showDialog({ title: 'Input', message: msg, type: 'prompt', default: def });

    // ─── Vec3 ────────────────────────────────────────────────
    // A 3D vector class. Yes, in a chat app.
    // Used by the wave animation engine for the Aether pane.
    // Because why import a math library when you can write 10 lines?
    class Vec3 {
        constructor(x, y, z) { this.x = x; this.y = y; this.z = z; }
        add(v) { return new Vec3(this.x+v.x, this.y+v.y, this.z+v.z); }
        sub(v) { return new Vec3(this.x-v.x, this.y-v.y, this.z-v.z); }
        mul(s) { return new Vec3(this.x*s, this.y*s, this.z*s); }
        scale(s) { return new Vec3(this.x*s, this.y*s, this.z*s); }  // alias for mul
        dot(v) { return this.x*v.x + this.y*v.y + this.z*v.z; }
        length() { return Math.sqrt(this.dot(this)); }
        normalize() { const l = this.length(); return l === 0 ? new Vec3(0,0,0) : this.mul(1/l); }
        cross(v) { return new Vec3(this.y*v.z-this.z*v.y, this.z*v.x-this.x*v.z, this.x*v.y-this.y*v.x); }
        reflect(n) { return this.sub(n.mul(2*this.dot(n))); }
        negate() { return new Vec3(-this.x, -this.y, -this.z); }
    }
    window.Vec3 = Vec3; // expose for canvas renderer

