    async function saveHooksConfig() {
        const g = (id,fb='') => ($(`${id}`)||{value:fb}).value;
        const cfg = {
            gmail:gmailKey.value, outlook:outlookKey.value,
            tavily:tavilyKey.value, brave:braveKey.value, serper:serperKey.value,
            puter:puterKey?puterKey.value:'', github:githubToken.value,
            weather:g('weather-key'), weatherLoc:g('weather-location','London,UK'),
            slackToken:g('slack-token'), slackChannel:g('slack-channel','#general'),
            notionToken:g('notion-token'), notionDb:g('notion-db'),
            hueHost:g('hue-host'), hueKey:g('hue-key'),
            jiraUrl:g('jira-url'), jiraToken:g('jira-token'), jiraEmail:g('jira-email'),
            gitlabToken:g('gitlab-token'), gitlabUrl:g('gitlab-url','https://gitlab.com'),
            googleToken:g('google-token'), msToken:g('ms-token'),
            firecrawlKey:g('firecrawl-key'),
            // ── X / Twitter Search ──────────────────────────────
            xBearerToken:g('x-bearer-token'), xSearchMode:g('x-search-mode','recent'),
            // ── Trello ──────────────────────────────────────────
            trelloApiKey:g('trello-api-key'), trelloToken:g('trello-token'), trelloBoardId:g('trello-board-id'),
            sttEngine:g('stt-engine-select','none'), sttWhisperKey:g('stt-whisper-key'),
            // Browser automation
            browserAgentUrl:g('browser-agent-url','http://localhost:7860'),
            browserAgentEngine:g('browser-agent-engine','browser-use'),
            browserAgentEnabled: document.getElementById('browser-agent-enabled')?.checked||false,
            sttWhisperCppUrl:g('stt-whisper-cpp-url','http://localhost:9000'),
            sttGoogleKey:g('stt-google-key'), sttVoskUrl:g('stt-vosk-url','http://localhost:2700'),
            sttLanguage:g('stt-language','en-US'),
        };
        localStorage.setItem(HOOKS_KEY, JSON.stringify(cfg));
        hooksConfig = {...hooksConfig,...cfg};
        // Mirror plain keys for Discovery skill host sync (same-origin only)
        try {
            localStorage.setItem('aether_hooks_plain', JSON.stringify({
                tavily: cfg.tavily || '',
                serper: cfg.serper || '',
                brave: cfg.brave || '',
                openweather: cfg.weather || '',
            }));
        } catch (e) {}
        // Save TTS config
        const ttsEng = ($('tts-engine')||{value:'none'}).value;
        const ttsPiper = ($('tts-piper-url')||{value:'http://localhost:5000/tts'}).value;
        const ttsVoice = ($('tts-voice')||{value:'af_heart'}).value;
        const ttsSpd = parseFloat(($('tts-speed')||{value:'1.0'}).value)||1.0;
        ttsConfig = { engine: ttsEng, piperUrl: ttsPiper, voice: ttsVoice, speed: ttsSpd };
        localStorage.setItem(TTS_KEY, JSON.stringify(ttsConfig));
        updateTTSIndicator();
        showNotification('Hooks saved','success');
        updateServicesStatus();
        try { if (typeof syncDiscoveryKeysFromHooks === 'function') syncDiscoveryKeysFromHooks(); } catch(e) {}
    }

    function updateServicesStatus() {
        serviceProvider.textContent = apiConfig.provider;
        serviceModel.textContent = apiConfig.model;
        serviceContextLimit.textContent = state.contextLimit === Infinity ? 'Unlimited' : state.contextLimit.toLocaleString();
        const set = (el, v) => { if(!el) return; el.textContent = v ? 'Configured' : 'Not configured'; el.className = 'service-status' + (v ? ' configured' : ''); };
        set(serviceGmail, hooksConfig.gmail); set(serviceOutlook, hooksConfig.outlook);
        set(serviceTavily, hooksConfig.tavily); set(serviceBrave, hooksConfig.brave);
        set(serviceSerper, hooksConfig.serper); set(servicePuter, hooksConfig.puter);
        set(serviceGithub, hooksConfig.github);
        set($('service-weather'), hooksConfig.weather);
        set($('service-slack'), hooksConfig.slackToken);
        set($('service-notion'), hooksConfig.notionToken);
        // ── New services ──────────────────────────────────────
        set($('service-x'),      hooksConfig.xBearerToken);
        set($('service-trello'), hooksConfig.trelloApiKey && hooksConfig.trelloToken);
        // FS Access: show linked folder name, not just configured/not
        const fsEl = $('service-fs');
        if (fsEl) {
            fsEl.textContent = codingFolderHandle ? '📁 ' + codingFolderHandle.name : 'Not linked';
            fsEl.className   = 'service-status' + (codingFolderHandle ? ' configured' : '');
        }
        updateQwen35StatusBadge();
    }

    // ═══════════════════════════════════════════════════════════
    // SECTION 12: DEVICE DETECTION & AUTO-ADAPTATION
    // Uses matchMedia('(pointer: coarse)') — the only reliable
    // way to detect touch devices. maxTouchPoints lies on
    // Windows touch-screen laptops. This doesn't.
    // Auto-collapses sidebar on mobile after 3s to fix the
    // "X button doesn't work" bug that plagues every mobile web app.
    // ═══════════════════════════════════════════════════════════
    const device = (() => {
        const coarse = window.matchMedia('(pointer: coarse)').matches;
        const w      = window.innerWidth;
        const isMobile  = coarse && w < 768;
        const isTablet  = coarse && w >= 768 && w < 1100;
        const isDesktop = !coarse || w >= 1100;
        return { isMobile, isTablet, isDesktop, w, coarse };
    })();

    function applyDeviceClass() {
        const root = document.documentElement;
        root.classList.remove('device-mobile','device-tablet','device-desktop');
        if (device.isMobile)       { root.classList.add('device-mobile');  root.dataset.device = 'mobile'; }
        else if (device.isTablet)  { root.classList.add('device-tablet');  root.dataset.device = 'tablet'; }
        else                       { root.classList.add('device-desktop'); root.dataset.device = 'desktop'; }
        // Log for debugging
        console.log('[AETHER] Device:', root.dataset.device, '|', window.innerWidth + 'px', '| pointer:', device.coarse ? 'coarse' : 'fine');
    }
    applyDeviceClass();

    // Mobile: auto-collapse sidebar after 3s to fix unresponsive X button
    if (device.isMobile) {
        setTimeout(() => {
            if (sidebar && !sidebar.classList.contains('hidden')) {
                sidebar.classList.add('hidden');
                sidebar.style.transform = 'translateX(-100%)';
                sidebar.style.pointerEvents = 'none';
            }
        }, 3000);
    }

    // Re-evaluate on resize (orientation change etc.)
    let resizeTimer;
    window.addEventListener('resize', () => {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(() => {
            const w2 = window.innerWidth;
            const coarse2 = window.matchMedia('(pointer: coarse)').matches;
            device.w = w2; device.coarse = coarse2;
            device.isMobile  = coarse2 && w2 < 768;
            device.isTablet  = coarse2 && w2 >= 768 && w2 < 1100;
            device.isDesktop = !coarse2 || w2 >= 1100;
            applyDeviceClass();
        }, 100);
    });

    // ═══════════════════════════════════════════════════════════
    // SECTION 13: TTS — TEXT-TO-SPEECH ENGINE
    // Four engines: Groq PlayAI, Piper (local), Kokoro 82M (neural),
    // and browser SpeechSynthesis. User picks one in Hooks settings.
    // Each has its own config, error handling, and notification.
    // If all fail, AETHER stays silent. Like a thoughtful pause,
    // but caused by network errors.
    // ═══════════════════════════════════════════════════════════
    const TTS_KEY = 'aether_tts_config';
    let ttsConfig = { engine:'none', piperUrl:'http://localhost:5000/tts', voice:'af_heart', speed:1.0 };
    let ttsWorker = null;

    (function loadTtsConfig(){
        try { const s = localStorage.getItem(TTS_KEY); if(s) ttsConfig={...ttsConfig,...JSON.parse(s)}; } catch {}
        updateTTSIndicator();
    })();

    function updateTTSIndicator() {
        let ind = document.getElementById('tts-indicator');
        if (ttsConfig.engine && ttsConfig.engine !== 'none') {
            if (!ind) {
                ind = document.createElement('span');
                ind.id = 'tts-indicator';
                ind.className = 'tts-indicator';
                ind.title = `TTS: ${ttsConfig.engine}`;
                ind.innerHTML = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" width="14" height="14"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/></svg>`;
                const sr = document.querySelector('.status-right');
                if (sr) sr.insertAdjacentElement('afterbegin', ind);
            }
            ind.style.display = 'inline-flex';
        } else if (ind) {
            ind.style.display = 'none';
        }
    }

    async function speakTTS(text) {
        const clean = text.replace(/<[^>]+>/g,'').replace(/\*+/g,'').slice(0,1000);
        if(!clean || ttsConfig.engine==='none') return;

        // ── Groq TTS (PlayAI via Groq API) ───────────────────
        if (ttsConfig.engine === 'groq-tts') {
            agentStatus('generic','Speaking via Groq TTS\u2026');
            try {
                const groqKey = apiConfig.apiKey || ttsConfig.groqKey || '';
                const res = await fetch('https://api.groq.com/openai/v1/audio/speech', {
                    method: 'POST',
                    headers: { 'Authorization': 'Bearer ' + groqKey, 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        model: 'playai-tts',
                        input: clean,
                        voice: ttsConfig.voice || 'Aaliyah-PlayAI',
                        response_format: 'mp3'
                    })
                });
                if (!res.ok) throw new Error('Groq TTS HTTP ' + res.status);
                const blob = await res.blob();
                const audio = new Audio(URL.createObjectURL(blob));
                audio.play();
                agentDone();
            } catch(e) { agentDone(); reportFeatureError('Groq TTS', e); }
            return;
        }

        if(ttsConfig.engine === 'piper') {
            agentStatus('generic','Speaking via Piper\u2026');
            try {
                const res = await fetch(ttsConfig.piperUrl, {
                    method:'POST', headers:{'Content-Type':'application/json'},
                    body: JSON.stringify({ text: clean, voice: ttsConfig.voice, speed: ttsConfig.speed })
                });
                if(!res.ok) throw new Error('Piper HTTP ' + res.status);
                const blob = await res.blob();
                const audio = new Audio(URL.createObjectURL(blob));
                audio.play();
                agentDone();
            } catch(e) { agentDone(); reportFeatureError('Piper TTS', e); }
            return;
        }

        if(ttsConfig.engine === 'kokoro') {
            agentStatus('generic','Loading Kokoro model\u2026');
            try {
                // Kokoro 82M via Hugging Face Transformers.js
                if(!window.KokoroPipeline) {
                    const { pipeline } = await import('https://cdn.jsdelivr.net/npm/@huggingface/transformers@3.x/dist/transformers.min.js');
                    window.KokoroPipeline = await pipeline('text-to-speech', 'onnx-community/Kokoro-82M-ONNX');
                }
                agentStatus('generic','Synthesising…');
                const out = await window.KokoroPipeline(clean, { voice: ttsConfig.voice || 'af_heart' });
                const wavBlob = pcmToWav(out.audio, out.sampling_rate);
                const audio = new Audio(URL.createObjectURL(wavBlob));
                audio.play();
                agentDone();
            } catch(e) { agentDone(); reportFeatureError('Kokoro TTS', e); }
            return;
        }

        if(ttsConfig.engine === 'browser') {
            // Fully supported on: Chrome, Edge, Firefox, Safari, and all localhost origins
            if (typeof speechSynthesis === 'undefined') {
                showNotification('Browser TTS not supported in this environment','warn');
                return;
            }
            const utt = new SpeechSynthesisUtterance(clean);
            utt.rate  = ttsConfig.speed || 1.0;
            utt.pitch = 1.0;
            utt.volume = 1.0;
            // Apply saved voice if configured
            if (ttsConfig.voice && ttsConfig.voice !== 'default') {
                // voices may not be loaded immediately — wait for them
                const applyVoice = () => {
                    const voices = speechSynthesis.getVoices();
                    const match = voices.find(v => v.name === ttsConfig.voice || v.voiceURI === ttsConfig.voice);
                    if (match) utt.voice = match;
                };
                if (speechSynthesis.getVoices().length) {
                    applyVoice();
                } else {
                    speechSynthesis.addEventListener('voiceschanged', applyVoice, {once:true});
                }
            }
            // Cancel any existing speech before starting new
            speechSynthesis.cancel();
            setTimeout(() => speechSynthesis.speak(utt), 50);
        }
    }

    function pcmToWav(pcmData, sampleRate) {
        const len = pcmData.length, buf = new ArrayBuffer(44+len*2), view = new DataView(buf);
        const wr = (off,str) => { for(let i=0;i<str.length;i++) view.setUint8(off+i,str.charCodeAt(i)); };
        wr(0,'RIFF'); view.setUint32(4,36+len*2,true); wr(8,'WAVE'); wr(12,'fmt ');
        view.setUint32(16,16,true); view.setUint16(20,1,true); view.setUint16(22,1,true);
        view.setUint32(24,sampleRate,true); view.setUint32(28,sampleRate*2,true);
        view.setUint16(32,2,true); view.setUint16(34,16,true); wr(36,'data');
        view.setUint32(40,len*2,true);
        for(let i=0;i<len;i++) view.setInt16(44+i*2,Math.max(-32768,Math.min(32767,pcmData[i]*32768)),true);
        return new Blob([buf],{type:'audio/wav'});
    }


    // ─── STT — SPEECH TO TEXT ────────────────────────────────
    // Supported: Browser Web Speech API, OpenAI Whisper, Whisper.cpp, Google Cloud, Vosk
    const STT_KEY = 'aether_stt_config';
    let sttConfig = {
        engine: 'none',         // none | browser | whisper | whisper-cpp | google | vosk
        whisperKey: '',          // OpenAI Whisper API key
        whisperCppUrl: 'http://localhost:9000', // whisper.cpp local server
        googleKey: '',           // Google Cloud Speech key
        voskUrl: 'http://localhost:2700', // Vosk server URL
        language: 'en-US',
    };
    let sttRecording = false;
    let sttStream = null;
    let sttMediaRecorder = null;
    let sttChunks = [];
    let sttBrowserRecog = null;

    (function loadSTTConfig(){
        try { const s=localStorage.getItem(STT_KEY); if(s) sttConfig={...sttConfig,...JSON.parse(s)}; } catch {}
        if(sttConfig.engine && sttConfig.engine!=='none') state.sttEngine=sttConfig.engine;
        updateMicIndicator();
    })();

    function updateMicIndicator() {
        const btn = document.getElementById('stt-btn');
        if (!btn) return;
        const active = sttConfig.engine && sttConfig.engine !== 'none';
        btn.style.opacity = active ? '1' : '0.4';
        btn.title = active ? `STT: ${sttConfig.engine} — click to record` : 'STT not configured (HOOKS → Speech-to-Text)';
    }

    async function toggleSTT() {
        if (sttConfig.engine === 'none') {
            showAetherDialog({
                title: 'Speech-to-Text Not Configured',
                html: '<p style="color:#99aabb">Configure an STT engine in <strong>HOOKS → Speech-to-Text</strong> first.</p><p style="color:#445;font-size:.72rem;margin-top:8px">Supported: Browser (free), OpenAI Whisper, Whisper.cpp (local), Google Cloud, Vosk (local)</p>',
                confirmLabel: 'Open HOOKS', cancelLabel: 'Cancel',
                onConfirm: () => document.getElementById('btn-hooks')?.click(),
            });
            return;
        }
        if (sttRecording) {
            stopSTT();
        } else {
            await startSTT();
        }
    }

    async function startSTT() {
        if (sttConfig.engine === 'whisperjs') { return toggleWhisperJS(); }
        const btn = document.getElementById('stt-btn');

        // Detect localhost / secure context — browser STT requires secure origin
        const isSecureContext = window.isSecureContext ||
            location.protocol === 'https:' ||
            location.hostname === 'localhost' ||
            location.hostname === '127.0.0.1' ||
            location.hostname.endsWith('.local');

        if (sttConfig.engine === 'browser') {
            // Web Speech API — supported on Chrome/Edge and localhost
            const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
            if (!SR) {
                showNotification('Browser STT requires Chrome, Edge, or a Chromium-based browser','error');
                return;
            }
            if (!isSecureContext) {
                showNotification('Browser STT requires HTTPS or localhost','warn');
                return;
            }
            sttBrowserRecog = new SR();
            sttBrowserRecog.lang = sttConfig.language;
            sttBrowserRecog.continuous = true;   // Keep listening until manually stopped
            sttBrowserRecog.interimResults = true;
            sttBrowserRecog.maxAlternatives = 1;
            sttBrowserRecog.onstart = () => { sttRecording=true; if(btn) btn.classList.add('recording'); showNotification('🎤 Listening…','info'); };
            sttBrowserRecog.onresult = e => {
                const inp = document.getElementById('user-input');
                if (!inp) return;
                let interim = '', final = '';
                for (let i = e.resultIndex; i < e.results.length; i++) {
                    if (e.results[i].isFinal) final += e.results[i][0].transcript;
                    else interim += e.results[i][0].transcript;
                }
                if (final) {
                    inp.value = (inp.value + ' ' + final).trim();
                    inp.style.height='auto'; inp.style.height=inp.scrollHeight+'px';
                }
            };
            sttBrowserRecog.onend = () => {
                sttRecording=false; if(btn) btn.classList.remove('recording');
                // Auto-restart if still expected to be recording (continuous mode)
            };
            sttBrowserRecog.onerror = e => {
                sttRecording=false; if(btn) btn.classList.remove('recording');
                if (e.error === 'not-allowed') {
                    reportFeatureError('STT Mic Permission', new Error(e.error));
                } else if (e.error === 'no-speech') {
                    showNotification('No speech detected — try again','warn');
                } else {
                    reportFeatureError('Browser STT', new Error(e.error));
                }
            };
            try { sttBrowserRecog.start(); } catch(e2) { reportFeatureError('Browser STT', e2); }
            return;
        }
        // Mic recording for API-based engines
        try {
            sttStream = await navigator.mediaDevices.getUserMedia({ audio:true });
            sttChunks = [];
            sttMediaRecorder = new MediaRecorder(sttStream, { mimeType: 'audio/webm' });
            sttMediaRecorder.ondataavailable = e => { if(e.data.size>0) sttChunks.push(e.data); };
            sttMediaRecorder.onstop = () => transcribeAudio(new Blob(sttChunks,{type:'audio/webm'}));
            sttMediaRecorder.start();
            sttRecording = true;
            if (btn) btn.classList.add('recording');
            showNotification('🎤 Recording… tap mic to stop','info');
        } catch(e) {
            reportFeatureError('Microphone Access', e);
        }
    }

    function stopSTT() {
        const btn = document.getElementById('stt-btn');
        sttRecording = false;
        if (btn) btn.classList.remove('recording');
        if (sttBrowserRecog) { sttBrowserRecog.stop(); sttBrowserRecog=null; return; }
        if (sttMediaRecorder && sttMediaRecorder.state!=='inactive') sttMediaRecorder.stop();
        if (sttStream) { sttStream.getTracks().forEach(t=>t.stop()); sttStream=null; }
    }

    async function transcribeAudio(blob) {
        agentStatus('generic','Transcribing\u2026');
        try {
            let transcript = '';
            if (sttConfig.engine === 'groq-whisper') {
                // Groq Whisper API — ultra-fast, supports whisper-large-v3-turbo
                const fd = new FormData();
                fd.append('file', blob, 'audio.webm');
                fd.append('model', 'whisper-large-v3-turbo');
                fd.append('language', sttConfig.language.split('-')[0]);
                fd.append('response_format', 'json');
                const groqKey = apiConfig.apiKey || sttConfig.whisperKey;
                const res = await fetch('https://api.groq.com/openai/v1/audio/transcriptions', {
                    method: 'POST', headers: { 'Authorization': 'Bearer ' + groqKey }, body: fd
                });
                if (!res.ok) throw new Error('Groq Whisper HTTP ' + res.status);
                const d = await res.json();
                transcript = d.text || '';
            } else if (sttConfig.engine === 'whisper') {
                const fd = new FormData();
                fd.append('file', blob, 'audio.webm');
                fd.append('model','whisper-1');
                fd.append('language', sttConfig.language.split('-')[0]);
                const res = await fetch('https://api.openai.com/v1/audio/transcriptions', {
                    method:'POST', headers:{'Authorization':'Bearer '+sttConfig.whisperKey}, body:fd
                });
                if (!res.ok) throw new Error('HTTP ' + res.status);
                const d = await res.json();
                transcript = d.text || '';
            } else if (sttConfig.engine === 'whisper-cpp') {
                const fd = new FormData(); fd.append('file', blob, 'audio.wav');
                const res = await fetch(sttConfig.whisperCppUrl+'/inference', {method:'POST',body:fd});
                const d = await res.json();
                transcript = d.text || '';
            } else if (sttConfig.engine === 'google') {
                // Convert to base64 for Google REST API
                const arrayBuf = await blob.arrayBuffer();
                const b64 = btoa(String.fromCharCode(...new Uint8Array(arrayBuf)));
                const res = await fetch(`https://speech.googleapis.com/v1/speech:recognize?key=${sttConfig.googleKey}`, {
                    method:'POST', headers:{'Content-Type':'application/json'},
                    body: JSON.stringify({ config:{ encoding:'WEBM_OPUS',sampleRateHertz:48000,languageCode:sttConfig.language }, audio:{content:b64} })
                });
                const d = await res.json();
                transcript = d.results?.[0]?.alternatives?.[0]?.transcript || '';
            } else if (sttConfig.engine === 'vosk') {
                const fd = new FormData(); fd.append('audio', blob, 'audio.webm');
                const res = await fetch(`${sttConfig.voskUrl}/transcribe`, {method:'POST',body:fd});
                const d = await res.json();
                transcript = d.text || '';
            }
            agentDone();
            if (transcript) {
                const inp = document.getElementById('user-input');
                if (inp) {
                    inp.value = (inp.value ? inp.value+' ' : '') + transcript;
                    inp.style.height='auto'; inp.style.height=inp.scrollHeight+'px';
                    inp.focus();
                }
            } else {
                showNotification('No speech detected','warn');
            }
        } catch(e) { agentDone(); reportFeatureError('Speech-to-Text', e); }
    }

    // ─── CODING MODE ─────────────────────────────────────────
    // Inspired by Claude Code — AETHER can preview, run, and fix code on the air
    // Features: Enhanced code blocks, file tagging, live preview, diff view, auto-fix
    const CODING_MODE_KEY = 'aether_coding_mode';

    // ─── AETHER CODE FOLDER ACCESS ───────────────────────────
    // ═══════════════════════════════════════════════════════════
    // FILE SYSTEM ACCESS API — Full Implementation
    //
    // AETHER Code uses the browser's native File System Access API
    // to give the AI real read/write access to your project folder.
    // This is not a virtual FS — changes write to disk immediately.
    //
    // Handle is lost on page reload (browser security model).
    // We store the folder name and re-prompt on reconnect.
    // New in this version: fs_rename, fs_mkdir, fs_copy, fs_stat,
    // fs_exists, showOpenFilePicker, showSaveFilePicker, file watcher,
    // AETHER.md limit raised from 600 → 2000 chars.
    // ═══════════════════════════════════════════════════════════

    let codingFolderHandle = null; // FileSystemDirectoryHandle

    // ── Capability detection ──────────────────────────────────
    const FS_SUPPORTED   = typeof window !== 'undefined' && 'showDirectoryPicker' in window;
    const FS_FILE_PICKER = typeof window !== 'undefined' && 'showOpenFilePicker' in window;

    // ── Link a folder ─────────────────────────────────────────
    async function openCodingFolder() {
        if (!FS_SUPPORTED) { showNotification('File System Access API not supported. Use Chrome 86+ or Edge 86+.', 'warn'); return; }
        try {
            codingFolderHandle = await window.showDirectoryPicker({ mode: 'readwrite', startIn: 'documents' });
            registerFSTools();
            updateCodingFolderUI();
            saveFolderName(codingFolderHandle.name);
            startFSWatcher();
            showNotification('📁 Folder linked: ' + codingFolderHandle.name + ' — read/write/delete/rename/mkdir active', 'success');
        } catch(e) { if (e.name !== 'AbortError') reportFeatureError('Folder Access', e); }
    }

    // ── Open single file (file picker dialog) ─────────────────
    async function openFilePicker(opts={}) {
        if (!FS_FILE_PICKER) { showNotification('File picker not supported in this browser.', 'warn'); return null; }
        try {
            const handles = await window.showOpenFilePicker({ multiple: opts.multiple||false, types: opts.types||[], excludeAcceptAllOption: false });
            return opts.multiple ? handles : handles[0];
        } catch(e) { if (e.name !== 'AbortError') reportFeatureError('File Open', e); return null; }
    }

    // ── Save file dialog ──────────────────────────────────────
    async function saveFilePicker(suggestedName, types=[]) {
        if (!FS_FILE_PICKER) { showNotification('Save dialog not supported in this browser.', 'warn'); return null; }
        try {
            return await window.showSaveFilePicker({ suggestedName, types });
        } catch(e) { if (e.name !== 'AbortError') reportFeatureError('File Save', e); return null; }
    }

    async function writeToFileHandle(handle, content) {
        const w = await handle.createWritable(); await w.write(content); await w.close();
    }

    // ── Register all FS tools ─────────────────────────────────
    function registerFSTools() {
        TOOL_REGISTRY['fs_read']      = { fn: async(p)   => await fsFolderRead(p),     desc: 'Read file from coding folder' };
        TOOL_REGISTRY['fs_write']     = { fn: async(a)   => await fsFolderWrite(a),    desc: 'Write full file. Format: path\\ncontent — prefer fs_patch for edits' };
        TOOL_REGISTRY['fs_patch']     = { fn: async(a)   => await fsFolderPatch(a),    desc: 'Surgical edit. Formats: path|||old|||new  OR  path\\n<<<<<<< SEARCH\\nold\\n=======\\nnew\\n>>>>>>> REPLACE' };
        TOOL_REGISTRY['search_replace']= { fn: async(a)  => await fsFolderPatch(a),    desc: 'Alias of fs_patch — surgical search/replace in a file' };
        TOOL_REGISTRY['fs_delete']    = { fn: async(p)   => await fsFolderDelete(p),   desc: 'Delete file or directory' };
        TOOL_REGISTRY['fs_list']      = { fn: async(p)   => await fsFolderShell('ls '+(p||'').trim()), desc: 'List files' };
        TOOL_REGISTRY['fs_rename']    = { fn: async(a)   => await fsFolderRename(a),   desc: 'Rename/move. Format: oldPath|newPath' };
        TOOL_REGISTRY['fs_mkdir']     = { fn: async(p)   => await fsFolderMkdir(p),    desc: 'Create directory (recursive)' };
        TOOL_REGISTRY['fs_copy']      = { fn: async(a)   => await fsFolderCopy(a),     desc: 'Copy file. Format: src|dest' };
        TOOL_REGISTRY['fs_stat']      = { fn: async(p)   => await fsFolderStat(p),     desc: 'File metadata: size, type, modified' };
        TOOL_REGISTRY['fs_exists']    = { fn: async(p)   => await fsFolderExists(p),   desc: 'Check exists: returns true/false' };
        TOOL_REGISTRY['shell']        = { fn: async(cmd) => await fsFolderShell(cmd),  desc: 'Shell: ls, cat, grep, head, tail, wc, find, tree, pwd' };
        try {
            if (typeof AETHER_ToolRuntime !== 'undefined') AETHER_ToolRuntime.enrichRegistry(TOOL_REGISTRY);
        } catch (_) {}
    }

    /** CODE apply mode: ask (ghost) | auto (write now) | plan (ghost, never auto) */
    function getCodeAcceptMode() {
        try {
            var el = document.getElementById('code-accept-mode');
            if (el && el.value) return el.value;
            return localStorage.getItem('aether_code_accept_mode') || 'ask';
        } catch (_) { return 'ask'; }
    }

    function setCodeSessionStatus(status, hint) {
        var st = document.getElementById('code-session-status');
        if (st) {
            st.dataset.status = status || 'idle';
            st.textContent = status || 'idle';
        }
        if (hint != null) {
            var h = document.getElementById('code-session-hint');
            if (h) h.textContent = hint;
        }
    }

    function pushCodeToolCard(name, phase, argPreview, resultPreview) {
        var tl = document.getElementById('code-tool-timeline');
        if (!tl || !state.codingMode) return null;
        var empty = tl.querySelector('.code-tool-empty');
        if (empty) empty.remove();
        var card = document.createElement('div');
        card.className = 'code-tool-card ' + (phase || 'running');
        card.dataset.tool = name || '';
        card.innerHTML =
            '<div class="code-tool-card-top">' +
            '<span class="code-tool-card-name">' + escapeHtml(name || 'tool') + '</span>' +
            '<span class="code-tool-card-phase">' + escapeHtml(phase || 'running') + '</span>' +
            '</div>' +
            (argPreview ? '<div class="code-tool-card-arg">' + escapeHtml(String(argPreview).slice(0, 120)) + '</div>' : '') +
            (resultPreview != null ? '<div class="code-tool-card-result">' + escapeHtml(String(resultPreview).slice(0, 240)) + '</div>' : '');
        tl.insertBefore(card, tl.firstChild);
        // Cap timeline length
        while (tl.children.length > 40) tl.removeChild(tl.lastChild);
        return card;
    }

    function finishCodeToolCard(card, phase, resultPreview) {
        if (!card) return;
        card.classList.remove('running', 'ok', 'err');
        card.classList.add(phase === 'err' ? 'err' : 'ok');
        var ph = card.querySelector('.code-tool-card-phase');
        var text = resultPreview != null ? String(resultPreview) : '';
        var msMatch = text.match(/\bms=(\d+)/);
        var clsMatch = text.match(/\bclass=(\w+)/);
        if (ph) {
            ph.textContent = (phase || 'ok') + (msMatch ? ' ' + msMatch[1] + 'ms' : '');
        }
        if (clsMatch) card.dataset.cls = clsMatch[1];
        if (resultPreview != null) {
            var r = card.querySelector('.code-tool-card-result');
            if (!r) {
                r = document.createElement('div');
                r.className = 'code-tool-card-result';
                card.appendChild(r);
            }
            // Strip header line for compact body when envelope present
            var body = text;
            if (/^tool=/.test(text) || /^ok=/.test(text.split('\n')[0] || '')) {
                var lines = text.split('\n');
                body = lines.slice(1).join('\n') || text;
            }
            r.textContent = body.slice(0, 280);
        }
    }

    /** Build a rich tool-result DOM node from envelope output */
    function renderToolResultCard(name, result) {
        const toolEl = document.createElement('div');
        const text = String(result || '');
        const ok = !(typeof AETHER_ToolRuntime !== 'undefined'
            ? AETHER_ToolRuntime.isFailureString(text)
            : /ok=false|error:|denied/i.test(text));
        const msM = text.match(/\bms=(\d+)/);
        const clsM = text.match(/\bclass=(\w+)/);
        toolEl.className = 'aether-msg tool-result-msg code-tool-inline' + (ok ? ' tool-ok' : ' tool-err');
        const hdr = document.createElement('div');
        hdr.className = 'code-tool-inline-hdr';
        const left = document.createElement('span');
        left.textContent = '⚙ ' + name + (clsM ? ' · ' + clsM[1] : '');
        const right = document.createElement('span');
        right.textContent = (ok ? 'ok' : 'err') + (msM ? ' · ' + msM[1] + 'ms' : '');
        right.style.color = ok ? '#50c080' : '#ff6688';
        hdr.appendChild(left);
        hdr.appendChild(right);
        const body = document.createElement('div');
        body.className = 'code-tool-inline-body';
        let bodyText = text;
        if (/^tool=/.test(text) || /^ok=/.test((text.split('\n')[0] || ''))) {
            bodyText = text.split('\n').slice(1).join('\n') || text;
        }
        body.textContent = bodyText.slice(0, 4000);
        toolEl.appendChild(hdr);
        toolEl.appendChild(body);
        return toolEl;
    }

    function syncCodeAgentShell() {
        var on = !!state.codingMode;
        var rail = document.getElementById('code-session-rail');
        var right = document.getElementById('code-right-rail');
        var treePanel = document.getElementById('coding-file-tree');
        var termPanel = document.getElementById('coding-terminal');
        if (rail) {
            rail.style.display = on ? 'flex' : 'none';
            rail.setAttribute('aria-hidden', on ? 'false' : 'true');
        }
        // Mobile CODE: panel visibility owned by AETHER_CodeMobile (tabbed UI)
        var mobileCode = false;
        try {
            mobileCode = on && typeof AETHER_CodeMobile !== 'undefined' && AETHER_CodeMobile.isMobileCode && AETHER_CodeMobile.isMobileCode();
        } catch (_) {}
        if (!mobileCode) {
            if (right) {
                right.style.display = on ? 'flex' : 'none';
                right.setAttribute('aria-hidden', on ? 'false' : 'true');
            }
            if (treePanel) {
                treePanel.style.display = (on && codingFolderHandle) ? 'flex' : 'none';
            }
            if (termPanel) {
                termPanel.style.display = (on && codingFolderHandle) ? 'flex' : 'none';
            }
            var chatEl = document.getElementById('chat-display');
            if (chatEl) chatEl.style.display = '';
        }
        var folderEl = document.getElementById('code-session-folder');
        if (folderEl) {
            folderEl.textContent = codingFolderHandle
                ? codingFolderHandle.name
                : (on ? 'no folder — link one' : 'no folder');
        }
        // Dock ghost into CODE rail when coding; undock when off
        try {
            if (typeof AETHER_Ghost !== 'undefined' && AETHER_Ghost.setHost) {
                var ghostHost = document.getElementById('code-ghost-host');
                AETHER_Ghost.setHost(on && ghostHost ? ghostHost : null);
            }
        } catch (e) {}
        updateCodingTurnBadge(state.currentConversationId || '');
        if (!on) setCodeSessionStatus('idle', 'Plan → Patch → Verify');
        try {
            if (typeof AETHER_CodePro !== 'undefined' && AETHER_CodePro.renderBar) AETHER_CodePro.renderBar();
        } catch (_) {}
        try {
            if (typeof AETHER_CodeMobile !== 'undefined' && AETHER_CodeMobile.sync) AETHER_CodeMobile.sync();
        } catch (_) {}
    }
    window.syncCodeAgentShell = syncCodeAgentShell;
    window.openCodingFolder = openCodingFolder;

    // Host bridges for Code Pro (ghost restore, verify terminal, status)
    window.setCodeSessionStatus = setCodeSessionStatus;
    window.fsFolderShell = typeof fsFolderShell === 'function' ? fsFolderShell : window.fsFolderShell;
    // fsFolderRead / fsFolderWrite / __aetherForceWrite already exposed near FS tools

    function saveFolderName(name) { try { localStorage.setItem('aether_last_folder', name); } catch(_) {} }
    function getLastFolderName()  { return localStorage.getItem('aether_last_folder') || null; }

    // ── File change watcher (polling — no native watch() in FS API) ─
    let _fsWatcherTimer = null;
    let _fsLastSnapshot = null;

    async function fsBuildSnapshot(dirHandle, prefix='', depth=0) {
        const snap = [];
        if (depth > 2) return snap; // limit depth to avoid performance issues
        for await (const [name, handle] of dirHandle.entries()) {
            if (name.startsWith('.')) continue;
            const p = prefix ? prefix + '/' + name : name;
            if (handle.kind === 'file') {
                try { const f = await (await handle.getFile()); snap.push(p + ':' + f.size + ':' + f.lastModified); }
                catch { snap.push(p + ':?'); }
            } else {
                snap.push(p + '/');
                const sub = await fsBuildSnapshot(handle, p, depth + 1);
                snap.push(...sub);
            }
        }
        return snap;
    }

    function startFSWatcher() {
        if (_fsWatcherTimer) clearInterval(_fsWatcherTimer);
        if (!codingFolderHandle) return;
        _fsLastSnapshot = null;
        // ── Tick counter: skip the first 2 polls while the baseline snapshot
        // is being built right after folder link. Without this, the watcher
        // would fire "Folder changed externally" immediately on every link
        // because _fsLastSnapshot goes null→snap on the very first tick.
        // Also: we only notify ONCE per change cluster, not on every differing tick.
        let _fsWatchTick = 0;
        let _fsNotifiedThisCycle = false;
        _fsWatcherTimer = setInterval(async () => {
            if (!codingFolderHandle) { clearInterval(_fsWatcherTimer); return; }
            try {
                const snap = (await fsBuildSnapshot(codingFolderHandle)).join('|');
                _fsWatchTick++;
                if (_fsWatchTick <= 2) {
                    // First two ticks: just build the baseline, don't compare
                    _fsLastSnapshot = snap;
                    return;
                }
                if (_fsLastSnapshot !== null && snap !== _fsLastSnapshot && !_fsNotifiedThisCycle) {
                    // Something changed externally — show a subtle badge on the
                    // folder button instead of a full notification toast.
                    // Only once per change cluster (resets when snapshot stabilises).
                    _fsNotifiedThisCycle = true;
                    const btn = document.getElementById('coding-folder-btn');
                    if (btn && !btn.querySelector('.fs-changed-badge')) {
                        const badge = document.createElement('span');
                        badge.className = 'fs-changed-badge';
                        badge.title = 'Files changed externally — click to dismiss';
                        badge.textContent = '●';
                        badge.onclick = (e) => { e.stopPropagation(); badge.remove(); };
                        btn.appendChild(badge);
                    }
                } else if (snap === _fsLastSnapshot) {
                    // Snapshot stabilised — reset notification flag
                    _fsNotifiedThisCycle = false;
                }
                _fsLastSnapshot = snap;
            } catch { clearInterval(_fsWatcherTimer); }
        }, 5000); // 5s polling — less aggressive than the old 3s
    }

    function stopFSWatcher() { if (_fsWatcherTimer) { clearInterval(_fsWatcherTimer); _fsWatcherTimer = null; } }

    // ── Core CRUD ─────────────────────────────────────────────

    async function fsFolderRead(filePath) {
        if (!codingFolderHandle) {
            const n = getLastFolderName();
            return n ? 'Folder "'+n+'" disconnected (page reload). Click "Link Folder" to reconnect.' : 'No folder linked.';
        }
        try {
            filePath = assertSafeFsPath(filePath, false);
            const parts = filePath.split('/').filter(Boolean);
            let dir = codingFolderHandle;
            for (const p of parts.slice(0,-1)) dir = await dir.getDirectoryHandle(p);
            const fh = await dir.getFileHandle(parts[parts.length-1]);
            return await (await fh.getFile()).text();
        } catch(e) { return 'fs_read error: ' + e.message; }
    }

    async function fsFolderWrite(arg, opts) {
        opts = opts || {};
        if (!codingFolderHandle) return 'No folder linked.';
        const nl = arg.indexOf('\n'); if (nl === -1) return 'fs_write: format is path\ncontent';
        let path = arg.slice(0, nl).trim(), text = arg.slice(nl+1);
        try {
            path = assertSafeFsPath(path, true);
            const parts = path.split('/').filter(Boolean); let dir = codingFolderHandle;
            for (const p of parts.slice(0,-1)) dir = await dir.getDirectoryHandle(p, { create: true });
            const fh = await dir.getFileHandle(parts[parts.length-1], { create: true });
            // Capture old content for diff before overwriting
            var oldContent = '';
            try {
                var existing = await fh.getFile();
                if (existing.size > 0 && existing.size < 500000) {
                    oldContent = await existing.text();
                }
            } catch(e2) {}
            // Ghost commits: in coding mode without Beast / auto, propose instead of write
            try {
                const beastOn = state.beastMode || (typeof AETHER_Beast !== 'undefined' && AETHER_Beast.isEnabled());
                const acceptMode = getCodeAcceptMode();
                const forceWrite = !!opts.force || acceptMode === 'auto' || beastOn;
                if (state.codingMode && !forceWrite && typeof AETHER_Ghost !== 'undefined' && oldContent !== text) {
                    AETHER_Ghost.propose({
                        path: path,
                        before: oldContent,
                        after: text,
                        message: 'fs_write proposal',
                        source: 'fs_write',
                        kind: 'write',
                    });
                    return 'ok=false ghost=true path=' + path + ' msg=Ghost commit proposed (not written) — Accept in Ghost rail or set apply=auto / BEAST';
                }
            } catch (gErr) {}
            await writeToFileHandle(fh, text);
            var result = 'ok=true path=' + path + ' bytes=' + text.length;
            if (oldContent && oldContent !== text) {
                var adds = 0, dels = 0;
                var oLines = oldContent.split('\n'), nLines = text.split('\n');
                var oi = 0, ni = 0;
                while (oi < oLines.length || ni < nLines.length) {
                    if (oi < oLines.length && ni < nLines.length && oLines[oi] === nLines[ni]) { oi++; ni++; }
                    else if (ni < nLines.length && (oi >= oLines.length || nLines[ni] !== oLines[oi])) { adds++; ni++; }
                    else if (oi < oLines.length) { dels++; oi++; }
                }
                result += ' diff=+' + adds + '/-' + dels;
            }
            if (typeof updateCodingFolderUI === 'function') try { updateCodingFolderUI(); } catch(_) {}
            return result;
        } catch(e) { return 'ok=false error=fs_write: ' + e.message; }
    }

    // Force write used by Ghost Accept (skip re-ghosting)
    window.__aetherForceWrite = async function(path, content) {
        return fsFolderWrite(path + '\n' + content, { force: true });
    };
    window.fsFolderWrite = fsFolderWrite;
    window.fsFolderRead = fsFolderRead;

    /**
     * Surgical patch — live insertions/subtractions.
     * Accepted formats:
     *   1) path|||old|||new
     *   2) path\n<<<<<<< SEARCH\nold\n=======\nnew\n>>>>>>> REPLACE
     *   3) path\nold\n<<<AETHER_SEP>>>\nnew
     *   4) JSON {"path","old_string"|"old","new_string"|"new", replace_all?}
     */
    function parseFsPatchArg(arg) {
        arg = String(arg || '').trim();
        if (!arg) return { error: 'empty argument' };

        // JSON object
        if (arg.startsWith('{')) {
            try {
                var j = JSON.parse(arg);
                var pathJ = j.path || j.file || j.filename;
                var oldJ = j.old_string != null ? j.old_string : (j.old != null ? j.old : j.search);
                var newJ = j.new_string != null ? j.new_string : (j.new != null ? j.new : j.replace);
                if (!pathJ || oldJ == null || newJ == null) return { error: 'JSON needs path, old_string, new_string' };
                return { path: String(pathJ).trim(), oldStr: String(oldJ), newStr: String(newJ), replaceAll: !!j.replace_all };
            } catch (e) {
                return { error: 'invalid JSON: ' + e.message };
            }
        }

        // path|||old|||new  (bracket-friendly, no newlines required)
        if (arg.includes('|||')) {
            var parts = arg.split('|||');
            if (parts.length < 3) return { error: 'format path|||old|||new needs 3 segments' };
            return {
                path: parts[0].trim(),
                oldStr: parts.slice(1, -1).join('|||'),
                newStr: parts[parts.length - 1],
                replaceAll: false,
            };
        }

        // SEARCH / REPLACE fence
        var fence = arg.match(/^([^\n]+)\n<<<<<<<\s*SEARCH\n([\s\S]*?)\n=======\n([\s\S]*?)\n>>>>>>>\s*REPLACE\s*$/);
        if (fence) {
            return { path: fence[1].trim(), oldStr: fence[2], newStr: fence[3], replaceAll: false };
        }

        // path\nold\n<<<AETHER_SEP>>>\nnew
        var sep = '\n<<<AETHER_SEP>>>\n';
        var si = arg.indexOf(sep);
        if (si !== -1) {
            var head = arg.slice(0, si);
            var nl = head.indexOf('\n');
            if (nl === -1) return { error: 'AETHER_SEP format needs path\\nold\\n<<<AETHER_SEP>>>\\nnew' };
            return {
                path: head.slice(0, nl).trim(),
                oldStr: head.slice(nl + 1),
                newStr: arg.slice(si + sep.length),
                replaceAll: false,
            };
        }

        return {
            error: 'Unrecognized fs_patch format. Use path|||old|||new or path\\n<<<<<<< SEARCH\\n...\\n=======\\n...\\n>>>>>>> REPLACE',
        };
    }

    async function fsFolderPatch(arg) {
        if (!codingFolderHandle) return 'ok=false error=No folder linked.';
        var parsed = parseFsPatchArg(arg);
        if (parsed.error) return 'ok=false error=fs_patch: ' + parsed.error;
        var path = parsed.path;
        var oldStr = parsed.oldStr;
        var newStr = parsed.newStr;
        if (!path) return 'ok=false error=fs_patch: missing path';
        if (oldStr === newStr) return 'ok=false error=fs_patch: old_string and new_string are identical';

        var before = await fsFolderRead(path);
        if (typeof before === 'string' && before.startsWith('fs_read error')) {
            return 'ok=false error=fs_patch: cannot read ' + path + ' — ' + before;
        }
        if (typeof before === 'string' && (before.startsWith('No folder') || before.startsWith('Folder "'))) {
            return 'ok=false error=' + before;
        }
        before = String(before);

        var idx = before.indexOf(oldStr);
        if (idx === -1) {
            // Helpful diagnostics: show nearby line if first line of old matches
            var firstLine = oldStr.split('\n')[0].slice(0, 80);
            var hint = firstLine && before.includes(firstLine)
                ? ' (first line found but full block mismatched — re-read file)'
                : ' (string not in file — re-read with fs_read)';
            return 'ok=false error=old_string not found in ' + path + hint;
        }
        if (!parsed.replaceAll && before.indexOf(oldStr, idx + 1) !== -1) {
            return 'ok=false error=old_string not unique in ' + path + ' — include more context or set replace_all';
        }

        var after;
        if (parsed.replaceAll) {
            after = before.split(oldStr).join(newStr);
        } else {
            after = before.slice(0, idx) + newStr + before.slice(idx + oldStr.length);
        }

        var stats = (typeof AETHER_Ghost !== 'undefined' && AETHER_Ghost.diffStats)
            ? AETHER_Ghost.diffStats(before, after)
            : { adds: newStr.split('\n').length, dels: oldStr.split('\n').length };

        var beastOn = state.beastMode || (typeof AETHER_Beast !== 'undefined' && AETHER_Beast.isEnabled && AETHER_Beast.isEnabled());
        var acceptMode = getCodeAcceptMode();
        var applyNow = beastOn || acceptMode === 'auto';

        if (state.codingMode && !applyNow && typeof AETHER_Ghost !== 'undefined') {
            AETHER_Ghost.propose({
                path: path,
                before: before,
                after: after,
                old_string: oldStr,
                new_string: newStr,
                message: 'fs_patch +' + stats.adds + '/-' + stats.dels,
                source: 'fs_patch',
                kind: 'patch',
            });
            setCodeSessionStatus('writing', 'ghost patch: ' + path);
            return 'ok=true ghost=true path=' + path + ' diff=+' + stats.adds + '/-' + stats.dels +
                ' msg=Patch proposed — Accept in Ghost rail (or apply=auto / BEAST)';
        }

        // Direct write
        var writeRes = await fsFolderWrite(path + '\n' + after, { force: true });
        setCodeSessionStatus('writing', 'patched ' + path);
        return 'ok=true ghost=false path=' + path + ' diff=+' + stats.adds + '/-' + stats.dels + ' ' + writeRes;
    }
    window.fsFolderPatch = fsFolderPatch;

    async function fsFolderDelete(path) {
        if (!codingFolderHandle) return 'No folder linked.';
        try {
            path = assertSafeFsPath(path, true);
            const parts = path.split('/').filter(Boolean); let dir = codingFolderHandle;
            for (const p of parts.slice(0,-1)) dir = await dir.getDirectoryHandle(p);
            await dir.removeEntry(parts[parts.length-1], { recursive: true });
            return 'Deleted: ' + path;
        } catch(e) { return 'fs_delete error: ' + e.message; }
    }

    // ── Extended FS operations ────────────────────────────────

    async function fsFolderMkdir(path) {
        if (!codingFolderHandle) return 'No folder linked.';
        try {
            path = assertSafeFsPath(path, true);
            let dir = codingFolderHandle;
            for (const p of path.split('/').filter(Boolean)) dir = await dir.getDirectoryHandle(p, { create: true });
            return 'Created: ' + path;
        } catch(e) { return 'fs_mkdir error: ' + e.message; }
    }

    async function fsFolderStat(path) {
        if (!codingFolderHandle) return 'No folder linked.';
        try {
            const parts = path.split('/').filter(Boolean); let dir = codingFolderHandle;
            for (const p of parts.slice(0,-1)) dir = await dir.getDirectoryHandle(p);
            const name = parts[parts.length-1];
            try {
                const fh = await dir.getFileHandle(name); const f = await fh.getFile();
                return `Path: ${path}\nType: file\nSize: ${fmtSize(f.size)} (${f.size.toLocaleString()} bytes)\nModified: ${new Date(f.lastModified).toLocaleString()}\nMIME: ${f.type||'unknown'}`;
            } catch { await dir.getDirectoryHandle(name); return `Path: ${path}\nType: directory`; }
        } catch(e) { return 'fs_stat error: ' + e.message; }
    }

    async function fsFolderExists(path) {
        if (!codingFolderHandle) return 'false';
        try {
            const parts = path.split('/').filter(Boolean); let dir = codingFolderHandle;
            for (const p of parts.slice(0,-1)) dir = await dir.getDirectoryHandle(p);
            const name = parts[parts.length-1];
            try { await dir.getFileHandle(name); return 'true (file)'; } catch {}
            try { await dir.getDirectoryHandle(name); return 'true (directory)'; } catch {}
            return 'false';
        } catch { return 'false'; }
    }

    async function fsFolderRename(arg) {
        // FS API has no rename() — implement as copy+delete (files only)
        if (!codingFolderHandle) return 'No folder linked.';
        const [oldPath, newPath] = (arg||'').split('|').map(s=>s.trim());
        if (!oldPath || !newPath) return 'Format: oldPath|newPath';
        const content = await fsFolderRead(oldPath);
        if (content.startsWith('fs_read error:')) return 'Rename failed: ' + content;
        const wr = await fsFolderWrite(newPath + '\n' + content);
        if (wr.startsWith('fs_write error:')) return 'Rename failed: ' + wr;
        await fsFolderDelete(oldPath);
        return `Renamed: ${oldPath} → ${newPath}`;
    }

    async function fsFolderCopy(arg) {
        if (!codingFolderHandle) return 'No folder linked.';
        const [src, dest] = (arg||'').split('|').map(s=>s.trim());
        if (!src || !dest) return 'Format: srcPath|destPath';
        const content = await fsFolderRead(src);
        if (content.startsWith('fs_read error:')) return 'Copy failed: ' + content;
        return await fsFolderWrite(dest + '\n' + content);
    }

    // ── AETHER.md context injection (limit 600 → 2000 chars) ─
    async function readAetherMd() {
        if (!codingFolderHandle) return null;
        try {
            const fh = await codingFolderHandle.getFileHandle('AETHER.md');
            const text = await (await fh.getFile()).text();
            if (text.length <= 2000) return text;
            return text.slice(0, 2000) + '\n\n[AETHER.md truncated at 2000 chars]';
        } catch { return null; }
    }
    async function fsFolderList(path='') {
        // Basic list — used internally. For full ls flags use fsFolderShell().
        if (!codingFolderHandle) return 'No folder linked.';
        try {
            let dir = codingFolderHandle;
            if (path) for (const p of path.split('/').filter(Boolean)) dir = await dir.getDirectoryHandle(p);
            const entries = [];
            for await (const [name, handle] of dir.entries()) {
                entries.push((handle.kind === 'directory' ? '\ud83d\udcc1 ' : '\ud83d\udcc4 ') + name);
            }
            return entries.sort().join('\n') || '(empty)';
        } catch(e) { return 'fs_list error: ' + e.message; }
    }

    // ─── AETHER CODE SHELL ENGINE ─────────────────────────────
    // Interprets UNIX-style commands against the linked FileSystemDirectoryHandle.
    // Supported: ls, ls -a, ls -la/-al, grep, cat, head, tail, wc, find, pwd, tree.
    // This is NOT a real shell — it's a browser-native FS explorer that speaks
    // shell syntax. No pipes, no env vars, no process spawning.
    // Think of it as "ls for people who forgot they're in a browser."
    //
    // Called from TOOL_REGISTRY['shell'] and from the Coding Mode chat parser
    // when a message looks like a shell command.

    // ── Resolve a path string against the root handle ─────────
    async function fsResolveDir(pathStr) {
        if (typeof AETHER_Security !== 'undefined' && AETHER_Security.safePath) {
            const sp = AETHER_Security.safePath(pathStr || '');
            if (!sp.ok) throw new Error('path blocked: ' + sp.error);
            pathStr = sp.path;
        }
        let dir = codingFolderHandle;
        const parts = (pathStr || '').split('/').filter(p => p && p !== '.');
        for (const p of parts) {
            if (p === '..') {
                throw new Error('.. traversal blocked');
            }
            dir = await dir.getDirectoryHandle(p);
        }
        return dir;
    }

    /** Guard FS path before read/write/delete */
    function assertSafeFsPath(pathStr, forWrite) {
        if (typeof AETHER_Security === 'undefined' || !AETHER_Security.safePath) return pathStr;
        const sp = AETHER_Security.safePath(pathStr || '');
        if (!sp.ok) throw new Error('path blocked: ' + sp.error);
        if (forWrite && sp.sensitive) throw new Error('write to sensitive path blocked: ' + sp.path);
        return sp.path;
    }

    // ── Recursively collect all entries for tree/find ─────────
    async function fsCollectEntries(dirHandle, prefix, maxDepth, depth, showHidden) {
        if (depth > maxDepth) return [];
        const out = [];
        const entries = [];
        for await (const [name, handle] of dirHandle.entries()) {
            if (!showHidden && name.startsWith('.')) continue;
            entries.push({ name, handle });
        }
        entries.sort((a, b) => {
            // Dirs first, then alpha
            if (a.handle.kind !== b.handle.kind) return a.handle.kind === 'directory' ? -1 : 1;
            return a.name.localeCompare(b.name);
        });
        for (const { name, handle } of entries) {
            const fullPath = prefix ? prefix + '/' + name : name;
            out.push({ path: fullPath, kind: handle.kind, handle });
            if (handle.kind === 'directory' && depth < maxDepth) {
                const sub = await fsCollectEntries(handle, fullPath, maxDepth, depth + 1, showHidden);
                out.push(...sub);
            }
        }
        return out;
    }

    // ── Format a file size in bytes to human-readable ─────────
    function fmtSize(bytes) {
        if (bytes < 1024)     return bytes + 'B';
        if (bytes < 1048576)  return (bytes / 1024).toFixed(1) + 'K';
        return (bytes / 1048576).toFixed(1) + 'M';
    }

    // ── Main shell command dispatcher ─────────────────────────
    async function fsFolderShell(rawCmd) {
        if (!codingFolderHandle) {
            const last = getLastFolderName();
            return last
                ? `No folder linked. Last folder: "${last}". Click Link Folder to reconnect.`
                : 'No folder linked. Click Link Folder to connect a project directory.';
        }

        // Security: allowlist + denylist before any FS work
        if (typeof AETHER_Security !== 'undefined' && AETHER_Security.validateShellCommand) {
            const vs = AETHER_Security.validateShellCommand(rawCmd);
            if (!vs.ok) return 'ok=false error=shell security: ' + vs.error;
            rawCmd = vs.command;
        }

        // Trim, collapse runs of whitespace
        const cmd = rawCmd.trim().replace(/\s+/g, ' ');
        const parts = cmd.split(' ');
        const prog  = parts[0].toLowerCase();

        try {
            // ── pwd ──────────────────────────────────────────────
            if (prog === 'pwd') {
                return '/' + codingFolderHandle.name;
            }

            // ── ls [flags] [path] ────────────────────────────────
            if (prog === 'ls') {
                // Parse flags and path: ls, ls -a, ls -la, ls -al, ls src/, ls -la src/
                let showHidden = false;
                let longFmt    = false;
                let targetPath = '';

                for (let i = 1; i < parts.length; i++) {
                    const p = parts[i];
                    if (p.startsWith('-')) {
                        if (p.includes('a')) showHidden = true;
                        if (p.includes('l')) longFmt    = true;
                    } else {
                        targetPath = p;
                    }
                }

                const dir = await fsResolveDir(targetPath);
                const entries = [];
                for await (const [name, handle] of dir.entries()) {
                    if (!showHidden && name.startsWith('.')) continue;
                    entries.push({ name, handle });
                }
                // Sort: dirs first, then alpha within each group
                entries.sort((a, b) => {
                    if (a.handle.kind !== b.handle.kind) return a.handle.kind === 'directory' ? -1 : 1;
                    return a.name.localeCompare(b.name);
                });

                if (!entries.length) return '(empty)';

                if (longFmt) {
                    // -l: permissions-style listing with size, date, name
                    const rows = await Promise.all(entries.map(async ({ name, handle }) => {
                        if (handle.kind === 'directory') {
                            return `drwxr-xr-x  -           ${name}/`;
                        }
                        try {
                            const file = await (await handle.getFile());
                            const date = new Date(file.lastModified).toLocaleDateString('en-GB', { day:'2-digit', month:'short', year:'2-digit' });
                            return `-rw-r--r--  ${fmtSize(file.size).padStart(6)}  ${date}  ${name}`;
                        } catch {
                            return `-rw-r--r--       ?           ${name}`;
                        }
                    }));
                    const label = targetPath ? targetPath : codingFolderHandle.name;
                    return `total ${entries.length}  (${label})\n` + rows.join('\n');
                }

                // Short format: columns
                const names = entries.map(({ name, handle }) =>
                    handle.kind === 'directory' ? name + '/' : name
                );
                return names.join('  ');
            }

            // ── cat <file> [file2 ...] ───────────────────────────
            if (prog === 'cat') {
                if (parts.length < 2) return 'cat: missing file operand';
                const results = [];
                for (const filePath of parts.slice(1)) {
                    const content = await fsFolderRead(filePath);
                    results.push(parts.length > 2 ? `==> ${filePath} <==\n${content}` : content);
                }
                return results.join('\n\n');
            }

            // ── head [-n N] <file> ───────────────────────────────
            if (prog === 'head') {
                let n = 10, filePath = '';
                for (let i = 1; i < parts.length; i++) {
                    if (parts[i] === '-n' && parts[i+1]) { n = parseInt(parts[++i]) || 10; }
                    else if (parts[i].match(/^-\d+$/)) { n = Math.abs(parseInt(parts[i])); }
                    else { filePath = parts[i]; }
                }
                if (!filePath) return 'head: missing file operand';
                const content = await fsFolderRead(filePath);
                if (content.startsWith('fs_read error:') || content.startsWith('Folder not')) return content;
                return content.split('\n').slice(0, n).join('\n');
            }

            // ── tail [-n N] <file> ───────────────────────────────
            if (prog === 'tail') {
                let n = 10, filePath = '';
                for (let i = 1; i < parts.length; i++) {
                    if (parts[i] === '-n' && parts[i+1]) { n = parseInt(parts[++i]) || 10; }
                    else if (parts[i].match(/^-\d+$/)) { n = Math.abs(parseInt(parts[i])); }
                    else { filePath = parts[i]; }
                }
                if (!filePath) return 'tail: missing file operand';
                const content = await fsFolderRead(filePath);
                if (content.startsWith('fs_read error:') || content.startsWith('Folder not')) return content;
                const lines = content.split('\n');
                return lines.slice(-n).join('\n');
            }

            // ── wc [-l|-w|-c] <file> ─────────────────────────────
            if (prog === 'wc') {
                const flags    = parts.filter(p => p.startsWith('-'));
                const filePath = parts.find((p, i) => i > 0 && !p.startsWith('-'));
                if (!filePath) return 'wc: missing file operand';
                const content = await fsFolderRead(filePath);
                if (content.startsWith('fs_read error:') || content.startsWith('Folder not')) return content;
                const lines = content.split('\n').length;
                const words = content.trim().split(/\s+/).filter(Boolean).length;
                const chars = content.length;
                if (flags.includes('-l')) return `${lines}  ${filePath}`;
                if (flags.includes('-w')) return `${words}  ${filePath}`;
                if (flags.includes('-c')) return `${chars}  ${filePath}`;
                // Default: lines words chars
                return `${String(lines).padStart(6)} ${String(words).padStart(7)} ${String(chars).padStart(7)}  ${filePath}`;
            }

            // ── grep [-r] [-i] [-n] [-l] <pattern> [path] ────────
            if (prog === 'grep') {
                let recursive = false, ignoreCase = false, lineNums = false, filesOnly = false;
                const rawArgs = parts.slice(1);
                const nonFlags = [];

                for (const a of rawArgs) {
                    if (a.startsWith('-')) {
                        if (a.includes('r') || a.includes('R')) recursive = true;
                        if (a.includes('i')) ignoreCase = true;
                        if (a.includes('n')) lineNums   = true;
                        if (a.includes('l')) filesOnly  = true;
                    } else {
                        nonFlags.push(a);
                    }
                }

                if (!nonFlags.length) return 'grep: missing pattern';
                const pattern  = nonFlags[0];
                const target   = nonFlags[1] || '';   // file or dir
                const flags    = ignoreCase ? 'gi' : 'g';
                let re;
                try { re = new RegExp(pattern, flags); } catch(e) { return 'grep: invalid pattern: ' + e.message; }

                const results = [];

                const grepFile = async (filePath) => {
                    const content = await fsFolderRead(filePath);
                    if (!content || content.startsWith('fs_read error:')) return;
                    const lines = content.split('\n');
                    let fileMatched = false;
                    lines.forEach((line, idx) => {
                        if (re.test(line)) {
                            re.lastIndex = 0; // reset for global flag
                            fileMatched = true;
                            if (!filesOnly) {
                                const prefix = lineNums ? `${filePath}:${idx+1}: ` : `${filePath}: `;
                                results.push(prefix + line.trim().slice(0, 200));
                            }
                        }
                        re.lastIndex = 0;
                    });
                    if (filesOnly && fileMatched) results.push(filePath);
                };

                if (recursive || !target) {
                    // Recursive — walk from root or target dir
                    const entries = await fsCollectEntries(
                        target ? await fsResolveDir(target) : codingFolderHandle,
                        target, 8, 0, false
                    );
                    for (const e of entries) {
                        if (e.kind === 'file') await grepFile(e.path);
                        if (results.length > 60) { results.push('... (truncated at 60 matches)'); break; }
                    }
                } else {
                    // Single file
                    await grepFile(target);
                }

                return results.length ? results.join('\n') : `grep: no matches for "${pattern}"`;
            }

            // ── find [path] [-name pattern] [-type f|d] ───────────
            if (prog === 'find') {
                let basePath  = '';
                let nameGlob  = '';
                let typeFilter = '';   // 'f' | 'd' | ''

                for (let i = 1; i < parts.length; i++) {
                    if (parts[i] === '-name' && parts[i+1])  { nameGlob  = parts[++i]; }
                    else if (parts[i] === '-type' && parts[i+1]) { typeFilter = parts[++i]; }
                    else if (!parts[i].startsWith('-'))       { basePath = parts[i]; }
                }

                const baseDir = basePath ? await fsResolveDir(basePath) : codingFolderHandle;
                const entries = await fsCollectEntries(baseDir, basePath, 10, 0, true);
                let matches = entries;

                if (typeFilter === 'f') matches = matches.filter(e => e.kind === 'file');
                if (typeFilter === 'd') matches = matches.filter(e => e.kind === 'directory');

                if (nameGlob) {
                    const globRe = new RegExp(
                        '^' + nameGlob.replace(/\./g,'\\.').replace(/\*/g,'.*').replace(/\?/g,'.') + '$'
                    );
                    matches = matches.filter(e => globRe.test(e.path.split('/').pop()));
                }

                if (!matches.length) return '(no matches)';
                return matches.slice(0, 100).map(e =>
                    (basePath ? '' : './') + e.path + (e.kind === 'directory' ? '/' : '')
                ).join('\n');
            }

            // ── tree [-a] [-L depth] [path] ──────────────────────
            if (prog === 'tree') {
                let showHidden = false, maxDepth = 3, targetPath = '';
                for (let i = 1; i < parts.length; i++) {
                    if (parts[i] === '-a') showHidden = true;
                    else if (parts[i] === '-L' && parts[i+1]) { maxDepth = parseInt(parts[++i]) || 3; }
                    else if (!parts[i].startsWith('-')) { targetPath = parts[i]; }
                }
                const dir = targetPath ? await fsResolveDir(targetPath) : codingFolderHandle;
                const label = targetPath || codingFolderHandle.name;

                const buildTree = async (dirHandle, prefix, depth) => {
                    if (depth > maxDepth) return [];
                    const lines = [];
                    const entries = [];
                    for await (const [name, handle] of dirHandle.entries()) {
                        if (!showHidden && name.startsWith('.')) continue;
                        entries.push({ name, handle });
                    }
                    entries.sort((a, b) => {
                        if (a.handle.kind !== b.handle.kind) return a.handle.kind === 'directory' ? -1 : 1;
                        return a.name.localeCompare(b.name);
                    });
                    for (let i = 0; i < entries.length; i++) {
                        const { name, handle } = entries[i];
                        const isLast   = i === entries.length - 1;
                        const branch   = isLast ? '└── ' : '├── ';
                        const childPfx = isLast ? '    ' : '│   ';
                        const icon     = handle.kind === 'directory' ? '📁 ' : '';
                        lines.push(prefix + branch + icon + name);
                        if (handle.kind === 'directory' && depth < maxDepth) {
                            const sub = await buildTree(handle, prefix + childPfx, depth + 1);
                            lines.push(...sub);
                        }
                    }
                    return lines;
                };

                const treeLines = await buildTree(dir, '', 0);
                const fileCount = treeLines.filter(l => !l.includes('📁')).length;
                const dirCount  = treeLines.filter(l => l.includes('📁')).length;
                return label + '\n' + treeLines.join('\n') +
                    `\n\n${dirCount} director${dirCount===1?'y':'ies'}, ${fileCount} file${fileCount===1?'':'s'}`;
            }

            // ── mkdir <path> ──────────────────────────────────────
            if (prog === 'mkdir') {
                if (parts.length < 2) return 'mkdir: missing operand';
                const results = [];
                for (const p of parts.slice(1)) {
                    results.push(await fsFolderMkdir(p));
                }
                return results.join('\n');
            }

            // ── touch <file> ──────────────────────────────────────
            if (prog === 'touch') {
                if (parts.length < 2) return 'touch: missing file operand';
                const results = [];
                for (const filePath of parts.slice(1)) {
                    try {
                        const partsPath = filePath.split('/').filter(Boolean);
                        let dir = codingFolderHandle;
                        for (const p of partsPath.slice(0, -1)) dir = await dir.getDirectoryHandle(p, { create: true });
                        const fh = await dir.getFileHandle(partsPath[partsPath.length - 1], { create: true });
                        // Read then write to update modification time
                        const existing = await (await fh.getFile()).text();
                        await writeToFileHandle(fh, existing);
                        results.push('  touched: ' + filePath);
                    } catch(e) { results.push('  touch error: ' + e.message); }
                }
                return results.join('\n');
            }

            // ── sort <file> ───────────────────────────────────────
            if (prog === 'sort') {
                if (parts.length < 2) return 'sort: missing file operand';
                const filePath = parts[1];
                const content = await fsFolderRead(filePath);
                if (content.startsWith('fs_read error:')) return content;
                return content.split('\n').filter((_, i, a) => !(i === a.length - 1 && _ === '')).sort().join('\n');
            }

            // ── uniq [<file>] ─────────────────────────────────────
            if (prog === 'uniq') {
                const filePath = parts[1];
                if (!filePath) return 'uniq: missing file operand';
                const content = await fsFolderRead(filePath);
                if (content.startsWith('fs_read error:')) return content;
                const lines = content.split('\n');
                const result = [];
                for (const line of lines) {
                    if (result[result.length - 1] !== line) result.push(line);
                }
                return result.join('\n');
            }

            // ── diff <file1> <file2> ──────────────────────────────
            if (prog === 'diff') {
                if (parts.length < 3) return 'diff: missing operand after \'' + (parts[1] || '') + '\'';
                const [a, b] = [await fsFolderRead(parts[1]), await fsFolderRead(parts[2])];
                if (a.startsWith('fs_read error:')) return a;
                if (b.startsWith('fs_read error:')) return b;
                const linesA = a.split('\n'), linesB = b.split('\n');
                const maxLen = Math.max(linesA.length, linesB.length);
                const out = [];
                let hasDiff = false;
                for (let i = 0; i < maxLen; i++) {
                    if (linesA[i] !== linesB[i]) {
                        hasDiff = true;
                        if (i < linesA.length) out.push((i + 1).toString().padStart(4) + ' - ' + linesA[i].slice(0, 120));
                        else out.push((i + 1).toString().padStart(4) + ' -');
                        if (i < linesB.length) out.push((i + 1).toString().padStart(4) + ' + ' + linesB[i].slice(0, 120));
                        else out.push((i + 1).toString().padStart(4) + ' +');
                    }
                }
                if (!hasDiff) return '(identical)';
                return '--- ' + parts[1] + '\n+++ ' + parts[2] + '\n' + out.join('\n');
            }

            // ── help ─────────────────────────────────────────────
            if (prog === 'help' || prog === '?') {
                return [
                    'AETHER Code Shell — available commands:',
                    '',
                    '  pwd                        Show current folder path',
                    '  ls [-a] [-l] [path]        List files (−a: show hidden, −l: long format)',
                    '  cat <file> [file2 ...]     Print file contents',
                    '  head [-n N] <file>         First N lines (default 10)',
                    '  tail [-n N] <file>         Last N lines (default 10)',
                    '  wc [-l|-w|-c] <file>       Word/line/char count',
                    '  grep [-r] [-i] [-n] [-l] <pattern> [path]',
                    '                             Search for pattern in files',
                    '  find [path] [-name glob] [-type f|d]',
                    '                             Find files by name or type',
                    '  tree [-a] [-L depth] [path] Directory tree',
                    '  mkdir <path>               Create directory (recursive)',
                    '  touch <file> [file2 ...]   Create empty file or update timestamp',
                    '  sort <file>                Sort lines alphabetically',
                    '  uniq <file>                Remove adjacent duplicate lines',
                    '  diff <file1> <file2>       Line-by-line file comparison',
                    '  help                       Show this help',
                    '',
                    'Paths are relative to the linked folder root.',
                    'No pipes yet. No env vars. But it is pretty good for a browser.',
                ].join('\n');
            }

            return `${prog}: command not found. Type "help" to see available commands.`;

        } catch(e) {
            return `${prog}: ${e.message}`;
        }
    }

    // ─────────────────────────────────────────────────────────────
    // FEATURE: GIT-AWARE DIFF VIEW
    // ─────────────────────────────────────────────────────────────
    // Computes a minimal line-based diff between oldContent and newContent
    // and renders a .diff-card element. Inserted before the code block.
    async function showFileDiff_inline(oldContent, newContent, filename, wrapper) {
        if (!oldContent || oldContent === newContent) return;
        var oldLines = oldContent.split('\n');
        var newLines = newContent.split('\n');
        var adds = 0, dels = 0;

        // Simple LCS-based diff for small files, fallback to line-prefix match
        var diffHtml = '';
        var maxLen = Math.max(oldLines.length, newLines.length);
        var oi = 0, ni = 0;
        while (oi < oldLines.length || ni < newLines.length) {
            if (oi < oldLines.length && ni < newLines.length && oldLines[oi] === newLines[ni]) {
                diffHtml += '<div class="diff-line ctx"> ' + escapeHtml(oldLines[oi]) + '</div>';
                oi++; ni++;
            } else if (ni < newLines.length && (oi >= oldLines.length || newLines[ni] !== oldLines[oi])) {
                diffHtml += '<div class="diff-line add">+ ' + escapeHtml(newLines[ni]) + '</div>';
                adds++; ni++;
            } else if (oi < oldLines.length) {
                diffHtml += '<div class="diff-line del">- ' + escapeHtml(oldLines[oi]) + '</div>';
                dels++; oi++;
            }
        }
        if (adds === 0 && dels === 0) return;

        var card = document.createElement('div');
        card.className = 'diff-card';
        card.innerHTML = '<div class="diff-card-header">'
            + '<span class="diff-card-filename">' + escapeHtml(filename) + '</span>'
            + '<span class="diff-card-stats">'
            + '<span class="diff-stat-add">+' + adds + '</span>'
            + '<span class="diff-stat-del">-' + dels + '</span>'
            + '</span></div>'
            + '<div class="diff-card-body">' + diffHtml + '</div>';
        wrapper.parentNode.insertBefore(card, wrapper);
    }

    // ─────────────────────────────────────────────────────────────
    // FEATURE: FILE TREE PANEL
    // ─────────────────────────────────────────────────────────────
    // Renders a visual tree of the linked coding folder in the
    // #coding-file-tree panel. Supports click-to-open.
    async function renderFileTree() {
        var treeBody = document.getElementById('coding-tree-body');
        var treeLabel = document.getElementById('coding-tree-label');
        var treePanel = document.getElementById('coding-file-tree');
        if (!treeBody || !treePanel) return;
        if (!codingFolderHandle) { treePanel.style.display = 'none'; return; }

        treePanel.style.display = 'block';
        treeBody.innerHTML = '<div class="coding-tree-loading">Loading…</div>';
        if (treeLabel) treeLabel.textContent = codingFolderHandle.name;

        try {
            var entries = [];
            await buildTreeEntries(codingFolderHandle, '', 0, entries);
            treeBody.innerHTML = '';
            renderTreeNodes(treeBody, entries, 0);
        } catch(e) {
            treeBody.innerHTML = '<div class="coding-tree-loading">Error: ' + escapeHtml(e.message) + '</div>';
        }
    }

    async function buildTreeEntries(dirHandle, prefix, depth, out) {
        if (depth > 3) return; // limit depth
        var list = [];
        for await (var entry of dirHandle.entries()) {
            var name = entry[0], handle = entry[1];
            if (name.startsWith('.') && name !== '.env') continue;
            var path = prefix ? prefix + '/' + name : name;
            if (handle.kind === 'directory') {
                list.push({ name: name, path: path, isDir: true, handle: handle });
            } else {
                list.push({ name: name, path: path, isDir: false, handle: handle });
            }
        }
        list.sort(function(a, b) {
            if (a.isDir !== b.isDir) return a.isDir ? -1 : 1;
            return a.name.localeCompare(b.name);
        });
        for (var item of list) {
            out.push(item);
            if (item.isDir) {
                await buildTreeEntries(item.handle, item.path, depth + 1, out);
            }
        }
    }

    function renderTreeNodes(container, entries, depth) {
        for (var item of entries) {
            if (item._depth !== undefined && item._depth !== depth) continue;
            item._depth = depth;
            var el = document.createElement('div');
            el.className = 'coding-tree-item' + (item.isDir ? ' dir' : '');
            var indent = Array(depth + 1).join('<span class="tree-spacer" style="width:12px"></span>');
            el.innerHTML = indent
                + '<span class="tree-icon">' + (item.isDir ? '\ud83d\udcc1' : '\ud83d\udcc4') + '</span>'
                + '<span class="tree-name">' + escapeHtml(item.name) + '</span>';
            el.title = item.path;
            el.onclick = function(path, isDir) {
                return function() {
                    if (isDir) return;
                    // Open file in the workspace editor
                    var content = '';
                    (async function() {
                        try {
                            var f = await codingFolderHandle.getFileHandle(path);
                            var file = await f.getFile();
                            content = await file.text();
                            window.openWorkspaceEditor(path, content, true);
                        } catch(e) {
                            showNotification('Cannot read ' + path + ': ' + e.message, 'error');
                        }
                    })();
                };
            }(item.path, item.isDir);
            container.appendChild(el);
        }
    }

    // ─────────────────────────────────────────────────────────────
    // FEATURE: CODING TERMINAL PANEL
    // ─────────────────────────────────────────────────────────────
    // Persistent terminal with scrollback, command history, and
    // inline shell execution against the linked folder.
    var _terminalHistory = [];
    var _terminalHistoryIdx = -1;

    function initCodingTerminal() {
        var termBody = document.getElementById('coding-terminal-body');
        var termInput = document.getElementById('coding-terminal-input');
        var termClear = document.getElementById('coding-terminal-clear');
        var termMinMax = document.getElementById('coding-terminal-minmax');
        var termPanel = document.getElementById('coding-terminal');
        if (!termInput || !termBody || !termPanel) return;

        // Show/hide terminal with coding mode
        function updateTerminal() {
            termPanel.style.display = (state.codingMode && codingFolderHandle) ? 'flex' : 'none';
            if (termPanel.style.display === 'flex') {
                var cwd = document.getElementById('coding-terminal-cwd');
                if (cwd && codingFolderHandle) cwd.textContent = '/' + codingFolderHandle.name;
            }
        }
        // Watch coding mode + folder changes
        var cmObserver = new MutationObserver(function() { updateTerminal(); });
        var cmBtn = document.getElementById('btn-coding-mode');
        if (cmBtn) cmObserver.observe(cmBtn, { attributes: true, attributeFilter: ['class'] });
        updateTerminal();

        // Re-evaluate when folder is linked
        var origOpenCodingFolder = window.openCodingFolder;
        // We patch updateCodingFolderUI call chain instead — see renderFileTree hook below

        termInput.addEventListener('keydown', async function(e) {
            if (e.key === 'Enter') {
                var cmd = termInput.value.trim();
                if (!cmd) return;
                termInput.value = '';
                _terminalHistory.push(cmd);
                _terminalHistoryIdx = _terminalHistory.length;

                // Show command in terminal
                var line = document.createElement('div');
                line.className = 'coding-terminal-line';
                line.innerHTML = '<span style="color:#50c080">$</span> ' + escapeHtml(cmd);
                termBody.appendChild(line);
                termBody.scrollTop = termBody.scrollHeight;

                // Execute
                var result = '';
                try {
                    if (cmd === 'help') {
                        result = 'Available: ls, cat, head, tail, wc, grep, find, tree, pwd, mkdir, touch, sort, uniq, diff, clear, help';
                    } else if (cmd === 'clear') {
                        termBody.innerHTML = '';
                        return;
                    } else if (typeof fsFolderShell === 'function') {
                        result = await fsFolderShell(cmd);
                    } else {
                        result = 'Shell not available';
                    }
                } catch(ex) {
                    result = 'Error: ' + ex.message;
                }

                if (result) {
                    var outLine = document.createElement('div');
                    outLine.className = 'coding-terminal-line';
                    outLine.textContent = result;
                    termBody.appendChild(outLine);
                    termBody.scrollTop = termBody.scrollHeight;
                }
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                if (_terminalHistory.length === 0) return;
                _terminalHistoryIdx = Math.max(0, _terminalHistoryIdx - 1);
                termInput.value = _terminalHistory[_terminalHistoryIdx] || '';
            } else if (e.key === 'ArrowDown') {
                e.preventDefault();
                if (_terminalHistory.length === 0) return;
                _terminalHistoryIdx = Math.min(_terminalHistory.length, _terminalHistoryIdx + 1);
                termInput.value = _terminalHistoryIdx < _terminalHistory.length ? (_terminalHistory[_terminalHistoryIdx] || '') : '';
            }
        });

        if (termClear) {
            termClear.onclick = function() { termBody.innerHTML = ''; };
        }
        if (termMinMax) {
            termMinMax.onclick = function() {
                termPanel.classList.toggle('minimized');
                termMinMax.textContent = termPanel.classList.contains('minimized') ? '\u25b2' : '\u2500';
            };
        }
    }

    // Hook: update terminal + file tree when folder is linked
    function updateCodingFolderUI() {
        // Update folder button text (was original body)
        var btn = document.getElementById('coding-folder-btn');
        if (btn) {
            btn.textContent = codingFolderHandle ? ('📁 ' + codingFolderHandle.name) : '📂 Link Folder';
            btn.title = codingFolderHandle ? 'Linked: ' + codingFolderHandle.name : 'Give AETHER Code access to a project folder';
        }
        var railBtn = document.getElementById('code-rail-link-folder');
        if (railBtn) {
            railBtn.textContent = codingFolderHandle ? ('📁 ' + codingFolderHandle.name) : '📁 Folder';
        }
        if (codingFolderHandle) {
            renderFileTree();
            var cwd = document.getElementById('coding-terminal-cwd');
            if (cwd) cwd.textContent = '/' + codingFolderHandle.name;
            var inited = localStorage.getItem('aether_project_inited');
            if (!inited) {
                showProjectInitWizard();
            }
        }
        syncCodeAgentShell();
    }

