    function showProjectInitWizard() {
        if (!codingFolderHandle) return;
        var overlay = document.createElement('div');
        overlay.className = 'init-wizard-overlay';
        overlay.id = 'init-wizard-overlay';

        var stackBtns = '';
        for (var key in PROJECT_TEMPLATES) {
            var t = PROJECT_TEMPLATES[key];
            stackBtns += '<button class="init-wizard-stack-btn" data-stack="' + key + '">'
                + '<span class="stack-icon">' + t.icon + '</span>'
                + '<span>' + t.name + '<br><span class="stack-desc">' + t.desc + '</span></span>'
                + '</button>';
        }

        overlay.innerHTML = '<div class="init-wizard-modal">'
            + '<div class="init-wizard-title"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#00f3ff" stroke-width="2"><polygon points="12 2 2 7 12 22 22 7"/></svg> Initialize Project</div>'
            + '<div class="init-wizard-sub">Choose a template for <strong>' + escapeHtml(codingFolderHandle.name) + '</strong></div>'
            + '<div class="init-wizard-stacks">' + stackBtns + '</div>'
            + '<div class="init-wizard-actions">'
            + '<button id="init-wizard-skip" class="">Skip — empty project</button>'
            + '<button id="init-wizard-confirm" class="primary">Generate</button>'
            + '</div></div>';

        document.body.appendChild(overlay);

        var selectedStack = null;
        overlay.querySelectorAll('.init-wizard-stack-btn').forEach(function(btn) {
            btn.onclick = function() {
                overlay.querySelectorAll('.init-wizard-stack-btn').forEach(function(b) {
                    b.style.borderColor = 'rgba(255,255,255,0.06)';
                    b.style.background = 'rgba(255,255,255,0.03)';
                });
                btn.style.borderColor = 'rgba(0,243,255,0.3)';
                btn.style.background = 'rgba(0,243,255,0.06)';
                selectedStack = btn.dataset.stack;
            };
        });

        document.getElementById('init-wizard-skip').onclick = function() {
            localStorage.setItem('aether_project_inited', '1');
            overlay.remove();
            // Still create a basic AETHER.md
            generateAetherMd(null);
        };

        document.getElementById('init-wizard-confirm').onclick = async function() {
            if (!selectedStack) { showNotification('Select a template first', 'warn'); return; }
            var tmpl = PROJECT_TEMPLATES[selectedStack];
            if (!tmpl) return;
            var confirmBtn = document.getElementById('init-wizard-confirm');
            confirmBtn.textContent = 'Generating…';
            confirmBtn.disabled = true;
            try {
                for (var fname in tmpl.files) {
                    try {
                        var handle = await codingFolderHandle.getFileHandle(fname, { create: true });
                        var writable = await handle.createWritable();
                        await writable.write(tmpl.files[fname]);
                        await writable.close();
                    } catch(e) {
                        console.warn('Failed to create ' + fname + ': ' + e.message);
                    }
                }
                await generateAetherMd(selectedStack);
                localStorage.setItem('aether_project_inited', '1');
                overlay.remove();
                renderFileTree();
                showNotification('Project initialized: ' + tmpl.name, 'success');
            } catch(e) {
                showNotification('Init failed: ' + e.message, 'error');
                confirmBtn.textContent = 'Generate';
                confirmBtn.disabled = false;
            }
        };

        // Close on overlay click
        overlay.onclick = function(e) {
            if (e.target === overlay) {
                localStorage.setItem('aether_project_inited', '1');
                overlay.remove();
                generateAetherMd(null);
            }
        };
    }

    async function generateAetherMd(stackKey) {
        if (!codingFolderHandle) return;
        var aetherContent = '# AETHER Code — Project Rules\n\n'
            + '## Project\n- Name: ' + codingFolderHandle.name + '\n'
            + (stackKey ? '- Stack: ' + (PROJECT_TEMPLATES[stackKey]?.name || stackKey) + '\n' : '')
            + '- Managed by AETHER Code\n\n'
            + '## Commands\n- Build: _(add your build command)_\n- Test: _(add your test command)_\n- Run: _(add your run command)_\n\n'
            + '## Guidelines\n- Write clear, maintainable code\n- Add tests for non-trivial functions\n- Follow the project\'s existing conventions\n';
        try {
            var handle = await codingFolderHandle.getFileHandle('AETHER.md', { create: true });
            var writable = await handle.createWritable();
            await writable.write(aetherContent);
            await writable.close();
        } catch(e) {
            console.warn('AETHER.md creation skipped: ' + e.message);
        }
    }

