    // ─────────────────────────────────────────────────────────────
    // QUEUE SYSTEM (Ques)
    // ─────────────────────────────────────────────────────────────
    var _taskQueue = [];
    var _queueRunning = false;

    function queueAdd(label, type, action) {
        var id = 'q_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6);
        _taskQueue.push({ id: id, label: label, type: type || 'custom', status: 'pending', action: action || null, result: null });
        queueRender();
        if (!_queueRunning) queueProcessNext();
        return id;
    }

    async function queueProcessNext() {
        if (_queueRunning) return;
        var item = _taskQueue.find(function(i) { return i.status === 'pending'; });
        if (!item) { _queueRunning = false; queueRender(); return; }
        _queueRunning = true;
        item.status = 'running';
        queueRender();

        try {
            var result;
            if (item.type === 'shell' && typeof fsFolderShell === 'function') {
                result = await fsFolderShell(item.action || item.label);
            } else if (item.type === 'lint' && codingFolderHandle) {
                var parts = (item.action || item.label).replace(/^lint\s+/i, '').split(/\s+/);
                var fn = parts[0];
                if (!fn) { result = 'Specify a file to lint'; item.status = 'failed'; }
                else {
                    result = await fsFolderShell('cat ' + fn);
                    // Simple heuristic lint: check for common issues
                    var issues = [];
                    var lines = result.split('\n');
                    lines.forEach(function(l, i) {
                        if (l.length > 120) issues.push('Line ' + (i+1) + ': >120 chars');
                        if (/\t/.test(l)) issues.push('Line ' + (i+1) + ': contains tabs');
                        if (/^\s+$/.test(l) && l.length > 0) issues.push('Line ' + (i+1) + ': trailing whitespace');
                    });
                    result = issues.length ? issues.join('\n') : 'No style issues found.';
                }
            } else if (typeof item.action === 'function') {
                result = await item.action();
            } else if (item.action) {
                result = item.action;
            } else {
                result = 'Done.';
            }
            item.result = String(result).slice(0, 300);
            item.status = 'done';
        } catch(e) {
            item.result = e.message;
            item.status = 'failed';
        }

        _queueRunning = false;
        queueRender();

        // Show notification for completed tasks
        if (item.status === 'done') {
            showNotification('Queue: ' + item.label + ' ✓', 'success');
        } else {
            showNotification('Queue: ' + item.label + ' ✗ ' + item.result, 'error');
        }

        // Process next
        queueProcessNext();
    }

    function queueRemove(id) {
        _taskQueue = _taskQueue.filter(function(i) { return i.id !== id; });
        queueRender();
    }

    function queueClearDone() {
        _taskQueue = _taskQueue.filter(function(i) { return i.status === 'pending' || i.status === 'running'; });
        queueRender();
    }

    function queueRender() {
        var list = document.getElementById('queue-list');
        if (!list) return;
        var pending = _taskQueue.filter(function(i) { return i.status !== 'done' && i.status !== 'failed'; });
        var done = _taskQueue.filter(function(i) { return i.status === 'done' || i.status === 'failed'; });
        list.innerHTML = '';
        if (_taskQueue.length === 0) {
            list.innerHTML = '<div class="queue-empty">No tasks queued.</div>';
            return;
        }
        pending.concat(done).forEach(function(item) {
            var el = document.createElement('div');
            el.className = 'queue-item';
            var statusIcon = '';
            if (item.status === 'pending') statusIcon = '<span class="q-status pending"></span>';
            else if (item.status === 'running') statusIcon = '<span class="q-status running"></span>';
            else if (item.status === 'done') statusIcon = '<span class="q-status done">✓</span>';
            else statusIcon = '<span class="q-status failed">✗</span>';
            el.innerHTML = statusIcon
                + '<span class="q-label" title="' + escapeHtml(item.result || '') + '">' + escapeHtml(item.label) + '</span>'
                + '<button class="q-remove" data-qid="' + item.id + '">✕</button>';
            list.appendChild(el);
        });
        list.querySelectorAll('.q-remove').forEach(function(btn) {
            btn.onclick = function() { queueRemove(btn.dataset.qid); };
        });
    }

    // Wire queue UI
    setTimeout(function() {
        var queueInput = document.getElementById('queue-input');
        var queueAddBtn = document.getElementById('queue-add-btn');
        var queueClearBtn = document.getElementById('queue-clear-btn');
        if (queueAddBtn && queueInput) {
            function addFromInput() {
                var val = queueInput.value.trim();
                if (!val) return;
                queueInput.value = '';
                var type = 'custom';
                var action = null;
                if (/^lint\b/i.test(val)) { type = 'lint'; action = val; }
                else if (/^(ls|cat|grep|tree|find|head|tail|wc|pwd|mkdir)\b/i.test(val)) { type = 'shell'; action = val; }
                queueAdd(val, type, action);
            }
            queueAddBtn.onclick = addFromInput;
            queueInput.addEventListener('keydown', function(e) {
                if (e.key === 'Enter') addFromInput();
            });
        }
        if (queueClearBtn) {
            queueClearBtn.onclick = queueClearDone;
        }
    }, 50);

    // ─────────────────────────────────────────────────────────────
    // CODE INTELLIGENCE (LSP-like)
    // ─────────────────────────────────────────────────────────────
    var _symbolIndex = [];
    // Expose for AETHER_CodePro @symbol / @file mentions
    try {
        Object.defineProperty(window, '_symbolIndex', {
            get: function () { return _symbolIndex; },
            set: function (v) { _symbolIndex = v || []; },
            configurable: true,
        });
    } catch (_) { window._symbolIndex = _symbolIndex; }

    async function indexWorkspaceSymbols() {
        if (!codingFolderHandle) return;
        _symbolIndex = [];
        try {
            await indexDirSymbols(codingFolderHandle, '');
            renderSymbolList('');
        } catch(e) {
            console.warn('Symbol indexing error:', e.message);
        }
    }

    async function indexDirSymbols(dirHandle, prefix) {
        for await (var entry of dirHandle.entries()) {
            var name = entry[0], handle = entry[1];
            if (name.startsWith('.') || name === 'node_modules' || name === 'vendor') continue;
            var path = prefix ? prefix + '/' + name : name;
            if (handle.kind === 'directory') {
                await indexDirSymbols(handle, path);
            } else {
                var ext = name.split('.').pop().toLowerCase();
                if (!['js','ts','jsx','tsx','py','rs','go','java','rb','php','c','cpp','h','hpp','css','html'].includes(ext)) continue;
                try {
                    var file = await handle.getFile();
                    if (file.size > 100000) continue; // skip large files
                    var text = await file.text();
                    extractSymbols(text, path, ext);
                } catch(e) {}
            }
        }
    }

    function extractSymbols(code, filePath, ext) {
        var lines = code.split('\n');
        var patterns = {
            js: [/^(?:export\s+)?(?:async\s+)?function\s+(\w+)/g, /^(?:export\s+)?class\s+(\w+)/g, /^(?:export\s+)?(?:const|let|var)\s+(\w+)\s*=/g, /^(?:export\s+)?interface\s+(\w+)/g, /^(?:export\s+)?type\s+(\w+)\s*=/g],
            py: [/^def\s+(\w+)/g, /^class\s+(\w+)/g, /^\s*(\w+)\s*=\s*(?:lambda|def)/g],
            rs: [/^fn\s+(\w+)/g, /^struct\s+(\w+)/g, /^enum\s+(\w+)/g, /^trait\s+(\w+)/g, /^impl\s+(\w+)/g],
            go: [/^func\s+(?:\w+\s+)?(\w+)/g, /^type\s+(\w+)\s+(?:struct|interface)/g],
            java: [/(?:public|private|protected)?\s*(?:static\s+)?(?:class|interface)\s+(\w+)/g, /(?:public|private|protected)?\s*(?:\w+\s+)?(\w+)\s*\([^)]*\)\s*\{/g],
        };
        var pats = patterns[ext] || patterns['js'];
        lines.forEach(function(line) {
            pats.forEach(function(re) {
                re.lastIndex = 0;
                var m = re.exec(line);
                if (m) {
                    var kind = 'symbol';
                    if (/^(?:export\s+)?(?:async\s+)?function/.test(line)) kind = 'function';
                    else if (/^(?:export\s+)?class/.test(line)) kind = 'class';
                    else if (/^def\s+/.test(line)) kind = 'function';
                    else if (/^class\s+/.test(line)) kind = 'class';
                    else if (/^(?:export\s+)?(?:const|let|var)\s+/.test(line)) kind = 'variable';
                    else if (/(?:interface|type)\s+/.test(line)) kind = 'type';
                    _symbolIndex.push({ name: m[1], kind: kind, file: filePath, line: line.trim() });
                }
            });
        });
    }

    function renderSymbolList(query) {
        var list = document.getElementById('symbol-list');
        if (!list) return;
        var q = (query || '').toLowerCase();
        var matches = q ? _symbolIndex.filter(function(s) { return s.name.toLowerCase().includes(q); }) : _symbolIndex.slice(0, 50);
        matches.sort(function(a, b) { return a.name.localeCompare(b.name); });
        list.innerHTML = '';
        if (matches.length === 0) {
            list.innerHTML = '<div class="queue-empty">' + (_symbolIndex.length === 0 ? 'Link a folder to index symbols.' : 'No symbols match "' + escapeHtml(q) + '".') + '</div>';
            return;
        }
        matches.slice(0, 80).forEach(function(sym) {
            var el = document.createElement('div');
            el.className = 'symbol-item';
            var icon = sym.kind === 'function' ? 'ƒ' : sym.kind === 'class' ? '◉' : sym.kind === 'type' ? '⊡' : '•';
            el.innerHTML = '<span class="symbol-kind">' + icon + '</span>'
                + '<span>' + escapeHtml(sym.name) + '</span>'
                + '<span style="color:#3a5060;margin-left:auto;font-size:.55rem">' + escapeHtml(sym.file) + '</span>';
            el.title = sym.line;
            el.onclick = function() {
                // Open the file in workspace editor
                if (typeof window.openWorkspaceEditor === 'function') {
                    (async function() {
                        try {
                            var f = await codingFolderHandle.getFileHandle(sym.file);
                            var file = await f.getFile();
                            var content = await file.text();
                            window.openWorkspaceEditor(sym.file, content, true);
                        } catch(e2) {
                            showNotification('Cannot open ' + sym.file, 'error');
                        }
                    })();
                }
            };
            list.appendChild(el);
        });
    }

    // Wire symbol search
    setTimeout(function() {
        var symInput = document.getElementById('symbol-search-input');
        var symRefresh = document.getElementById('symbol-refresh-btn');
        if (symInput) {
            symInput.addEventListener('input', function() { renderSymbolList(this.value); });
        }
        if (symRefresh) {
            symRefresh.onclick = function() {
                indexWorkspaceSymbols();
                showNotification('Symbols re-indexed', 'info');
            };
        }
    }, 50);

    // Expose queue + symbols to chat via :queue command parsing
    window._queueAdd = queueAdd;

    function toggleCodingMode() {
        state.codingMode = !state.codingMode;
        if (state.codingMode && typeof window._aetherExpandModes === 'function') window._aetherExpandModes();
        const btn = document.getElementById('btn-coding-mode');
        if (btn) btn.classList.toggle('active', state.codingMode);
        document.body.classList.toggle('coding-mode', state.codingMode);
        const indicator = document.getElementById('coding-mode-indicator');
        if (indicator) {
            indicator.style.display = state.codingMode ? 'flex' : 'none';
            if (state.codingMode) {
                if (!document.getElementById('coding-turn-badge')) {
                    const tb = document.createElement('span');
                    tb.id = 'coding-turn-badge'; tb.className = 'coding-turn-badge';
                    tb.style.display = 'none'; indicator.appendChild(tb);
                }
                if (!document.getElementById('coding-folder-btn')) {
                    const fb = document.createElement('button');
                    fb.id = 'coding-folder-btn'; fb.className = 'coding-folder-btn';
                    fb.textContent = '\ud83d\udcc2 Link Folder'; fb.title = 'Give AETHER Code access to a project folder';
                    fb.onclick = (e) => { e.stopPropagation(); openCodingFolder(); };
                    indicator.appendChild(fb);
                }
                updateCodingFolderUI();
            }
        }
        // Reset turn counter for current session when toggling
        if (state.currentConversationId) resetCodingTurns(state.currentConversationId);
        // Switch sidebar to Code tab + enter terminal-agent shell
        if (state.codingMode) {
            var codeTab = document.querySelector('.sidebar-tab[data-tab="code"]');
            if (codeTab) codeTab.click();
            if (codingFolderHandle) setTimeout(function() { indexWorkspaceSymbols(); }, 300);
            // Ensure FS tools (incl. fs_patch) are registered even before folder link
            try { registerFSTools(); } catch (_) {}
        }
        if (state.codingMode) {
            const onboarding = { hasReadme: false, hasTests: false, hasAetherMd: false, fileCount: 0 };
            if (state.workspaceEnabled) {
                const files = Object.keys(wsFileCache);
                onboarding.hasReadme  = files.some(f => /^readme/i.test(f));
                onboarding.hasTests   = files.some(f => /test/i.test(f));
                onboarding.hasAetherMd = !!wsFileCache['AETHER.md'];
                onboarding.fileCount  = files.length;
            }
            const notices = [];
            if (onboarding.hasAetherMd) notices.push('AETHER.md ✓');
            if (onboarding.hasTests)    notices.push('tests ✓');
            if (!onboarding.hasAetherMd && onboarding.fileCount > 0) notices.push('tip: add AETHER.md for project rules');
            const poolInfo = 'Turn limit: ' + AETHER_TOOL_POOL.maxTurns + ' · fs_patch · Ghost';
            showNotification('⌨ AETHER Code — ' + (notices.join(' · ') || poolInfo), 'success');
            setCodeSessionStatus('idle', codingFolderHandle ? 'Ready — Plan → Patch → Verify' : 'Link a folder to enable live FS');
        } else {
            const tb = document.getElementById('coding-turn-badge');
            if (tb) tb.style.display = 'none';
            showNotification('AETHER Code off', 'info');
        }
        syncCodeAgentShell();
        try {
            if (typeof AETHER_CodePro !== 'undefined') {
                AETHER_CodePro.installGhostHook && AETHER_CodePro.installGhostHook();
                AETHER_CodePro.renderBar && AETHER_CodePro.renderBar();
                AETHER_CodePro.wireMentions && AETHER_CodePro.wireMentions(document.getElementById('user-input'));
            }
        } catch (_) {}
        saveState();
    }

    // Wire CODE rail controls once DOM is ready
    (function initCodeAgentChrome() {
        function bind() {
            var linkBtn = document.getElementById('code-rail-link-folder');
            if (linkBtn && !linkBtn._bound) {
                linkBtn._bound = true;
                linkBtn.onclick = function () { openCodingFolder(); };
            }
            var modeSel = document.getElementById('code-accept-mode');
            if (modeSel && !modeSel._bound) {
                modeSel._bound = true;
                try {
                    var saved = localStorage.getItem('aether_code_accept_mode');
                    if (saved) modeSel.value = saved;
                } catch (_) {}
                modeSel.onchange = function () {
                    try { localStorage.setItem('aether_code_accept_mode', modeSel.value); } catch (_) {}
                    showNotification('CODE apply mode: ' + modeSel.value, 'info');
                };
            }
        }
        if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', bind);
        else bind();
        setTimeout(bind, 500);
    })();


    // ═══════════════════════════════════════════════════════════
    // DIFF / PATCH VIEW
    // When code is fenced as 'diff', 'patch', or auto-detected as
    // a diff (>30% +/- lines), render with coloured line gutters:
    //   + green  — added line
    //   - red    — deleted line
    //   * yellow — modified/edited line
    //
    // This turns AETHER's code edits from "here's the new file"
    // into "here's exactly what changed and why."
    // ═══════════════════════════════════════════════════════════

    function isDiffLang(lang) {
        return ['diff','patch','diff-js','diff-py','diff-ts','diff-css','diff-html'].includes((lang||'').toLowerCase());
    }

    function looksLikeDiff(code) {
        const lines = code.split('\n').filter(l => l.trim());
        if (lines.length < 4) return false;
        const markers = lines.filter(l => /^[+\-!]/.test(l) && !l.startsWith('+++') && !l.startsWith('---')).length;
        return markers / lines.length > 0.3;
    }

    function renderDiffBlock(code, lang, wrapper) {
        const pre = document.createElement('pre'); pre.className = 'cb-diff-pre';
        const lines = code.split('\n');
        lines.forEach((line, idx) => {
            const row = document.createElement('div'); row.className = 'diff-line';
            let marker = '\u00a0', type = 'ctx';
            if (line.startsWith('+++') || line.startsWith('---')) { type = 'header'; marker = '\u00a0'; }
            else if (line.startsWith('@@')) { type = 'hunk'; marker = '\u00a0'; }
            else if (line.startsWith('+')) { marker = '+'; type = 'add'; }
            else if (line.startsWith('-')) { marker = '-'; type = 'del'; }
            else if (line.startsWith('*') || line.startsWith('!')) { marker = '*'; type = 'mod'; }
            row.classList.add('diff-' + type);
            const gutter = document.createElement('span');
            gutter.className = 'diff-gutter'; gutter.textContent = marker;
            const lineNum = document.createElement('span');
            lineNum.className = 'diff-linenum'; lineNum.textContent = idx + 1;
            const content = document.createElement('span'); content.className = 'diff-content';
            // Strip the leading marker for syntax highlighting
            const stripped = (type === 'add' || type === 'del' || type === 'mod') ? line.slice(1) : line;
            const codeEl = document.createElement('code'); codeEl.textContent = stripped;
            // Highlight with the underlying language (strip 'diff-' prefix)
            const baseLang = (lang||'').replace(/^diff-/,'') || 'javascript';
            if (type === 'ctx' || type === 'add' || type === 'del' || type === 'mod') {
                highlightWithHljs(codeEl, baseLang);
            } else {
                codeEl.style.color = '#4a6070';
            }
            content.appendChild(codeEl);
            row.appendChild(gutter); row.appendChild(lineNum); row.appendChild(content);
            pre.appendChild(row);
        });
        wrapper.appendChild(pre);
    }

    // Enhanced code block factory for Coding Mode
    // Creates named, tagged, previewable blocks with auto-fix capability
    function createCodingBlock(lang, code, filename = null) {
        // Always render as enhanced coding block with file card UI
        // (codingMode adds extra features but the block always shows)

        const ext          = filename ? filename.split('.').pop() : lang;
        const detectedLang = lang || ext || 'code';
        const lineCount    = code.split('\n').length;
        const charCount    = code.length;
        const wrapper      = document.createElement('div');
        wrapper.className  = 'coding-block';
        wrapper.dataset.lang = detectedLang;
        wrapper.dataset.file = filename || '';

        const previewLangs = ['html','htm','javascript','js','typescript','ts','css','jsx','tsx','vue','svelte'];
        const canPreview   = previewLangs.includes(detectedLang.toLowerCase());
        const canRun       = ['python','js','javascript','bash','sh','ruby','go','rust','c','cpp','java','php'].includes(detectedLang.toLowerCase());
        const canDeploy    = ['html','htm'].includes(detectedLang.toLowerCase()) && !!(puterAuthed || hooksConfig.puter);

        // ── Header ────────────────────────────────────────────
        const header = document.createElement('div'); header.className = 'cb-header';
        const hdrLeft = document.createElement('div'); hdrLeft.className = 'cb-header-left';
        const fileTag = filename
            ? '<span class="cb-file"><svg class="ic-xs"><use href="#ic-file"/></svg>' + filename + '</span>'
            : '<span class="cb-lang-badge">' + detectedLang.toUpperCase() + '</span>';
        hdrLeft.innerHTML = fileTag + '<span class="cb-lines">' + lineCount + ' lines</span><span class="cb-chars">' + (charCount > 999 ? (charCount/1000).toFixed(1)+'k' : charCount) + ' chars</span>';

        const hdrRight = document.createElement('div'); hdrRight.className = 'cb-header-right';

        function makeCBBtn(cls, title, svgPath, label) {
            const b = document.createElement('button'); b.className = 'cb-btn ' + cls; b.title = title;
            b.innerHTML = '<svg class="ic-xs" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">' + svgPath + '</svg>' + (label ? label : '');
            return b;
        }

        const copyBtn    = makeCBBtn('cb-btn-copy',    'Copy code',     '<rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/>', 'Copy');
        const fixBtn     = makeCBBtn('cb-btn-fix',     'Fix with AETHER','<path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z"/>', 'Fix');
        const saveBtn    = makeCBBtn('cb-btn-save',    'Save to workspace','<path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/>', 'Save');
        const vscodeBtn  = makeCBBtn('cb-btn-vscode',  'Open in VS Code','<rect x="2" y="2" width="20" height="20" rx="3"/><path d="M6 12l4-4 4 4-4 4z" fill="currentColor" stroke="none"/>', 'VS Code');
        const planBtn    = makeCBBtn('cb-btn-plan',    'Plan execution', '<circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/>', 'Plan');

        hdrRight.appendChild(copyBtn);
        if (canPreview) {
            const prevBtn = makeCBBtn('cb-btn-preview', 'Open full preview window','<path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>', 'Preview');
            hdrRight.appendChild(prevBtn);
            prevBtn.onclick = () => openFullPreviewWindow(code, detectedLang, filename);
        }
        if (canRun) hdrRight.appendChild(planBtn);
        hdrRight.appendChild(fixBtn);
        hdrRight.appendChild(saveBtn);
        hdrRight.appendChild(vscodeBtn);
        if (canDeploy) {
            const deployBtn = makeCBBtn('cb-btn-deploy', 'Deploy to Puter.site','<path d="M5 12.55a11 11 0 0 1 14.08 0"/><path d="M1.42 9a16 16 0 0 1 21.16 0"/><path d="M8.53 16.11a6 6 0 0 1 6.95 0"/><line x1="12" y1="20" x2="12.01" y2="20"/>', '\u29c6 Deploy');
            hdrRight.appendChild(deployBtn);
            deployBtn.onclick = async () => {
                const name = filename ? filename.replace(/\.html?$/i, '') : 'aether-' + Date.now();
                await puterDeploy({ [filename || 'index.html']: code }, name);
            };
        }

        header.appendChild(hdrLeft); header.appendChild(hdrRight);

        // ── Code body ─────────────────────────────────────────
        const body = document.createElement('div'); body.className = 'cb-body';
        const nums = document.createElement('div'); nums.className = 'cb-line-nums';
        let currentCode = code; // mutable — updated when Format is applied
        function rebuildNums(src) {
            nums.innerHTML = '';
            src.split('\n').forEach((_,i) => { const n = document.createElement('span'); n.textContent = i+1; nums.appendChild(n); });
        }

        // ── Diff / Patch view ─────────────────────────────────
        // If the language is 'diff'/'patch', or the content auto-detects
        // as a diff (>30% +/- lines), use the coloured gutter renderer.
        // Green + added, Red - deleted, Yellow * edited. Much clearer than
        // dumping a wall of green text with no context.
        if (isDiffLang(detectedLang) || looksLikeDiff(code)) {
            wrapper.classList.add('cb-is-diff');
            renderDiffBlock(code, detectedLang, body);
            // Don't add line number gutter — diff has its own
        } else {
            rebuildNums(code);
            const pre = document.createElement('pre'); const codeEl = document.createElement('code');
            // ── Highlight: prefer hljs, fall back to applySH ──────────────
            codeEl.textContent = code; highlightWithHljs(codeEl, detectedLang); pre.appendChild(codeEl);
            body.appendChild(nums); body.appendChild(pre);
        }

        // ── Format button (Prettier) ───────────────────────────
        // Only shown for languages Prettier actually supports. Formats
        // the code in-place: updates both the display and the copy buffer.
        // If Prettier throws (common with AI-generated partial snippets),
        // shows a brief error tooltip and leaves the code untouched.
        const prettierParser = getPrettierParser(detectedLang);
        if (prettierParser && window.prettier) {
            const fmtBtn = makeCBBtn('cb-btn-format', 'Format with Prettier',
                '<path d="M3 6h18M3 12h12M3 18h8" stroke-linecap="round"/>', '⬡ Format');
            hdrRight.insertBefore(fmtBtn, copyBtn.nextSibling);
            fmtBtn.onclick = async () => {
                fmtBtn.textContent = '…';
                fmtBtn.disabled = true;
                const { formatted, error } = await formatWithPrettier(currentCode, detectedLang);
                if (error) {
                    fmtBtn.textContent = '⚠ ' + error.slice(0, 40);
                    setTimeout(() => { fmtBtn.innerHTML = '⬡ Format'; fmtBtn.disabled = false; }, 2500);
                    return;
                }
                // Update display and internal code reference
                currentCode = formatted;
                codeEl.classList.add('formatting');
                await new Promise(r => setTimeout(r, 120)); // one frame flash
                codeEl.textContent = formatted;
                highlightWithCM(codeEl, detectedLang);
                codeEl.classList.remove('formatting');
                rebuildNums(formatted);
                fmtBtn.innerHTML = '✓ Formatted';
                fmtBtn.disabled = false;
                setTimeout(() => { fmtBtn.innerHTML = '⬡ Format'; }, 2000);
                // Also update the copy button to use the formatted code
                copyBtn.onclick = () => navigator.clipboard.writeText(formatted).then(() => {
                    copyBtn.innerHTML = '✓ Copied!';
                    setTimeout(() => { copyBtn.innerHTML = '&#128203; Copy'; }, 2000);
                });
            };
        }

        // ── Plan pane ─────────────────────────────────────────
        const planPane = document.createElement('div'); planPane.className = 'cb-plan-pane hidden';
        planPane.innerHTML = '<div class="cb-plan-loading"><div class="dr-spinner-sm"></div> Planning execution\u2026</div>';

        // ── Run output ────────────────────────────────────────
        const consolePane = document.createElement('div'); consolePane.className = 'cb-console hidden';
        const consoleBar  = document.createElement('div'); consoleBar.className = 'cb-console-bar';
        consoleBar.innerHTML = '<span class="cb-console-title"><svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="4 17 10 11 4 5"/><line x1="12" y1="19" x2="20" y2="19"/></svg>Console</span>';
        const cbActns  = document.createElement('div'); cbActns.style.cssText = 'display:flex;gap:4px;';
        const clrBtn   = document.createElement('button'); clrBtn.className = 'cb-console-clear'; clrBtn.textContent = 'CLR';
        const cloBtn   = document.createElement('button'); cloBtn.className = 'cb-console-close'; cloBtn.textContent = '\u00d7';
        cbActns.appendChild(clrBtn); cbActns.appendChild(cloBtn);
        consoleBar.appendChild(cbActns);
        const consoleOut = document.createElement('div'); consoleOut.className = 'cb-console-output';
        const consoleInpRow = document.createElement('div'); consoleInpRow.className = 'cb-console-input-row';
        consoleInpRow.innerHTML = '<span class="cb-console-prompt">&gt;</span>';
        const consoleInp = document.createElement('input'); consoleInp.className = 'cb-console-input'; consoleInp.placeholder = 'Evaluate JavaScript\u2026'; consoleInp.spellcheck = false;
        consoleInpRow.appendChild(consoleInp);
        consolePane.appendChild(consoleBar); consolePane.appendChild(consoleOut); consolePane.appendChild(consoleInpRow);

        wrapper.appendChild(header); wrapper.appendChild(planPane); wrapper.appendChild(body); wrapper.appendChild(consolePane);

        // ── Wire: Copy ────────────────────────────────────────
        copyBtn.onclick = () => navigator.clipboard.writeText(code).then(() => {
            copyBtn.innerHTML = '<svg class="ic-xs" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg>Copied!';
            setTimeout(() => { copyBtn.innerHTML = '<svg class="ic-xs" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>Copy'; }, 2000);
        });

        // ── Wire: Plan ────────────────────────────────────────
        planBtn.onclick = async () => {
            planPane.classList.remove('hidden');
            planPane.innerHTML = '<div class="cb-plan-loading"><div class="dr-spinner-sm"></div> Planning\u2026</div>';
            try {
                const planText = await callAISimple([
                    { role: 'system', content: 'You are a code execution planner. Given code, produce a brief step-by-step execution plan showing: 1) what the code does, 2) expected output, 3) potential issues, 4) suggested tests. Be concise, use short bullet points.' },
                    { role: 'user', content: 'Language: ' + detectedLang + '\n\n```\n' + code + '\n```' }
                ], apiConfig.model);
                planPane.innerHTML = '';
                const planContent = document.createElement('div'); planContent.className = 'cb-plan-content';
                planContent.appendChild(parseMarkdown(planText));
                const runFromPlan = document.createElement('button'); runFromPlan.className = 'cb-btn cb-btn-run'; runFromPlan.style.marginTop = '8px';
                runFromPlan.innerHTML = '<svg class="ic-xs" viewBox="0 0 24 24" fill="currentColor"><polygon points="5 3 19 12 5 21 5 3"/></svg> Run Now';
                runFromPlan.onclick = () => executeCode();
                planPane.appendChild(planContent); planPane.appendChild(runFromPlan);
            } catch(e) {
                planPane.innerHTML = '<div style="color:#ff6464;font-size:.72rem;padding:8px;">Plan failed: ' + e.message + '</div>';
            }
        };

        // ── Wire: Run ─────────────────────────────────────────
        async function executeCode() {
            consolePane.classList.remove('hidden');
            const outEl = consoleOut;
            outEl.innerHTML = '';
            function cbLog(type, msg) {
                const line = document.createElement('div'); line.className = 'cb-console-line cb-console-' + type;
                const ts   = new Date().toLocaleTimeString('en-GB', {hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit'});
                line.innerHTML = '<span class="cb-console-ts">' + ts + '</span><span class="cb-console-text">' + escapeHtml(String(msg)) + '</span>';
                outEl.appendChild(line); outEl.scrollTop = outEl.scrollHeight;
            }
            cbLog('info', 'Running ' + detectedLang + '\u2026');
            try {
                const res = await pistonRun(detectedLang, code);
                if (res.output) res.output.split('\n').forEach(l => cbLog(res.success ? 'log' : 'error', l));
                else cbLog('info', '(no output)');
                cbLog('info', 'Exit: ' + (res.code ?? 0));
            } catch(e) { cbLog('error', 'Run error: ' + e.message); }
        }

        // ── Wire: VS Code ─────────────────────────────────────
        vscodeBtn.onclick = () => {
            const content = encodeURIComponent(code);
            // Try vscode:// URI — works if VS Code is installed
            const uri = 'vscode://file/?content=' + content;
            window.open(uri, '_blank');
            // Fallback: copy and notify
            setTimeout(() => {
                navigator.clipboard.writeText(code);
                showNotification('Code copied — paste into VS Code (vscode:// URIs require VS Code installed)', 'info');
            }, 500);
        };

        // ── Wire: Fix ─────────────────────────────────────────
        fixBtn.onclick = () => {
            const inp = document.getElementById('user-input');
            if (inp) {
                const ref = filename ? 'file: ' + filename : detectedLang + ' code';
                inp.value = 'Fix the following ' + ref + ':\n```' + detectedLang + '\n' + code + '\n```\n\nDescribe what is wrong and provide a corrected version.';
                inp.style.height = 'auto'; inp.style.height = Math.min(inp.scrollHeight, 200) + 'px';
                inp.focus(); inp.scrollIntoView({ behavior: 'smooth', block: 'center' });
                showNotification('Code pasted for fixing \u2014 add error details and send', 'info');
            }
        };

        // ── Wire: Diff ────────────────────────────────────────
        if (filename && state.workspaceEnabled) {
            const diffBtn = makeCBBtn('cb-btn-diff', 'Diff with workspace version','<line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/>', 'Diff');
            hdrRight.insertBefore(diffBtn, saveBtn);
            diffBtn.onclick = async () => {
                try {
                    const orig = await readFile(filename);
                    if (!orig) { showNotification(filename + ' not in workspace', 'warn'); return; }
                    showFileDiff_inline && showFileDiff_inline(orig, code, filename, wrapper);
                } catch(e) { reportFeatureError('File Diff', e); }
            };
        }

        // ── Wire: Save ────────────────────────────────────────
        saveBtn.onclick = async () => {
            if (!state.workspaceEnabled) { showNotification('Enable Workspace to save files', 'warn'); return; }
            const saveName = filename || 'code.' + getExtForLang(detectedLang);
            showAetherDialog({
                title: 'Save to Workspace', html: '<p style="color:#aab;font-size:.8rem">Save as:</p>',
                type: 'prompt', inputPlaceholder: saveName, inputValue: saveName,
                confirmLabel: 'Save', cancelLabel: 'Cancel',
                onConfirm: async (name) => { if (!name) return; await writeFile(name, code); showNotification('Saved: ' + name, 'success'); },
            });
        };

        // ── Wire: Console ─────────────────────────────────────
        const consoleBtnEl = makeCBBtn('cb-btn-console', 'Open console','<polyline points="4 17 10 11 4 5"/><line x1="12" y1="19" x2="20" y2="19"/>', 'Console');
        hdrRight.appendChild(consoleBtnEl);
        consoleBtnEl.onclick = () => { consolePane.classList.toggle('hidden'); if (!consolePane.classList.contains('hidden')) consoleInp.focus(); };
        clrBtn.onclick    = () => { consoleOut.innerHTML = ''; };
        cloBtn.onclick    = () => consolePane.classList.add('hidden');
        consoleInp.addEventListener('keydown', async e => {
            if (e.key !== 'Enter' || !consoleInp.value.trim()) return;
            const expr = consoleInp.value; consoleInp.value = '';
            // Security: no eval — expression console disabled (use Piston Run for code)
            try {
                const r = (typeof AETHER_safeCalculate === 'function' && /^[\d\s+\-*/().,%^eE]+$/.test(expr))
                    ? AETHER_safeCalculate(expr)
                    : null;
                if (r == null) throw new Error('eval disabled — use Run for code, or math-only expressions');
                consoleOut.insertAdjacentHTML('beforeend', '<div class="cb-console-line cb-console-log"><span class="cb-console-ts">JS</span><span class="cb-console-text">' + escapeHtml(String(r)) + '</span></div>');
            }
            catch(e) { consoleOut.insertAdjacentHTML('beforeend', '<div class="cb-console-line cb-console-error"><span class="cb-console-ts">ERR</span><span class="cb-console-text">' + escapeHtml(e.message) + '</span></div>'); }
            consoleOut.scrollTop = consoleOut.scrollHeight;
        });

        return wrapper;
    }

    // ── Full-window preview ───────────────────────────────────
    // ── Construct Notification Card ──────────────────────────
    // Renders an app-card in the chat (like Images 3/4) when a Construct is built.
    // Returns the card DOM element; also appends it to display if display is set.
    function renderConstructCard(title, lang, onOpen, steps) {
        const card = document.createElement('div');
        card.className = 'construct-notify-card';

        // Icon
        const iconWrap = document.createElement('div'); iconWrap.className = 'cnc-icon';
        iconWrap.innerHTML = '<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><polygon points="12 2 2 7 12 22 22 7"/></svg>';

        // Body: title + steps
        const body = document.createElement('div'); body.className = 'cnc-body';
        const titleEl = document.createElement('div'); titleEl.className = 'cnc-title'; titleEl.textContent = title || 'AETHER Construct';
        const langBadge = document.createElement('span'); langBadge.className = 'cnc-badge'; langBadge.textContent = (lang || 'html').toUpperCase();
        titleEl.appendChild(langBadge);
        body.appendChild(titleEl);

        if (steps && steps.length) {
            const stepsEl = document.createElement('div'); stepsEl.className = 'cnc-steps';
            steps.forEach((s, i) => {
                const row = document.createElement('div'); row.className = 'cnc-step' + (i === 0 ? ' cnc-step-active' : '');
                row.innerHTML = '<span class="cnc-step-dot"></span><span>' + s + '</span>';
                stepsEl.appendChild(row);
            });
            body.appendChild(stepsEl);
        }

        // Open button
        const openBtn = document.createElement('button'); openBtn.className = 'cnc-open-btn';
        openBtn.textContent = 'Open';
        openBtn.onclick = () => { if (typeof onOpen === 'function') onOpen(); };

        card.appendChild(iconWrap);
        card.appendChild(body);
        card.appendChild(openBtn);

        if (typeof display !== 'undefined' && display) {
            display.appendChild(card);
            smoothScrollToBottom();
        }
        return card;
    }

    function openFullPreviewWindow(code, lang, filename) {
        // Build full preview HTML with proper doctype and back button toolbar
        const langLc = (lang || '').toLowerCase();
        let previewBody = code;

        if (['javascript','js','typescript','ts'].includes(langLc)) {
            previewBody = '<div id="root"></div><script>\n' + code + '\n<\/script>';
        } else if (langLc === 'css') {
            previewBody = '<style>' + code + '</style>'
                + '<div style="padding:20px;color:#ccd"><h2 style="color:#00f3ff;font-family:monospace;font-size:1rem">CSS Preview</h2>'
                + '<p>Styles are active. Add HTML elements to see them applied.</p>'
                + '<div class="demo-box">Demo element</div></div>';
        }

        const backBtn = '<div id="_aether_toolbar" style="position:fixed;top:0;left:0;right:0;z-index:99999;'
            + 'background:rgba(4,5,10,0.95);backdrop-filter:blur(8px);'
            + 'border-bottom:1px solid rgba(0,243,255,0.2);'
            + 'display:flex;align-items:center;gap:10px;padding:6px 12px;font-family:monospace;font-size:.72rem;">'
            + '<button onclick="window.close()" style="background:rgba(0,243,255,0.1);border:1px solid rgba(0,243,255,0.3);'
            + 'color:#00f3ff;padding:4px 12px;border-radius:4px;cursor:pointer;font-family:monospace;font-size:.7rem;">'
            + '← Close Preview</button>'
            + '<span style="color:#445566;">AETHER Preview</span>'
            + '<span style="color:#223344;flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">'
            + (filename || lang + ' preview') + '</span>'
            + '<button onclick="document.getElementById(\'_aether_toolbar\').style.display=\'none\'" '
            + 'style="background:transparent;border:none;color:#334455;cursor:pointer;font-size:.8rem;">✕</button>'
            + '</div><div style="height:37px"></div>';

        const fullHTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n'
            + '<meta charset="UTF-8">\n'
            + '<meta name="viewport" content="width=device-width,initial-scale=1">\n'
            + '<title>' + (filename || 'AETHER Preview') + '</title>\n'
            + '<style>*{box-sizing:border-box}body{margin:0;background:#05060e;color:#c8d8e8;font-family:system-ui,sans-serif}</style>\n'
            + '</head>\n<body>\n'
            + backBtn
            + previewBody
            + '\n</body>\n</html>';

        // Use blob URL — avoids same-origin restrictions and blue screen from empty about:blank
        const blob = new Blob([fullHTML], { type: 'text/html;charset=utf-8' });
        const blobURL = URL.createObjectURL(blob);
        const win = window.open(blobURL, '_blank', 'width=1100,height=750,menubar=no,toolbar=yes,location=yes');
        if (!win) {
            // Fallback: open in same-tab iframe overlay
            openPreviewOverlay(fullHTML, filename || lang);
            return;
        }
        // Revoke after load
        setTimeout(() => URL.revokeObjectURL(blobURL), 30000);
        showNotification('Preview opened — use the toolbar button to close', 'success');
    }

    function openPreviewOverlay(html, title) {
        const existing = document.getElementById('aether-preview-overlay');
        if (existing) existing.remove();
        const overlay = document.createElement('div');
        overlay.id = 'aether-preview-overlay';
        overlay.style.cssText = 'position:fixed;inset:0;z-index:8000;background:#05060e;display:flex;flex-direction:column;';

        // Constructs header bar
        const bar = document.createElement('div'); bar.className = 'construct-bar';
        const titleEl = document.createElement('div'); titleEl.className = 'construct-title';
        titleEl.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polygon points="12 2 2 7 12 22 22 7"/></svg>'
            + '<span>AETHER Constructs</span>'
            + '<span class="construct-badge">LIVE</span>'
            + '<span style="color:#334455;font-size:.65rem;margin-left:4px">' + (title || 'Untitled') + '</span>';
        const backBtn = document.createElement('button'); backBtn.className = 'construct-back';
        backBtn.innerHTML = '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="15 18 9 12 15 6"/></svg> Close';
        backBtn.onclick = () => overlay.remove();
        bar.appendChild(titleEl); bar.appendChild(backBtn);

        const frame = document.createElement('iframe');
        frame.style.cssText = 'flex:1;border:none;width:100%;background:#fff;';
        frame.setAttribute('sandbox', 'allow-scripts allow-same-origin allow-forms allow-modals allow-downloads');
        overlay.appendChild(bar); overlay.appendChild(frame);
        document.body.appendChild(overlay);
        frame.srcdoc = html;
        showNotification('\u25b3 Construct opened', 'success');
    }


    function getExtForLang(lang) {
        const map = { javascript:'js', typescript:'ts', python:'py', rust:'rs', go:'go', css:'css', html:'html', java:'java', cpp:'cpp', c:'c', bash:'sh', shell:'sh', json:'json', yaml:'yml', markdown:'md', sql:'sql' };
        return map[lang.toLowerCase()] || 'txt';
    }

    // Parse ```lang:filename.ext code fences
    function parseCodingFence(langLine) {
        // Formats: ```js:app.js  or  ```python:utils.py  or  ```javascript
        const colonIdx = langLine.indexOf(':');
        if (colonIdx > 0) {
            return { lang: langLine.slice(0, colonIdx), filename: langLine.slice(colonIdx+1) };
        }
        return { lang: langLine, filename: null };
    }

    // ─── QWEN 3.5 NATIVE SUPPORT ─────────────────────────────
    // Model family based on technical deep-dive (March 2026)
    // Architecture: Gated DeltaNet hybrid + Early Fusion multimodality
    // Context: 262K native, >1M w/ RoPE scaling (YaRN)
    // All support: Adaptive Thinking (<think>), MTP, vLLM, GGUF, MLC-LLM

    // ─── QWEN 3.5 SERIES (0.8B, 2B, 4B, 9B, 25B, 35B-A3B MoE) ──────────
    const QWEN35_REGISTRY = {
        'qwen3.5-0.8b':             { params:'0.8B', active:'0.8B', arch:'GDN+FFN', ctx:262144, moe:false, mmScore:55.9 },
        'qwen3.5-2b':               { params:'2B',   active:'2B',   arch:'GDN+FFN', ctx:262144, moe:false, mmScore:79.4 },
        'qwen3.5-4b':               { params:'4B',   active:'4B',   arch:'GDN+FFN', ctx:262144, moe:false, mmScore:null },
        'qwen3.5-9b':               { params:'9B',   active:'9B',   arch:'GDN+FFN', ctx:262144, moe:false, mmScore:87.7 },
        'qwen3.5-25b':              { params:'25B',  active:'25B',  arch:'GDN+FFN', ctx:262144, moe:false, mmScore:null },
        'qwen3.5-35b-a3b':          { params:'35B',  active:'3B',   arch:'MoE 256E/8A', ctx:262144, moe:true,  mmScore:86.8 },
        'qwen3.5-0.8b-instruct':    { params:'0.8B', active:'0.8B', arch:'GDN+FFN', ctx:262144, moe:false, mmScore:55.9 },
        'qwen3.5-2b-instruct':      { params:'2B',   active:'2B',   arch:'GDN+FFN', ctx:262144, moe:false, mmScore:79.4 },
        'qwen3.5-4b-instruct':      { params:'4B',   active:'4B',   arch:'GDN+FFN', ctx:262144, moe:false, mmScore:null },
        'qwen3.5-9b-instruct':      { params:'9B',   active:'9B',   arch:'GDN+FFN', ctx:262144, moe:false, mmScore:87.7 },
        'qwen3.5-25b-instruct':     { params:'25B',  active:'25B',  arch:'GDN+FFN', ctx:262144, moe:false, mmScore:null },
        'qwen3.5-35b-a3b-instruct': { params:'35B',  active:'3B',   arch:'MoE 256E/8A', ctx:262144, moe:true, mmScore:86.8 },
    };
    // ─── QWEN 3 SERIES (0.6B, 1.7B, 4B, 8B, 14B, 32B) ─────────────────
    // Qwen 3 — dense transformer, 128K context, native thinking, MTP
    const QWEN3_BASE_REGISTRY = {
        'qwen3-0.6b':             { params:'0.6B', ctx:32768,  thinking:true },
        'qwen3-1.7b':             { params:'1.7B', ctx:32768,  thinking:true },
        'qwen3-4b':               { params:'4B',   ctx:131072, thinking:true },
        'qwen3-8b':               { params:'8B',   ctx:131072, thinking:true },
        'qwen3-14b':              { params:'14B',  ctx:131072, thinking:true },
        'qwen3-32b':              { params:'32B',  ctx:131072, thinking:true },
        'qwen3-0.6b-instruct':    { params:'0.6B', ctx:32768,  thinking:true },
        'qwen3-1.7b-instruct':    { params:'1.7B', ctx:32768,  thinking:true },
        'qwen3-4b-instruct':      { params:'4B',   ctx:131072, thinking:true },
        'qwen3-8b-instruct':      { params:'8B',   ctx:131072, thinking:true },
        'qwen3-14b-instruct':     { params:'14B',  ctx:131072, thinking:true },
        'qwen3-32b-instruct':     { params:'32B',  ctx:131072, thinking:true },
        'qwen3-235b-a22b':        { params:'235B', ctx:131072, thinking:true, moe:true },
        'qwen3-235b-a22b-instruct':{ params:'235B',ctx:131072, thinking:true, moe:true },
    };
    const ALL_QWEN3 = Object.keys(QWEN3_BASE_REGISTRY);

    function isQwen3BaseModel(model) {
        if(!model) return false;
        const m = model.toLowerCase().replace(/\s+/g,'');
        return ALL_QWEN3.some(k => m === k || m.includes(k));
    }
    function isAnyQwenModel(model) { return isQwen35Model(model) || isQwen3BaseModel(model); }
    const ALL_QWEN35 = Object.keys(QWEN35_REGISTRY);

    function isQwen35Model(model) {
        if (!model) return false;
        const m = model.toLowerCase().replace(/\s+/g, '');
        return ALL_QWEN35.some(k => m.includes(k.replace(/-/g,'').replace(/\./g,'')));
    }

    // Normalize model string to registry key
    function getQwen35Key(model) {
        if (!model) return null;
        const m = model.toLowerCase().replace(/\s+/g,'').replace(/\./g,'').replace(/-/g,'');
        return ALL_QWEN35.find(k => m.includes(k.replace(/\./g,'').replace(/-/g,'')));
    }

    function getQwen35Spec(model) {
        const key = getQwen35Key(model);
        return key ? QWEN35_REGISTRY[key] : null;
    }

    function isQwen3Model(model) { return isQwen35Model(model); } // alias for compat

    // Models that support native thinking / extended reasoning
    const THINKING_MODELS = new Set([
        // Anthropic
        'claude-3-5-sonnet-20241022', 'claude-3-5-haiku-20241022',
        'claude-4-6-sonnet-20250514', 'claude-4-6-opus-20250514',
        // Qwen3.5 series — all support enable_thinking
        'qwen3.5-35b-a3b-instruct','qwen3.5-25b-instruct','qwen3.5-9b-instruct',
        'qwen3.5-4b-instruct','qwen3.5-2b-instruct','qwen3.5-0.8b-instruct',
        // Qwen3 series
        'qwen3-235b-a22b-instruct','qwen3-32b-instruct','qwen3-14b-instruct',
        'qwen3-8b-instruct','qwen3-4b-instruct','qwen3-1.7b-instruct','qwen3-0.6b-instruct',
        // DeepSeek reasoner
        'deepseek-reasoner','deepseek-r1','deepseek-r1-distill-llama-70b',
        // OpenAI o-series
        'o4-mini','o3','o3-mini','o1','o1-mini','o1-preview',
    ]);

    function modelSupportsThinking(model) {
        const m = (model || '').toLowerCase();
        return THINKING_MODELS.has(m)
            || m.includes('deepseek-r1')
            || m.includes('o4') || m.includes('o3') || m.includes('o1')
            || isAnyQwenModel(m)
            || (m.includes('claude') && (m.includes('3-5') || m.includes('4-')));
    }

    // Inject adaptive thinking param for Qwen3.5 API calls
    // enable_thinking:true in the API body activates <think> blocks
    function qwen35APIBody(baseBody) {
        if (!isQwen35Model(apiConfig.model)) return baseBody;
        return {
            ...baseBody,
            enable_thinking: state.coTEnabled,
            // MTP: request 4 speculative tokens for speed
            num_speculative_tokens: 4,
        };
    }

    // Badge HTML for Qwen3.5 models shown in UI
    function qwen35Badge(model) {
        const spec = getQwen35Spec(model);
        if (!spec) return '';
        const moeTag = spec.moe ? `<span class="qw-moe-tag">MoE</span>` : '';
        return `<span class="qwen35-badge">
            <span class="qw-logo">⬡</span>
            <span class="qw-name">Qwen3.5</span>
            <span class="qw-size">${spec.params}</span>
            ${moeTag}
            <span class="qw-ctx">${(spec.ctx/1000).toFixed(0)}K</span>
        </span>`;
    }

    // Creative activation messages — rotates on each detection
    const QWEN35_ACTIVATION_MSGS = [
        (spec) => `AETHER is built for Qwen3.5-${spec.params} · The brain is alive`,
        (spec) => `Neural architecture aligned — Qwen3.5-${spec.params}${spec.moe ? ' MoE' : ''} detected`,
        (spec) => `⬡ Gated DeltaNet online · 262K context awakened`,
        (spec) => `Qwen3.5-${spec.params} · Adaptive Thinking enabled · Ready`,
        (spec) => `${spec.moe ? 'Sparse MoE' : 'GDN hybrid'} architecture confirmed · AETHER synced`,
        (spec) => `Early fusion multimodal core engaged — Qwen3.5-${spec.params}`,
    ];
    let qwen35MsgIdx = 0;

    function showQwen35Banner(spec) {
        // Remove existing
        document.getElementById('qwen35-banner')?.remove();

        const banner = document.createElement('div');
        banner.id = 'qwen35-banner';
        banner.className = 'qwen35-banner';
        const msg = QWEN35_ACTIVATION_MSGS[qwen35MsgIdx % QWEN35_ACTIVATION_MSGS.length](spec);
        qwen35MsgIdx++;

        const archLabel = spec.moe ? 'Sparse MoE · 256 experts · 8 active' : 'Gated DeltaNet + FFN · Linear-O(n)';
        banner.innerHTML = `
            <div class="qw35-banner-left">
                <svg class="qw35-svg-icon" viewBox="0 0 32 32" fill="none">
                    <path d="M16 2 L28 9 L28 23 L16 30 L4 23 L4 9 Z" stroke="#00ff88" stroke-width="1.5" stroke-linejoin="round"/>
                    <path d="M16 7 L23 11 L23 19 L16 23 L9 19 L9 11 Z" stroke="#00ff88" stroke-width="1" stroke-linejoin="round" opacity="0.5"/>
                    <circle cx="16" cy="15" r="2.5" fill="#00ff88"/>
                    <circle cx="16" cy="8"  r="1.2" fill="#00ff88" class="qw35-pulse-dot"/>
                    <circle cx="23" cy="19" r="1.2" fill="#00ff88" class="qw35-pulse-dot" style="animation-delay:.3s"/>
                    <circle cx="9"  cy="19" r="1.2" fill="#00ff88" class="qw35-pulse-dot" style="animation-delay:.6s"/>
                    <line x1="16" y1="10" x2="16" y2="12.5" stroke="#00ff88" stroke-width="0.8"/>
                    <line x1="22" y1="18" x2="18.2" y2="16.2" stroke="#00ff88" stroke-width="0.8"/>
                    <line x1="10" y1="18" x2="13.8" y2="16.2" stroke="#00ff88" stroke-width="0.8"/>
                </svg>
                <div class="qw35-banner-text">
                    <span class="qw35-headline">${msg}</span>
                    <span class="qw35-subline">${archLabel} · ${spec.ctx >= 262144 ? '262K ctx native' : spec.ctx/1000+'K ctx'} · Early Fusion MM · MTP</span>
                </div>
            </div>
            <div class="qw35-banner-badges">
                <span class="qw35-tag">${spec.params}</span>
                ${spec.moe ? '<span class="qw35-tag qw35-tag-moe">MoE</span>' : ''}
                <span class="qw35-tag qw35-tag-ctx">262K</span>
                <span class="qw35-tag qw35-tag-think">⚡ Think</span>
            </div>
            <button class="qw35-dismiss" onclick="document.getElementById('qwen35-banner')?.remove()" title="Dismiss">×</button>`;

        // Insert after control-sector
        const cs = document.querySelector('.control-sector');
        if (cs?.parentNode) cs.parentNode.insertBefore(banner, cs.nextSibling);
        else document.querySelector('.dashboard')?.prepend(banner);

        // Auto-dismiss after 8s
        setTimeout(() => {
            banner.classList.add('qw35-fadeout');
            setTimeout(() => banner.remove(), 600);
        }, 8000);
    }

    // Status bar badge (persistent while model is active)
    function updateQwen35StatusBadge() {
        let badge = document.getElementById('qwen35-status-badge');
        if (isQwen35Model(apiConfig.model)) {
            const spec = getQwen35Spec(apiConfig.model);
            if (!spec) return;
            if (!badge) {
                badge = document.createElement('span');
                badge.id = 'qwen35-status-badge';
                const sr = document.querySelector('.status-right');
                if (sr) sr.insertAdjacentElement('afterbegin', badge);
            }
            badge.className = 'qwen35-status-badge';
            badge.innerHTML = `
                <svg class="qw35-mini-icon" viewBox="0 0 32 32" fill="none">
                    <path d="M16 2 L28 9 L28 23 L16 30 L4 23 L4 9 Z" stroke="#00ff88" stroke-width="2" stroke-linejoin="round"/>
                    <circle cx="16" cy="15" r="3" fill="#00ff88"/>
                    <circle cx="16" cy="7" r="1.5" fill="#00ff88"/>
                    <circle cx="23" cy="20" r="1.5" fill="#00ff88"/>
                    <circle cx="9"  cy="20" r="1.5" fill="#00ff88"/>
                </svg>
                <span class="qw35-sb-name">Qwen3.5</span>
                <span class="qw35-sb-size">${spec.params}</span>
                ${spec.moe ? '<span class="qw35-sb-moe">MoE</span>' : ''}`;
            badge.title = `${spec.arch} · ${spec.ctx/1024 >= 256 ? '262K' : spec.ctx/1000+'K'} ctx · Adaptive Thinking · Early Fusion MM`;

            // Show banner on first detection or model change
            if (badge.dataset.lastModel !== apiConfig.model) {
                badge.dataset.lastModel = apiConfig.model;
                showQwen35Banner(spec);
            }
        } else if (badge) {
            badge.remove();
        }
    }

    // ─── MMD SYSTEM PROMPT FILES (.mmd) ─────────────────────
    // Multi-Modal Definition files — loaded from workspace or localStorage
    const MMD_KEY = 'aether_mmd_prompts';

    function saveMmdPrompt(name, content) {
        const existing = JSON.parse(localStorage.getItem(MMD_KEY)||'{}');
        existing[name] = { content, updated: new Date().toISOString() };
        localStorage.setItem(MMD_KEY, JSON.stringify(existing));
    }

    function loadMmdPrompts() {
        try { return JSON.parse(localStorage.getItem(MMD_KEY)||'{}'); } catch { return {}; }
    }

    function getMmdPrompt(name) {
        const all = loadMmdPrompts();
        return all[name]?.content || null;
    }

    async function loadMmdFromWorkspace() {
        if(!state.workspaceEnabled) return null;
        try {
            const content = await readFile('SYSTEM_PROMPT.mmd');
            if(content && content.trim()) return content.trim();
        } catch {}
        return null;
    }

    // Parse .mmd format: sections delimited by ## SECTION_NAME
    function parseMmd(content) {
        const sections = {};
        const parts = content.split(/^##\s+(.+)$/m);
        for(let i=1; i<parts.length; i+=2) {
            sections[parts[i].trim().toUpperCase()] = parts[i+1]?.trim() || '';
        }
        return sections;
    }

    // ─── PHILIPS HUE ─────────────────────────────────────────
    async function hueGetLights() {
        if(!hooksConfig.hueHost||!hooksConfig.hueKey) return '⚠ Philips Hue not configured. Add Bridge IP and Application Key in HOOKS.';
        agentStatus('generic','Fetching Hue lights…');
        try {
            const res = await fetch(`http://${hooksConfig.hueHost}/api/${hooksConfig.hueKey}/lights`);
            const data = await res.json();
            agentDone();
            return Object.entries(data).map(([id,l])=>
                `- Light **${id}** (${l.name}): ${l.state.on?'💡 ON':'⚫ OFF'} | Bri: ${l.state.bri||'—'}`
            ).join('\n') || 'No lights found';
        } catch(e) { agentDone(); return `⚠ Hue error: ${e.message}`; }
    }

    async function hueSetLight(lightId, on, brightness) {
        if(!hooksConfig.hueHost||!hooksConfig.hueKey) return '⚠ Philips Hue not configured.';
        agentStatus('generic',`Setting light ${lightId}…`);
        try {
            const body = { on };
            if(brightness!=null) body.bri = Math.max(1,Math.min(254,Math.round(brightness*2.54)));
            await fetch(`http://${hooksConfig.hueHost}/api/${hooksConfig.hueKey}/lights/${lightId}/state`,
                { method:'PUT', headers:{'Content-Type':'application/json'}, body:JSON.stringify(body) });
            agentDone();
            return `✓ Light ${lightId} set to ${on?'ON':'OFF'}${brightness!=null?' @ '+brightness+'%':''}`;
        } catch(e) { agentDone(); return `⚠ Hue error: ${e.message}`; }
    }

    // ─── JIRA ─────────────────────────────────────────────────
    async function jiraSearch(jql, maxResults=10) {
        if(!hooksConfig.jiraUrl||!hooksConfig.jiraToken) return '⚠ Jira not configured. Add URL and API token in HOOKS.';
        agentStatus('generic','Searching Jira…');
        try {
            const auth = btoa(`${hooksConfig.jiraEmail}:${hooksConfig.jiraToken}`);
            const res = await fetch(`${hooksConfig.jiraUrl}/rest/api/3/search?jql=${encodeURIComponent(jql)}&maxResults=${maxResults}`, {
                headers: { 'Authorization': `Basic ${auth}`, 'Accept': 'application/json' }
            });
            if(!res.ok) throw new Error(`HTTP ${res.status}`);
            const d = await res.json();
            agentDone();
            const rows = (d.issues||[]).map(i=>
                `- **${i.key}** [${i.fields.status?.name}] ${i.fields.summary}`).join('\n');
            return `**Jira (${d.total} results):**\n${rows||'No issues found'}`;
        } catch(e) { agentDone(); return `⚠ Jira error: ${e.message}`; }
    }

    async function jiraCreateIssue(project, summary, description='', type='Task') {
        if(!hooksConfig.jiraUrl||!hooksConfig.jiraToken) return '⚠ Jira not configured.';
        agentStatus('generic','Creating Jira issue…');
        try {
            const auth = btoa(`${hooksConfig.jiraEmail}:${hooksConfig.jiraToken}`);
            const res = await fetch(`${hooksConfig.jiraUrl}/rest/api/3/issue`, {
                method:'POST',
                headers: { 'Authorization':`Basic ${auth}`, 'Content-Type':'application/json', 'Accept':'application/json' },
                body: JSON.stringify({ fields: { project:{key:project}, summary, description:{ type:'doc',version:1,content:[{type:'paragraph',content:[{type:'text',text:description}]}] }, issuetype:{name:type} } })
            });
            const d = await res.json();
            agentDone();
            if(d.key) return `✓ Jira issue created: **${d.key}** — ${summary}`;
            return `⚠ Jira: ${JSON.stringify(d.errors||d)}`;
        } catch(e) { agentDone(); return `⚠ Jira error: ${e.message}`; }
    }

    // ─── GITLAB ───────────────────────────────────────────────
    async function gitlabGetIssues(projectId, state='opened') {
        if(!hooksConfig.gitlabToken) return '⚠ GitLab not configured. Add token in HOOKS.';
        agentStatus('generic','Fetching GitLab issues…');
        try {
            const base = hooksConfig.gitlabUrl||'https://gitlab.com';
            const res = await fetch(`${base}/api/v4/projects/${encodeURIComponent(projectId)}/issues?state=${state}&per_page=15`,
                { headers: { 'PRIVATE-TOKEN': hooksConfig.gitlabToken } });
            if(!res.ok) throw new Error(`HTTP ${res.status}`);
            const issues = await res.json();
            agentDone();
            return `**GitLab Issues (${issues.length}):**\n` +
                issues.map(i=>`- **#${i.iid}** [${i.state}] ${i.title}`).join('\n');
        } catch(e) { agentDone(); return `⚠ GitLab error: ${e.message}`; }
    }

    async function gitlabCreateMR(projectId, title, sourceBranch, targetBranch='main') {
        if(!hooksConfig.gitlabToken) return '⚠ GitLab not configured.';
        agentStatus('generic','Creating GitLab MR…');
        try {
            const base = hooksConfig.gitlabUrl||'https://gitlab.com';
            const res = await fetch(`${base}/api/v4/projects/${encodeURIComponent(projectId)}/merge_requests`, {
                method:'POST',
                headers: { 'PRIVATE-TOKEN':hooksConfig.gitlabToken, 'Content-Type':'application/json' },
                body: JSON.stringify({ title, source_branch:sourceBranch, target_branch:targetBranch })
            });
            const d = await res.json();
            agentDone();
            return d.web_url ? `✓ MR created: [${d.title}](${d.web_url})` : `⚠ GitLab: ${JSON.stringify(d.message||d)}`;
        } catch(e) { agentDone(); return `⚠ GitLab error: ${e.message}`; }
    }

