    // 2. Multi-file Search
    async function workspaceSearch(q) {
        if (!q||!state.workspaceEnabled) return [];
        const files = state.workspaceMode==='fs' ? Object.keys(state.workspaceFiles) : WS_FILES;
        const re = new RegExp(q.replace(/[.*+?^${}()|[\]\\]/g,'\\$&'),'gi');
        const results = [];
        for (const fn of files) {
            const content = wsFileCache[fn] || await readFile(fn);
            if (!content) continue;
            wsFileCache[fn]=content;
            const hits = content.split('\n').reduce((a,line,i)=>{
                if([...line.matchAll(re)].length) a.push({line:i+1,text:line.trim().slice(0,120)});
                return a;
            },[]);
            if (hits.length) results.push({file:fn,hits});
        }
        return results;
    }
    async function showWorkspaceSearch() {
        showAetherDialog({
            title:'🔍 Workspace Search',
            html:`<input id="wss-inp" type="text" placeholder="Search all workspace files…" autocomplete="off"
                    style="width:100%;background:#030408;border:1px solid #1e2535;color:#ccd;font-family:monospace;font-size:.76rem;padding:8px 10px;border-radius:3px;outline:none;margin-bottom:10px">
                  <div id="wss-out" style="max-height:280px;overflow:auto;font-family:monospace;font-size:.68rem;color:#445">Type to search…</div>`,
            confirmLabel:'Close', cancelLabel:null, onConfirm:()=>{}
        });
        const inp=document.getElementById('wss-inp'), out=document.getElementById('wss-out');
        if(!inp||!out)return; inp.focus();
        let t;
        inp.addEventListener('input',()=>{
            clearTimeout(t); t=setTimeout(async()=>{
                const q=inp.value.trim(); if(!q){out.innerHTML='<span style="color:#334">Type to search…</span>';return;}
                out.innerHTML='<span style="color:#445">Searching…</span>';
                const r=await workspaceSearch(q);
                if(!r.length){out.innerHTML=`<span style="color:#334">No results for "${escapeHtml(q)}"</span>`;return;}
                const hl=s=>escapeHtml(s).replace(new RegExp(escapeHtml(q),'gi'),m=>`<mark style="background:rgba(0,243,255,.18);color:#00f3ff">${m}</mark>`);
                out.innerHTML=r.map(f=>`<div style="margin-bottom:9px"><div style="color:#00f3ff;margin-bottom:3px">📄 ${f.file} <span style="color:#334">(${f.hits.length})</span></div>${f.hits.slice(0,6).map(h=>`<div style="padding:1px 0;color:#778"><span style="color:#334;margin-right:5px">L${h.line}</span>${hl(h.text)}</div>`).join('')}</div>`).join('');
            },220);
        });
    }

