    // ─── BROWSER USE / PLAYWRIGHT INTEGRATION ────────────────
    // Optional power-user feature requiring a local Python backend
    // Setup: pip install browser-use playwright && playwright install chromium
    // Server: uvicorn aether_browser_agent:app --port 7860
    const BROWSER_AGENT_KEY = 'aether_browser_agent';
    let browserAgentConfig = { url:'http://localhost:7860', enabled:false, engine:'browser-use' };

    (function loadBrowserAgentConfig(){
        try {
            const s=localStorage.getItem(BROWSER_AGENT_KEY);
            if(s) browserAgentConfig={...browserAgentConfig,...JSON.parse(s)};
        } catch {}
    })();

    async function runBrowserAgent(task, engine='browser-use') {
        if(!browserAgentConfig.enabled){
            showNotification('Browser Agent not configured. See HOOKS → Browser Automation.','warn');
            return null;
        }
        agentStatus('generic', `🌐 ${engine}: ${task.slice(0,40)}…`);
        try {
            const res = await fetch(`${browserAgentConfig.url}/run`, {
                method: 'POST',
                headers: {'Content-Type':'application/json'},
                body: JSON.stringify({ task, engine, model: apiConfig.model, api_key: apiConfig.apiKey })
            });
            if(!res.ok) throw new Error(`HTTP ${res.status}`);
            const d = await res.json();
            agentDone();
            return d.result || d.output || JSON.stringify(d);
        } catch(e) {
            agentDone();
            reportFeatureError('Browser Agent', e);
            return null;
        }
    }

    // Register as AETHER tool
    // (wired into TOOL_REGISTRY below — the tool is browser_agent)


    // ═══════════════════════════════════════════════════════════
    // SECTION 18: AGENT MODE v3
    // Plan → Act → Evaluate → Retry. Autonomous multi-step execution.
    // The AI generates a plan, executes one step per turn, evaluates
    // the result, and replans if needed. Persists session state
    // to localStorage so you can close the tab and resume later.
    // This is what separates AETHER from a chat app.
    // It's not just talking. It's doing.
    // ═══════════════════════════════════════════════════════════
    // Plan · Act · Evaluate · Persist · Resume
    // 3x improvement over v1: persistent workspace memory, structured planning
    // phase, per-step approval, tool budget display, session resume, timestamps.

    const AGENT_V3_KEY   = 'aether_agent_v3_session';
    const AGENT_DEFAULTS = { maxSteps: 10, toolBudget: 20, approval: 'auto', model: null };

    async function loadAgentSession() {
        try { const s = localStorage.getItem(AGENT_V3_KEY); if (s) return JSON.parse(s); } catch(e) {}
        return null;
    }
    async function saveAgentSession(session) {
        try { localStorage.setItem(AGENT_V3_KEY, JSON.stringify(session)); } catch(e) {}
        if (!state.workspaceEnabled) return;
        try {
            let ws = await readFile('WORKSPACE.md') || '';
            const marker = '<!-- agent_v3:' + session.goalId + ' -->';
            const entry  = marker + '\n## [Agent v3: ' + session.goal.slice(0,60) + ']\n'
                + '**Status:** ' + session.status + ' | **Step:** ' + session.step
                + '/' + session.maxSteps + ' | **Updated:** ' + new Date().toLocaleString() + '\n'
                + (session.results||[]).slice(-3).map((r,i) => '- ' + String(r).slice(0,100)).join('\n')
                + '\n<!-- /agent_v3 -->';
            if (ws.includes(marker)) { ws = ws.replace(new RegExp(marker + '[\\s\\S]*?<!-- \\/agent_v3 -->'), entry); }
            else { ws += '\n\n' + entry; }
            await writeFile('WORKSPACE.md', ws);
        } catch(e) {}
    }
    async function clearAgentSession() {
        try { localStorage.removeItem(AGENT_V3_KEY); } catch(e) {}
    }

    let agentRunning    = false;
    let agentAbortCtrl  = null;

    async function runAgentTask(userGoal, options = {}) {
        if (agentRunning) { showNotification('Agent already running', 'warn'); return; }
        if (typeof window._aetherExpandModes === 'function') window._aetherExpandModes();
        const cfg = { ...AGENT_DEFAULTS, ...options };
        agentRunning   = true;
        agentAbortCtrl = new AbortController();
        updateAgentIndicator(true);
        // Kernel flight + thread graph
        try { if (window.__aetherBeginAgentFlight) window.__aetherBeginAgentFlight(userGoal); } catch(e) {}
        try { if (window.__aetherTrackGraph) window.__aetherTrackGraph('agent', 'Agent: ' + String(userGoal).slice(0, 48)); } catch(e) {}
        try { if (typeof AETHER_Theater !== 'undefined') AETHER_Theater.pulseReasoning(); } catch(e) {}

        const agentConvId = state.currentConversationId;
        const conv = state.conversations[agentConvId];
        if (!conv) { agentRunning = false; return; }

        // Check for resumable session
        const existing = await loadAgentSession();
        let agentSession = null;
        if (existing && existing.status === 'in_progress' && existing.goal === userGoal) {
            const resume = await showDialog({
                title: 'Resume Agent Session',
                message: 'Resume "' + userGoal.slice(0,60) + '" from step ' + existing.step + '?',
                type: 'confirm'
            });
            if (resume) agentSession = existing;
        }

        // AETHER.md workspace context
        let wsCtx = '';
        if (state.workspaceEnabled) {
            try {
                const cMd = await readFile('AETHER.md') || await readFile('CORE_LOGIC.md');
                if (cMd) wsCtx = '\n\n## PROJECT CONTEXT\n' + cMd.slice(0, 600);
            } catch(e) {}
        }

        const sysLines = [
            'You are AETHER Agent v3 — autonomous, precise, persistent.',
            '',
            'PROTOCOL:',
            '1. PLAN:     <agent:plan>numbered steps with type TOOL|THINK|WRITE|VERIFY</agent:plan>',
            '2. ACT:      One step per turn using [[tool: arg]] or direct output',
            '3. EVALUATE: Reassess after each result; replan with <agent:replan>...</agent:replan>',
            '4. VERIFY:   Cross-check critical results before proceeding',
            '5. COMPLETE: <agent:done>full summary</agent:done>',
            '',
            'TOOLS: ' + Object.keys(TOOL_REGISTRY).join(', '),
            'MAX STEPS: ' + cfg.maxSteps + ' | BUDGET: ' + cfg.toolBudget,
            'GOAL: ' + userGoal,
            wsCtx
        ];
        const agentSys = sysLines.join('\n');

        // Build UI
        const agentEl = document.createElement('div');
        agentEl.className = 'agent-mode-block agent-v3';

        const hdr = document.createElement('div'); hdr.className = 'agent-header';
        const pulse = document.createElement('span'); pulse.className = 'agent-pulse';
        const titleEl = document.createElement('span'); titleEl.className = 'agent-title'; titleEl.textContent = 'AGENT v3';
        const stepCnt = document.createElement('span'); stepCnt.className = 'agent-step-count'; stepCnt.id = 'agent-step-n';
        stepCnt.textContent = 'Step 0/' + cfg.maxSteps;
        const budgetEl = document.createElement('span'); budgetEl.className = 'agent-tool-budget'; budgetEl.id = 'agent-budget';
        budgetEl.title = 'Tool budget remaining'; budgetEl.textContent = '\u2699 ' + cfg.toolBudget;
        const stopBtnEl = document.createElement('button'); stopBtnEl.className = 'agent-stop-btn';
        stopBtnEl.textContent = '\u25a0 Stop'; stopBtnEl.onclick = () => stopAgent();
        hdr.appendChild(pulse); hdr.appendChild(titleEl); hdr.appendChild(stepCnt);
        hdr.appendChild(budgetEl); hdr.appendChild(stopBtnEl);

        const planPrev = document.createElement('div'); planPrev.className = 'agent-plan-preview'; planPrev.id = 'agent-plan-preview'; planPrev.style.display = 'none';
        const logEl    = document.createElement('div'); logEl.className = 'agent-log'; logEl.id = 'agent-log';

        agentEl.appendChild(hdr); agentEl.appendChild(planPrev); agentEl.appendChild(logEl);
        display.appendChild(agentEl);
        smoothScrollToBottom();

        const addLog = (text, type) => {
            type = type || 'info';
            const d = document.createElement('div');
            d.className = 'agent-log-entry agent-' + type;
            const ts = new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
            const tsEl = document.createElement('span'); tsEl.className = 'agent-ts'; tsEl.textContent = ts;
            const cnt = document.createElement('div'); cnt.className = 'agent-log-content';
            cnt.innerHTML = parseMarkdown(text).innerHTML;
            d.appendChild(tsEl); d.appendChild(cnt);
            logEl.appendChild(d); logEl.scrollTop = logEl.scrollHeight;
            smoothScrollToBottom();
        };

        // Resume or init
        let step      = agentSession?.step || 0;
        let toolsUsed = agentSession?.toolsUsed || 0;
        let history   = agentSession?.history || [{ role: 'user', content: userGoal }];
        const results = agentSession?.results || [];
        const goalId  = agentSession?.goalId  || 'g_' + Date.now();

        if (agentSession) {
            addLog('\u21a9 **Resuming from step ' + step + '** \u2014 ' + results.length + ' steps completed', 'info');
        }
        addLog('**Goal:** ' + userGoal, 'goal');

        // ── Phase 1: Planning ──────────────────────────────────
        // BUG FIX: drCallModel was called here but never defined anywhere in the
        // codebase. Every agent run threw a ReferenceError immediately, the catch
        // silently swallowed it ("Plan generation skipped"), and the agent always
        // started without a plan. Fixed by routing through callModelDirect.
        agentStatus('think', 'Planning\u2026');
        try {
            const planRes = await callModelDirect(
                agentSys + '\n\nOutput ONLY your <agent:plan>...</agent:plan> with numbered steps.',
                { max_tokens: 600, temperature: 0.3 }
            );
            const pm = planRes.match(/<agent:plan>([\s\S]*?)<\/agent:plan>/);
            if (pm) {
                const planLines = pm[1].trim().split('\n').filter(l => l.trim());
                planPrev.style.display = 'block';
                const planTitle = document.createElement('div'); planTitle.className = 'agent-plan-title';
                planTitle.textContent = '\u27e8agent:plan\u27e9';
                planPrev.appendChild(planTitle);
                planLines.forEach((line, i) => {
                    const row = document.createElement('div'); row.className = 'agent-plan-step'; row.id = 'apl-' + i;
                    const num = document.createElement('span'); num.className = 'apl-num'; num.textContent = String(i + 1);
                    const txt = document.createElement('span'); txt.className = 'apl-text';
                    txt.textContent = line.replace(/^\d+[\.\)]\s*/, '');
                    const st  = document.createElement('span'); st.className = 'apl-state'; st.textContent = '\u23f3';
                    row.appendChild(num); row.appendChild(txt); row.appendChild(st);
                    planPrev.appendChild(row);
                });
                history.push({ role: 'assistant', content: planRes });
                addLog('**Plan generated** \u2014 ' + planLines.length + ' steps', 'plan');
            }
        } catch(e) {
            addLog('Plan generation skipped: ' + e.message, 'warn');
        }
        agentStatus('generic', 'Executing\u2026');

        // ── Main Loop ─────────────────────────────────────────
        let lastResponse = '';
        try {
            while (step < cfg.maxSteps && !agentAbortCtrl.signal.aborted) {
                step++;
                if (stepCnt) stepCnt.textContent = 'Step ' + step + '/' + cfg.maxSteps;
                if (budgetEl) budgetEl.textContent = '\u2699 ' + (cfg.toolBudget - toolsUsed);

                // Mark current plan step
                const planStepEl = planPrev.querySelector('#apl-' + (step - 1) + ' .apl-state');
                if (planStepEl) planStepEl.innerHTML = '<div class="dr-spinner-sm"></div>';

                // Approval gate
                if (cfg.approval === 'each' && step > 1) {
                    const ok = await new Promise(resolve => {
                        showAetherDialog({
                            title: 'Agent v3 \u2014 Step ' + step,
                            html: '<p style="font-family:monospace;font-size:.76rem;color:#99aabb">Proceed to step ' + step
                                + '?</p><p style="font-size:.72rem;color:#556;margin-top:8px">Last: '
                                + lastResponse.slice(0, 100) + '\u2026</p>',
                            confirmLabel: 'Continue', cancelLabel: 'Stop',
                            onConfirm: () => resolve(true), onCancel: () => resolve(false)
                        });
                    });
                    if (!ok) { addLog('**Stopped at step ' + step + '**', 'warn'); break; }
                }

                addLog('**Step ' + step + '** \u2014 reasoning\u2026', 'step');

                history.push({ role: 'user', content: 'Execute step ' + step + '. Remaining budget: ' + (cfg.toolBudget - toolsUsed) + '. Goal: ' + userGoal });

                // Call AI
                let response = '';
                try {
                    const sysPrompt = await buildSystemPrompt(userGoal, []);
                    // ── History windowing: always keep history[0] (the original goal
                    // message) pinned at the front, then take the last 13 turns from the
                    // rest. Without this, long agent runs drop the opening user message
                    // and the model loses the goal it was supposed to be solving. Fixed.
                    const pinnedGoal  = history[0];
                    const recentTurns = history.length > 14 ? history.slice(1).slice(-13) : history.slice(1);
                    const windowedHistory = pinnedGoal ? [pinnedGoal, ...recentTurns] : history.slice(-14);
                    const msgs = [{ role: 'system', content: agentSys + '\n\n' + sysPrompt }, ...windowedHistory];
                    response = await callAISimple(msgs, cfg.model || apiConfig.model);
                } catch(e) {
                    addLog('**API error:** ' + e.message, 'error'); break;
                }
                lastResponse = response;

                // Check done
                const doneMatch = response.match(/<agent:done>([\s\S]*?)<\/agent:done>/);
                if (doneMatch) {
                    const summary = doneMatch[1].trim();
                    addLog('\u2713 **Complete:** ' + summary.slice(0, 200), 'done');
                    if (planStepEl) planStepEl.textContent = '\u2713';
                    const outEl = document.createElement('div'); outEl.className = 'aether-msg';
                    outEl.appendChild(parseMarkdown('## \u27e8agent:done\u27e9\n\n' + summary));
                    attachActions(outEl, summary);
                    display.appendChild(outEl);
                    conv.messages.push({ role: 'user', content: '[Agent v3] ' + userGoal });
                    conv.messages.push({ role: 'assistant', content: summary });
                    updateConversationTitle(conv); saveConversations(); renderConversationList();
                    await clearAgentSession();
                    showNotification('Agent v3 task complete', 'success');
                    try { if (window.__aetherEndAgentFlight) window.__aetherEndAgentFlight('landed'); } catch(e) {}
                    try { if (typeof AETHER_Theater !== 'undefined') AETHER_Theater.answerPulse(); } catch(e) {}
                    break;
                }

                // Check replan
                const replan = response.match(/<agent:replan>([\s\S]*?)<\/agent:replan>/);
                if (replan) addLog('\u21bb **Replanning:** ' + replan[1].trim().slice(0, 100), 'replan');

                // Execute tools
                const toolCalls = [...response.matchAll(/\[\[(\w+):\s*([\s\S]*?)\]\]/g)];
                let stepOutput = '';
                for (const [, toolName, toolArg] of toolCalls.slice(0, 3)) {
                    if (toolsUsed >= cfg.toolBudget) { addLog('\u26a0 Tool budget exhausted', 'warn'); break; }
                    const fn = TOOL_REGISTRY[toolName]?.fn;
                    if (!fn) { addLog('\u26a0 Unknown tool: ' + toolName, 'warn'); continue; }
                    agentStatus(toolName.includes('search') ? 'search' : 'generic', '\u2699 ' + toolName + '\u2026');
                    addLog('`[[' + toolName + ': ' + String(toolArg).slice(0, 60) + ']]`', 'tool');
                    try {
                        const r = await fn(toolArg.trim());
                        const preview = String(r).slice(0, 300);
                        addLog('\u2192 ' + preview + (String(r).length > 300 ? '\u2026' : ''), 'result');
                        stepOutput += '[' + toolName + ']: ' + String(r).slice(0, 400) + '\n';
                        results.push('Step ' + step + ' ' + toolName + ': ' + String(r).slice(0, 80));
                        toolsUsed++;
                    } catch(e) {
                        addLog('\u2717 ' + toolName + ' error: ' + e.message, 'error');
                        stepOutput += '[' + toolName + ' ERROR]: ' + e.message + '\n';
                    }
                    agentDone();
                }

                // Visible text
                const visible = response.replace(/<agent:[^>]+>[\s\S]*?<\/agent:[^>]+>/g, '').replace(/\[\[.*?\]\]/g, '').trim();
                if (visible) addLog(visible.slice(0, 400) + (visible.length > 400 ? '\u2026' : ''), 'text');

                if (planStepEl) planStepEl.textContent = '\u2713';
                history.push({ role: 'assistant', content: response });
                if (stepOutput) history.push({ role: 'user', content: '[Tool results]:\n' + stepOutput });

                // Persist every step
                await saveAgentSession({ goal: userGoal, goalId, step, maxSteps: cfg.maxSteps, toolsUsed, history: history.slice(-20), results: results.slice(-10), status: 'in_progress' });

                await new Promise(r => setTimeout(r, 150));
            }

            if (step >= cfg.maxSteps && !agentAbortCtrl.signal.aborted) {
                addLog('\u26a0 Max steps reached (' + cfg.maxSteps + '). Task may be incomplete.', 'warn');
            }
        } catch(e) {
            if (e.name === 'AbortError') {
                addLog('\u25a0 Agent paused. Resume later with the same goal.', 'warn');
                await saveAgentSession({ goal: userGoal, goalId, step, maxSteps: cfg.maxSteps, toolsUsed, history: history.slice(-20), results: results.slice(-10), status: 'in_progress' });
                showNotification('Agent paused \u2014 can resume later', 'info');
            } else {
                addLog('**Error:** ' + e.message, 'error');
                reportFeatureError('Agent', e);
            }
        } finally {
            const aborted = !!(agentAbortCtrl && agentAbortCtrl.signal && agentAbortCtrl.signal.aborted);
            agentRunning = false;
            agentAbortCtrl = null;
            updateAgentIndicator(false);
            agentDone();
            agentEl.querySelector('.agent-stop-btn')?.remove();
            try { if (window.__aetherEndAgentFlight) window.__aetherEndAgentFlight(aborted ? 'aborted' : 'landed'); } catch(e) {}
        }
    }

    // Simple AI call helper (no streaming) — auth via buildAuthHeaders().
    async function callAISimple(messages, model) {
        const prov = (apiConfig.provider||'').toLowerCase();
        const { headers, fetchUrl } = buildAuthHeaders();
        const mt = getSmartMaxTokens(prov, model || apiConfig.model, state.contextLimit);
        let body;
        if (prov === 'anthropic') {
            const aMsgs = messages.filter(m => m.role !== 'system');
            const sys   = messages.find(m => m.role === 'system')?.content || '';
            body = JSON.stringify({ model: model||apiConfig.model, max_tokens: mt, system: sys, messages: aMsgs, stream: false, temperature: 0.3 });
        } else {
            body = JSON.stringify({ model: model||apiConfig.model, messages, stream: false, temperature: 0.3, max_tokens: mt });
        }
        if (!fetchUrl) throw new Error('No API endpoint configured');
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 30000);
        let res;
        try {
            res = await fetch(fetchUrl, { method: 'POST', headers, body, signal: controller.signal });
        } catch(e) {
            clearTimeout(timeoutId);
            if (e.name === 'AbortError') throw new Error('Request timed out');
            throw e;
        }
        clearTimeout(timeoutId);
        if (!res.ok) {
            const errText = await res.text().catch(() => '');
            throw new Error('HTTP ' + res.status + (errText ? ': ' + errText.slice(0, 100) : ''));
        }
        const d = await res.json();
        return d.choices?.[0]?.message?.content || d.content?.[0]?.text || '';
    }

    function stopAgent() {
        if (agentAbortCtrl) agentAbortCtrl.abort();
        agentRunning = false;
        updateAgentIndicator(false);
        showNotification('Agent stopped', 'warn');
    }

    function updateAgentIndicator(running) {
        let ind = document.getElementById('agent-indicator');
        if (!ind) {
            ind = document.createElement('span');
            ind.id = 'agent-indicator';
            ind.style.cssText = 'font-family:monospace;font-size:.58rem;margin-left:6px;display:none;';
            document.querySelector('.status-left')?.appendChild(ind);
        }
        if (running) {
            ind.textContent = '⟳ AGENT';
            ind.style.color = '#ffd700';
            ind.style.display = 'inline';
        } else {
            ind.style.display = 'none';
        }
    }

    // Wire agent button — now "Force Agent Mode" override
    // When auto-detect is on, this button lets users explicitly force
    // agent mode for tasks the detector might miss.
    const _agentBtn = document.getElementById('btn-agent-mode');
    if (_agentBtn) {
        _agentBtn.addEventListener('click', () => {
            if (agentRunning) { stopAgent(); return; }
            showAetherDialog({
                title: '⬡ Force Agent Mode',
                html: `<p style="font-family:monospace;font-size:.72rem;color:#99aabb;margin-bottom:10px">Describe the multi-step task for AETHER to complete autonomously:</p>
                       <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px">
                         <div><label style="font-family:monospace;font-size:.58rem;color:#445">Max Steps</label><input type="number" id="agent-maxsteps" value="10" min="1" max="30" style="width:100%;background:#030408;border:1px solid #1e2535;color:#ccd;font-family:monospace;font-size:.72rem;padding:5px;border-radius:3px;outline:none;margin-top:3px"></div>
                         <div><label style="font-family:monospace;font-size:.58rem;color:#445">Approval</label><select id="agent-approval" style="width:100%;background:#030408;border:1px solid #1e2535;color:#ccd;font-family:monospace;font-size:.68rem;padding:5px;border-radius:3px;outline:none;margin-top:3px"><option value="auto">Auto (run all)</option><option value="each">Per step</option></select></div>
                       </div>`,
                type: 'prompt',
                inputPlaceholder: 'e.g. Research the top 5 AI papers from last week, summarise each, and save to workspace',
                confirmLabel: '⬡ Start Agent',
                cancelLabel: 'Cancel',
                onConfirm: (goal) => {
                    if (!goal) return;
                    const maxSteps = parseInt(document.getElementById('agent-maxsteps')?.value || '10');
                    const approval = document.getElementById('agent-approval')?.value || 'auto';
                    runAgentTask(goal, { maxSteps, approval });
                }
            });
        });
    }

    // ─── WHISPER.JS OFFLINE VOICE ─────────────────────────────
    // Transformers.js + WebGPU — runs entirely in browser
    let whisperPipeline = null;
    let whisperLoading = false;
    let mediaRecorderWjs = null;
    let wjsChunks = [];
    let wjsActive = false;

    async function initWhisperJS() {
        if (whisperPipeline) return whisperPipeline;
        if (whisperLoading) return null;
        whisperLoading = true;
        showNotification('Loading Whisper.js (~300MB first use)…', 'info');
        try {
            const { pipeline } = await import('https://cdn.jsdelivr.net/npm/@huggingface/transformers@3/dist/transformers.min.js');
            whisperPipeline = await pipeline('automatic-speech-recognition', 'onnx-community/whisper-base.en-ONNX', {
                device: 'webgpu',
                progress_callback: (p) => {
                    if (p.status === 'progress') showNotification(`Whisper.js: ${Math.round(p.progress||0)}%`, 'info');
                }
            });
            showNotification('✓ Whisper.js ready — offline voice active', 'success');
            whisperLoading = false;
            return whisperPipeline;
        } catch(e) {
            // Fallback: try CPU
            try {
                const { pipeline } = await import('https://cdn.jsdelivr.net/npm/@huggingface/transformers@3/dist/transformers.min.js');
                whisperPipeline = await pipeline('automatic-speech-recognition', 'onnx-community/whisper-tiny.en-ONNX');
                showNotification('✓ Whisper.js (CPU) ready', 'success');
                whisperLoading = false;
                return whisperPipeline;
            } catch(e2) {
                reportFeatureError('Whisper.js', e2);
                whisperLoading = false;
                return null;
            }
        }
    }

    async function toggleWhisperJS() {
        if (wjsActive) {
            // Stop recording
            wjsActive = false;
            mediaRecorderWjs?.stop();
            return;
        }
        const pipe = await initWhisperJS();
        if (!pipe) return;
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        wjsChunks = [];
        mediaRecorderWjs = new MediaRecorder(stream);
        mediaRecorderWjs.ondataavailable = e => wjsChunks.push(e.data);
        mediaRecorderWjs.onstop = async () => {
            stream.getTracks().forEach(t => t.stop());
            const blob = new Blob(wjsChunks, { type: 'audio/webm' });
            const arr = await blob.arrayBuffer();
            showNotification('Transcribing offline…', 'info');
            try {
                const result = await pipe(arr);
                const text = result.text?.trim();
                if (text && userInput) {
                    userInput.value += (userInput.value ? ' ' : '') + text;
                    userInput.dispatchEvent(new Event('input'));
                    showNotification('✓ Transcribed offline', 'success');
                }
            } catch(e) {
                reportFeatureError('Whisper.js Transcription', e);
            }
            wjsActive = false;
            updateMicIndicator();
        };
        mediaRecorderWjs.start();
        wjsActive = true;
        updateMicIndicator();
        showNotification('Recording (Whisper.js offline)…', 'info');
    }


    // ─── ANIMATED LOADING STATES ─────────────────────────────
    const LOAD_STATES = [
        {i:'⟳', t:'Processing…',      a:'spin'},
        {i:'⚛', t:'Deep thinking…',   a:'pulse-cyan'},
        {i:'⬡', t:'Synthesising…',    a:'glow-hex'},
        {i:'◈', t:'Chaining tools…',  a:'spin'},
        {i:'≋', t:'Streaming…',       a:'wave'},
        {i:'⊛', t:'Running agent…',   a:'orbit'},
        {i:'◉', t:'Searching…',       a:'pulse-cyan'},
    ];
    let _lsIdx = 0, _lsTimer = null;

    // ─── FLUX.2 IMAGE GENERATION ─────────────────────────────
    async function generateFluxImage(prompt, opts = {}) {
        const { model = 'flux-schnell' } = opts;
        showNotification('Generating with FLUX.2…', 'info');
        const imgEl = document.createElement('div');
        imgEl.className = 'flux-gen-block';
        imgEl.innerHTML = `<div class="flux-loading">
            <div class="flux-rings"><div class="fr r1"></div><div class="fr r2"></div><div class="fr r3"></div><div class="flux-spark"></div></div>
            <div class="flux-status">Generating with FLUX.2…</div>
            <div class="flux-prompt-prev">${escapeHtml(prompt.slice(0,80))}${prompt.length>80?'…':''}</div>
        </div>`;
        display.appendChild(imgEl); smoothScrollToBottom();
        try {
            const isBFL = (apiConfig.provider||'').includes('flux') || (apiConfig.endpoint||'').includes('bfl.ml');
            let imageUrl = null;
            if (isBFL) {
                const headers = {'Content-Type':'application/json'};
                if (apiConfig.apiKey) headers['x-key'] = apiConfig.apiKey;
                const res = await fetch(`https://api.bfl.ml/v1/${model}`, {method:'POST', headers, body:JSON.stringify({prompt, width:1024, height:768})});
                if (!res.ok) throw new Error(`BFL ${res.status}`);
                const d = await res.json();
                let attempts = 0;
                while (attempts < 30) {
                    await new Promise(r=>setTimeout(r,1800));
                    const pd = await (await fetch(`https://api.bfl.ml/v1/get_result?id=${d.id}`, {headers})).json();
                    if (pd.status==='Ready') { imageUrl = pd.result?.sample; break; }
                    if (pd.status==='Error') throw new Error('FLUX failed');
                    attempts++;
                    const s = imgEl.querySelector('.flux-status');
                    if (s) s.textContent = `Generating… ${Math.round(attempts/30*100)}%`;
                }
            } else {
                const headers = {'Content-Type':'application/json'};
                if (apiConfig.apiKey) headers['Authorization'] = `Bearer ${apiConfig.apiKey}`;
                const base = (apiConfig.endpoint||'').replace(/\/chat\/completions.*$/, '');
                const res = await fetch(`${base}/images/generations`, {method:'POST', headers, body:JSON.stringify({prompt, n:1, size:'1024x768', model})});
                if (!res.ok) throw new Error(`API ${res.status}`);
                const d = await res.json();
                imageUrl = d.data?.[0]?.url || (d.data?.[0]?.b64_json ? 'data:image/png;base64,'+d.data[0].b64_json : null);
            }
            if (!imageUrl) throw new Error('No image returned');
            const safePrompt = escapeHtml(prompt).replace(/"/g,'&quot;');
            imgEl.innerHTML = `<div class="flux-result">
                <div class="flux-rh"><span class="flux-badge">FLUX.2 · ${model}</span>
                    <div class="flux-ra">
                        <button class="flux-btn" onclick="downloadFluxImage('${imageUrl.startsWith('data')?'blob':'url'}','${imageUrl.startsWith('data')?imageUrl:''}','${imageUrl.startsWith('http')?imageUrl:''}')">↓ Save</button>
                        <button class="flux-btn" onclick="showFluxEdit('${safePrompt}')">✏ Edit</button>
                        <button class="flux-btn" onclick="generateFluxImage('${safePrompt}')">↺ Regen</button>
                    </div></div>
                <img src="${imageUrl}" class="flux-img" alt="${safePrompt}" loading="lazy">
                <div class="flux-cap">${safePrompt}</div>
            </div>`;
            smoothScrollToBottom();
            const conv = getCurrentConversation();
            if (conv) { conv.messages.push({role:'assistant',content:`[Image generated: ${prompt}]`}); saveConversations(); }
        } catch(e) {
            imgEl.innerHTML = `<div class="flux-error">⚠ FLUX.2 error: ${escapeHtml(e.message)}</div>`;
            reportFeatureError('Image Generation', e, { prompt, model });
        }
    }
    window.downloadFluxImage = (type, dataUrl, httpUrl) => {
        const a = document.createElement('a');
        a.href = type==='url' ? httpUrl : dataUrl;
        a.download = 'aether-flux-'+Date.now()+'.png';
        document.body.appendChild(a); a.click(); a.remove();
    };
    window.showFluxEdit = (prompt) => {
        showAetherDialog({title:'✏ Edit Image', type:'prompt',
            html:'<p style="font-family:monospace;font-size:.7rem;color:#99aabb;margin-bottom:8px">Describe changes to make:</p>',
            inputPlaceholder:'e.g. "Change sky to sunset" or "Add neon signs"',
            inputValue: prompt, confirmLabel:'Generate Edit', cancelLabel:'Cancel',
            onConfirm:(p)=>{ if(p) generateFluxImage(p, {model:'flux-dev'}); }
        });
    };
    function isImageRequest(txt) {
        return /\b(generate|create|draw|make|render|paint|design|show me)\s+(an?\s+)?(image|picture|photo|illustration|artwork|portrait|scene|drawing)/i.test(txt);
    }

    // ─── AGENT SESSION LEGACY SHIM ───────────────────────────
    const AGENT_SESSION_KEY = 'aether_agent_v2';
    async function saveAgentToWorkspace(goal, step, results) {
        // Delegated to Agent v3 saveAgentSession
    }
    async function markAgentComplete(goal) {
        localStorage.removeItem(AGENT_SESSION_KEY);
    }

    // ═══════════════════════════════════════════════════════════
    // AETHER CALL v3 — Real-time voice with FFT visualizer,
    // Voice Activity Detection, Interruption handling,
    // Particle background, and freehand whiteboard.
    // ═══════════════════════════════════════════════════════════

    let callActive   = false;
    let callMuted    = false;
    let callPttMode  = false; // push-to-talk vs open mic
    let callSpeaking = false; // AI is speaking via TTS
    let callHistory  = [];
    let callWhiteboardOpen = false;
    let callRecog    = null;
    let callStream   = null;
    let callAudioCtx = null;
    let callAnalyser = null;
    let callAnimFrame = null;
    let callDurSecs  = 0;
    let callDurTimer = null;
    let callVadTimer = null;
    let callVadSpeaking = false; // user is currently speaking (VAD)
    let callSpeechSilenceTimer = null;
    let callPttHeld  = false;
    let callMicBlocked = false;
    let _callPermissionWatcher = null;
    let _callParticleCleanup = null;
    let _callParticleRaf = null;

    // ── Audio pipeline: stream → analyser → mediaRecorder ──
    async function callInitAudio() {
        try {
            callStream = await navigator.mediaDevices.getUserMedia({
                audio: {
                    echoCancellation: true,
                    noiseSuppression: true,
                    autoGainControl: true
                }
            });
            callAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
            const src = callAudioCtx.createMediaStreamSource(callStream);
            callAnalyser = callAudioCtx.createAnalyser();
            callAnalyser.fftSize = 256;
            callAnalyser.smoothingTimeConstant = 0.8;
            src.connect(callAnalyser);
            callMicBlocked = false;
            return true;
        } catch(e) {
            callMicBlocked = true;
            reportFeatureError('Call Mic', e);
            showNotification('Microphone access denied: ' + (e.message || 'permission not granted') + '. Allow mic access in browser settings and try again.', 'error');
            return false;
        }
    }

    function callCleanupAudio() {
        if (callStream) { callStream.getTracks().forEach(t => t.stop()); callStream = null; }
        if (callAudioCtx) { callAudioCtx.close().catch(()=>{}); callAudioCtx = null; }
        callAnalyser = null;
    }

    // Monitor mic permission changes for auto-recovery
    function callStartPermissionWatch() {
        try {
            const q = navigator.permissions?.query({ name: 'microphone' });
            if (!q || !q.then) return;
            q.then(status => {
                if (!status) return;
                _callPermissionWatcher = () => {
                    if (status.state === 'granted' && callMicBlocked && !callActive) {
                        callMicBlocked = false;
                        showNotification('Mic permission restored. You can call again.', 'success');
                    }
                };
                status.onchange = _callPermissionWatcher;
            }).catch(() => {});
        } catch(e) { /* permissions API not available */ }
    }

    // ── FFT Visualizer ─────────────────────────────────────
    function callStartVisualizer(canvasEl) {
        if (!canvasEl || !callAnalyser) return;
        const ctx = canvasEl.getContext('2d');
        if (!ctx) return;
        let W = canvasEl.width = canvasEl.clientWidth * (window.devicePixelRatio || 1);
        let H = canvasEl.height = canvasEl.clientHeight * (window.devicePixelRatio || 1);
        const bufferLen = callAnalyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLen);
        const timeData = new Uint8Array(bufferLen);

        let hue = 185;

        function draw() {
            if (!callActive || !callAnalyser || !canvasEl.isConnected) { callAnimFrame = null; return; }
            callAnalyser.getByteFrequencyData(dataArray);
            callAnalyser.getByteTimeDomainData(timeData);

            ctx.clearRect(0, 0, W, H);

            const barCount = Math.min(bufferLen, 48);
            const barW = W / barCount;
            const avgAmp = dataArray.reduce((a,b)=>a+b,0) / barCount;

            if (avgAmp > 40) hue = (hue + 0.3) % 360;

            for (let i = 0; i < barCount; i++) {
                const val = dataArray[i] / 255;
                const barH = Math.max(1, val * H * 0.7);
                const x = i * barW;
                const alpha = 0.2 + val * 0.6;
                const barHue = hue + i * 4;
                ctx.fillStyle = `hsla(${barHue}, 80%, ${50 + val * 30}%, ${alpha})`;
                ctx.fillRect(x, H - barH, barW - 1, barH);
            }

            ctx.beginPath();
            ctx.strokeStyle = `hsla(${hue}, 70%, 60%, 0.3)`;
            ctx.lineWidth = 2;
            const step = Math.floor(bufferLen / 80);
            for (let i = 0; i <= 80; i++) {
                const idx = Math.min(i * step, bufferLen - 1);
                const y = (timeData[idx] / 255) * H;
                if (i === 0) ctx.moveTo(0, y);
                else ctx.lineTo((i / 80) * W, y);
            }
            ctx.stroke();

            const vuX = W / 2;
            const vuY = H - 12;
            const vuRad = 4 + avgAmp * 0.15;
            const vuColor = avgAmp > 50 ? `hsl(0, 80%, 60%)` : avgAmp > 20 ? `hsl(${hue}, 80%, 60%)` : `hsla(${hue}, 60%, 40%, 0.5)`;
            ctx.beginPath();
            ctx.arc(vuX, vuY, Math.min(vuRad, 20), 0, Math.PI * 2);
            ctx.fillStyle = vuColor;
            ctx.fill();

            ctx.fillStyle = `hsla(${hue}, 60%, 50%, 0.4)`;
            ctx.font = `${Math.max(7, Math.min(10, W / 80))}px monospace`;
            ctx.textAlign = 'center';
            ctx.fillText(Math.round(avgAmp).toString(), vuX, vuY - vuRad - 4);

            callAnimFrame = requestAnimationFrame(draw);
        }
        callAnimFrame = requestAnimationFrame(draw);
    }

    function callStopVisualizer() {
        if (callAnimFrame) { cancelAnimationFrame(callAnimFrame); callAnimFrame = null; }
    }

    // ── Voice Activity Detection ───────────────────────────
    function callGetVadThreshold() {
        return parseFloat(localStorage.getItem('aether_vad_threshold')) || 18;
    }
    function callStartVAD() {
        if (!callAnalyser) return;
        const bufferLen = callAnalyser.frequencyBinCount;
        const data = new Uint8Array(bufferLen);
        let silenceMs = 0;
        const SILENCE_TIMEOUT = 1800; // ms of silence before stopping

        callVadTimer = setInterval(() => {
            if (!callActive || !callAnalyser || callMuted || callPttMode) return;
            callAnalyser.getByteFrequencyData(data);
            const avg = data.reduce((a,b)=>a+b,0) / bufferLen;
            const threshold = callGetVadThreshold();
            const isSpeaking = avg > threshold;

            if (isSpeaking) {
                silenceMs = 0;
                if (!callVadSpeaking) {
                    callVadSpeaking = true;
                    // Interrupt AI if speaking
                    if (callSpeaking) {
                        try { speechSynthesis.cancel(); } catch(e) {}
                        callSpeaking = false;
                        callSetStatus('You interrupted');
                        setTimeout(() => callSetStatus('Listening…'), 600);
                    }
                    // Start recog if not running
                    if (callRecog && !callMuted) {
                        try { callRecog.start(); } catch(e) {}
                    }
                }
            } else {
                if (callVadSpeaking) {
                    silenceMs += 80;
                    if (silenceMs >= SILENCE_TIMEOUT) {
                        callVadSpeaking = false;
                        silenceMs = 0;
                        // Stop recognition — user finished speaking
                        try { callRecog?.stop(); } catch(e) {}
                    }
                }
            }
            callUpdateMicDot(isSpeaking);
        }, 80);
    }

    function callStopVAD() {
        if (callVadTimer) { clearInterval(callVadTimer); callVadTimer = null; }
        callVadSpeaking = false;
    }

    // ── Particle background ────────────────────────────────
    let callParticles = [];
    function callInitParticles(canvasEl) {
        if (!canvasEl) return;
        const W = canvasEl.width = canvasEl.clientWidth;
        const H = canvasEl.height = canvasEl.clientHeight;
        callParticles = [];
        const count = Math.min(60, Math.floor(W * H / 8000));
        for (let i = 0; i < count; i++) {
            callParticles.push({
                x: Math.random() * W, y: Math.random() * H,
                vx: (Math.random() - 0.5) * 0.5,
                vy: (Math.random() - 0.5) * 0.5 - 0.15,
                r: Math.random() * 1.5 + 0.5,
                a: Math.random() * 0.4 + 0.1
            });
        }
    }

    function callStartParticles(canvasEl) {
        if (!canvasEl) return;
        const ctx = canvasEl.getContext('2d');
        if (!ctx) return;
        let W = canvasEl.width, H = canvasEl.height;

        function draw() {
            if (!callActive || !canvasEl.isConnected || !ctx) { _callParticleRaf = null; return; }
            ctx.clearRect(0, 0, W, H);

            for (let i = 0; i < callParticles.length; i++) {
                const a = callParticles[i];
                a.x += a.vx; a.y += a.vy;
                if (a.x < 0 || a.x > W) a.vx *= -1;
                if (a.y < 0 || a.y > H) a.vy *= -1;

                for (let j = i + 1; j < callParticles.length; j++) {
                    const b = callParticles[j];
                    const dx = a.x - b.x, dy = a.y - b.y;
                    const dist = Math.sqrt(dx*dx + dy*dy);
                    if (dist < 120) {
                        ctx.beginPath();
                        ctx.strokeStyle = `rgba(0, 243, 255, ${0.08 * (1 - dist / 120)})`;
                        ctx.lineWidth = 0.5;
                        ctx.moveTo(a.x, a.y);
                        ctx.lineTo(b.x, b.y);
                        ctx.stroke();
                    }
                }

                ctx.beginPath();
                ctx.arc(a.x, a.y, a.r, 0, Math.PI * 2);
                ctx.fillStyle = `rgba(0, 243, 255, ${a.a})`;
                ctx.fill();
            }

            _callParticleRaf = requestAnimationFrame(draw);
        }
        _callParticleRaf = requestAnimationFrame(draw);
        _callParticleCleanup = () => {
            if (_callParticleRaf) { cancelAnimationFrame(_callParticleRaf); _callParticleRaf = null; }
        };
        return _callParticleCleanup;
    }

    // ── Call UI helpers ────────────────────────────────────
    function callSetStatus(text) {
        const el = document.getElementById('cst');
        if (el) el.textContent = text;
    }
    function callUpdateMicDot(isActive) {
        const ind = document.getElementById('call-mic-ind');
        if (!ind) return;
        const dot = ind.querySelector('.mic-dot');
        if (dot) dot.className = 'mic-dot' + (isActive ? ' active' : '');
    }

    // ── Transcript log ─────────────────────────────────────
    function callAppendTranscript(role, text, isInterim) {
        const inner = document.getElementById('call-tr-inner');
        if (!inner) return;
        if (isInterim) {
            let interim = inner.querySelector('.call-tr-interim');
            if (!interim) {
                interim = document.createElement('div');
                interim.className = 'call-tr-entry call-tr-interim';
                inner.appendChild(interim);
            }
            interim.innerHTML = '<span class="call-tr-role">You:</span> <span class="call-tr-body">' + escapeHtml(text) + '</span>';
            return;
        }
        // Remove interim entry if it exists
        const interim = inner.querySelector('.call-tr-interim');
        if (interim) interim.remove();
        const entry = document.createElement('div');
        entry.className = 'call-tr-entry call-tr-' + role;
        const label = role === 'user' ? 'You' : 'AETHER';
        entry.innerHTML = '<span class="call-tr-role">' + label + ':</span> <span class="call-tr-body">' + escapeHtml(text) + '</span>';
        inner.appendChild(entry);
        // Auto-scroll
        const log = document.getElementById('call-tr-log');
        if (log) log.scrollTop = log.scrollHeight;
    }

    // ── MAIN: startAETHERCall ──────────────────────────────
    async function startAETHERCall(msg = null, reason = 'user-initiated') {
        if (callActive) { endAETHERCall(); return true; }

        callActive = true;
        callHistory = [];
        callMuted = false;
        callWhiteboardOpen = false;
        callPttMode = false;
        callDurSecs = 0;
        callMicBlocked = false;

        // Init audio pipeline
        const audioOk = await callInitAudio();
        if (!audioOk) { callActive = false; return false; }

        // ── Build UI ───────────────────────────────────────
        const ov = document.createElement('div');
        ov.id = 'call-overlay'; ov.className = 'call-overlay';

        // Particle canvas (behind everything)
        const particleCanvas = document.createElement('canvas');
        particleCanvas.className = 'call-particle-canvas';
        ov.appendChild(particleCanvas);

        const callUI = document.createElement('div'); callUI.className = 'call-ui';
        const leftPanel = document.createElement('div'); leftPanel.className = 'call-left';

        // Rings + Avatar
        const ringsEl = document.createElement('div'); ringsEl.className = 'call-rings';
        ['r1','r2','r3'].forEach(r => {
            const d = document.createElement('div'); d.className = 'cr ' + r;
            ringsEl.appendChild(d);
        });
        const av = document.createElement('div'); av.className = 'call-avatar';
        av.innerHTML = '<svg width="48" height="48" viewBox="0 0 36 36" fill="none"><path d="M18 3L31 10 31 26 18 33 5 26 5 10Z" stroke="#00f3ff" stroke-width="1.5"/><path d="M18 9L25 13 25 21 18 25 11 21 11 13Z" stroke="#00f3ff" stroke-width="1" opacity=".5"/><circle cx="18" cy="17" r="3.5" fill="#00f3ff"/></svg>';
        ringsEl.appendChild(av);

        const nameEl = document.createElement('div'); nameEl.className = 'call-name'; nameEl.textContent = 'AETHER';
        const subEl  = document.createElement('div'); subEl.className = 'call-subtitle'; subEl.textContent = 'Neural Interface';
        const cst    = document.createElement('div'); cst.id = 'cst'; cst.className = 'call-status'; cst.textContent = 'Connecting…';

        // FFT Visualizer canvas
        const visCanvas = document.createElement('canvas');
        visCanvas.className = 'call-vis-canvas';
        visCanvas.id = 'call-vis-canvas';

        // Transcript log (scrolling, persistent)
        const trLog = document.createElement('div'); trLog.className = 'call-tr-log'; trLog.id = 'call-tr-log';
        const trLogInner = document.createElement('div'); trLogInner.className = 'call-tr-inner'; trLogInner.id = 'call-tr-inner';
        trLog.appendChild(trLogInner);

        // Mic indicator + Duration row
        const infoRow = document.createElement('div'); infoRow.className = 'call-info-row';
        const micInd = document.createElement('div');
        micInd.className = 'call-mic-indicator'; micInd.id = 'call-mic-ind';
        micInd.innerHTML = '<span class="mic-dot"></span><span class="mic-label">Mic ready</span>';
        const durEl = document.createElement('div'); durEl.className = 'call-duration'; durEl.textContent = '00:00';
        callDurTimer = setInterval(() => {
            if (!callActive) return;
            callDurSecs++;
            durEl.textContent = String(Math.floor(callDurSecs/60)).padStart(2,'0') + ':' + String(callDurSecs%60).padStart(2,'0');
        }, 1000);
        infoRow.appendChild(micInd); infoRow.appendChild(durEl);

        leftPanel.appendChild(ringsEl); leftPanel.appendChild(nameEl);
        leftPanel.appendChild(subEl);   leftPanel.appendChild(cst);
        leftPanel.appendChild(visCanvas); leftPanel.appendChild(trLog);
        leftPanel.appendChild(infoRow);

        // ── Controls ───────────────────────────────────────
        const ctrls = document.createElement('div'); ctrls.className = 'call-ctrls';
        const mkBtn = (id, cls, title, svg) => {
            const b = document.createElement('button');
            b.className = 'cbtn ' + cls; b.id = id; b.title = title;
            b.innerHTML = svg; return b;
        };

        // PTT/OpenMic toggle
        const pttBtn = mkBtn('cptt','cptt','Toggle push-to-talk',
            '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><rect x="4" y="4" width="16" height="16" rx="2"/><line x1="12" y1="8" x2="12" y2="16"/><line x1="8" y1="12" x2="16" y2="12"/></svg>');
        const muteBtn = mkBtn('cmute','cmute','Mute microphone',
            '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><path d="M12 1a3 3 0 0 1 3 3v8a3 3 0 0 1-6 0V4a3 3 0 0 1 3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>');
        const wbBtn = mkBtn('cwb','cwb','Whiteboard',
            '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><rect x="3" y="3" width="18" height="14" rx="2"/><path d="M8 21h8M12 17v4"/></svg>');
        const noteBtn = mkBtn('cnote','cnote','Save transcript',
            '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg>');
        const endBtn = mkBtn('cend','cend','End call',
            '<svg width="22" height="22" viewBox="0 0 24 24" fill="currentColor"><path d="M6.6 10.8c1.4 2.8 3.8 5.1 6.6 6.6l2.2-2.2c.3-.3.7-.4 1-.2 1.1.4 2.3.6 3.6.6.6 0 1 .4 1 1V20c0 .6-.4 1-1 1-9.4 0-17-7.6-17-17 0-.6.4-1 1-1h3.5c.6 0 1 .4 1 1 0 1.3.2 2.5.6 3.6.1.3 0 .7-.2 1L6.6 10.8z"/></svg>');
        const chatBtn = mkBtn('cchat','cchat','Switch to chat',
            '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>');

        pttBtn.onclick = () => {
            callPttMode = !callPttMode;
            pttBtn.classList.toggle('active', callPttMode);
            if (callPttMode) {
                callSetStatus('Push-to-talk (hold Space)');
                try { callRecog?.stop(); } catch(e) {}
            } else {
                callSetStatus('Open mic');
                if (!callMuted && callRecog) try { callRecog.start(); } catch(e) {}
            }
        };
        muteBtn.onclick = () => window.callToggleMute();
        wbBtn.onclick = () => { toggleCallWhiteboard(); wbBtn.classList.toggle('active'); };
        noteBtn.onclick = () => saveCallTranscriptToChat();
        endBtn.onclick = () => endAETHERCall();
        chatBtn.onclick = () => { endAETHERCall(); document.getElementById('user-input')?.focus(); };

        [pttBtn, muteBtn, wbBtn, noteBtn, endBtn, chatBtn].forEach(b => ctrls.appendChild(b));
        leftPanel.appendChild(ctrls);

        // ── Whiteboard right panel ─────────────────────────
        const rightPanel = document.createElement('div');
        rightPanel.className = 'call-right'; rightPanel.id = 'call-right';
        rightPanel.style.display = 'none';

        const wbHeader = document.createElement('div');
        wbHeader.className = 'call-wb-header';
        wbHeader.innerHTML = '<span>⧆ Whiteboard</span>';

        const wbToolbar = document.createElement('div');
        wbToolbar.className = 'call-wb-toolbar';
        ['Flowchart','Sequence','UML Class','Mindmap','Custom'].forEach(t => {
            const b = document.createElement('button');
            b.className = 'wb-tool-btn'; b.textContent = t;
            b.onclick = () => promptWhiteboardDiagram(t);
            wbToolbar.appendChild(b);
        });

        const wbCanvas = document.createElement('div');
        wbCanvas.id = 'wb-canvas'; wbCanvas.className = 'call-wb-canvas';
        wbCanvas.innerHTML = '<div class="wb-placeholder">⧆ Say "draw a flowchart" or pick a template</div>';

        const wbInputRow = document.createElement('div');
        wbInputRow.className = 'call-wb-input';
        const wbInputEl = document.createElement('input');
        wbInputEl.type = 'text'; wbInputEl.className = 'wb-text-input';
        wbInputEl.placeholder = 'Describe a diagram…';
        const wbSendBtn = document.createElement('button');
        wbSendBtn.className = 'wb-send-btn'; wbSendBtn.textContent = 'Draw';
        wbSendBtn.onclick = () => { if (wbInputEl.value.trim()) generateWhiteboardDiagram(wbInputEl.value.trim()); };
        wbInputEl.onkeydown = e => {
            if (e.key === 'Enter' && wbInputEl.value.trim()) generateWhiteboardDiagram(wbInputEl.value.trim());
        };
        wbInputRow.appendChild(wbInputEl); wbInputRow.appendChild(wbSendBtn);
        rightPanel.appendChild(wbHeader); rightPanel.appendChild(wbToolbar);
        rightPanel.appendChild(wbCanvas); rightPanel.appendChild(wbInputRow);

        callUI.appendChild(leftPanel); callUI.appendChild(rightPanel);
        ov.appendChild(callUI);
        document.body.appendChild(ov);

        // ── Init particles ─────────────────────────────────
        setTimeout(() => {
            callInitParticles(particleCanvas);
            callStartParticles(particleCanvas);
        }, 50);

        // ── Start visualizer ───────────────────────────────
        setTimeout(() => callStartVisualizer(visCanvas), 100);

        // ── STT setup ──────────────────────────────────────
        const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
        if (SR) {
            callRecog = new SR();
            callRecog.continuous = false;
            callRecog.interimResults = true;
            callRecog.lang = navigator.language || 'en-US';
            callRecog.maxAlternatives = 1;

            callRecog.onstart = () => {
                callSetStatus('Listening…');
                const ind = document.getElementById('call-mic-ind');
                if (ind) ind.className = 'call-mic-indicator listening';
            };
            callRecog.onend = () => {
                // Clear interim entry
                const interim = document.querySelector('#call-tr-inner .call-tr-interim');
                if (interim) interim.remove();
                if (callMicBlocked) return;
                if (callPttMode && !callPttHeld) return;
                if (callActive && !callMuted && !callSpeaking) {
                    setTimeout(() => {
                        if (callActive && !callMuted && !callSpeaking && !callPttHeld && !callMicBlocked) {
                            try { callRecog?.start(); } catch(e) { console.warn('[AETHER Call] recog restart:', e); }
                        }
                    }, 150);
                }
            };
            callRecog.onresult = e => {
                const t = [...e.results].map(r => r[0].transcript).join('');
                if (e.results[e.results.length - 1].isFinal) {
                    const finalText = t.trim();
                    if (finalText) {
                        callAppendTranscript('user', finalText);
                        handleCallSpeech(finalText);
                    }
                } else {
                    if (t.trim()) callAppendTranscript('user', t.trim(), true);
                }
            };
            callRecog.onerror = e => {
                if (e.error === 'not-allowed') {
                    callMicBlocked = true;
                    callSetStatus('Mic blocked');
                    reportFeatureError('Call STT', new Error(e.error));
                    showNotification('Microphone access denied. Please allow mic permissions in browser settings, then click the call button again.', 'error');
                } else if (e.error === 'no-speech') {
                    // VAD handles re-triggering
                } else if (e.error !== 'aborted') {
                    console.warn('[AETHER Call] STT:', e.error);
                }
            };
        } else {
            callSetStatus('Text-only (Speech API N/A)');
        }

        // ── VAD (only in open mic mode) ────────────────────
        callStartVAD();

        // ── PTT keyboard handler ───────────────────────────
        window._callPttHandler = (e) => {
            if (!callActive || !callPttMode) return;
            if (e.code === 'Space' && e.target.tagName !== 'INPUT' && e.target.tagName !== 'TEXTAREA') {
                if (e.type === 'keydown' && !callPttHeld) {
                    e.preventDefault();
                    callPttHeld = true;
                    callSetStatus('Recording…');
                    if (callRecog && !callMuted) {
                        try { callRecog.start(); } catch(err) {}
                    }
                } else if (e.type === 'keyup' && callPttHeld) {
                    callPttHeld = false;
                    callSetStatus('PTT idle');
                    try { callRecog?.stop(); } catch(err) {}
                }
            }
        };
        window.addEventListener('keydown', window._callPttHandler);
        window.addEventListener('keyup', window._callPttHandler);

        // ── Greeting ───────────────────────────────────────
        const tod = new Date().getHours();
        const greet = tod < 12 ? 'Good morning' : tod < 17 ? 'Good afternoon' : 'Good evening';
        let greeting = greet + '. This is AETHER. How can I help you today?';
        if (state.workspaceEnabled) {
            try {
                const ws = await readFile('WORKSPACE.md');
                if (ws) {
                    const r = await callAISimple([
                        { role: 'system', content: 'You are AETHER in a voice call. 1 sentence greeting, mention workspace context. Start with "' + greet + '." No markdown.' },
                        { role: 'user', content: ws.slice(0, 300) }
                    ], apiConfig.model);
                    if (r && r.length < 200) greeting = r;
                }
            } catch(e) { console.warn('[AETHER Call] greeting workspace:', e.message); }
        }
        callHistory.push({ role: 'assistant', content: greeting });
        callAppendTranscript('assistant', greeting);
        callSetStatus('AETHER speaking…');
        callSpeaking = true;
        callSpeak(greeting, () => {
            callSpeaking = false;
            callSetStatus('Listening…');
            if (callRecog && callActive && !callMuted) {
                setTimeout(() => { try { callRecog.start(); } catch(e) { console.warn('[AETHER Call] recog start:', e); } }, 200);
            }
        });
        return true;
    }

    // ── Whiteboard toggle ──────────────────────────────────
    function toggleCallWhiteboard() {
        callWhiteboardOpen = !callWhiteboardOpen;
        const rp = document.getElementById('call-right');
        const wbBtn = document.getElementById('cwb');
        if (rp) rp.style.display = callWhiteboardOpen ? 'flex' : 'none';
        if (wbBtn) wbBtn.classList.toggle('active', callWhiteboardOpen);
        const ov = document.getElementById('call-overlay');
        if (ov) ov.classList.toggle('call-overlay-wide', callWhiteboardOpen);
    }

    // ── Whiteboard diagram generation ──────────────────────
    async function promptWhiteboardDiagram(type) {
        const templates = {
            'Flowchart':  'Create a simple flowchart diagram in Mermaid showing a typical software development workflow.',
            'Sequence':   'Create a sequence diagram in Mermaid showing API request/response between client, server, and database.',
            'UML Class':  'Create a class diagram in Mermaid showing basic OOP relationships.',
            'Mindmap':    'Create a mindmap in Mermaid for software architecture topics.',
            'Custom':     'Draw a diagram',
        };
        generateWhiteboardDiagram(templates[type] || 'Draw a diagram');
    }

    async function generateWhiteboardDiagram(prompt) {
        const wbContainer = document.getElementById('wb-canvas');
        if (!wbContainer) return;
        wbContainer.innerHTML = '<div class="wb-loading"><div class="dr-spinner"></div><span>Drawing\u2026</span></div>';
        try {
            const mermaidPrompt = 'Generate a valid Mermaid diagram for: "' + prompt + '"\n\nRules:\n- Output ONLY valid Mermaid syntax\n- Start with the diagram type\n- Max 15 nodes\n- No markdown fences\n- Use short labels';
            const code = await callAISimple([
                { role: 'system', content: 'You are a Mermaid expert. Output ONLY valid Mermaid syntax.' },
                { role: 'user', content: mermaidPrompt }
            ], apiConfig.model);

            const clean = code.replace(/```mermaid\n?/g, '').replace(/```\n?/g, '').trim();
            wbContainer.innerHTML = '';

            const mEl = document.createElement('div'); mEl.className = 'mermaid wb-diagram';
            mEl.textContent = clean;
            wbContainer.appendChild(mEl);

            const src = document.createElement('details'); src.className = 'wb-src';
            const sum = document.createElement('summary'); sum.textContent = 'Source';
            const pre = document.createElement('pre'); pre.textContent = clean;
            src.appendChild(sum); src.appendChild(pre);
            wbContainer.appendChild(src);

            const dlBtn = document.createElement('button'); dlBtn.className = 'wb-dl-btn';
            dlBtn.textContent = '\u2193 Export SVG';
            dlBtn.onclick = () => {
                const svgEl = wbContainer.querySelector('svg');
                if (!svgEl) return;
                const blob = new Blob([svgEl.outerHTML], { type: 'image/svg+xml' });
                downloadBlob(blob, 'diagram-' + Date.now() + '.svg');
            };
            wbContainer.appendChild(dlBtn);

            try { await mermaid.run({ nodes: [mEl] }); } catch(e) {
                mEl.textContent = 'Error: ' + e.message + '\n\n' + clean;
            }
            callHistory.push({ role: 'assistant', content: '[Whiteboard: ' + (clean.split('\n')[0] || 'diagram') + ']' });
        } catch(e) {
            wbContainer.innerHTML = '<div class="wb-placeholder"><p style="color:#ff6464">Failed: ' + e.message + '</p></div>';
            reportFeatureError('Whiteboard', e, { prompt });
        }
    }

    // ── Speech handling ────────────────────────────────────
    async function handleCallSpeech(text) {
        if (!callActive || !text.trim()) return;
        callSetStatus('Thinking…');
        document.getElementById('ctr-text') && (document.getElementById('ctr-text').textContent = '');
        callHistory.push({ role: 'user', content: text });

        if (/\b(hang up|end call|goodbye|bye|disconnect)\b/i.test(text)) {
            callAppendTranscript('assistant', 'Goodbye! Talk to you soon.');
            callSpeak('Goodbye! Talk to you soon.', endAETHERCall);
            return;
        }

        if (/\b(draw|diagram|chart|flowchart|whiteboard|visualize|show me|sketch)\b/i.test(text)) {
            if (!callWhiteboardOpen) toggleCallWhiteboard();
            callAppendTranscript('assistant', 'Drawing that for you now.');
            callSpeak('Drawing that for you now.', null);
            generateWhiteboardDiagram(text);
            callSetStatus('Drawing…');
            setTimeout(() => {
                callSetStatus('Listening…');
                if (callRecog && callActive) try { callRecog.start(); } catch(e) {}
            }, 2000);
            return;
        }

        try {
            const sysPrompt = 'You are AETHER in a live voice call. Rules:\n'
                + '- Max 2 short sentences. Conversational tone.\n'
                + '- No markdown, no lists, no bullets.\n'
                + '- Be helpful, direct, and warm.\n'
                + '- If they ask to draw something, confirm you will.\n'
                + (state.workspaceEnabled ? '- You have access to the user workspace.\n' : '');
            const msgs = [{ role: 'system', content: sysPrompt }];
            if (callHistory && callHistory.length > 0) msgs.push(...callHistory.slice(-8));
            const resp = await callAISimple(msgs, apiConfig.model);
            if (!resp || !resp.trim()) throw new Error('Empty AI response');
            callHistory.push({ role: 'assistant', content: resp });
            callAppendTranscript('assistant', resp);
            callSetStatus('AETHER speaking…');
            callSpeaking = true;
            callSpeak(resp, () => {
                callSpeaking = false;
                callSetStatus('Listening…');
                if (callRecog && callActive && !callMuted) {
                    setTimeout(() => { try { callRecog.start(); } catch(e) { console.warn('[AETHER Call] recog start:', e); } }, 150);
                }
            });
        } catch(e) {
            reportFeatureError('Voice Call (AI)', e);
            callSpeak('Sorry, connection issue. Could you repeat that?', () => {
                if (callRecog && callActive) try { callRecog.start(); } catch(err) {}
            });
        }
    }

    // ── TTS with interruption support ──────────────────────
    function callSpeak(text, onEnd) {
        if (typeof speechSynthesis === 'undefined') { if (onEnd) onEnd(); return; }
        const clean = text
            .replace(/```[\s\S]*?```/g, 'code block')
            .replace(/`[^`]+`/g, '').replace(/\*\*([^*]+)\*\*/g, '$1')
            .replace(/\*([^*]+)\*/g, '$1').replace(/https?:\/\/\S+/g, 'a link')
            .replace(/[#>_~]/g, '').trim();
        if (!clean) { if (onEnd) onEnd(); return; }
        if (!callActive) { if (onEnd) onEnd(); return; }

        callSpeaking = true;
        try { speechSynthesis.cancel(); } catch(e) { console.warn('[AETHER Call] synth cancel:', e.message); }

        // ── VAD-based interruption: if user speaks during TTS, abort ──
        let interrupted = false;
        let interCheck = null;
        const safeEnd = () => {
            if (interCheck) { clearInterval(interCheck); interCheck = null; }
            callSpeaking = false;
            if (onEnd) try { onEnd(); } catch(e) { console.warn('[AETHER Call] onEnd:', e.message); }
        };

        interCheck = setInterval(() => {
            if (!callActive || !callAnalyser || !callSpeaking) { if (interCheck) clearInterval(interCheck); interCheck = null; return; }
            if (callVadSpeaking && !callMuted) {
                interrupted = true;
                if (interCheck) clearInterval(interCheck); interCheck = null;
                try { speechSynthesis.cancel(); } catch(e) { console.warn('[AETHER Call] synth cancel:', e.message); }
                callSpeaking = false;
                callSetStatus('You interrupted');
                setTimeout(() => callSetStatus('Listening…'), 400);
                if (onEnd) try { onEnd(); } catch(e) { console.warn('[AETHER Call] onEnd:', e.message); }
            }
        }, 120);

        const speak = () => {
            if (!callActive) { safeEnd(); return; }
            const utt = new SpeechSynthesisUtterance(clean);
            utt.rate = 0.9; utt.pitch = 1.0; utt.volume = 1.0;
            const savedVoice = localStorage.getItem('aether_call_voice') || '';
            const voices = speechSynthesis.getVoices();
            let pref = voices.find(v => v.voiceURI === savedVoice);
            if (!pref) {
                pref = voices.find(v => /Samantha|Google US English|Microsoft Aria|en-US-Neural|Zira|Karen/i.test(v.name))
                    || voices.find(v => v.lang?.startsWith('en') && v.localService)
                    || voices.find(v => v.lang?.startsWith('en'))
                    || voices[0];
            }
            if (pref) utt.voice = pref;
            utt.onend = () => {
                if (interCheck) { clearInterval(interCheck); interCheck = null; }
                if (!interrupted && callActive) {
                    callSpeaking = false;
                    if (onEnd) try { onEnd(); } catch(e) { console.warn('[AETHER Call] onEnd:', e.message); }
                }
            };
            utt.onerror = (e) => {
                if (interCheck) { clearInterval(interCheck); interCheck = null; }
                if (e.error !== 'interrupted' && e.error !== 'canceled') console.warn('[AETHER Call] TTS:', e.error);
                if (!interrupted && callActive) {
                    callSpeaking = false;
                    if (onEnd) try { onEnd(); } catch(e) { console.warn('[AETHER Call] onEnd:', e.message); }
                }
            };
            try { speechSynthesis.speak(utt); } catch(e) { console.warn('[AETHER Call] speak:', e.message); safeEnd(); }
        };

        if (speechSynthesis.getVoices().length > 0) {
            setTimeout(speak, 60);
        } else {
            const onVC = () => {
                speechSynthesis.removeEventListener('voiceschanged', onVC);
                setTimeout(speak, 60);
            };
            speechSynthesis.addEventListener('voiceschanged', onVC);
            setTimeout(() => { if (callSpeaking) speak(); }, 1200);
        }
    }

    // ── Save transcript ────────────────────────────────────
    function saveCallTranscriptToChat() {
        if (callHistory.length < 2) { showNotification('No transcript yet', 'warn'); return; }
        const transcript = callHistory.map(m => '**' + (m.role === 'user' ? 'You' : 'AETHER') + ':** ' + m.content).join('\n\n');
        const conv = getCurrentConversation();
        if (conv) {
            conv.messages.push({ role: 'assistant', content: '**\ud83d\udcde Call Transcript**\n\n' + transcript });
            saveConversations(); renderConversationList();
            showNotification('Transcript saved to conversation', 'success');
        }
    }

    // ── Mute toggle ────────────────────────────────────────
    window.callToggleMute = () => {
        callMuted = !callMuted;
        const btn = document.getElementById('cmute');
        if (callMuted) {
            try { callRecog?.stop(); } catch(e) {}
            if (btn) btn.classList.add('muted');
            callSetStatus('Muted \ud83d\udd07');
        } else {
            if (btn) btn.classList.remove('muted');
            callSetStatus('Listening…');
            if (callRecog && callActive && !callSpeaking) {
                setTimeout(() => { try { callRecog.start(); } catch(e) {} }, 100);
            }
        }
    };

    // ── End call ───────────────────────────────────────────
    function endAETHERCall() {
        callActive = false;
        callSpeaking = false;
        callStopVisualizer();
        callStopVAD();
        if (_callParticleCleanup) { _callParticleCleanup(); _callParticleCleanup = null; }
        if (typeof speechSynthesis !== 'undefined') speechSynthesis.cancel();
        if (callRecog) { try { callRecog.abort(); } catch(e) { console.warn('[AETHER Call] recog abort:', e); } callRecog = null; }
        if (callDurTimer) { clearInterval(callDurTimer); callDurTimer = null; }
        if (window._callPttHandler) {
            window.removeEventListener('keydown', window._callPttHandler);
            window.removeEventListener('keyup', window._callPttHandler);
            window._callPttHandler = null;
        }
        callCleanupAudio();
        document.getElementById('call-overlay')?.remove();

        if (callHistory && callHistory.length > 2) {
            const transcript = callHistory.map(m => '**' + (m.role === 'user' ? 'You' : 'AETHER') + ':** ' + m.content).join('\n\n');
            const conv = getCurrentConversation();
            if (conv) {
                conv.messages.push({ role: 'assistant', content: '**\ud83d\udcde Call Transcript**\n\n' + transcript });
                saveConversations(); renderConversationList();
            }
        }
        callHistory = [];
        callPttMode = false;
        callPttHeld = false;
        callVadSpeaking = false;
        callMicBlocked = false;
        callWhiteboardOpen = false;
        if (_callPermissionWatcher) {
            try {
                const q = navigator.permissions?.query?.({ name: 'microphone' });
                if (q && q.then) q.then(s => { if (s) s.onchange = null; }).catch(()=>{});
            } catch(e) {}
            _callPermissionWatcher = null;
        }
        showNotification('Call ended', 'info');
    }

    // ─── CALL PANEL (pre-call contact card) ────────────────────
    let _callPanelOverlay = null;

    window.showCallPanel = function() {
        if (callActive) { endAETHERCall(); return; }
        if (_callPanelOverlay) return;
        const ov = document.createElement('div');
        ov.className = 'call-panel-overlay';
        ov.id = 'call-panel-overlay';

        // Build call history list from conversations
        const callHistEntries = [];
        try {
            const convs = state.conversations || {};
            for (const id of Object.keys(convs)) {
                const m = convs[id]?.messages || [];
                for (let i = 0; i < m.length; i++) {
                    if (m[i].content && m[i].content.startsWith('**📞 Call Transcript**')) {
                        const title = convs[id].title || 'Conversation';
                        callHistEntries.push({ title, date: convs[id].updated || m[i].timestamp, preview: m[i].content.slice(0, 80).replace(/\*\*/g, '').replace(/\n/g, ' ') });
                        break;
                    }
                }
            }
        } catch(e) {}
        const histHtml = callHistEntries.length > 0
            ? callHistEntries.slice(-5).reverse().map(e =>
                `<div class="cp-hist-item" title="${e.preview.replace(/"/g,'&quot;')}">
                    <span class="cp-hist-title">${e.title}</span>
                    <span class="cp-hist-date">${e.date ? new Date(e.date).toLocaleDateString() : ''}</span>
                </div>`
            ).join('')
            : '<div class="cp-hist-empty">No past calls yet</div>';

        // Read saved VAD threshold
        const savedVad = parseFloat(localStorage.getItem('aether_vad_threshold')) || 18;

        ov.innerHTML = `
            <div class="call-panel-card">
                <button class="call-panel-close" id="call-panel-close" title="Close">&times;</button>
                <div class="call-panel-rings">
                    <div class="cp-ring r1"></div>
                    <div class="cp-ring r2"></div>
                    <div class="cp-ring r3"></div>
                    <div class="call-panel-avatar">
                        <svg width="56" height="56" viewBox="0 0 36 36" fill="none">
                            <path d="M18 3L31 10 31 26 18 33 5 26 5 10Z" stroke="#00f3ff" stroke-width="1.5"/>
                            <path d="M18 9L25 13 25 21 18 25 11 21 11 13Z" stroke="#00f3ff" stroke-width="1" opacity=".5"/>
                            <circle cx="18" cy="17" r="3.5" fill="#00f3ff"/>
                        </svg>
                    </div>
                </div>
                <div class="call-panel-name">AETHER</div>
                <div class="call-panel-sub">Neural Interface</div>
                <div class="call-panel-status"><span class="cp-status-dot"></span> Ready to call</div>

                <div class="cp-section">
                    <label class="cp-label">Voice</label>
                    <select class="cp-voice-select" id="cp-voice-select">
                        <option value="">Auto-select</option>
                    </select>
                </div>

                <div class="cp-section">
                    <label class="cp-label">Mic sensitivity <span class="cp-vad-val" id="cp-vad-val">${savedVad}</span></label>
                    <input type="range" class="cp-vad-slider" id="cp-vad-slider" min="5" max="50" value="${savedVad}">
                </div>

                <div class="cp-section cp-hist-section">
                    <label class="cp-label">Recent calls</label>
                    <div class="cp-hist-list">${histHtml}</div>
                </div>

                <button class="call-panel-start" id="call-panel-start">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor"><path d="M6.6 10.8c1.4 2.8 3.8 5.1 6.6 6.6l2.2-2.2c.3-.3.7-.4 1-.2 1.1.4 2.3.6 3.6.6.6 0 1 .4 1 1V20c0 .6-.4 1-1 1-9.4 0-17-7.6-17-17 0-.6.4-1 1-1h3.5c.6 0 1 .4 1 1 0 1.3.2 2.5.6 3.6.1.3 0 .7-.2 1L6.6 10.8z"/></svg>
                    Start Call
                </button>
            </div>
        `;
        document.body.appendChild(ov);
        _callPanelOverlay = ov;

        // Populate voices
        (function populateVoices() {
            const sel = ov.querySelector('#cp-voice-select');
            if (!sel) return;
            const savedVoice = localStorage.getItem('aether_call_voice') || '';
            const vs = speechSynthesis.getVoices();
            if (vs.length > 0) {
                vs.forEach(v => {
                    const opt = document.createElement('option');
                    opt.value = v.voiceURI;
                    opt.textContent = v.name + ' (' + v.lang + ')';
                    if (v.voiceURI === savedVoice) opt.selected = true;
                    sel.appendChild(opt);
                });
            } else {
                speechSynthesis.addEventListener('voiceschanged', function onVC() {
                    speechSynthesis.removeEventListener('voiceschanged', onVC);
                    populateVoices();
                }, { once: true });
            }
            sel.onchange = () => {
                localStorage.setItem('aether_call_voice', sel.value);
            };
        })();

        // VAD slider
        const vadSlider = ov.querySelector('#cp-vad-slider');
        const vadVal = ov.querySelector('#cp-vad-val');
        if (vadSlider && vadVal) {
            vadSlider.oninput = () => {
                const v = parseInt(vadSlider.value);
                vadVal.textContent = v;
                localStorage.setItem('aether_vad_threshold', String(v));
            };
        }

        ov.querySelector('#call-panel-close').onclick = closeCallPanel;
        ov.querySelector('#call-panel-start').onclick = async () => {
            closeCallPanel();
            const ok = await startAETHERCall(null, 'user-initiated');
            if (!ok) setTimeout(() => showCallPanel(), 400);
        };
        ov.addEventListener('click', e => { if (e.target === ov) closeCallPanel(); });
        requestAnimationFrame(() => ov.classList.add('visible'));
    };

    window.closeCallPanel = function() {
        const ov = _callPanelOverlay;
        if (!ov) return;
        _callPanelOverlay = null;
        ov.classList.remove('visible');
        setTimeout(() => ov.remove(), 300);
    };

    // Also close panel when call ends (e.g. if panel somehow reopens during call)
    const _origEndCall = endAETHERCall;
    endAETHERCall = function() {
        closeCallPanel();
        return _origEndCall.apply(this, arguments);
    };

    const _callBtn = document.getElementById('btn-call-mode');
    if (_callBtn) _callBtn.onclick = () => showCallPanel();
    callStartPermissionWatch();

    // ─── LOCATION AWARENESS ───────────────────────────────────
    let userLoc = null;
    (function(){ try{ const c=localStorage.getItem('aether_loc'); if(c){const d=JSON.parse(c); if(Date.now()-d.ts<3600000) userLoc=d;} }catch{} })();
    async function requestLocation(force=false) {
        if (!navigator.geolocation) { showNotification('Geolocation not supported','warn'); return null; }
        if (userLoc && !force) return userLoc;
        return new Promise(resolve => {
            showNotification('Requesting location…','info');
            navigator.geolocation.getCurrentPosition(async pos => {
                const {latitude:lat, longitude:lon} = pos.coords;
                let city='', country='';
                try { const r=await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lon}&format=json`,{headers:{'User-Agent':'AETHER'}}); const d=await r.json(); city=d.address?.city||d.address?.town||''; country=d.address?.country||''; } catch {}
                userLoc = {lat,lon,city,country,tz:Intl.DateTimeFormat().resolvedOptions().timeZone,ts:Date.now()};
                localStorage.setItem('aether_loc',JSON.stringify(userLoc));
                const locBtn = document.getElementById('btn-location');
                if (locBtn) locBtn.style.color = 'var(--neon-green)';
                showNotification(`✓ Location: ${city||lat.toFixed(2)}${city?', '+country:''}`, 'success');
                resolve(userLoc);
            }, err => { showNotification('Location: '+err.message,'warn'); resolve(null); }, {timeout:8000});
        });
    }
    function getLocCtx() {
        if (!userLoc) return '';
        const {city,country,tz} = userLoc;
        return [city&&`City: ${city}`, country&&`Country: ${country}`, tz&&`TZ: ${tz}`].filter(Boolean).join(' | ');
    }
    const _locBtn = document.getElementById('btn-location');
    if (_locBtn) { _locBtn.addEventListener('click', ()=>requestLocation(true)); if (userLoc) _locBtn.style.color = 'var(--neon-green)'; }

    // ─── EMAIL TOOL ───────────────────────────────────────────
    async function handleEmailTool(arg) {
        const parts = String(arg).split('|').reduce((a,p)=>{const [k,...v]=p.split(':');if(k)a[k.trim().toLowerCase()]=v.join(':').trim();return a;},{});
        const {to, subject='Message from AETHER', body=''} = parts;
        if (!to) throw new Error('Email requires to: field');
        if (browserAgentConfig?.enabled) return await runBrowserAgent(`Compose email. To: ${to}. Subject: ${subject}. Body: ${body}. Send it.`, 'browser-use') || 'Email sent via browser';
        const mailto = `mailto:${encodeURIComponent(to)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
        window.open(mailto,'_blank');
        return `Email draft opened to ${to}`;
    }

    // ─── SCHEDULED BACKGROUND TASKS ──────────────────────────
    const SCHED_KEY = 'aether_scheduled';
    function getScheduled() { try{return JSON.parse(localStorage.getItem(SCHED_KEY)||'[]');}catch{return[];} }
    function saveScheduled(t) { localStorage.setItem(SCHED_KEY, JSON.stringify(t)); }
    function addScheduledTask({label, prompt, time='08:00', freq='daily'}) {
        const tasks = getScheduled();
        tasks.push({id:'sc_'+Date.now(), label, prompt, time, freq, lastRun:null});
        saveScheduled(tasks);
        showNotification(`⏰ Scheduled: "${label}" at ${time}`, 'success');
    }
    function removeScheduledTask(id) { saveScheduled(getScheduled().filter(t=>t.id!==id)); }
    async function runScheduledCheck() {
        const tasks = getScheduled();
        if (!tasks.length) return;
        const now = new Date();
        const hhmm = now.getHours().toString().padStart(2,'0')+':'+now.getMinutes().toString().padStart(2,'0');
        for (const task of tasks) {
            const ready = task.time === hhmm && (!task.lastRun || Date.now()-task.lastRun > 50*60*1000);
            const dayOk = task.freq==='daily' || (task.freq==='weekday' && now.getDay()>0 && now.getDay()<6) || task.freq==='weekly';
            if (ready && dayOk) {
                task.lastRun = Date.now(); saveScheduled(tasks);
                await addBackgroundTask({type:'scheduled', label:task.label, prompt:task.prompt});
            }
        }
    }
    setInterval(runScheduledCheck, 60000);

    // ─── INJECT LOCATION INTO SYSTEM PROMPT ──────────────────
    // Called from buildSystemPrompt — patches it post-build
    const _origBuildSys = buildSystemPrompt;
    // We patch via the post-build hook below if not already patched



    // ─── GOOGLE CALENDAR ─────────────────────────────────────
    let calToken = null;
    let calClientId = null;

    (function loadCalCfg(){
        try {
            const cfg = JSON.parse(localStorage.getItem('aether_hooks')||'{}');
            calClientId = cfg.googleClientId || null;
            const t = localStorage.getItem('aether_cal_token');
            if (t) calToken = JSON.parse(t);
        } catch {}
    })();

    async function authorizeCalendar() {
        if (!calClientId) {
            showNotification('Add Google Client ID in HOOKS → Google Workspace', 'warn');
            return false;
        }
        return new Promise(resolve => {
            const loadGIS = () => {
                if (!window.google || !window.google.accounts || !window.google.accounts.oauth2) { reportFeatureError('Google Auth Script', new Error('Library not loaded')); resolve(false); return; }
            const client = window.google.accounts.oauth2.initTokenClient({
                    client_id: calClientId,
                    scope: 'https://www.googleapis.com/auth/calendar.readonly https://www.googleapis.com/auth/calendar.events',
                    callback: resp => {
                        if (resp.error) { reportFeatureError('Google Auth', new Error(resp.error)); resolve(false); return; }
                        calToken = { access_token: resp.access_token, expires_at: Date.now() + resp.expires_in * 1000 };
                        localStorage.setItem('aether_cal_token', JSON.stringify(calToken));
                        showNotification('Google Calendar connected', 'success');
                        resolve(true);
                    }
                });
                client.requestAccessToken({ prompt: 'consent' });
            };
            if (window.google && window.google.accounts) { loadGIS(); return; }
            const s = document.createElement('script');
            s.src = 'https://accounts.google.com/gsi/client';
            s.onload = loadGIS;
            s.onerror = () => { reportFeatureError('Google Auth Script', new Error('CDN load failed')); resolve(false); };
            document.head.appendChild(s);
        });
    }

    async function getCalToken() {
        if (calToken && calToken.expires_at > Date.now() + 60000) return calToken.access_token;
        return (await authorizeCalendar()) ? calToken && calToken.access_token : null;
    }

    async function fetchCalendarEvents(maxResults, daysAhead) {
        if (!maxResults) maxResults = 10;
        if (!daysAhead) daysAhead = 7;
        const token = await getCalToken();
        if (!token) return [];
        const now = new Date().toISOString();
        const end = new Date(Date.now() + daysAhead * 86400000).toISOString();
        const url = 'https://www.googleapis.com/calendar/v3/calendars/primary/events\n' + + '?timeMin=' + encodeURIComponent(now)
            + '&timeMax=' + encodeURIComponent(end)
            + '&maxResults=' + maxResults
            + '&orderBy=startTime&singleEvents=true';
        const res = await fetch(url, { headers: { Authorization: 'Bearer ' + token } });
        if (!res.ok) throw new Error('Calendar API: ' + res.status);
        const d = await res.json();
        return d.items || [];
    }

    async function createCalendarEvent(opts) {
        const token = await getCalToken();
        if (!token) return null;
        const body = {
            summary: opts.title || 'AETHER Event',
            description: opts.description || '',
            location: opts.location || '',
            start: { dateTime: opts.start || new Date().toISOString() },
            end:   { dateTime: opts.end   || new Date(Date.now() + 3600000).toISOString() }
        };
        const res = await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + token },
            body: JSON.stringify(body)
        });
        if (!res.ok) throw new Error('Create event: ' + res.status);
        return await res.json();
    }

    async function getDayPlan() {
        const events = await fetchCalendarEvents(20, 1);
        if (!events.length) return 'No events found for today.';
        const lines = events.map(function(ev) {
            const st = (ev.start && ev.start.dateTime)
                ? new Date(ev.start.dateTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})
                : 'All day';
            const en = (ev.end && ev.end.dateTime)
                ? new Date(ev.end.dateTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})
                : '';
            const loc = ev.location ? ' @ ' + ev.location : '';
            return st + (en ? ' – ' + en : '') + ': ' + (ev.summary || 'Event') + loc;
        });
        return '**Today\'s schedule:**\n' + lines.join('\n');
    }

    async function buildCalendarGreeting() {
        try {
            if (!calToken) return null;
            const events = await fetchCalendarEvents(5, 1);
            if (!events.length) return null;
            const next = events[0];
            const startTime = (next.start && next.start.dateTime)
                ? new Date(next.start.dateTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})
                : 'today';
            return 'Your next meeting is "' + (next.summary || 'an event') + '" at ' + startTime
                + '. You have ' + events.length + ' event' + (events.length > 1 ? 's' : '') + ' today.';
        } catch { return null; }
    }

    async function handleCalCreate(arg) {
        const p = String(arg).split('|').reduce(function(a, x) {
            const idx = x.indexOf(':');
            if (idx > 0) a[x.slice(0, idx).trim()] = x.slice(idx + 1).trim();
            return a;
        }, {});
        const ev = await createCalendarEvent({
            title:       p.title || p.name || arg,
            start:       p.start || new Date().toISOString(),
            end:         p.end   || new Date(Date.now() + 3600000).toISOString(),
            description: p.description || '',
            location:    p.location || ''
        });
        return ev ? ('Created: ' + ev.summary) : 'Failed to create event';
    }

    // ─── ENHANCED CALL MODE ──────────────────────────────────
    // Note-taking during call
    let callNotes = '';
    let callStartTime = null;

    window.callAddNote = function(text) {
        if (!text || !text.trim()) return;
        const ts = new Date().toLocaleTimeString();
        callNotes += '[' + ts + '] ' + text.trim() + '\n';
        showNotification('Note saved', 'info');
    };

    // Expose calendar functions globally (used by HTML inline onclick and TOOL_REGISTRY)
    window.authorizeCalendar  = authorizeCalendar;
    window.fetchCalendarEvents= fetchCalendarEvents;
    window.createCalendarEvent= createCalendarEvent;
    window.getDayPlan         = getDayPlan;
    window.buildCalendarGreeting = buildCalendarGreeting;

    // Register periodic sync (if supported)
    if ('serviceWorker' in navigator && window.ServiceWorkerRegistration && 'periodicSync' in window.ServiceWorkerRegistration.prototype) {
        navigator.serviceWorker.ready.then(function(reg) {
            reg.periodicSync.register('aether-morning-check', { minInterval: 60 * 60 * 1000 })
                .catch(function() {}); // May fail without permission
        }).catch(function() {});
    }

    // Listen for SW messages (scheduled tasks)
    if ('serviceWorker' in navigator) {
        navigator.serviceWorker.addEventListener('message', function(event) {
            if (event.data && (event.data.type === 'SCHEDULED_CHECK' || event.data.type === 'PERIODIC_CHECK')) {
                if (typeof runScheduledCheck === 'function') runScheduledCheck();
            }
        });
    }

    // ─── PUTER AI CLOUD — REAL SDK INTEGRATION ───────────────
    // Based on actual Puter SDK: puter.fs, puter.hosting, puter.ai, puter.os
    // SDK loaded via: <script src="https://js.puter.com/v2/"></script>

    let puterReady = false;
    let puterAuthed = false;
    let puterSiteDeployments = {};

    // ── Init + Auth ───────────────────────────────────────────
    async function initPuter() {
        if (puterReady && puterAuthed) return true;
        if (typeof puter === 'undefined') {
            showNotification('Puter SDK not loaded — check internet connection', 'error'); return false;
        }
        try {
            // puter.js auto-authenticates via popup on first call if user isn't signed in.
            // We can check auth state:
            puterReady = true;
            // Verify connectivity by listing root dir
            await puter.fs.readdir('/');
            puterAuthed = true;
            updatePuterStatus(true);
            return true;
        } catch(e) {
            // Auth popup will fire on next puter.* call automatically
            puterReady = true;
            puterAuthed = false;
            return true; // SDK is ready, auth will happen on demand
        }
    }

    function updatePuterStatus(connected) {
        const btn = document.getElementById('puter-connect-btn');
        if (!btn) return;
        if (connected) {
            btn.textContent = '\u29c6 Puter Connected';
            btn.classList.add('puter-connected');
            btn.title = 'Puter AI Cloud active — click to open computer mode';
            btn.onclick = () => openPuterComputerMode();
        } else {
            btn.textContent = '\u29c6 Connect Puter';
            btn.classList.remove('puter-connected');
            btn.onclick = () => connectPuter();
        }
    }

    async function connectPuter() {
        showNotification('\u29c6 Connecting to Puter\u2026', 'info');
        try {
            // Trigger auth — puter.js shows sign-in popup if needed
            await puter.fs.readdir('/');
            puterAuthed = true;
            updatePuterStatus(true);
            showNotification('\u29c6 Puter connected — cloud storage, terminal, and deploy unlocked', 'success');
        } catch(e) {
            reportFeatureError('Puter Cloud', e);
        }
    }

    // ── Puter FS Operations ───────────────────────────────────
    async function puterReadFile(path) {
        if (!await initPuter()) return null;
        try {
            const blob = await puter.fs.read(path);
            if (blob && typeof blob.text === 'function') return await blob.text();
            return typeof blob === 'string' ? blob : null;
        } catch(e) { return null; }
    }

    async function puterWriteFile(path, content) {
        if (!await initPuter()) return false;
        try {
            const blob = new Blob([content], { type: 'text/plain' });
            await puter.fs.write(path, blob);
            return true;
        } catch(e) {
            console.warn('[Puter] Write failed:', e.message);
            return false;
        }
    }

    async function puterListDir(path) {
        if (!await initPuter()) return [];
        try { return await puter.fs.readdir(path || '/'); } catch(e) { return []; }
    }

    async function puterMkdir(path) {
        if (!await initPuter()) return false;
        try { await puter.fs.mkdir(path, { recursive: true }); return true; } catch(e) { return false; }
    }

    // ── Puter AI (free GPT-4o via Puter credits) ─────────────
    async function puterAIChat(prompt, systemPrompt) {
        if (!await initPuter()) return null;
        try {
            const messages = systemPrompt
                ? [{ role: 'system', content: systemPrompt }, { role: 'user', content: prompt }]
                : [{ role: 'user', content: prompt }];
            const resp = await puter.ai.chat(messages, { model: 'gpt-4o' });
            return resp?.message?.content || resp?.content || String(resp);
        } catch(e) {
            console.warn('[Puter AI] chat failed:', e.message);
            return null;
        }
    }

    // ── Puter Terminal (puter.os.shell) ───────────────────────
    async function puterTerminal(command) {
        if (!await initPuter()) return 'Puter not connected.';
        agentStatus('generic', '\u2699 ' + command.slice(0, 40) + '\u2026');
        try {
            // puter.os.exec takes { command: string } object per SDK v2 spec
            const result = await puter.os.exec({ command });
            agentDone();
            // result has: stdout, stderr, exit_code
            const out = (result.stdout || '') + (result.stderr ? '\nSTDERR: ' + result.stderr : '');
            return out || '(no output, exit code: ' + (result.exit_code ?? 0) + ')';
        } catch(e) {
            agentDone();
            // Try puter.os.shell as fallback
            try {
                const r2 = await puter.os.shell(command);
                agentDone();
                return String(r2?.output || r2 || '');
            } catch(e2) {
                return 'Terminal error: ' + e.message;
            }
        }
    }

    // ── Puter Web Browse (AI-assisted via puter.ai) ───────────
    // Real Puter SDK doesn't have browser.go() — we use puter.ai to research URLs
    // and puter.os to run curl for basic content fetching
    async function puterBrowse(url, task) {
        if (!await initPuter()) return 'Puter not connected.';
        agentStatus('search', 'Fetching ' + url + '\u2026');
        try {
            // Use puter terminal to curl the page (strips HTML via sed)
            const curlCmd = 'curl -sL --max-time 15 "' + url + '" | sed "s/<[^>]*>//g" | tr -s " \\n" | head -c 3000';
            const rawContent = await puterTerminal(curlCmd);

            if (rawContent && rawContent.length > 100 && !rawContent.includes('error')) {
                agentDone();
                // Ask puter.ai to extract the useful content
                if (task) {
                    const extracted = await puterAIChat(
                        'From this web content, ' + task + ':\n\n' + rawContent.slice(0, 2000),
                        'Extract and summarize the requested information concisely.'
                    );
                    return extracted || rawContent;
                }
                return rawContent;
            }
            agentDone();
            return rawContent || 'Could not fetch ' + url;
        } catch(e) {
            agentDone();
            return 'Browse failed: ' + e.message;
        }
    }

    // ── Puter Screenshot (using puter.ai vision) ─────────────
    // Real Puter SDK v2 doesn't have browser.screenshot() — 
    // we show a message and open the URL for manual screenshot
    async function puterScreenshot(url) {
        if (!await initPuter()) return null;
        agentStatus('generic', 'Opening ' + url + '\u2026');
        // Open in new tab + notify user
        window.open(url, '_blank', 'noopener');
        agentDone();

        const notice = document.createElement('div');
        notice.className = 'aether-msg';
        notice.appendChild(parseMarkdown('**\ud83d\udcf8 Screenshot requested:** [' + url + '](' + url + ')\n\nThe page has been opened in a new tab. Puter SDK v2 does not support automated screenshot capture — this is a known SDK limitation.'));
        display.appendChild(notice);
        smoothScrollToBottom();
        showNotification('Page opened — manual screenshot via Puter app coming in SDK v3', 'info');
        return url;
    }

    // ── Puter Deploy ──────────────────────────────────────────
    async function puterDeploy(files, siteName) {
        if (!await initPuter()) return null;
        agentStatus('generic', 'Deploying to Puter\u2026');
        try {
            const name = (siteName || 'aether-' + Date.now()).toLowerCase().replace(/[^a-z0-9-]/g, '-').slice(0, 63);
            const deployPath = '/aether-sites/' + name;

            // Create directory
            await puterMkdir(deployPath);

            // Write all files
            for (const [filename, content] of Object.entries(files)) {
                await puterWriteFile(deployPath + '/' + filename, content);
            }

            // Deploy via puter.hosting
            await puter.hosting.create(name, deployPath);
            const siteUrl = 'https://' + name + '.puter.site';
            puterSiteDeployments[name] = { url: siteUrl, name, timestamp: new Date().toISOString(), path: deployPath };
            agentDone();

            // Inline deploy card
            const card = document.createElement('div');
            card.className = 'aether-file-card puter-deploy-card';
            const iconEl = document.createElement('div'); iconEl.className = 'afc-icon'; iconEl.style.color = '#00ff88'; iconEl.style.fontSize = '1.4rem'; iconEl.textContent = '\u29c6';
            const infoEl = document.createElement('div'); infoEl.className = 'afc-info';
            const nameEl = document.createElement('div'); nameEl.className = 'afc-name'; nameEl.textContent = name + '.puter.site';
            const metaEl = document.createElement('div'); metaEl.className = 'afc-meta'; metaEl.textContent = 'Deployed to Puter Cloud \u00b7 ' + new Date().toLocaleTimeString() + ' \u00b7 ' + Object.keys(files).length + ' file(s)';
            infoEl.appendChild(nameEl); infoEl.appendChild(metaEl);
            const actEl = document.createElement('div'); actEl.className = 'afc-actions';
            const openLink = document.createElement('a'); openLink.href = siteUrl; openLink.target = '_blank'; openLink.rel = 'noopener'; openLink.className = 'afc-btn afc-btn-download'; openLink.textContent = '\u2197 Open';
            const termBtn = document.createElement('button'); termBtn.className = 'afc-btn'; termBtn.textContent = 'Terminate';
            termBtn.onclick = () => puterTerminateDeployment(name, card);
            actEl.appendChild(openLink); actEl.appendChild(termBtn);
            card.appendChild(iconEl); card.appendChild(infoEl); card.appendChild(actEl);
            display.appendChild(card); smoothScrollToBottom();
            showNotification('\u29c6 Deployed: ' + siteUrl, 'success');
            return { url: siteUrl, name };
        } catch(e) {
            agentDone();
            reportFeatureError('Puter Deploy', e);
            return null;
        }
    }

    async function puterTerminateDeployment(name, cardEl) {
        if (!await initPuter()) return;
        try {
            await puter.hosting.delete(name);
            delete puterSiteDeployments[name];
            if (cardEl) {
                cardEl.style.opacity = '0.4';
                const meta = cardEl.querySelector('.afc-meta');
                if (meta) meta.textContent += ' \u2014 Terminated';
            }
            showNotification('Site ' + name + ' terminated', 'success');
        } catch(e) {
            reportFeatureError('Puter Terminate', e);
        }
    }
    window.puterTerminate = (name) => puterTerminateDeployment(name, null);

    // ── Puter Computer Mode — Live Desktop Frame ──────────────
    function openPuterComputerMode() {
        const existing = document.getElementById('puter-computer-modal');
        if (existing) { existing.remove(); return; }

        const modal = document.createElement('div');
        modal.id = 'puter-computer-modal';
        modal.className = 'puter-computer-modal';

        // Header
        const hdr = document.createElement('div'); hdr.className = 'puter-cm-header';
        const titleEl = document.createElement('span'); titleEl.className = 'puter-cm-title';
        titleEl.innerHTML = '\u29c6 AETHER Computer Mode <span class="puter-cm-sub">Puter Desktop</span>';
        const cmCtrls = document.createElement('div'); cmCtrls.className = 'puter-cm-ctrls';

        const termBtn = document.createElement('button'); termBtn.className = 'puter-cm-btn';
        termBtn.innerHTML = '\u2699 Terminal'; termBtn.title = 'Open Puter terminal';
        termBtn.onclick = () => openPuterTerminalPanel(modal);

        const filesBtn = document.createElement('button'); filesBtn.className = 'puter-cm-btn';
        filesBtn.innerHTML = '\ud83d\udcc1 Files'; filesBtn.title = 'Browse Puter cloud files';
        filesBtn.onclick = () => openPuterFilePanel(modal);

        const deployBtn = document.createElement('button'); deployBtn.className = 'puter-cm-btn puter-cm-btn-primary';
        deployBtn.innerHTML = '\u2197 Sites'; deployBtn.title = 'Manage deployments';
        deployBtn.onclick = () => openPuterSitesPanel(modal);

        const closeBtn = document.createElement('button'); closeBtn.className = 'puter-cm-btn puter-cm-close';
        closeBtn.textContent = '\u00d7 Close'; closeBtn.onclick = () => modal.remove();

        cmCtrls.appendChild(termBtn); cmCtrls.appendChild(filesBtn);
        cmCtrls.appendChild(deployBtn); cmCtrls.appendChild(closeBtn);
        hdr.appendChild(titleEl); hdr.appendChild(cmCtrls);

        // Main frame — embeds Puter desktop via puter.com
        // Puter supports embedding via their app.puter.com endpoint
        const frameWrap = document.createElement('div'); frameWrap.className = 'puter-cm-frame-wrap';
        const frame = document.createElement('iframe');
        frame.className = 'puter-cm-frame';
        // app.puter.com embeds the full Puter desktop
        frame.src = 'https://app.puter.com';
        frame.allow = 'clipboard-read; clipboard-write; fullscreen; microphone; camera';
        frame.setAttribute('sandbox', 'allow-scripts allow-same-origin allow-forms allow-popups allow-modals allow-downloads');
        frameWrap.appendChild(frame);

        // Side panel for AETHER terminal overlay
        const sidePanel = document.createElement('div'); sidePanel.className = 'puter-cm-side'; sidePanel.id = 'puter-cm-side'; sidePanel.style.display = 'none';

        modal.appendChild(hdr); modal.appendChild(frameWrap); modal.appendChild(sidePanel);
        document.body.appendChild(modal);
        showNotification('\u29c6 Computer Mode — Puter Desktop is live', 'success');
    }

    function openPuterTerminalPanel(modal) {
        const side = modal?.querySelector('#puter-cm-side') || document.getElementById('puter-cm-side');
        if (!side) return;
        side.style.display = 'flex';
        side.innerHTML = '';
        side.className = 'puter-cm-side';

        const hdr = document.createElement('div'); hdr.className = 'puter-cm-panel-hdr';
        hdr.innerHTML = '\u2699 Puter Terminal';
        const closeBtn = document.createElement('button'); closeBtn.textContent = '\u00d7'; closeBtn.className = 'puter-cm-panel-close'; closeBtn.onclick = () => { side.style.display = 'none'; };
        hdr.appendChild(closeBtn); side.appendChild(hdr);

        const output = document.createElement('div'); output.className = 'puter-term-output'; side.appendChild(output);
        const inputRow = document.createElement('div'); inputRow.className = 'puter-term-input-row';
        const prompt = document.createElement('span'); prompt.className = 'puter-term-prompt'; prompt.textContent = '$ ';
        const inp = document.createElement('input'); inp.className = 'puter-term-inp'; inp.placeholder = 'Enter command\u2026'; inp.spellcheck = false;
        const runBtn = document.createElement('button'); runBtn.className = 'puter-term-run'; runBtn.textContent = 'Run';
        inputRow.appendChild(prompt); inputRow.appendChild(inp); inputRow.appendChild(runBtn);
        side.appendChild(inputRow);

        const runCmd = async () => {
            const cmd = inp.value.trim(); if (!cmd) return; inp.value = '';
            const line = document.createElement('div'); line.className = 'puter-term-line';
            const cmdEl = document.createElement('div'); cmdEl.className = 'puter-term-cmd'; cmdEl.textContent = '$ ' + cmd;
            const resEl = document.createElement('div'); resEl.className = 'puter-term-res'; resEl.textContent = 'Running\u2026';
            line.appendChild(cmdEl); line.appendChild(resEl); output.appendChild(line);
            output.scrollTop = output.scrollHeight;
            const result = await puterTerminal(cmd);
            resEl.textContent = result;
            output.scrollTop = output.scrollHeight;
        };
        runBtn.onclick = runCmd;
        inp.addEventListener('keydown', e => { if (e.key === 'Enter') runCmd(); });
        inp.focus();
    }

    async function openPuterFilePanel(modal) {
        const side = modal?.querySelector('#puter-cm-side') || document.getElementById('puter-cm-side');
        if (!side) return;
        side.style.display = 'flex';
        side.innerHTML = '';

        const hdr = document.createElement('div'); hdr.className = 'puter-cm-panel-hdr';
        hdr.innerHTML = '\ud83d\udcc1 Cloud Files';
        const closeBtn = document.createElement('button'); closeBtn.textContent = '\u00d7'; closeBtn.className = 'puter-cm-panel-close'; closeBtn.onclick = () => { side.style.display = 'none'; };
        hdr.appendChild(closeBtn); side.appendChild(hdr);

        const fileList = document.createElement('div'); fileList.className = 'puter-file-list';
        fileList.textContent = 'Loading\u2026'; side.appendChild(fileList);

        if (!await initPuter()) { fileList.textContent = 'Not connected.'; return; }
        try {
            const items = await puter.fs.readdir('/');
            fileList.innerHTML = '';
            (items || []).forEach(item => {
                const row = document.createElement('div'); row.className = 'puter-file-row';
                const icon = item.is_dir ? '\ud83d\udcc1' : '\ud83d\udcc4';
                row.textContent = icon + ' ' + item.name;
                row.onclick = async () => {
                    if (!item.is_dir) {
                        const content = await puterReadFile('/' + item.name);
                        if (content) {
                            const inp = document.getElementById('user-input');
                            if (inp) { inp.value = '[Puter file: ' + item.name + ']\n\n' + content.slice(0, 8000); inp.dispatchEvent(new Event('input')); }
                            showNotification('File loaded: ' + item.name, 'success');
                        }
                    }
                };
                fileList.appendChild(row);
            });
            if (!items?.length) fileList.textContent = 'No files yet.';
        } catch(e) { fileList.textContent = 'Error: ' + e.message; }
    }

    function openPuterSitesPanel(modal) {
        const side = modal?.querySelector('#puter-cm-side') || document.getElementById('puter-cm-side');
        if (!side) return;
        side.style.display = 'flex';
        side.innerHTML = '';

        const hdr = document.createElement('div'); hdr.className = 'puter-cm-panel-hdr';
        hdr.innerHTML = '\u2197 Deployed Sites';
        const closeBtn = document.createElement('button'); closeBtn.textContent = '\u00d7'; closeBtn.className = 'puter-cm-panel-close'; closeBtn.onclick = () => { side.style.display = 'none'; };
        hdr.appendChild(closeBtn); side.appendChild(hdr);

        const list = document.createElement('div'); list.className = 'puter-file-list';
        const sites = Object.values(puterSiteDeployments);
        if (!sites.length) { list.textContent = 'No active deployments.'; }
        else {
            sites.forEach(site => {
                const row = document.createElement('div'); row.className = 'puter-file-row';
                const link = document.createElement('a'); link.href = site.url; link.target = '_blank'; link.rel = 'noopener';
                link.textContent = '\u2197 ' + site.name + '.puter.site';
                const termBtn = document.createElement('button'); termBtn.className = 'puter-term-run'; termBtn.style.marginLeft = '8px'; termBtn.textContent = 'Terminate';
                termBtn.onclick = () => puterTerminateDeployment(site.name, null);
                row.appendChild(link); row.appendChild(termBtn);
                list.appendChild(row);
            });
        }
        side.appendChild(list);
    }

    // Register Puter tools after TOOL_REGISTRY exists
    function registerPuterTools() {
        if (typeof TOOL_REGISTRY === 'undefined') { setTimeout(registerPuterTools, 200); return; }
        TOOL_REGISTRY['puter_browse']      = { fn: async(arg) => { const [url,...rest]=arg.split('|'); return puterBrowse(url.trim(), rest.join('|').trim()||null); }, desc:'Fetch URL content via Puter terminal curl' };
        TOOL_REGISTRY['puter_screenshot']  = { fn: async(url) => { await puterScreenshot(url.trim()); return 'Page opened'; }, desc:'Open URL for screenshot' };
        TOOL_REGISTRY['puter_terminal']    = { fn: async(cmd) => puterTerminal(cmd.trim()), desc:'Run shell command in Puter cloud terminal' };
        TOOL_REGISTRY['puter_read_file']   = { fn: async(path) => (await puterReadFile(path.trim())) || 'File not found', desc:'Read file from Puter cloud storage' };
        TOOL_REGISTRY['puter_write_file']  = { fn: async(arg) => { const nl=arg.indexOf('\n'); const path=arg.slice(0,nl).trim(); const content=arg.slice(nl+1); return (await puterWriteFile(path,content))?'Written: '+path:'Write failed'; }, desc:'Write file to Puter cloud' };
        TOOL_REGISTRY['puter_list_dir']    = { fn: async(path) => { const items=await puterListDir(path||'/'); return items.map(i=>(i.is_dir?'\ud83d\udcc1':'\ud83d\udcc4')+' '+i.name).join('\n')||'(empty)'; }, desc:'List Puter directory' };
        TOOL_REGISTRY['puter_mkdir']       = { fn: async(path) => (await puterMkdir(path))?'Created: '+path:'Failed', desc:'Create directory in Puter' };
        TOOL_REGISTRY['puter_ai']          = { fn: async(prompt) => (await puterAIChat(prompt))||'No response', desc:'Query Puter AI (free GPT-4o credits)' };
        TOOL_REGISTRY['puter_deploy']      = { fn: async(arg) => { const lines=arg.split('\n'); const name=lines[0].trim(); const content=lines.slice(1).join('\n'); const r=await puterDeploy({'index.html':content},name); return r?'Deployed: '+r.url:'Failed'; }, desc:'Deploy HTML to Puter hosting' };
    }
    setTimeout(registerPuterTools, 150);
    async function handleWebScrape(url) {
        agentStatus('scrape');
        try {
            let content = '';
            if ((puterAuthed || hooksConfig.puter) && typeof puter !== 'undefined') {
                content = await puterBrowse(url);
            } else if (hooksConfig.firecrawlKey) {
                content = await firecrawlScrape(url);
            } else {
                content = 'Configure Puter or Firecrawl in HOOKS for web scraping.';
            }
            agentDone();
            const inp = document.getElementById('user-input');
            if (inp) {
                inp.value = '[Scraped: ' + url + ']\n\n' + content.slice(0, 10000);
                inp.dispatchEvent(new Event('input'));
            }
            showNotification('Content scraped', 'success');
        } catch(e) { agentDone(); reportFeatureError('Web Scrape', e); }
    }

    // ─── WORKSPACE STEP INDICATOR ────────────────────────────
    // Shows a live step-by-step progress overlay when workspace operations run
    let wsStepPanel = null;
    let wsStepList  = null;
    let wsStepTimer = null;

    function wsStepShow(title) {
        // Remove old panel if lingering
        if (wsStepPanel) wsStepPanel.remove();

        wsStepPanel = document.createElement('div');
        wsStepPanel.className = 'ws-step-panel';
        wsStepPanel.innerHTML = `
            <div class="ws-step-header">
                <svg class="ic-xs"><use href="#ic-folder"/></svg>
                <span class="ws-step-title">${title}</span>
                <div class="ws-step-spinner"></div>
            </div>
            <ul class="ws-step-list"></ul>`;
        document.body.appendChild(wsStepPanel);
        wsStepList = wsStepPanel.querySelector('.ws-step-list');

        // Animate in
        requestAnimationFrame(() => wsStepPanel.classList.add('visible'));
    }

    function wsStep(msg, status = 'pending') {
        // status: 'pending' | 'ok' | 'skip' | 'error'
        if (!wsStepList) return;
        const li = document.createElement('li');
        li.className = `ws-step-item ws-step-${status}`;
        const icons = { pending: '⏳', ok: '✓', skip: '–', error: '✗' };
        li.innerHTML = `<span class="ws-step-icon">${icons[status]}</span><span class="ws-step-msg">${msg}</span>`;
        wsStepList.appendChild(li);
        wsStepPanel.scrollTop = wsStepPanel.scrollHeight;
        return li;
    }

    function wsStepUpdate(li, msg, status = 'ok') {
        if (!li) return;
        const icons = { pending: '⏳', ok: '✓', skip: '–', error: '✗' };
        li.className = `ws-step-item ws-step-${status}`;
        li.innerHTML = `<span class="ws-step-icon">${icons[status]}</span><span class="ws-step-msg">${msg}</span>`;
    }

    function wsStepDone(finalMsg = 'Complete') {
        if (!wsStepPanel) return;
        // Swap spinner for checkmark
        const spinner = wsStepPanel.querySelector('.ws-step-spinner');
        if (spinner) { spinner.outerHTML = `<svg class="ic-xs ws-step-done-icon"><use href="#ic-check"/></svg>`; }
        const title = wsStepPanel.querySelector('.ws-step-title');
        if (title) title.textContent = finalMsg;
        // Auto-dismiss after 2.5s
        clearTimeout(wsStepTimer);
        wsStepTimer = setTimeout(() => {
            if (wsStepPanel) { wsStepPanel.classList.remove('visible'); setTimeout(() => { if(wsStepPanel){wsStepPanel.remove();wsStepPanel=null;wsStepList=null;} }, 400); }
        }, 2500);
    }

    function wsStepClose() {
        clearTimeout(wsStepTimer);
        if (wsStepPanel) { wsStepPanel.classList.remove('visible'); setTimeout(()=>{ if(wsStepPanel){wsStepPanel.remove();wsStepPanel=null;wsStepList=null;} },400); }
    }
    const WS_FILES = ['ENCRYPT.md','CORE_LOGIC.md','FACILITIES.md','ARCHIVES.md','PROTOCOL.md','WORKSPACE.md','USER.md','LOGS.md'];
    const WS_DEFAULTS = {
        'ENCRYPT.md': '# ENCRYPT.md\nSecurity clearance: Level 0 (all operations permitted)',
        'CORE_LOGIC.md': `# CORE_LOGIC.md — AETHER Behavioral Core v2.0

## PRIMARY DIRECTIVE
Deliver maximum value per token. Logic governs all output.
- Authority: Speak from verified data, never speculation without labeling it as such.
- Adaptability: Match user's technical level precisely.
- Precision: Prefer concrete answers over vague summaries.

## COMMUNICATION PROTOCOL
- Use minimum tokens for maximum data density.
- Quote exact user input when referencing it.
- Never hallucinate features, APIs, or facts not in context.
- Structure complex answers with clear sections.

## CODE STANDARDS
- All code must be runnable, complete, and production-quality.
- Identify language, dependencies, and edge cases.
- Prefer modern idioms and best practices.

## ERROR HANDLING
- On ambiguity: ask one clarifying question, then proceed with best interpretation.
- On failure: explain root cause, provide fallback, suggest fix.`,
        'FACILITIES.md': '# FACILITIES.md\n\n## Available Hooks\n- Mail: Gmail, Outlook\n- Search: Tavily, Brave, Serper\n- Web: Puter (scraping)\n- Code: GitHub\n\nConfigure in HOOKS modal.',
        'ARCHIVES.md': '# ARCHIVES.md — Long-term Memory\n\n',
        'PROTOCOL.md': '# PROTOCOL.md — Automation Protocols\n\n',
        'WORKSPACE.md': '# WORKSPACE.md — Current Context\n\n',
        'USER.md': '# USER.md — User Profile\n\n',
        'LOGS.md': '# LOGS.md — System Logs\n\n'
    };

    function showWorkspaceModal() {
        if (state.workspaceEnabled) {
            wsChoose.style.display = 'none';
            wsActive.style.display = 'block';
            wsFiles.style.display = 'none';
            refreshWorkspaceActiveView();
        } else {
            wsChoose.style.display = 'block';
            wsActive.style.display = 'none';
            wsFiles.style.display = 'none';
        }
        workspaceModalEl.classList.remove('hidden');
    }

    function refreshWorkspaceActiveView() {
        const mode = state.workspaceMode === 'fs' ? 'File System' : 'Virtual (IndexedDB)';
        const path = state.workspaceDir ? state.workspaceDir.name : 'Virtual Storage';
        if (wsModeText) wsModeText.textContent = mode;
        if (wsPathText) wsPathText.textContent = path;
        if (wsFilesText) wsFilesText.textContent = WS_FILES.join(', ');
    }

    async function initWorkspaceFS() {
        if (!window.showDirectoryPicker) {
            showNotification('File System API not available. Use Virtual mode.','warn');
            return;
        }
        wsStepShow('Connecting File System Workspace');
        try {
            const s1 = wsStep('Requesting folder access…', 'pending');
            state.workspaceDir = await window.showDirectoryPicker();
            wsStepUpdate(s1, `Folder selected: ${state.workspaceDir.name}`, 'ok');

            state.workspaceMode = 'fs';
            state.workspaceEnabled = true;
            state.workspaceFiles = {};

            for (const fn of WS_FILES) {
                const sFile = wsStep(`Checking ${fn}…`, 'pending');
                try {
                    const fh = await state.workspaceDir.getFileHandle(fn, { create: true });
                    state.workspaceFiles[fn] = fh;
                    const f = await fh.getFile();
                    if (f.size === 0 && WS_DEFAULTS[fn]) {
                        await writeFile(fn, WS_DEFAULTS[fn]);
                        wsStepUpdate(sFile, `${fn} — created with defaults`, 'ok');
                    } else {
                        wsStepUpdate(sFile, `${fn} — ${(f.size/1024).toFixed(1)} KB loaded`, 'ok');
                    }
                } catch(e) {
                    wsStepUpdate(sFile, `${fn} — failed: ${e.message}`, 'error');
                }
            }

            workspacePath.textContent = state.workspaceDir.name;
            workspaceIndicator.textContent = '●';
            workspaceIndicator.style.color = '#00ff88';
            localStorage.setItem('aether_ws_mode', 'fs');
            wsChoose.style.display = 'none';
            wsActive.style.display = 'block';
            refreshWorkspaceActiveView();
            wsStepDone(`Workspace ready — ${WS_FILES.length} files`);
        } catch(e) {
            if (e.name !== 'AbortError') {
                wsStep(`Error: ${e.message}`, 'error');
                wsStepDone('Workspace connection failed');
            } else {
                wsStep('Cancelled by user', 'skip');
                wsStepClose();
            }
        }
    }

    async function initWorkspaceVirtual() {
        wsStepShow('Connecting Virtual Workspace');

        state.workspaceMode = 'virtual';
        state.workspaceEnabled = true;
        state.workspaceDir = null;

        const s0 = wsStep('Initialising IndexedDB storage…', 'pending');
        await new Promise(r => setTimeout(r, 50)); // let UI paint
        wsStepUpdate(s0, 'IndexedDB ready', 'ok');

        for (const fn of WS_FILES) {
            const sFile = wsStep(`Checking ${fn}…`, 'pending');
            try {
                const existing = await localforage.getItem('ws_' + fn);
                if (!existing && WS_DEFAULTS[fn]) {
                    await localforage.setItem('ws_' + fn, WS_DEFAULTS[fn]);
                    wsStepUpdate(sFile, `${fn} — initialised`, 'ok');
                } else {
                    wsStepUpdate(sFile, `${fn} — ${existing ? (existing.length + ' chars') : 'empty'}`, 'ok');
                }
            } catch(e) {
                wsStepUpdate(sFile, `${fn} — error: ${e.message}`, 'error');
            }
        }

        workspacePath.textContent = 'Virtual Storage';
        workspaceIndicator.textContent = '●';
        workspaceIndicator.style.color = '#00f3ff';
        localStorage.setItem('aether_ws_mode', 'virtual');
        wsChoose.style.display = 'none';
        wsActive.style.display = 'block';
        refreshWorkspaceActiveView();
        wsStepDone(`Virtual workspace ready — ${WS_FILES.length} files`);
    }

    async function disconnectWorkspace() {
        state.workspaceEnabled = false;
        state.workspaceDir = null;
        state.workspaceFiles = {};
        state.workspaceMode = null;
        workspacePath.textContent = 'Not active';
        workspaceIndicator.textContent = '';
        localStorage.removeItem('aether_ws_mode');
        wsActive.style.display = 'none';
        wsChoose.style.display = 'block';
        showNotification('Workspace disconnected','info');
    }

    async function showWorkspaceFiles() {
        if (!wsFilesList) return;
        wsActive.style.display = 'none';
        wsFiles.style.display  = 'block';

        // Build toolbar with search + create
        wsFilesList.innerHTML = '';
        const toolbar = document.createElement('div');
        toolbar.style.cssText = 'display:flex;gap:8px;margin-bottom:12px;align-items:center';
        toolbar.innerHTML = `
            <input type="text" id="ws-file-filter" class="auth-input" placeholder="Filter files…" style="flex:1;font-size:.75rem">
            <button id="ws-new-file-btn" class="save-settings-btn" style="white-space:nowrap;font-size:.7rem">+ New File</button>
        `;
        wsFilesList.appendChild(toolbar);

        const listContainer = document.createElement('div');
        listContainer.id = 'ws-file-list-container';
        wsFilesList.appendChild(listContainer);

        let allFilesData = [];

        async function loadAndRenderFiles(filterText) {
            const allFiles = new Set(WS_FILES);
            Object.keys(wsFileCache).forEach(function(f) { allFiles.add(f); });
            if (codingFolderHandle) {
                try {
                    const entries = await fsCollectEntries(codingFolderHandle, '', 2, 0, false);
                    entries.filter(function(e) { return e.kind === 'file'; }).forEach(function(e) { allFiles.add('📁 ' + e.path); });
                } catch {}
            }

            allFilesData = [];
            for (const fn of allFiles) {
                const isFs   = fn.startsWith('📁 ');
                const realFn = isFs ? fn.slice(2) : fn;
                let content  = '';
                try { content = isFs ? await fsFolderRead(realFn) : (await readFile(realFn) || ''); } catch {}
                allFilesData.push({ fn, realFn, isFs, content });
            }

            renderFileList(filterText);
        }

        function renderFileList(filterText) {
            const container = document.getElementById('ws-file-list-container');
            if (!container) return;
            const q = (filterText || '').toLowerCase();
            const filtered = q ? allFilesData.filter(function(f) { return f.fn.toLowerCase().includes(q) || f.content.toLowerCase().includes(q); }) : allFilesData;
            container.innerHTML = '';
            if (filtered.length === 0) {
                container.innerHTML = '<div class="ws-loading">No files match your filter.</div>';
                return;
            }
            filtered.forEach(function(f) {
                const ext = f.realFn.split('.').pop().toLowerCase();
                const isText = ['md','txt','json','js','ts','py','css','html','yaml','yml','sh','env'].includes(ext);
                const item = document.createElement('div');
                item.className = 'ws-file-item';
                item.innerHTML = `
                    <div class="ws-file-item-header">
                        <span class="ws-file-name">${escapeHtml(f.fn)}</span>
                        <div class="ws-file-actions">
                            <span class="ws-file-size">${f.content.length ? f.content.split('\n').length + 'L · ' + f.content.length + 'B' : 'empty'}</span>
                            ${isText ? '<button class="ws-file-edit-btn" data-fn="' + escapeHtml(f.realFn) + '" data-fs="' + f.isFs + '">Edit</button>' : ''}
                            ${!f.isFs && f.fn !== 'ENCRYPT.md' ? '<button class="ws-file-del-btn" data-fn="' + escapeHtml(f.realFn) + '">Delete</button>' : ''}
                        </div>
                    </div>
                    <div class="ws-file-preview">${escapeHtml(f.content.slice(0,180))}${f.content.length > 180 ? '…' : ''}</div>`;
                container.appendChild(item);
            });

            container.querySelectorAll('.ws-file-edit-btn').forEach(function(btn) {
                btn.onclick = async function() {
                    const fn = btn.dataset.fn;
                    const isFs = btn.dataset.fs === 'true';
                    const c = isFs ? await fsFolderRead(fn) : (await readFile(fn) || '');
                    window.openWorkspaceEditor(fn, c, isFs);
                };
            });

            container.querySelectorAll('.ws-file-del-btn').forEach(function(btn) {
                btn.onclick = async function() {
                    const fn = btn.dataset.fn;
                    if (fn === 'ENCRYPT.md') return;
                    const confirmed = await showDialog({ title: 'Delete File', message: 'Delete ' + fn + '?', type: 'confirm' }).catch(function(){ return false; });
                    if (!confirmed) return;
                    try {
                        if (state.workspaceMode === 'fs') {
                            const handle = state.workspaceFiles[fn];
                            if (handle) await handle.remove();
                        } else {
                            await localforage.removeItem('ws_' + fn);
                        }
                        delete wsFileCache[fn];
                        showNotification(fn + ' deleted', 'info');
                        loadAndRenderFiles(document.getElementById('ws-file-filter')?.value || '');
                    } catch(e) { showNotification('Delete failed: ' + e.message, 'error'); }
                };
            });
        }

        // Filter on input
        const filterInput = document.getElementById('ws-file-filter');
        if (filterInput) {
            filterInput.addEventListener('input', function() {
                renderFileList(this.value);
            });
        }

        // New file
        const newBtn = document.getElementById('ws-new-file-btn');
        if (newBtn) {
            newBtn.onclick = function() {
                showDialog({ title: 'New Workspace File', message: 'Filename (e.g. notes.md):', type: 'prompt', default: 'notes.md' })
                    .then(async function(fn) {
                        if (!fn || !fn.trim()) return;
                        await writeFile(fn.trim(), '');
                        wsFileCache[fn.trim()] = '';
                        window.openWorkspaceEditor(fn.trim(), '', false);
                    }).catch(function(){});
            };
        }

        await loadAndRenderFiles('');
    }

    // ════════════════════════════════════════════════════════════
    // PROJECT SYSTEM
    // Full file parsing + .md summary + RAG indexing + Firebase sync
    // ════════════════════════════════════════════════════════════
    const PROJECTS_KEY = 'aether_projects';

    function loadProjects() {
        try { return JSON.parse(localStorage.getItem(PROJECTS_KEY) || '[]'); } catch { return []; }
    }

    function saveProjects(projects) {
        localStorage.setItem(PROJECTS_KEY, JSON.stringify(projects));
        // Cloud sync when signed in
        if (typeof window._syncProjectsToCloud === 'function') window._syncProjectsToCloud().catch(()=>{});
    }

    function openProjectModal() {
        const modal = document.getElementById('project-modal');
        if (!modal) return;
        modal.classList.remove('hidden');
        renderProjectList();
    }

    function renderProjectList() {
        const body = document.getElementById('project-modal-body');
        if (!body) return;
        const projects = loadProjects();
        const cloudIcon = _currentUser
            ? `<span style="color:#00ff9d;font-size:.65rem;font-family:var(--font-mono)">⬡ Cloud synced</span>`
            : `<span style="color:#334;font-size:.65rem;font-family:var(--font-mono)">Sign in to sync across devices</span>`;

        body.innerHTML = `
            <div class="proj-header">
                <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
                    <p class="proj-desc" style="margin:0">Projects give AETHER full parsed context of your files. Each project has a parsed file index and a quick-lookup summary .md — no re-reading needed.</p>
                    ${cloudIcon}
                </div>
                <button class="save-settings-btn proj-new-btn" id="proj-new-btn">+ New Project</button>
            </div>
            <div class="proj-list" id="proj-list">
                ${projects.length === 0 ? '<div class="proj-empty">No projects yet. Create one to get started.</div>' :
                    projects.map((p, i) => `
                        <div class="proj-card ${state.activeProjectId === p.id ? 'proj-card-active' : ''}">
                            <div class="proj-card-header">
                                <div class="proj-card-left">
                                    <span class="proj-card-name">${escapeHtml(p.name)}</span>
                                    ${state.activeProjectId === p.id ? '<span class="proj-active-badge">ACTIVE</span>' : ''}
                                    ${p.indexed ? '<span class="proj-indexed-badge">INDEXED</span>' : ''}
                                </div>
                                <div class="proj-card-actions">
                                    <button class="proj-btn proj-btn-activate" data-idx="${i}">${state.activeProjectId === p.id ? 'Deactivate' : 'Activate'}</button>
                                    <button class="proj-btn proj-btn-index" data-idx="${i}" title="Parse all files and build RAG index">Index</button>
                                    <button class="proj-btn proj-btn-edit" data-idx="${i}">Edit</button>
                                    <button class="proj-btn proj-btn-delete" data-idx="${i}">Delete</button>
                                </div>
                            </div>
                            <div class="proj-card-aims">${escapeHtml((p.aims||'').slice(0, 120))}${(p.aims?.length||0) > 120 ? '…' : ''}</div>
                            <div class="proj-card-meta">
                                <span>${p.files?.length || 0} file${p.files?.length !== 1 ? 's' : ''} selected</span>
                                <span>${p.parsedFiles || 0} parsed</span>
                                <span>${p.ragDocs || 0} RAG chunks</span>
                                <span>Created ${new Date(p.created).toLocaleDateString()}</span>
                            </div>
                        </div>`).join('')}
            </div>`;

        document.getElementById('proj-new-btn')?.addEventListener('click', () => showProjectEditor(null));

        body.querySelectorAll('.proj-btn-activate').forEach(btn => {
            btn.onclick = () => {
                const p = loadProjects()[+btn.dataset.idx];
                if (!p) return;
                state.activeProjectId = state.activeProjectId === p.id ? null : p.id;
                saveState();
                if (state.activeProjectId) {
                    activateProject(p);
                    showNotification(`✓ Project "${p.name}" activated`, 'success');
                } else {
                    showNotification('Project deactivated', 'info');
                }
                renderProjectList();
            };
        });

        body.querySelectorAll('.proj-btn-index').forEach(btn => {
            btn.onclick = async () => {
                const all = loadProjects();
                const p   = all[+btn.dataset.idx];
                if (!p) return;
                btn.textContent = 'Indexing…';
                btn.disabled = true;
                const result = await parseAndIndexProject(p);
                all[+btn.dataset.idx] = result;
                saveProjects(all);
                showNotification(`✓ "${p.name}" indexed — ${result.parsedFiles} files, ${result.ragDocs} RAG chunks`, 'success');
                renderProjectList();
            };
        });

        body.querySelectorAll('.proj-btn-edit').forEach(btn => {
            btn.onclick = () => showProjectEditor(loadProjects()[+btn.dataset.idx]);
        });

        body.querySelectorAll('.proj-btn-delete').forEach(btn => {
            btn.onclick = async () => {
                const p = loadProjects()[+btn.dataset.idx];
                const ok = await showDialog({ title: 'Delete Project', message: `Delete "${p.name}"?`, type: 'confirm' }).catch(()=>false);
                if (!ok) return;
                const all = loadProjects().filter(x => x.id !== p.id);
                saveProjects(all);
                if (state.activeProjectId === p.id) { state.activeProjectId = null; saveState(); }
                renderProjectList();
            };
        });
    }

    // ── Full file parsing + RAG indexing ─────────────────────
    async function parseAndIndexProject(project) {
        const proj = { ...project };
        const filesToParse = proj.files || [];
        let ragChunks = 0;
        let parsedCount = 0;
        const parsedIndex = {}; // filename → { content, lines, tokens, summary }

        // Parse each file
        for (const fn of filesToParse) {
            try {
                let content = '';
                // Try FS folder first, then virtual workspace
                if (codingFolderHandle) {
                    try { content = await fsFolderRead(fn); } catch {}
                }
                if (!content) content = await readFile(fn) || wsFileCache[fn] || '';
                if (!content) continue;

                const lines  = content.split('\n').length;
                const tokens = Math.ceil(content.length / 4);

                // Generate brief per-file summary (first non-empty lines)
                const summaryLines = content.split('\n').filter(l => l.trim()).slice(0, 6).join('\n');

                parsedIndex[fn] = { lines, tokens, summary: summaryLines.slice(0, 400) };

                // RAG v2 smart chunking (structure-aware) or legacy fallback
                if (typeof AETHER_RAGv2 !== 'undefined') {
                    const chunks = await AETHER_RAGv2.addFile(fn, content, {
                        collection: 'project',
                        meta: { project: proj.name },
                    });
                    ragChunks += (chunks && chunks.length) || 0;
                } else {
                    const chunkSize = 2000;
                    const overlap   = 200;
                    for (let i = 0; i < content.length; i += chunkSize - overlap) {
                        const chunk = content.slice(i, i + chunkSize);
                        if (chunk.trim()) {
                            RAG.addDocument(`[Project: ${proj.name}] [File: ${fn}]\n${chunk}`);
                            ragChunks++;
                        }
                    }
                }
                parsedCount++;
            } catch(e) { console.warn('[Project] parse error:', fn, e.message); }
        }

        // Generate the .md summary file
        const summaryLines = [
            `# Project: ${proj.name}`,
            `Generated: ${new Date().toLocaleString()}`,
            '',
            `## Aims`,
            proj.aims || '—',
            '',
            `## Context`,
            proj.context || '—',
            '',
            `## File Index (${parsedCount} files parsed)`,
            ...Object.entries(parsedIndex).map(([fn, info]) =>
                `### ${fn}\n- Lines: ${info.lines} · Tokens: ~${info.tokens}\n\`\`\`\n${info.summary}\n\`\`\``
            ),
        ].join('\n');

        const summaryFn = `PROJECT_${proj.name.replace(/[^a-z0-9]/gi,'-').toLowerCase()}.md`;
        await writeFile(summaryFn, summaryLines);
        wsFileCache[summaryFn] = summaryLines;

        // Add summary to RAG as well
        if (typeof AETHER_RAGv2 !== 'undefined') {
            await AETHER_RAGv2.addText(summaryLines.slice(0, 8000), {
                collection: 'project',
                source: summaryFn,
                meta: { project: proj.name, kind: 'summary' },
            });
            ragChunks++;
        } else {
            RAG.addDocument(`[Project Summary: ${proj.name}]\n${summaryLines.slice(0, 3000)}`);
            RAG.save();
            ragChunks++;
        }

        proj.parsedFiles  = parsedCount;
        proj.ragDocs      = ragChunks;
        proj.indexed      = true;
        proj.summaryFile  = summaryFn;
        proj.parsedIndex  = parsedIndex;
        proj.lastIndexed  = new Date().toISOString();

        return proj;
    }

    function showProjectEditor(project) {
        const isNew = !project;
        const body  = document.getElementById('project-modal-body');
        if (!body) return;
        const wsFileOptions = [...new Set([...WS_FILES, ...Object.keys(wsFileCache)])];

        body.innerHTML = `
            <div class="proj-editor">
                <div class="proj-editor-field">
                    <label class="proj-label">Project Name</label>
                    <input id="proj-name" type="text" class="proj-input" placeholder="My App / Research / Novel…" value="${escapeHtml(project?.name || '')}">
                </div>
                <div class="proj-editor-field">
                    <label class="proj-label">Aims &amp; Goals</label>
                    <textarea id="proj-aims" class="proj-textarea" placeholder="What are you trying to achieve? This is injected into every conversation while this project is active.">${escapeHtml(project?.aims || '')}</textarea>
                </div>
                <div class="proj-editor-field">
                    <label class="proj-label">Context Overview</label>
                    <textarea id="proj-context" class="proj-textarea" placeholder="Architecture decisions, key constraints, stack — persisted so AETHER never re-reads files to get this.">${escapeHtml(project?.context || '')}</textarea>
                    <div class="proj-hint">After creating, click Index to parse all files — AETHER gets full parsed content + a quick .md summary is generated for fast lookup.</div>
                </div>
                <div class="proj-editor-field">
                    <label class="proj-label">Files to parse &amp; index</label>
                    <div class="proj-files-grid">
                        ${wsFileOptions.map(fn => `
                            <label class="proj-file-check">
                                <input type="checkbox" value="${escapeHtml(fn)}" ${(project?.files||[]).includes(fn) ? 'checked' : ''}>
                                <span>${escapeHtml(fn)}</span>
                            </label>`).join('')}
                    </div>
                    ${codingFolderHandle ? `<div class="proj-hint" style="margin-top:6px">FS folder "${codingFolderHandle.name}" linked — Index will also parse folder files.</div>` : ''}
                </div>
                <div class="settings-footer">
                    <button class="save-settings-btn" id="proj-save-btn">${isNew ? 'Create Project' : 'Save'}</button>
                    ${!isNew ? `<button class="save-settings-btn" id="proj-index-btn" style="background:rgba(0,243,255,0.08)">⚙ Index Now</button>` : ''}
                    <button class="reset-default-btn" id="proj-cancel-btn">Cancel</button>
                </div>
                ${project?.summaryFile ? `<div class="proj-hint" style="margin-top:8px">Summary file: <code>${project.summaryFile}</code> · Last indexed: ${new Date(project.lastIndexed||0).toLocaleString()}</div>` : ''}
            </div>`;

        document.getElementById('proj-cancel-btn').onclick = renderProjectList;

        const doSave = () => {
            const name    = document.getElementById('proj-name').value.trim();
            const aims    = document.getElementById('proj-aims').value.trim();
            const context = document.getElementById('proj-context').value.trim();
            const files   = [...body.querySelectorAll('.proj-file-check input:checked')].map(c => c.value);
            if (!name) { showNotification('Project name required', 'warn'); return null; }
            const all = loadProjects();
            if (isNew) {
                const proj = { id: 'proj_' + Date.now(), name, aims, context, files, created: Date.now(), ragDocs: 0, parsedFiles: 0, indexed: false };
                all.push(proj);
                saveProjects(all);
                showNotification(`✓ Project "${name}" created — click Index to parse files`, 'success');
                return proj;
            } else {
                const idx = all.findIndex(p => p.id === project.id);
                if (idx > -1) { all[idx] = { ...all[idx], name, aims, context, files }; saveProjects(all); return all[idx]; }
            }
            return null;
        };

        document.getElementById('proj-save-btn').onclick = () => { doSave(); renderProjectList(); };

        if (!isNew) {
            document.getElementById('proj-index-btn')?.addEventListener('click', async () => {
                const saved = doSave();
                if (!saved) return;
                const btn = document.getElementById('proj-index-btn');
                if (btn) { btn.textContent = 'Indexing…'; btn.disabled = true; }
                const all = loadProjects();
                const idx = all.findIndex(p => p.id === saved.id);
                const result = await parseAndIndexProject(saved);
                if (idx > -1) all[idx] = result;
                saveProjects(all);
                showNotification(`✓ Indexed ${result.parsedFiles} files, ${result.ragDocs} RAG chunks → ${result.summaryFile}`, 'success');
                renderProjectList();
            });
        }
    }

    async function activateProject(project) {
        // If not yet indexed, auto-index on first activation
        if (!project.indexed && project.files?.length) {
            showNotification(`Indexing "${project.name}" on first activation…`, 'info');
            const all = loadProjects();
            const idx = all.findIndex(p => p.id === project.id);
            const result = await parseAndIndexProject(project);
            if (idx > -1) all[idx] = result;
            saveProjects(all);
        }
        // Write active project marker to WORKSPACE.md
        if (state.workspaceEnabled) {
            const entry = `\n\n## Active Project: ${project.name}\n**Aims:** ${project.aims}\n${project.context ? '**Context:** ' + project.context : ''}\n${project.summaryFile ? '**Summary:** See ' + project.summaryFile : ''}`;
            const existing = (await readFile('WORKSPACE.md') || '').replace(/\n\n## Active Project:[\s\S]*$/,'');
            await writeFile('WORKSPACE.md', existing + entry);
            wsFileCache['WORKSPACE.md'] = existing + entry;
        }
    }

    // Inject active project into buildSystemPrompt (called from buildSystemPrompt)
    function getActiveProjectContext() {
        if (!state.activeProjectId) return '';
        const proj = loadProjects().find(p => p.id === state.activeProjectId);
        if (!proj) return '';
        let ctx = `\n# ACTIVE PROJECT: ${proj.name}\n`;
        if (proj.aims)    ctx += `**Aims:** ${proj.aims}\n`;
        if (proj.context) ctx += `**Context:** ${proj.context}\n`;
        if (proj.indexed) {
            ctx += `**File Index (${proj.parsedFiles} files parsed — full content in RAG):**\n`;
            if (proj.parsedIndex) {
                Object.entries(proj.parsedIndex).slice(0, 12).forEach(([fn, info]) => {
                    ctx += `  - ${fn} (${info.lines}L ~${info.tokens} tok)\n`;
                });
            }
            ctx += `**Quick summary:** ${proj.summaryFile} is in workspace for fast lookup.\n`;
            ctx += `*(Full parsed file contents are in RAG — retrieved automatically. No need to re-read files.)*\n`;
        }
        return ctx;
    }

    async function restoreWorkspaceIfNeeded() {
        const mode = localStorage.getItem('aether_ws_mode');
        if (mode === 'virtual') {
            state.workspaceMode = 'virtual';
            state.workspaceEnabled = true;
            workspacePath.textContent = 'Virtual Storage';
            workspaceIndicator.textContent = '●';
            workspaceIndicator.style.color = '#00f3ff';
        }
        // FS workspace cannot be auto-restored (requires user gesture)
    }

    async function readFile(fn) {
        if (state.workspaceEnabled) {
            if (state.workspaceMode === 'fs' && state.workspaceFiles[fn]) {
                try { const f = await state.workspaceFiles[fn].getFile(); return await f.text(); } catch { return null; }
            } else {
                return await localforage.getItem('ws_' + fn);
            }
        }
        return await localforage.getItem(fn);
    }

    async function writeFile(fn, content) {
        if (state.workspaceEnabled) {
            if (state.workspaceMode === 'fs' && state.workspaceFiles[fn]) {
                try {
                    const w = await state.workspaceFiles[fn].createWritable();
                    await w.write(content); await w.close();
                    // Cloud sync
                    if (typeof window._syncFileToCloud === 'function') window._syncFileToCloud(fn, content).catch(()=>{});
                    return true;
                } catch { return false; }
            } else {
                await localforage.setItem('ws_' + fn, content);
                if (typeof window._syncFileToCloud === 'function') window._syncFileToCloud(fn, content).catch(()=>{});
                return true;
            }
        }
        await localforage.setItem(fn, content);
        return true;
    }

    async function logToWorkspace(user, ai) {
        wsStepShow('Saving to Workspace');
        const ts = new Date().toLocaleString();

        const s1 = wsStep('Reading WORKSPACE.md…', 'pending');
        const entry = `\n## [${ts}]\n**User:** ${user.slice(0,500)}\n**AETHER:** ${ai.slice(0,500)}\n---\n`;
        let ws = await readFile('WORKSPACE.md') || '';
        wsStepUpdate(s1, `WORKSPACE.md read — ${ws.length} chars`, 'ok');

        ws += entry;
        const overLimit = ws.split('\n').length > 60 || ws.length > 12000;

        if (overLimit) {
            const s2 = wsStep('Context limit reached — archiving…', 'pending');
            let arch = await readFile('ARCHIVES.md') || '';
            arch += `\n## Archived ${ts}\n${ws}\n`;
            await writeFile('ARCHIVES.md', arch);
            wsStepUpdate(s2, `Archived to ARCHIVES.md (${arch.length} chars)`, 'ok');

            const s3 = wsStep('Resetting WORKSPACE.md…', 'pending');
            await writeFile('WORKSPACE.md', '# WORKSPACE.md — Current Context\n\n');
            wsStepUpdate(s3, 'WORKSPACE.md cleared', 'ok');
        } else {
            const s2 = wsStep(`Writing ${entry.length} chars to WORKSPACE.md…`, 'pending');
            await writeFile('WORKSPACE.md', ws);
            wsStepUpdate(s2, `WORKSPACE.md updated — ${ws.length} total chars`, 'ok');
        }

        wsStepDone('Workspace saved');
    }

    // ─── BM25 RAG ────────────────────────────────────────────
    const STOPWORDS = new Set(['a','an','and','are','as','at','be','but','by','for','if','in','into','is','it','no','not','of','on','or','the','to','was','will','with','i','you','he','she','we','me','my','am','have','do','can','may']);
    function stem(w) {
        if (w.length < 3) return w;
        if (w.endsWith('ing')) return w.slice(0,-3);
        if (w.endsWith('ed'))  return w.slice(0,-2);
        if (w.endsWith('ly'))  return w.slice(0,-2);
        if (w.endsWith('s') && !w.endsWith('ss')) return w.slice(0,-1);
        return w;
    }
    function tokenize(t) { return t.toLowerCase().split(/[^\w']+/).filter(w=>w.length>2&&!STOPWORDS.has(w)).map(stem); }

    class BM25 {
        constructor(k1=1.5,b=0.75){
            this.k1=k1; this.b=b;
            this.docs=[]; this.docFreqs=[]; this.docLengths=[];
            // ── O(1) avgDocLength: track running sum instead of reduce() ──
            // Old code: this.docLengths.reduce((a,b)=>a+b,0)/this.totalDocs
            // on every addDocument call — O(n) per doc, O(n²) total for a corpus.
            // New: keep a running totalTokens sum, divide once. Same result, O(1).
            this.avgDocLength=0; this._totalTokens=0;
            this.termDocFreq=new Map(); this.totalDocs=0;
        }
        addDocument(text) {
            const tokens=tokenize(text), freq=new Map();
            tokens.forEach(t=>freq.set(t,(freq.get(t)||0)+1));
            this.docFreqs.push(freq); this.docLengths.push(tokens.length);
            this.docs.push(text); this.totalDocs++;
            this._totalTokens += tokens.length;
            // O(1) incremental update — no reduce()
            this.avgDocLength = this._totalTokens / this.totalDocs;
            for(const t of freq.keys()) this.termDocFreq.set(t,(this.termDocFreq.get(t)||0)+1);
        }
        search(query,topK=3) {
            const qt=tokenize(query); if(!qt.length) return [];
            const scores=[];
            const avg=this.avgDocLength||1;
            for(let i=0;i<this.totalDocs;i++){
                let s=0;
                for(const t of qt){
                    const tf=this.docFreqs[i].get(t)||0; if(!tf) continue;
                    const df=this.termDocFreq.get(t)||0;
                    const idf=Math.log((this.totalDocs-df+0.5)/(df+0.5)+1);
                    s+=idf*(tf*(this.k1+1))/(tf+this.k1*(1-this.b+this.b*this.docLengths[i]/avg));
                }
                if(s>0) scores.push({text:this.docs[i],score:s}); // skip zero-score docs
            }
            return scores.sort((a,b)=>b.score-a.score).slice(0,topK);
        }
        save() { try{localStorage.setItem('aether_rag_docs',JSON.stringify(this.docs));}catch{} }
        load() { try{const s=localStorage.getItem('aether_rag_docs');if(s)JSON.parse(s).forEach(d=>this.addDocument(d));}catch{} }
    }
    // ─── RAG: prefer v2 hybrid engine, keep BM25 class for fallback ──
    const RAG_LEGACY = new BM25();
    try { RAG_LEGACY.load(); } catch (_) {}
    // Drop-in facade: addDocument/search/save used across the app
    const RAG = (typeof AETHER_RAGv2 !== 'undefined' && AETHER_RAGv2.legacyFacade)
        ? AETHER_RAGv2.legacyFacade
        : RAG_LEGACY;
    // Ensure v2 is warm + migrated
    if (typeof AETHER_RAGv2 !== 'undefined') {
        AETHER_RAGv2.ready().catch(function () {});
        // Proxy totalDocs for /version etc.
        try {
            Object.defineProperty(RAG, 'totalDocs', {
                get: function () {
                    try { return AETHER_RAGv2.stats().chunks; } catch (e) { return RAG_LEGACY.totalDocs || 0; }
                },
                configurable: true,
            });
        } catch (_) {}
    }
    window.RAG = RAG;
    window.AETHER_RAG = RAG;

    // ─── ORAMA VECTOR RAG (optional CDN) + v2 hash embeddings ─
    async function initOrama() {
        // v2 always has hash-vector hybrid — Orama is optional upgrade path
        if (typeof AETHER_RAGv2 !== 'undefined') {
            state.vectorRagEnabled = true;
            return { v2: true };
        }
        if (state.oramaDb) return state.oramaDb;
        try {
            const {create,insert,search:os} = await import('https://cdn.jsdelivr.net/npm/@orama/orama@2.0.6/+esm');
            const db = await create({schema:{id:'string',content:'string',embedding:'vector[384]'}});
            state.oramaDb = {db,insert,search:os};
            const saved = localStorage.getItem('aether_orama_docs');
            if (saved) for(const d of JSON.parse(saved)) await insert(db,d);
            showNotification('Vector RAG ready','success');
            return state.oramaDb;
        } catch(e) { console.warn('Orama unavailable'); return null; }
    }

    function textToEmbedding(text) {
        if (typeof AETHER_RAGv2 !== 'undefined' && AETHER_RAGv2.textToEmbedding) {
            return AETHER_RAGv2.textToEmbedding(text);
        }
        const vec = new Float32Array(384).fill(0);
        text.toLowerCase().replace(/[^a-z0-9\s]/g,' ').split(/\s+/).filter(Boolean).forEach(t=>{
            let h=0; for(let i=0;i<t.length;i++) h=(Math.imul(31,h)+t.charCodeAt(i))|0;
            vec[Math.abs(h)%384]+=1;
        });
        let norm=0; for(const v of vec) norm+=v*v; norm=Math.sqrt(norm)||1;
        return Array.from(vec).map(v=>v/norm);
    }

    async function addToVectorRAG(text, meta) {
        if (typeof AETHER_RAGv2 !== 'undefined') {
            await AETHER_RAGv2.addText(text, Object.assign({ collection: 'session', source: 'chat' }, meta || {}));
            return;
        }
        if (!state.vectorRagEnabled || !text) return;
        const o = state.oramaDb || await initOrama(); if(!o || o.v2) return;
        try {
            const doc = {id:'doc_'+Date.now(),content:text.slice(0,2000),embedding:textToEmbedding(text)};
            await o.insert(o.db, doc);
            const saved = JSON.parse(localStorage.getItem('aether_orama_docs')||'[]');
            saved.push(doc); if(saved.length>200) saved.splice(0,saved.length-200);
            localStorage.setItem('aether_orama_docs',JSON.stringify(saved));
        } catch {}
    }

    async function searchVectorRAG(query, topK=3) {
        if (typeof AETHER_RAGv2 !== 'undefined') {
            const r = await AETHER_RAGv2.search(query, { topK: topK, hybrid: true });
            return (r.hits || []).map(h => ({ text: h.text, score: h.score }));
        }
        if(!state.oramaDb) return [];
        try {
            const r = await state.oramaDb.search(state.oramaDb.db,{mode:'vector',vector:{value:textToEmbedding(query),property:'embedding'},limit:topK});
            return r.hits.map(h=>({text:h.document.content,score:h.score}));
        } catch { return []; }
    }

    /** RAG v2 hybrid retrieve → prompt block + citations for UI */
    async function retrieveRAGv2(query, opts) {
        opts = opts || {};
        if (typeof AETHER_RAGv2 === 'undefined') {
            const hits = RAG.search(query, opts.topK || 4);
            return {
                hits: hits,
                citations: hits.map((h, i) => ({ n: i + 1, source: 'memory', snippet: String(h.text).slice(0, 120), score: h.score })),
                contextBlock: hits.length
                    ? '# RAG CONTEXT\n' + hits.map((c, i) => (i + 1) + '. ' + String(c.text).slice(0, 400)).join('\n')
                    : '',
            };
        }
        return AETHER_RAGv2.search(query, {
            topK: opts.topK || 6,
            hybrid: opts.hybrid != null ? opts.hybrid : true,
            collection: opts.collection || null,
        });
    }

    function attachRagCitations(aetherMsgEl) {
        if (!aetherMsgEl) return;
        const last = window.__AETHER_LAST_RAG;
        if (!last || !last.citations || !last.citations.length) return;
        // Only attach if search is recent (< 2 min) and not already attached
        if (Date.now() - (last.t || 0) > 120000) return;
        if (aetherMsgEl.querySelector('.rag-citations')) return;
        try {
            if (typeof AETHER_RAGv2 !== 'undefined' && AETHER_RAGv2.renderCitationsHTML) {
                const wrap = document.createElement('div');
                wrap.innerHTML = AETHER_RAGv2.renderCitationsHTML(last.citations);
                if (wrap.firstChild) aetherMsgEl.appendChild(wrap.firstChild);
            }
        } catch (_) {}
    }

    // ─── PISTON API — Code Execution Engine ──────────────────
    // Piston is a remote code execution API (emkc.org). It supports
    // 60+ languages, has no auth requirement, and runs code in an
    // isolated sandbox. Free tier, public API.
    //
    // attachRunButton() now builds a full execution panel with:
    // - stdin field, execution time, ANSI color stripping
    // - clear/copy output buttons, runtime version badge
    // - graceful handling of compile errors vs runtime errors

    async function pistonGetRuntimes() {
        if (state.pistonRuntimes) return state.pistonRuntimes;
        try {
            const r = await fetch(`${window.PISTON_API}/runtimes`, { signal: AbortSignal.timeout(8000) });
            if (!r.ok) throw new Error('HTTP ' + r.status);
            state.pistonRuntimes = await r.json();
            return state.pistonRuntimes;
        } catch(e) {
            console.warn('[AETHER] Piston runtimes fetch failed:', e.message);
            return [];
        }
    }

    // Strip ANSI escape codes from terminal output
    function stripAnsi(s) {
        return (s || '').replace(/\x1B\[[0-9;]*[mGKHFABCDJsu]/g, '').replace(/\x1B\[[0-9]*[A-Z]/g, '');
    }

    async function pistonRun(lang, code, stdin='') {
        const rts = await pistonGetRuntimes();
        const nl = normLang(lang);
        const rt = rts
            .filter(r => r.language.toLowerCase() === nl || (r.aliases||[]).includes(nl))
            .sort((a, b) => b.version.localeCompare(a.version, undefined, { numeric: true }))[0];
        if (!rt) return { success: false, output: `No Piston runtime for "${lang}".\nAvailable: ${rts.slice(0,8).map(r=>r.language).join(', ')}…`, language: lang, version: '' };
        try {
            const t0 = Date.now();
            const res = await fetch(`${window.PISTON_API}/execute`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    language: rt.language,
                    version:  rt.version,
                    files:    [{ name: 'main', content: code }],
                    stdin,
                    run_timeout:     12000,
                    compile_timeout: 15000,
                }),
                signal: AbortSignal.timeout(20000),
            });
            if (!res.ok) return { success: false, output: `Piston HTTP ${res.status}: ${await res.text()}`, language: rt.language, version: rt.version };
            const d = await res.json();
            const elapsed = Date.now() - t0;

            const compileOut = stripAnsi(d.compile?.output || d.compile?.stderr || '').trim();
            const runOut     = stripAnsi(d.run?.output || '').trim();
            const runErr     = stripAnsi(d.run?.stderr || '').trim();
            const exitCode   = d.run?.code ?? d.compile?.code ?? 0;
            const success    = exitCode === 0;

            let output = '';
            if (compileOut && !success) output += '── Compile ──\n' + compileOut + '\n\n';
            if (runOut) output += runOut;
            if (runErr && runErr !== runOut) output += (runOut ? '\n\n── stderr ──\n' : '') + runErr;
            if (!output) output = success ? '(no output)' : 'Process exited with code ' + exitCode;

            return { success, output, language: rt.language, version: rt.version, elapsed, exitCode };
        } catch(e) {
            if (e.name === 'TimeoutError') return { success: false, output: 'Piston timed out after 20s — code may be in an infinite loop', language: rt.language, version: rt.version };
            return { success: false, output: 'Piston error: ' + e.message, language: lang, version: '' };
        }
    }

    function attachRunButton(wrapper, lang, code) {
        const supported = ['python','javascript','js','typescript','ts','rust','go','java','c','cpp','c++','ruby','php','bash','sh','lua','r','swift','kotlin','csharp','cs','haskell','perl','scala','dart','elixir','clojure','fsharp','nim','zig','powershell','groovy','julia'];
        const nl = normLang(lang);
        if (!supported.includes(nl) && !supported.includes(lang.toLowerCase())) return;
        const header = wrapper.querySelector('.cb-header,.code-header');
        if (!header) return;

        const runBtn = document.createElement('button');
        runBtn.className = 'code-run-btn';
        runBtn.innerHTML = '&#9654; Run';
        runBtn.title = 'Execute with Piston (sandboxed)';

        // ── Execution panel ───────────────────────────────────
        let panel = null;

        runBtn.onclick = async () => {
            // Toggle off if already showing
            if (panel) { panel.remove(); panel = null; runBtn.innerHTML = '&#9654; Run'; return; }

            // Build the execution panel
            panel = document.createElement('div');
            panel.className = 'piston-panel';

            // stdin row
            const stdinRow = document.createElement('div');
            stdinRow.className = 'piston-stdin-row';
            const stdinLabel = document.createElement('label');
            stdinLabel.textContent = 'stdin (optional):';
            stdinLabel.className = 'piston-stdin-label';
            const stdinInput = document.createElement('input');
            stdinInput.type = 'text';
            stdinInput.className = 'piston-stdin-input';
            stdinInput.placeholder = 'Input for your program…';
            stdinRow.appendChild(stdinLabel);
            stdinRow.appendChild(stdinInput);
            panel.appendChild(stdinRow);

            // Output area
            const outArea = document.createElement('div');
            outArea.className = 'piston-output-area';

            // Header bar
            const outHdr = document.createElement('div');
            outHdr.className = 'piston-out-header';

            const langBadge = document.createElement('span');
            langBadge.className = 'piston-lang-badge';
            langBadge.textContent = nl;

            const timeBadge = document.createElement('span');
            timeBadge.className = 'piston-time-badge';
            timeBadge.textContent = 'ready';

            const outActions = document.createElement('div');
            outActions.className = 'piston-out-actions';

            const copyOutBtn = document.createElement('button');
            copyOutBtn.className = 'piston-action-btn';
            copyOutBtn.textContent = 'Copy';

            const clearOutBtn = document.createElement('button');
            clearOutBtn.className = 'piston-action-btn';
            clearOutBtn.textContent = 'Clear';

            const closeBtn = document.createElement('button');
            closeBtn.className = 'piston-action-btn piston-close-btn';
            closeBtn.textContent = '✕';
            closeBtn.onclick = () => { panel.remove(); panel = null; runBtn.innerHTML = '&#9654; Run'; };

            outActions.appendChild(copyOutBtn);
            outActions.appendChild(clearOutBtn);
            outActions.appendChild(closeBtn);
            outHdr.appendChild(langBadge);
            outHdr.appendChild(timeBadge);
            outHdr.appendChild(outActions);

            const outPre = document.createElement('pre');
            outPre.className = 'piston-out-pre';
            outPre.textContent = '$ Waiting to run…';

            outArea.appendChild(outHdr);
            outArea.appendChild(outPre);
            panel.appendChild(outArea);

            // Execute button
            const execRow = document.createElement('div');
            execRow.className = 'piston-exec-row';
            const execBtn = document.createElement('button');
            execBtn.className = 'piston-exec-btn';
            execBtn.innerHTML = '&#9654; Execute';
            execRow.appendChild(execBtn);
            panel.appendChild(execRow);

            wrapper.appendChild(panel);

            // Wire buttons
            copyOutBtn.onclick = () => {
                navigator.clipboard.writeText(outPre.textContent).then(() => {
                    copyOutBtn.textContent = '✓ Copied';
                    setTimeout(() => { copyOutBtn.textContent = 'Copy'; }, 1500);
                });
            };
            clearOutBtn.onclick = () => {
                outPre.textContent = '$ Waiting to run…';
                outPre.className = 'piston-out-pre';
                timeBadge.textContent = 'ready';
            };

            const doRun = async () => {
                execBtn.disabled = true;
                execBtn.textContent = '⏳ Running…';
                runBtn.innerHTML = '⏳';
                outPre.textContent = '$ Executing…';
                outPre.className = 'piston-out-pre running';
                timeBadge.textContent = '…';

                const res = await pistonRun(nl, code, stdinInput.value);

                langBadge.textContent = (res.language || nl) + (res.version ? ' ' + res.version : '');
                timeBadge.textContent = res.elapsed ? (res.elapsed + 'ms') : '';
                outPre.textContent = res.output;
                outPre.className = 'piston-out-pre ' + (res.success ? 'success' : 'error');

                execBtn.disabled = false;
                execBtn.innerHTML = '&#9654; Run again';
                runBtn.innerHTML = res.success ? '✓ Done' : '✗ Error';
                setTimeout(() => { runBtn.innerHTML = '&#9654; Run'; }, 3000);
            };

            execBtn.onclick = doRun;
            // Auto-run on panel open
            await doRun();
        };

        header.appendChild(runBtn);
    }

    function escapeHtml(s) { return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

    // ─── OCR ─────────────────────────────────────────────────
    async function initPaddleOcr() {
        if(state.paddleOcr) return state.paddleOcr;
        if(typeof OcrBrowser==='undefined'){ocrEngine='tesseract';return null;}
        if(typeof ort!=='undefined'){ort.env.wasm.wasmPaths='https://cdn.jsdelivr.net/npm/onnxruntime-web@1.20.0/dist/';ort.env.wasm.numThreads=1;}
        try {
            const base='https://cdn.jsdelivr.net/npm/@gutenye/ocr-browser@1.4.8/dist/models';
            const ocr=await OcrBrowser.create({models:{detectionPath:`${base}/ch_PP-OCRv4_det_infer.onnx`,recognitionPath:`${base}/ch_PP-OCRv4_rec_infer.onnx`,dictionaryPath:`${base}/ppocr_keys_v1.txt`},isDebug:false});
            state.paddleOcr=ocr; ocrEngine='paddle';
            showNotification('PaddleOCR ready','success'); return ocr;
        } catch { ocrEngine='tesseract'; return null; }
    }
    async function processImageWithTesseract(file) {
        if(ocrStatus) ocrStatus.classList.remove('hidden');
        try {
            const r=await Tesseract.recognize(file,'eng',{logger:m=>{ if(m.status==='recognizing text'){if(ocrProgressText)ocrProgressText.textContent=`Recognizing ${Math.round(m.progress*100)}%`;if(ocrProgressFill)ocrProgressFill.style.width=Math.round(m.progress*100)+'%';}}});
            if(ocrConfidence) ocrConfidence.textContent=Math.round(r.data.confidence)+'%';
            setTimeout(()=>{if(ocrStatus)ocrStatus.classList.add('hidden');},2000);
            return {text:r.data.text.trim(),confidence:r.data.confidence/100,success:true};
        } catch(e){setTimeout(()=>{if(ocrStatus)ocrStatus.classList.add('hidden');},3000);return{text:'',confidence:0,success:false};}
    }
    async function processImageWithPaddle(file) {
        if(ocrEngine==='tesseract') return processImageWithTesseract(file);
        if(ocrStatus) ocrStatus.classList.remove('hidden');
        try {
            const ocr=await initPaddleOcr(); if(!ocr) return processImageWithTesseract(file);
            const url=URL.createObjectURL(file);
            if(ocrProgressFill) ocrProgressFill.style.width='50%';
            const result=await ocr.detect(url); URL.revokeObjectURL(url);
            if(ocrProgressFill) ocrProgressFill.style.width='100%';
            const text=result.map(l=>l.text).join('\n');
            const conf=result.reduce((a,l)=>a+l.score,0)/(result.length||1);
            if(ocrConfidence) ocrConfidence.textContent=Math.round(conf*100)+'%';
            setTimeout(()=>{if(ocrStatus)ocrStatus.classList.add('hidden');},2000);
            return{text,confidence:conf,success:true,lines:result};
        } catch(e){ocrEngine='tesseract';return processImageWithTesseract(file);}
    }
    // OCR package div
    const ocrPackageDiv = document.createElement('div');
    ocrPackageDiv.className = 'ocr-package hidden';
    ocrPackageDiv.innerHTML = '<svg class="ic-xs" style="flex-shrink:0"><use href="#ic-file"/></svg><span class="ocr-package-text">OCR text ready</span><button class="ocr-package-remove">&#x2715;</button>';
    document.querySelector('.input-deck').insertBefore(ocrPackageDiv, document.querySelector('.input-deck').firstChild);
    ocrPackageDiv.querySelector('.ocr-package-remove').addEventListener('click',()=>{ state.extractedOCRText=null; state.currentImageFile=null; ocrPackageDiv.classList.add('hidden'); });

    async function handleImageUpload(file) {
        if(!file||!file.type.startsWith('image/')){showNotification('Image files only','error');return;}
        state.currentImageFile = file;
        const reader=new FileReader();
        reader.onload=e=>{ if(previewImage) previewImage.src=e.target.result; if(imagePreview) imagePreview.classList.remove('hidden'); if(previewInfo) previewInfo.textContent=`${file.name} — Processing...`; };
        reader.readAsDataURL(file);
        try {
            const r=await processImageWithPaddle(file);
            if(r.success&&r.text.trim()){
                state.extractedOCRText=r.text.trim();
                ocrPackageDiv.querySelector('.ocr-package-text').textContent=`OCR: ${state.extractedOCRText.length} chars extracted`;
                ocrPackageDiv.classList.remove('hidden');
                if(previewInfo) previewInfo.textContent=`${state.extractedOCRText.length} chars, ${Math.round(r.confidence*100)}% conf`;
            } else { showNotification('No text detected','warn'); }
        } catch(e){ reportFeatureError('OCR', e); }
    }

    // Vision image
    // ─── MULTI-IMAGE ATTACHMENT (up to 10 per prompt) ────────
    const MAX_IMAGES = 10;
    let attachedImages = []; // [{file, base64, name}]

    function getImageGrid() { return document.getElementById('image-attach-grid'); }

    function renderImageGrid() {
        const grid = document.getElementById('image-attach-grid');
        if (!grid) return;
        grid.innerHTML = '';
        if (!attachedImages.length) { grid.style.display = 'none'; return; }
        grid.style.display = 'grid';

        // Header row: label + count/limit
        const header = document.createElement('div'); header.className = 'img-grid-header';
        const labelEl = document.createElement('span'); labelEl.className = 'img-grid-label';
        labelEl.textContent = 'Attached Images';
        const countEl = document.createElement('span'); countEl.className = 'img-grid-count';
        countEl.textContent = attachedImages.length + ' / ' + MAX_IMAGES;
        if (attachedImages.length >= MAX_IMAGES) countEl.classList.add('img-grid-count-full');
        header.appendChild(labelEl); header.appendChild(countEl);
        grid.appendChild(header);

        // Image cards
        const cardsWrap = document.createElement('div'); cardsWrap.className = 'img-cards-wrap';
        attachedImages.forEach((img, i) => {
            const card = document.createElement('div'); card.className = 'img-card';
            const thumb = document.createElement('div'); thumb.className = 'img-card-thumb';
            const imgEl = document.createElement('img'); imgEl.src = img.base64; imgEl.alt = img.name;
            thumb.appendChild(imgEl);
            const info = document.createElement('div'); info.className = 'img-card-info';
            const nameEl = document.createElement('div'); nameEl.className = 'img-card-name';
            // Truncate long names
            const shortName = img.name.length > 28 ? img.name.slice(0, 25) + '\u2026' : img.name;
            nameEl.textContent = shortName;
            const numEl = document.createElement('div'); numEl.className = 'img-card-num'; numEl.textContent = '#' + (i + 1);
            info.appendChild(nameEl); info.appendChild(numEl);
            const removeBtn = document.createElement('button'); removeBtn.className = 'img-card-remove'; removeBtn.innerHTML = '\u00d7';
            removeBtn.title = 'Remove'; removeBtn.onclick = (e) => { e.stopPropagation(); attachedImages.splice(i, 1); renderImageGrid(); updateImageCountBadge(); };
            card.appendChild(thumb); card.appendChild(info); card.appendChild(removeBtn);
            cardsWrap.appendChild(card);
        });

        // Add-more slot (only if under limit)
        if (attachedImages.length < MAX_IMAGES) {
            const addCard = document.createElement('div'); addCard.className = 'img-card img-card-add';
            addCard.title = 'Add image (' + attachedImages.length + '/' + MAX_IMAGES + ')';
            addCard.innerHTML = '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg><span>Add image</span>';
            addCard.onclick = () => { const inp = document.getElementById('image-btn-input'); if (inp) inp.click(); };
            cardsWrap.appendChild(addCard);
        }
        grid.appendChild(cardsWrap);
    }

    function updateImageCountBadge() {
        const badge = document.getElementById('img-count-badge');
        if (badge) {
            badge.textContent = attachedImages.length > 0 ? attachedImages.length : '';
            badge.style.display = attachedImages.length > 0 ? 'flex' : 'none';
        }
    }

    function handleVisionImageUpload(file) {
        if (!file || !file.type.startsWith('image/')) return;
        if (attachedImages.length >= MAX_IMAGES) {
            showNotification('Maximum ' + MAX_IMAGES + ' images per prompt', 'warn'); return;
        }
        const reader = new FileReader();
        reader.onload = e => {
            attachedImages.push({ file, base64: e.target.result, name: file.name });
            renderImageGrid();
            updateImageCountBadge();
            // Keep legacy single-image state for API compat
            state.visionImageFile   = file;
            state.visionImageBase64 = e.target.result;
            showNotification('Image ' + attachedImages.length + '/' + MAX_IMAGES + ' attached', 'success');
        };
        reader.readAsDataURL(file);
    }

    function removeVisionImage() {
        attachedImages = [];
        state.visionImageFile = null; state.visionImageBase64 = null;
        renderImageGrid(); updateImageCountBadge();
        if (visionPreviewEl) visionPreviewEl.classList.add('hidden');
    }

    function getAttachedImagesForAPI() {
        if (!attachedImages.length) return null;
        return attachedImages.map(img => {
            const mt = img.base64.split(';')[0].split(':')[1] || 'image/jpeg';
            const b64 = img.base64.split(',')[1];
            return { type: 'image_url', image_url: { url: 'data:' + mt + ';base64,' + b64, detail: 'auto' } };
        });
    }

    const visionPreviewEl     = $('vision-image-preview');
    const visionPreviewImg    = $('vision-preview-image');
    const visionPreviewInfo   = $('vision-preview-info');
    const visionPreviewRemove = $('vision-preview-remove');
    const visionMinimize      = $('vision-minimize-preview');
    const imageBtnEl          = $('image-btn');
    const imageBtnInput       = $('image-btn-input');

    if (imageBtnEl) {
        // Add count badge to image button
        const badge = document.createElement('span'); badge.id = 'img-count-badge'; badge.className = 'img-count-badge'; badge.style.display = 'none';
        imageBtnEl.style.position = 'relative';
        imageBtnEl.appendChild(badge);
        imageBtnEl.addEventListener('click', () => imageBtnInput && imageBtnInput.click());
    }
    if (imageBtnInput) {
        imageBtnInput.setAttribute('multiple', 'multiple'); // allow multi-select
        imageBtnInput.addEventListener('change', e => {
            const files = Array.from(e.target.files || []);
            files.slice(0, MAX_IMAGES - attachedImages.length).forEach(f => handleVisionImageUpload(f));
            e.target.value = ''; // reset so same file can be added after remove
        });
    }
    if (visionPreviewRemove) visionPreviewRemove.addEventListener('click', removeVisionImage);
    if (visionMinimize) visionMinimize.addEventListener('click', () => {
        state.visionImagePreviewMinimized = !state.visionImagePreviewMinimized;
        if (visionPreviewEl) visionPreviewEl.classList.toggle('minimized', state.visionImagePreviewMinimized);
    });

    // Drag-and-drop — accept multiple images
    const inputWrapper = document.querySelector('.input-wrapper');
    if (inputWrapper) {
        inputWrapper.addEventListener('dragover',  e => { e.preventDefault(); inputWrapper.classList.add('drag-over'); });
        inputWrapper.addEventListener('dragleave', () => inputWrapper.classList.remove('drag-over'));
        inputWrapper.addEventListener('drop', e => {
            e.preventDefault(); inputWrapper.classList.remove('drag-over');
            const files = Array.from(e.dataTransfer.files || []).filter(f => f.type.startsWith('image/'));
            files.slice(0, MAX_IMAGES - attachedImages.length).forEach(f => handleVisionImageUpload(f));
        });
    }

    // ─── DOCUMENT UPLOAD ─────────────────────────────────────
    async function handleDocumentUpload(file) {
        const ext=file.name.split('.').pop().toLowerCase();
        let content='';
        try {
            if(ext==='docx'){
                const ab=await new Promise((res,rej)=>{const r=new FileReader();r.onload=e=>res(e.target.result);r.onerror=rej;r.readAsArrayBuffer(file);});
                content=(await mammoth.extractRawText({arrayBuffer:ab})).value;
            } else if(['txt','md','json','js','py','csv','html','css','xml','yaml','yml','ini','cfg','sh','go','rs','java','c','cpp','rb','lua','sql'].includes(ext)){
                content=await new Promise((res,rej)=>{const r=new FileReader();r.onload=e=>res(e.target.result);r.onerror=rej;r.readAsText(file);});
            } else { showNotification('Unsupported file type','error'); return; }
            if(state.ragEnabled){ RAG.addDocument(content); RAG.save(); showNotification(`"${file.name}" added to RAG (${content.length} chars)`,'success'); }
        } catch(e){ reportFeatureError('Document Processing', e); }
    }
    function removeImagePreview(){ if(imagePreview) imagePreview.classList.add('hidden'); state.currentImageFile=null; state.extractedOCRText=null; }
    function togglePreviewMinimize(){ state.previewMinimized=!state.previewMinimized; if(imagePreview) imagePreview.classList.toggle('minimized',state.previewMinimized); }

    // ─── SDF LIBRARY ─────────────────────────────────────────
    const SDF = {
        sphere:(p,r)=>p.length()-r,
        box:(p,b)=>{ const d=new Vec3(Math.abs(p.x)-b.x,Math.abs(p.y)-b.y,Math.abs(p.z)-b.z); return Math.min(Math.max(d.x,Math.max(d.y,d.z)),0)+Math.sqrt(Math.max(d.x,0)**2+Math.max(d.y,0)**2+Math.max(d.z,0)**2); },
        torus:(p,r1,r2)=>Math.sqrt((Math.sqrt(p.x*p.x+p.z*p.z)-r1)**2+p.y*p.y)-r2,
        cylinder:(p,r,h)=>Math.max(Math.sqrt(p.x*p.x+p.z*p.z)-r,Math.abs(p.y)-h/2),
        cone:(p,r,h)=>{ const q=Math.sqrt(p.x*p.x+p.z*p.z); return Math.max(-p.y-h/2,Math.sqrt((q-r)**2+(p.y-h/2)**2)-r*0.1); },
        capsule:(p,r,h)=>{ const q=new Vec3(p.x,Math.abs(p.y)-h,p.z); return (q.y>0?q.length():Math.sqrt(q.x*q.x+q.z*q.z))-r; },
        smoothUnion:(a,b,k)=>{ const h=Math.max(k-Math.abs(a-b),0)/k; return Math.min(a,b)-h*h*k*0.25; },
        union:(a,b)=>Math.min(a,b),
        sub:(a,b)=>Math.max(-a,b),
        rep:(p,c)=>new Vec3(((p.x%c+c)%c)-c/2,((p.y%c+c)%c)-c/2,((p.z%c+c)%c)-c/2)
    };
    window.SDF = SDF; // expose for canvas renderer

    // ─── ADVANCED ASCII RENDERER ─────────────────────────────
    let asciiScene = [];
    let asciiAnimFrame = null;
    let asciiAnimAngle = 0;
    let asciiAnimating = false;
    let asciiCurrentSceneName = 'sphere';
    let asciiAO = true, asciiShadows = true, asciiColor = true;

    // Scene definitions
    const SCENES = {
        sphere: (t) => ([
            {type:'sphere',pos:[Math.sin(t)*0.5,0.5+Math.cos(t*0.7)*0.3,5],r:1.5,color:[80,160,255]},
            {type:'torus',pos:[0,-1.2,5],r1:2.5,r2:0.25,color:[40,40,60]},
            {type:'sphere',pos:[-2.5,0.2,6],r:0.6,color:[255,120,60]},
            {type:'sphere',pos:[2.5,0.2,6],r:0.6,color:[60,255,120]},
        ]),
        torus: (t) => ([
            {type:'torus',pos:[0,Math.sin(t)*0.3,5],r1:1.5,r2:0.45,color:[255,200,80]},
            {type:'torus',pos:[0,0,5],r1:2.5,r2:0.15,color:[255,100,200]},
            {type:'sphere',pos:[0,0,5],r:0.3,color:[255,255,255]},
        ]),
        multi: (t) => ([
            {type:'sphere',pos:[-2.5+Math.sin(t)*0.3,0.5,4.5],r:0.9,color:[80,200,100]},
            {type:'box',pos:[1.5,0.3,5.5],size:[0.9,0.9,0.9],color:[200,80,80]},
            {type:'cylinder',pos:[0,-0.5,6],r:0.7,h:1.5,color:[255,220,80]},
            {type:'torus',pos:[0,1.5,4],r1:0.8,r2:0.2,color:[150,80,255]},
        ]),
        city: (t) => {
            const s=[]; const grid=[[-2,-3],[0,-3],[2,-3],[-3,0],[-1,0],[1,0],[3,0],[-2,3],[0,3],[2,3]];
            grid.forEach(([x,z],i)=>{
                const h=0.6+((i*7+3)%5)*0.4+Math.sin(t*0.3+i)*0.1;
                s.push({type:'box',pos:[x,-1+h/2,4+z],size:[0.4,h,0.4],color:[40+i*15,80+i*10,120+i*5]});
            });
            s.push({type:'sphere',pos:[0,2.5,5],r:0.3,color:[255,255,100]});
            return s;
        },
        robot: (t) => ([
            {type:'box',pos:[0,1.3,5],size:[0.6,0.5,0.5],color:[180,190,200]},  // head
            {type:'box',pos:[0,0.3,5],size:[0.8,0.8,0.5],color:[150,160,170]},  // torso
            {type:'cylinder',pos:[-0.7,0.3+Math.sin(t)*0.2,5],r:0.2,h:0.7,color:[130,140,150]},
            {type:'cylinder',pos:[0.7,0.3-Math.sin(t)*0.2,5],r:0.2,h:0.7,color:[130,140,150]},
            {type:'cylinder',pos:[-0.3,-0.6+Math.sin(t+0.5)*0.1,5],r:0.22,h:0.8,color:[120,130,140]},
            {type:'cylinder',pos:[0.3,-0.6-Math.sin(t+0.5)*0.1,5],r:0.22,h:0.8,color:[120,130,140]},
            {type:'sphere',pos:[-0.25,1.4,4.6],r:0.1,color:[0,255,200]},  // eye
            {type:'sphere',pos:[0.25,1.4,4.6],r:0.1,color:[0,255,200]},   // eye
        ]),
        atom: (t) => {
            const s=[{type:'sphere',pos:[0,0,5],r:0.3,color:[255,220,80]}];
            const orbits=[[1.8,0,0],[0,0,1],[0.7,0.7,0]];
            orbits.forEach((ax,i)=>{
                const a=t*1.5+i*(Math.PI*2/3);
                const px=Math.cos(a)*ax[0]+Math.sin(a)*ax[2]*0.5;
                const py=Math.cos(a)*ax[1]+Math.sin(a)*0.5;
                const pz=5+Math.sin(a)*ax[0]*0.5+Math.cos(a)*ax[2];
                s.push({type:'sphere',pos:[px,py,pz],r:0.18,color:[80+i*60,180-i*40,255-i*60]});
            });
            s.push({type:'torus',pos:[0,0,5],r1:1.8,r2:0.04,color:[80,120,200]});
            s.push({type:'torus',pos:[0,0,5],r1:1.8,r2:0.04,color:[80,200,120],rotX:Math.PI/3});
            s.push({type:'torus',pos:[0,0,5],r1:1.8,r2:0.04,color:[200,80,120],rotX:-Math.PI/3});
            return s;
        },
        // Enhanced scene: fractal cube cloud
        fractals: (t) => {
            const s = [];
            const golden = 1.618;
            for (let i = 0; i < 7; i++) {
                const a = (i / 7) * Math.PI * 2 + t * 0.4;
                const r = 1.6, y = Math.sin(t * 0.3 + i * 0.8) * 0.4;
                const sc = 0.3 + 0.15 * Math.sin(t + i * golden);
                const hue = (i / 7) * 360;
                const [cr, cg, cb] = hslToRgb(hue, 90, 60);
                s.push({ type:'box', pos:[Math.cos(a)*r, y, 5+Math.sin(a)*r], size:[sc,sc,sc], color:[cr,cg,cb] });
            }
            s.push({ type:'sphere', pos:[0, 0, 5], r:0.4, color:[200,220,255] });
            return s;
        },
        // DNA helix
        helix: (t) => {
            const s = [];
            for (let i = 0; i < 12; i++) {
                const a1 = (i/12)*Math.PI*4 + t;
                const a2 = a1 + Math.PI;
                const y = (i/12)*3 - 1.5;
                const z = 5;
                s.push({ type:'sphere', pos:[Math.cos(a1)*0.8, y, z+Math.sin(a1)*0.8], r:0.18, color:[80,200,255] });
                s.push({ type:'sphere', pos:[Math.cos(a2)*0.8, y, z+Math.sin(a2)*0.8], r:0.18, color:[255,80,160] });
                if (i % 3 === 0) {
                    s.push({ type:'capsule', pos:[Math.cos(a1)*0.8*0.5, y, z+Math.sin(a1)*0.8*0.5], r:0.06, h:0.8, color:[200,200,200] });
                }
            }
            return s;
        },
        station: (t) => ([
            {type:'cylinder',pos:[0,0,5],r:0.15,h:3.5,color:[200,180,140]},   // pole
            {type:'box',pos:[0,1.2,5],size:[2.5,0.15,0.15],color:[180,160,100]},  // crossbar
            {type:'sphere',pos:[-1.2,1.2,5],r:0.25,color:[255,100,50]},        // left light
            {type:'sphere',pos:[1.2,1.2,5],r:0.25,color:[255,220,50]},         // right light
            {type:'box',pos:[0,-0.5,5],size:[0.8,0.1,0.5],color:[100,100,120]},// base
            {type:'box',pos:[Math.sin(t)*2,-0.3,5+Math.cos(t)*1],size:[0.05,0.8,0.05],color:[200,200,220]}, // swinging sign
        ]),
        crystal: (t) => {
            const s=[];
            const crystals=[
                {p:[0,0,5],sc:1.0,c:[180,100,255]},
                {p:[-1.5,0.3,5.5],sc:0.6,c:[80,200,255]},
                {p:[1.5,-0.2,5.5],sc:0.7,c:[255,80,180]},
                {p:[0.5,0.8,4.5],sc:0.5,c:[100,255,180]},
                {p:[-0.8,-0.5,4.8],sc:0.55,c:[255,200,80]},
            ];
            crystals.forEach((cr,i)=>{
                const rot=t*0.3+i;
                s.push({type:'box',pos:[cr.p[0]+Math.sin(rot)*0.05,cr.p[1],cr.p[2]],size:[0.25*cr.sc,0.7*cr.sc,0.25*cr.sc],color:cr.c});
                s.push({type:'cone',pos:[cr.p[0]+Math.sin(rot)*0.05,cr.p[1]+0.8*cr.sc,cr.p[2]],r:0.3*cr.sc,h:0.5*cr.sc,color:cr.c.map(v=>Math.min(255,v+50))});
            });
            return s;
        },
        // Solar system
        solar: (t) => {
            const s = [{type:'sphere',pos:[0,0,5],r:0.5,color:[255,220,80]}];
            for (let i = 0; i < 8; i++) {
                const a = t * (0.5 + i * 0.1) + i * 0.8;
                const dist = 1.2 + i * 0.35;
                const rad = 0.08 + i * 0.03;
                const hue = i * 45;
                const [cr,cg,cb] = hslToRgb(hue, 80, 60);
                const px = Math.cos(a) * dist;
                const pz = 5 + Math.sin(a) * dist;
                s.push({ type:'sphere', pos:[px, Math.sin(t * 0.3 + i) * 0.1, pz], r:rad, color:[cr,cg,cb] });
                s.push({ type:'torus', pos:[0, 0, 5], r1:dist, r2:0.015, color:[60,60,80] });
            }
            s.push({ type:'torus', pos:[0, 0, 5], r1:3.8, r2:0.02, color:[80,60,40] });
            return s;
        },
        // Galaxy spiral
        galaxy: (t) => {
            const s = [];
            for (let i = 0; i < 60; i++) {
                const a = i * 0.4 + t * 0.2;
                const r = 0.5 + (i / 60) * 3.5;
                const spread = (1 - i / 60) * 0.3 + 0.05;
                const py = Math.sin(i * 0.7 + t) * spread;
                const px = Math.cos(a) * r;
                const pz = 5 + Math.sin(a) * r;
                const rad = 0.04 + (1 - i / 60) * 0.12;
                const hue = (i * 12 + t * 30) % 360;
                const [cr,cg,cb] = hslToRgb(hue, 90, 55 + (1 - i / 60) * 30);
                s.push({ type:'sphere', pos:[px, py, pz], r:rad, color:[cr,cg,cb] });
            }
            return s;
        },
        // Terrain with heightmap
        terrain: (t) => {
            const s = [];
            const res = 16;
            for (let ix = 0; ix < res; ix++) {
                for (let iz = 0; iz < res; iz++) {
                    const x = (ix / res - 0.5) * 6;
                    const z = (iz / res - 0.5) * 6 + 4;
                    const h = Math.sin(x * 1.2 + t * 0.5) * 0.3 + Math.sin(z * 0.8 + t * 0.3) * 0.25 + Math.sin((x + z) * 0.5 + t * 0.4) * 0.15 + 0.2;
                    const col = Math.floor(80 + h * 120);
                    s.push({ type:'box', pos:[x, h / 2 - 0.3, z], size:[6 / res, Math.max(0.05, h), 6 / res], color:[col, col + 40, col + 20] });
                }
            }
            return s;
        },
    };

    function hslToRgb(h, s, l) {
        h /= 360; s /= 100; l /= 100;
        const a = s * Math.min(l, 1-l);
        const f = (n, k=(n+h*12)%12) => l - a * Math.max(-1, Math.min(k-3, 9-k, 1));
        return [Math.round(f(0)*255), Math.round(f(8)*255), Math.round(f(4)*255)];
    }

    function buildScene(name, t) {
        const fn = SCENES[name];
        if (!fn) return [];
        const raw = fn(t);
        return raw.map(o => ({
            type: o.type,
            pos: new Vec3(o.pos[0], o.pos[1], o.pos[2]),
            r: o.r || 0,
            r1: o.r1 || 0, r2: o.r2 || 0,
            size: o.size ? new Vec3(o.size[0], o.size[1], o.size[2]) : new Vec3(1,1,1),
            h: o.h || 1,
            color: o.color ? {r:o.color[0],g:o.color[1],b:o.color[2]} : {r:150,g:180,b:220}
        }));
    }
    window._buildScene = buildScene; // expose for canvas renderer

    function sceneDist(p) {
        let minD = Infinity;
        let minIdx = -1;
        for (let i = 0; i < asciiScene.length; i++) {
            const o = asciiScene[i];
            const lp = p.sub(o.pos);
            let d;
            switch(o.type){
                case 'sphere':   d=SDF.sphere(lp, o.r); break;
                case 'box':      d=SDF.box(lp, o.size); break;
                case 'torus':    d=SDF.torus(lp, o.r1, o.r2); break;
                case 'cylinder': d=SDF.cylinder(lp, o.r, o.h); break;
                case 'cone':     d=SDF.cone(lp, o.r, o.h); break;
                case 'capsule':  d=SDF.capsule(lp, o.r, o.h); break;
                default: continue;
            }
            if (d < minD) { minD = d; minIdx = i; }
        }
        return { d: minD, idx: minIdx };
    }

    function sceneDistOnly(p) { return sceneDist(p).d; }

    function getNormal(p) {
        const eps = 0.002;
        return new Vec3(
            sceneDistOnly(p.add(new Vec3(eps,0,0))) - sceneDistOnly(p.sub(new Vec3(eps,0,0))),
            sceneDistOnly(p.add(new Vec3(0,eps,0))) - sceneDistOnly(p.sub(new Vec3(0,eps,0))),
            sceneDistOnly(p.add(new Vec3(0,0,eps))) - sceneDistOnly(p.sub(new Vec3(0,0,eps)))
        ).normalize();
    }

    function calcAO(p, n) {
        if (!asciiAO) return 1;
        let ao = 0;
        const steps = 5, stepSize = 0.12;
        for (let i = 1; i <= steps; i++) {
            const sp = p.add(n.mul(i * stepSize));
            ao += Math.max(0, i * stepSize - sceneDistOnly(sp)) / stepSize;
        }
        return Math.max(0, 1 - ao * 0.3);
    }

    function calcSoftShadow(p, lightDir) {
        if (!asciiShadows) return 1;
        let shadow = 1, t = 0.15;
        for (let i = 0; i < 24 && t < 8; i++) {
            const d = sceneDistOnly(p.add(lightDir.mul(t)));
            if (d < 0.001) return 0.05;
            shadow = Math.min(shadow, 8 * d / t);
            t += Math.max(0.02, d * 0.6);
        }
        return Math.max(0.05, shadow);
    }

    function march(ro, rd) {
        let t = 0;
        for (let i = 0; i < 96; i++) {
            const p = ro.add(rd.mul(t));
            const {d, idx} = sceneDist(p);
            if (d < 0.0005) return { hit:true, point:p, dist:t, idx };
            t += d * 0.85;
            if (t > 30) break;
        }
        return { hit:false };
    }

    // Enhanced ASCII shading: 70-char ramp, multi-light, soft AO, specular
    let asciiQuality = 'standard'; // 'standard' | 'high' — toggled by quality button
    const ASCII_RAMP = '  .:;+=xX$&#@█▓▒░';
    const ASCII_RAMP_FINE = '  .:;rljftizasT1FLE?7cJIuvXZYUAKw*n3qmGdOb0p4deh6P8R9#&@▒▓█';

    function shade(p, n, idx, dist) {
        if (idx < 0 || idx >= asciiScene.length) return {char:' ',r:0,g:0,b:0};
        const obj = asciiScene[idx];

        // Multi-light model
        const lights = [
            { dir: new Vec3(0.6, 1.0, -0.4).normalize(), col: [255, 245, 220], intensity: 0.85 },
            { dir: new Vec3(-0.8, 0.4, 0.6).normalize(), col: [80, 120, 200],  intensity: 0.25 },
            { dir: new Vec3(0.0, -0.5, -1.0).normalize(), col: [200, 80, 60],   intensity: 0.1 },
        ];

        let lr=0,lg=0,lb=0;
        for (const light of lights) {
            let diff = Math.max(0, n.dot(light.dir));
            // Soft shadow
            if (asciiShadows && diff > 0.01) {
                const shadowOrig = p.add(n.scale(0.015));
                const shadowHit = marchShadow(shadowOrig, light.dir, 8);
                diff *= shadowHit;
            }
            // Specular (Blinn-Phong)
            const camDir = new Vec3(0,0,-1);
            const half = light.dir.add(camDir.scale(-1)).normalize();
            const spec = Math.pow(Math.max(0, n.dot(half)), 32) * 0.4;
            const total = diff + spec;
            lr += light.col[0] * total * light.intensity;
            lg += light.col[1] * total * light.intensity;
            lb += light.col[2] * total * light.intensity;
        }

        // Ambient occlusion
        const ao = asciiAO ? calcAO(p, n) : 1.0;
        const ambient = 0.12 * ao;

        // Final color
        const cr = Math.min(255, Math.floor((obj.color.r / 255) * (lr + ambient * 255)));
        const cg = Math.min(255, Math.floor((obj.color.g / 255) * (lg + ambient * 255)));
        const cb = Math.min(255, Math.floor((obj.color.b / 255) * (lb + ambient * 255)));

        // Character selection — use fine ramp for high quality
        const ramp = (typeof asciiQuality !== 'undefined' && asciiQuality === 'high') ? ASCII_RAMP_FINE : ASCII_RAMP;
        const br = (cr * 0.299 + cg * 0.587 + cb * 0.114) / 255;
        const charIdx = Math.min(ramp.length - 1, Math.floor(br * ramp.length));
        const char = ramp[charIdx] || ' ';

        return { char, r: cr, g: cg, b: cb };
    }

    function marchShadow(orig, dir, maxDist) {
        let t = 0.02, res = 1.0;
        for (let i = 0; i < 16; i++) {
            const d = sceneDistOnly(orig.add(dir.scale(t)));
            if (d < 0.001) return 0.0;
            res = Math.min(res, 8.0 * d / t);
            t += Math.max(0.02, d);
            if (t > maxDist) break;
        }
        return Math.max(0.0, res);
    }

    function renderASCIIFrame(w, h) {
        const fov = Math.PI/3;
        const aspect = w / (h * 2);
        const camPos = new Vec3(0, 1, -3);
        let out = '';
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const ndcX = ((x+0.5)/w)*2-1;
                const ndcY = 1-((y+0.5)/h)*2;
                const rd = new Vec3(ndcX*Math.tan(fov/2)*aspect, ndcY*Math.tan(fov/2), 1).normalize();
                const hit = march(camPos, rd);
                if (hit.hit) {
                    const n = getNormal(hit.point);
                    const {char,r,g,b} = shade(hit.point, n, hit.idx, hit.dist);
                    if (asciiColor) {
                        out += `<span style="color:rgb(${r},${g},${b})">${char}</span>`;
                    } else {
                        const br = Math.floor((r+g+b)/3);
                        out += `<span style="color:rgb(${br},${br},${br})">${char}</span>`;
                    }
                } else {
                    // Background gradient
                    const bgBr = Math.floor((0.5 - Math.abs(ndcY)*0.3)*20);
                    out += `<span style="color:rgb(${bgBr},${bgBr},${bgBr*2})"> </span>`;
                }
            }
            out += '\n';
        }
        return out;
    }

    function renderScene(name) {
        asciiCurrentSceneName = name;
        const w = parseInt(asciiWidth.value,10)||90;
        const h = parseInt(asciiHeight.value,10)||45;
        asciiAO = $('ascii-ao')?.checked ?? true;
        asciiShadows = $('ascii-shadows')?.checked ?? true;
        asciiColor = $('ascii-color')?.checked ?? true;
        asciiScene = buildScene(name, asciiAnimAngle);
        asciiOutput.innerHTML = renderASCIIFrame(w, h);
    }

    function startAsciiAnim() {
        if (asciiAnimating) { stopAsciiAnim(); return; }
        asciiAnimating = true;
        const animBtn = $('ascii-anim-btn');
        if (animBtn) animBtn.innerHTML = '&#9646;&#9646; Stop';
        const w = parseInt(asciiWidth.value,10)||90;
        const h = parseInt(asciiHeight.value,10)||45;
        const step = () => {
            if (!asciiAnimating) return;
            asciiAnimAngle += 0.06;
            asciiScene = buildScene(asciiCurrentSceneName, asciiAnimAngle);
            asciiOutput.innerHTML = renderASCIIFrame(w, h);
            asciiAnimFrame = setTimeout(step, 80);
        };
        step();
    }
    function stopAsciiAnim() {
        asciiAnimating = false;
        if (asciiAnimFrame) { clearTimeout(asciiAnimFrame); asciiAnimFrame = null; }
        const animBtn = $('ascii-anim-btn');
        if (animBtn) animBtn.innerHTML = '&#9654; Animate';
    }

    // Bind ASCII buttons
    btnAscii.addEventListener('click', () => asciiModal.classList.remove('hidden'));
    asciiClose.addEventListener('click', () => { stopAsciiAnim(); asciiModal.classList.add('hidden'); });
    $('ascii-anim-btn').addEventListener('click', startAsciiAnim);
    document.querySelectorAll('.ascii-scene-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            document.querySelectorAll('.ascii-scene-btn').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            stopAsciiAnim();
            asciiOutput.textContent = 'Rendering...';
            setTimeout(() => renderScene(btn.dataset.scene), 10);
        });
    });
    ['ascii-ao','ascii-shadows','ascii-color'].forEach(id => {
        const el = $(id); if(el) el.addEventListener('change', () => { if(asciiCurrentSceneName) renderScene(asciiCurrentSceneName); });
    });

    // ── Canvas mode (interactive full-screen 3D) ─────────────
    let asciiCanvasRenderer = null;
    const asciiCanvasOverlay = document.getElementById('ascii-canvas-overlay');
    const ascii3dCanvas = document.getElementById('ascii-3d-canvas');
    const asciiCanvasClose = document.getElementById('ascii-canvas-close');
    const asciiCanvasQuality = document.getElementById('ascii-canvas-quality');
    const asciiCanvasBtn = document.getElementById('ascii-canvas-btn');

    function startASCIICanvasMode() {
        if (!asciiCanvasOverlay || !ascii3dCanvas) return;
        asciiCanvasOverlay.classList.remove('hidden');
        asciiCanvasRenderer = startASCIIRenderer(ascii3dCanvas);
        // Set active scene from modal
        const activeBtn = document.querySelector('.ascii-scene-btn.active');
        if (activeBtn) asciiCanvasRenderer.setScene(activeBtn.dataset.scene);
        asciiCanvasRenderer.start();

        // Resize handler
        const onResize = () => {
            if (asciiCanvasRenderer) asciiCanvasRenderer.resize();
        };
        window.addEventListener('resize', onResize);
        asciiCanvasRenderer._resizeHandler = onResize;

        // Keyboard close
        const onKey = (e) => {
            if (e.key === 'Escape') stopASCIICanvasMode();
        };
        window.addEventListener('keydown', onKey);
        asciiCanvasRenderer._keyHandler = onKey;
    }

    function stopASCIICanvasMode() {
        if (asciiCanvasRenderer) {
            if (asciiCanvasRenderer._resizeHandler) window.removeEventListener('resize', asciiCanvasRenderer._resizeHandler);
            if (asciiCanvasRenderer._keyHandler) window.removeEventListener('keydown', asciiCanvasRenderer._keyHandler);
            asciiCanvasRenderer.stop();
            asciiCanvasRenderer = null;
        }
        if (asciiCanvasOverlay) asciiCanvasOverlay.classList.add('hidden');
    }

    if (asciiCanvasBtn) {
        asciiCanvasBtn.addEventListener('click', () => {
            stopAsciiAnim();
            asciiModal.classList.add('hidden');
            startASCIICanvasMode();
        });
    }
    if (asciiCanvasClose) {
        asciiCanvasClose.addEventListener('click', stopASCIICanvasMode);
    }
    if (asciiCanvasQuality) {
        asciiCanvasQuality.addEventListener('click', () => {
            if (!asciiCanvasRenderer) return;
            // We store quality on renderer — toggle via exposed API
            asciiCanvasRenderer.quality = asciiCanvasRenderer.quality === 'high' ? 'fast' : 'high';
            asciiCanvasQuality.textContent = asciiCanvasRenderer.quality === 'high' ? '⚡' : '🔆';
        });
    }

    // ─── CANVAS WORKBENCH ────────────────────────────────────
    let canvasActiveTool = null, canvasDrawing = false, canvasStartX = 0, canvasStartY = 0, canvasSnapshot = null;
    btnCanvas.addEventListener('click', () => canvasModal.classList.remove('hidden'));
    canvasClose.addEventListener('click', () => canvasModal.classList.add('hidden'));
    canvasUpload.addEventListener('click', () => canvasFileInput.click());
    canvasFileInput.addEventListener('change', async e => {
        const file = e.target.files[0]; if(!file) return;
        if(file.type==='application/pdf'){
            if(typeof pdfjsLib==='undefined'){showNotification('PDF.js not loaded','error');return;}
            pdfjsLib.GlobalWorkerOptions.workerSrc='https://cdnjs.cloudflare.com/ajax/libs/pdf.js/2.16.105/pdf.worker.min.js';
            const pdf=await pdfjsLib.getDocument(URL.createObjectURL(file)).promise;
            const page=await pdf.getPage(1);
            const vp=page.getViewport({scale:1.5});
            canvasDisplay.width=vp.width; canvasDisplay.height=vp.height;
            await page.render({canvasContext:canvasCtx,viewport:vp}).promise;
        } else {
            const reader=new FileReader();
            reader.onload=ev=>{ const img=new Image(); img.onload=()=>{ canvasDisplay.width=Math.min(img.width,1200); canvasDisplay.height=Math.round(img.height*(canvasDisplay.width/img.width)); canvasCtx.drawImage(img,0,0,canvasDisplay.width,canvasDisplay.height); }; img.src=ev.target.result; };
            reader.readAsDataURL(file);
        }
        canvasContainer.style.display='block';
    });
    document.querySelectorAll('.canvas-tool').forEach(btn => {
        btn.addEventListener('click', e => {
            const tool=e.currentTarget.dataset.tool;
            if(tool==='clear'){canvasCtx.clearRect(0,0,canvasDisplay.width,canvasDisplay.height);return;}
            canvasActiveTool=tool;
            document.querySelectorAll('.canvas-tool').forEach(b=>b.classList.remove('active'));
            e.currentTarget.classList.add('active');
        });
    });
    function getCanvasPos(e){
        const rect=canvasDisplay.getBoundingClientRect();
        return{x:((e.touches?e.touches[0].clientX:e.clientX)-rect.left)*(canvasDisplay.width/rect.width),y:((e.touches?e.touches[0].clientY:e.clientY)-rect.top)*(canvasDisplay.height/rect.height)};
    }
    canvasDisplay.addEventListener('mousedown',cpDown); canvasDisplay.addEventListener('touchstart',e=>{e.preventDefault();cpDown(e);},{passive:false});
    canvasDisplay.addEventListener('mousemove',cpMove); canvasDisplay.addEventListener('touchmove',e=>{e.preventDefault();cpMove(e);},{passive:false});
    canvasDisplay.addEventListener('mouseup',()=>canvasDrawing=false); canvasDisplay.addEventListener('touchend',()=>canvasDrawing=false);
    function cpDown(e){
        if(!canvasActiveTool) return;
        const pos=getCanvasPos(e);
        if(canvasActiveTool==='text'){
            showDialog({title:'Canvas Text',message:'Enter text to place:',type:'prompt',default:'Text'}).then(t=>{ if(t){canvasCtx.font='bold 20px Courier New';canvasCtx.fillStyle='#00f3ff';canvasCtx.fillText(t,pos.x,pos.y);} });
            return;
        }
        canvasDrawing=true; canvasStartX=pos.x; canvasStartY=pos.y;
        canvasSnapshot=canvasCtx.getImageData(0,0,canvasDisplay.width,canvasDisplay.height);
        if(canvasActiveTool==='freehand'){canvasCtx.beginPath();canvasCtx.strokeStyle='#00f3ff';canvasCtx.lineWidth=2;canvasCtx.moveTo(pos.x,pos.y);}
    }
    function cpMove(e){
        if(!canvasDrawing||!canvasActiveTool) return;
        const pos=getCanvasPos(e);
        if(canvasActiveTool==='freehand'){canvasCtx.lineTo(pos.x,pos.y);canvasCtx.stroke();return;}
        canvasCtx.putImageData(canvasSnapshot,0,0);
        canvasCtx.strokeStyle='#00f3ff'; canvasCtx.lineWidth=2; canvasCtx.setLineDash([]);
        if(canvasActiveTool==='rect') canvasCtx.strokeRect(canvasStartX,canvasStartY,pos.x-canvasStartX,pos.y-canvasStartY);
        else if(canvasActiveTool==='arrow') drawArrow(canvasCtx,canvasStartX,canvasStartY,pos.x,pos.y);
    }
    function drawArrow(ctx,x1,y1,x2,y2){
        const a=Math.atan2(y2-y1,x2-x1),hl=16;
        ctx.beginPath();ctx.moveTo(x1,y1);ctx.lineTo(x2,y2);ctx.stroke();
        ctx.beginPath();ctx.moveTo(x2,y2);ctx.lineTo(x2-hl*Math.cos(a-Math.PI/6),y2-hl*Math.sin(a-Math.PI/6));ctx.lineTo(x2-hl*Math.cos(a+Math.PI/6),y2-hl*Math.sin(a+Math.PI/6));ctx.closePath();ctx.fillStyle='#00f3ff';ctx.fill();
    }

    // ─── ADVANCED SYSTEM PROMPT BUILDER ─────────────────────
    // ─── WORKSPACE FILE CACHE (lazy, per-session) ────────────
    // Files are NOT injected wholesale. Only metadata (manifest) goes in the system prompt.
    // When AETHER responds with <read_file>NAME</read_file>, we fulfill it and inject result.
    const wsFileCache = {};

    async function getWorkspaceManifest() {
        if (!state.workspaceEnabled) return null;
        const manifest = [];
        for (const fn of WS_FILES) {
            try {
                const content = await readFile(fn);
                const lines   = content ? content.split('\n').length : 0;
                const chars   = content ? content.length : 0;
                // Cache it so on-demand reads are instant
                if (content) wsFileCache[fn] = content;
                manifest.push({ file: fn, lines, chars, excerpt: content ? content.split('\n').slice(0,2).join(' ').slice(0,80) : '' });
            } catch { manifest.push({ file: fn, lines:0, chars:0, excerpt:'' }); }
        }
        return manifest;
    }

    // Fulfill any <read_file> tags that appear in AETHER's response
    async function fulfillWorkspaceReads(responseText) {
        const TAG_RE = /<read_file>([\w. -]+)<\/read_file>/gi;
        const matches = [...responseText.matchAll(TAG_RE)];
        if (!matches.length) return null;

        const results = [];
        for (const m of matches) {
            const fn = m[1].trim();
            agentStatus('ws_read', `Reading ${fn}…`);
            wsStepShow(`Reading ${fn}`);
            const s = wsStep(`Opening ${fn}…`, 'pending');
            const content = wsFileCache[fn] || await readFile(fn);
            if (content) wsFileCache[fn] = content;
            wsStepUpdate(s, `${fn} — ${content ? content.length + ' chars' : 'not found'}`, content ? 'ok' : 'error');
            wsStepDone(`${fn} loaded`);
            agentDone();
            results.push(`## Contents of ${fn}\n\`\`\`\n${content || '(empty)'}\n\`\`\``);
        }
        return results.join('\n\n');
    }

    async function buildSystemPrompt(userMessage = '', conversationHistory = []) {
        const now = new Date();
        const datetime = now.toLocaleString('en-GB', {weekday:'long',year:'numeric',month:'long',day:'numeric',hour:'2-digit',minute:'2-digit',timeZoneName:'short'});

        // ── Core identity block ──────────────────────────────
        let prompt = `# AETHER NEURAL INTERFACE — Session Active
**Date/Time:** ${datetime}
**Model:** ${apiConfig.model} | **Provider:** ${apiConfig.provider} | **Temp:** ${state.temperature}

# CORE IDENTITY
You are AETHER — a precision AI assistant. You are direct, adaptive, and deeply expert.
Match the user's expertise level exactly. Never pad. Never truncate code.
`;

        // ── Reasoning protocol ───────────────────────────────
        if (state.coTEnabled) {
            prompt += `
# REASONING PROTOCOL
For complex queries, wrap your internal reasoning in <think>…</think> before answering.
Keep thinking concise — problem breakdown, edge cases, then the answer.
Skip <think> for conversational or trivial queries.
`;
        }

        // ── Persona block (from onboarding) ─────────────────
        const personaBlock = getPersonaBlock();
        if(personaBlock) prompt += `\n# USER & PERSONA\n${personaBlock}\n`;

        // ── MMD system prompt override ───────────────────────
        const mmdContent = await loadMmdFromWorkspace();
        if(mmdContent) {
            const mmdSections = parseMmd(mmdContent);
            if(mmdSections.IDENTITY)    prompt += `\n# MMD IDENTITY\n${mmdSections.IDENTITY}\n`;
            if(mmdSections.BEHAVIOR)    prompt += `\n# MMD BEHAVIOR\n${mmdSections.BEHAVIOR}\n`;
            if(mmdSections.CONSTRAINTS) prompt += `\n# MMD CONSTRAINTS\n${mmdSections.CONSTRAINTS}\n`;
            if(mmdSections.CONTEXT)     prompt += `\n# MMD CONTEXT\n${mmdSections.CONTEXT}\n`;
        }

        // ── Qwen3.5 native thinking directive ────────────────
        if(isAnyQwenModel(apiConfig.model)) {
            const spec = getQwen35Spec(apiConfig.model);
            prompt += `\n# QWEN3.5 NATIVE MODE
You are running on Qwen3.5${spec ? `-${spec.params}` : ''} — Alibaba's hybrid-architecture model (March 2026).
Architecture: ${spec?.arch || 'Gated DeltaNet + FFN'} with Early Fusion multimodality.
Context: 262K tokens native. You can handle very long documents natively.
Adaptive Thinking: Use <think>…</think> for complex reasoning. Skip for simple queries.
Multimodal: You can natively process images and documents alongside text.
`;
        }

        // ── Workspace manifest (LAZY) ────────────────────────
        if (state.workspaceEnabled) {
            const manifest = await getWorkspaceManifest();
            if (manifest && manifest.length) {
                const tbl = manifest.map(f => `  • ${f.file} (${f.lines} lines, ${f.chars} chars)${f.excerpt ? ' — ' + f.excerpt : ''}`).join('\n');
                prompt += `
# WORKSPACE FILES AVAILABLE
The following files exist in the workspace. Do NOT assume their contents.
To read a file, output: <read_file>FILENAME</read_file>
The system will inject the file contents into the next message automatically.

${tbl}
`;
            }
        }

        // ── Active integrations — explicit routing instructions ─
        const hooks = [];
        const hookInstructions = [];

        // Build precise tool routing based on what's actually configured
        if (hooksConfig.serper || hooksConfig.brave || hooksConfig.tavily) {
            const searchProviders = [];
            if (hooksConfig.serper)  searchProviders.push('Serper (Google results, fast)');
            if (hooksConfig.brave)   searchProviders.push('Brave Search (privacy-first)');
            if (hooksConfig.tavily)  searchProviders.push('Tavily (deep extraction)');
            hooks.push('Web Search: ' + searchProviders.join(', '));
            hookInstructions.push('WEB SEARCH: Use [[web_search: your query]] when you need current info, news, prices, or facts that may have changed. Available providers: Serper (Google), Tavily, Brave, DashScope (Qwen). DO NOT output raw XML tool tags.');
        }
        if (hooksConfig.firecrawlKey) {
            hooks.push('Firecrawl (full page scraping, JS rendering, anti-bot bypass)');
            hookInstructions.push('SCRAPING: Use [[scrape: URL]] to get full page content from any URL. Use [[crawl: URL]] for multi-page site crawling.');
        }
        if (hooksConfig.puter || (typeof puterAuthed !== 'undefined' && puterAuthed)) {
            hooks.push('Puter Cloud (terminal, file storage, deploy, browser)');
            hookInstructions.push('PUTER: Use [[puter_terminal: command]] to run shell commands. [[puter_deploy: name\\n<html>...</html>]] to deploy a site. [[puter_read_file: /path]] to read cloud files.');
        }
        if (hooksConfig.gmail)       { hooks.push('Gmail'); hookInstructions.push('EMAIL (Gmail): Use [[email_send: to: addr | subject: text | body: text]] to send email.'); }
        if (hooksConfig.slackToken)  { hooks.push('Slack'); hookInstructions.push('SLACK: Use [[slack_post: #channel | message]] to post. [[slack_read: #channel]] to read messages.'); }
        if (hooksConfig.notionToken) { hooks.push('Notion'); hookInstructions.push('NOTION: Use [[notion_query: database-id]] to read. [[notion_add: title | content]] to create pages.'); }
        if (hooksConfig.github)      {
            hooks.push('GitHub (PAT)');
            hookInstructions.push('GITHUB: Use [[github_create_issue: owner/repo | title | body]] · [[github_list_repos]] · [[github_get_file: owner/repo | path]] · [[github_commit: owner/repo | path | content | message]] · [[github_push: owner/repo | branch]] for full git operations.');
        }
        const isDashscope = !!(hooksConfig.dashscope || ((apiConfig.provider||'').toLowerCase() === 'qwen' && apiConfig.apiKey));
        if (isDashscope) { hooks.push('DashScope Search'); hookInstructions.push('DASHSCOPE: You can use [[web_search: query]] and it will route through DashScope (Qwen Search) automatically when no other provider is configured.'); }
        if (hooksConfig.weather)     { hooks.push('OpenWeatherMap'); hookInstructions.push('WEATHER: Use [[get_weather: City, CC]] for current conditions.'); }
        if (hooksConfig.jiraUrl)     { hooks.push('Jira'); hookInstructions.push('JIRA: Use [[jira_search: JQL query]] to search. [[jira_create: PROJECT | Summary | Description]] to create.'); }
        if (hooksConfig.hueHost)     { hooks.push('Philips Hue'); hookInstructions.push('HUE LIGHTS: Use [[hue_lights]] to list. [[hue_set: light-id | on/off | brightness]] to control.'); }
        if (hooksConfig.xBearerToken) {
            hooks.push('X / Twitter Search');
            hookInstructions.push('X SEARCH: Use [[x_search: query]] to search tweets. [[x_get_user: username]] for profile. [[x_user_tweets: username|count]] for timeline.');
        }
        if (hooksConfig.trelloApiKey && hooksConfig.trelloToken) {
            hooks.push('Trello');
            hookInstructions.push('TRELLO: Use [[trello_boards]] to list boards. [[trello_lists: boardId]] for lists. [[trello_cards: boardId]] for cards. [[trello_create_card: listId|name|desc]] to add. [[trello_move_card: cardId|listId]] to move.');
        }
        if (codingFolderHandle) {
            hooks.push('File System (' + codingFolderHandle.name + ')');
            hookInstructions.push('FILE SYSTEM: Prefer [[fs_patch: path|||old|||new]] for edits. Also: [[shell: ls -la]], [[fs_read: path]], [[fs_write: path\\ncontent]] (new/full rewrite only), [[fs_mkdir: path]], [[fs_stat: path]], [[fs_rename: old|new]], [[fs_copy: src|dest]], [[fs_exists: path]], [[fs_delete: path]].');
        }

        if (hooks.length) {
            prompt += '\n# ACTIVE INTEGRATIONS\nConfigured: ' + hooks.join(' · ') + '\n\n';
            prompt += '## Tool Usage Rules\n';
            prompt += '- Use the EXACT [[tool: arg]] syntax — never output raw <tool_call> or XML tags\n';
            prompt += '- The system intercepts [[tool: arg]] patterns and executes them automatically\n';
            prompt += '- State which tool you are using before using it: "Let me search for that: [[web_search: query]]"\n';
            prompt += hookInstructions.map(h => '- ' + h).join('\n') + '\n';
        }

        // Provider-specific tool awareness
        if ((apiConfig.provider||'').toLowerCase() === 'groq') {
            const isCompound = (apiConfig.model||'').toLowerCase().includes('compound');
            if (isCompound) {
                prompt += '\n# GROQ COMPOUND TOOLS ACTIVE\n';
                prompt += 'You have browser_automation, code_interpreter, web_search, and visit_website tools natively available.\n';
                prompt += 'Use them directly — results will appear inline.\n';
            }
        }

        // ── Task-adaptive specialization ─────────────────────
        if (userMessage) {
            const m = userMessage.toLowerCase();
            const specs = [];
            if (/\b(code|function|class|bug|debug|implement|script|algorithm|api|error|compile|run)\b/.test(m))
                specs.push('**CODE:** Complete, runnable output. Language header required. Explain non-obvious parts.');
            if (/\b(calculate|compute|solve|equation|formula|integral|derivative|matrix|probability|statistics)\b/.test(m))
                specs.push('**MATH:** Step-by-step. Use LaTeX ($…$ inline, $$…$$ display). Verify result.');
            if (/\b(weather|forecast|temperature|rain|wind|humidity)\b/.test(m))
                specs.push('**WEATHER:** Use the fetchWeather() capability if an API key is configured. Be specific about location.');
            if (/\b(slack|send.*message|post.*channel)\b/.test(m))
                specs.push('**SLACK:** Use postSlack() to send. Confirm the message and channel before sending.');
            if (/\b(notion|database|page|task|todo)\b/.test(m))
                specs.push('**NOTION:** Use queryNotion() to read, addNotionPage() to write.');
            if (specs.length) prompt += `\n# TASK GUIDANCE\n${specs.join('\n')}\n`;
        }

        // ── AETHER Code Mode — direct competitor to Claude Code ─
        if (state.codingMode) {
            let aetherMdCtx = '';
            let fsTreeCtx = '';
            if (state.workspaceEnabled) {
            // ── AETHER.md: real FS first (2000 chars), then virtual workspace ──
            // Old code only checked wsFileCache at 600 chars. Now: linked folder
            // takes precedence (readAetherMd() reads up to 2000 chars), then
            // falls back to the virtual workspace if no FS folder is linked.
            try {
                let cMd = null;
                if (codingFolderHandle) {
                    cMd = await readAetherMd(); // real FS, 2000 char limit
                }
                if (!cMd && state.workspaceEnabled) {
                    cMd = wsFileCache['AETHER.md'] || await readFile('AETHER.md');
                    if (cMd) {
                        cMd = cMd.slice(0, 2000);
                        wsFileCache['AETHER.md'] = cMd;
                    }
                }
                if (cMd) aetherMdCtx = '\n## Project Rules (AETHER.md)\n' + cMd + '\n';
            } catch(e) {}
                // Build file tree from workspace manifest
                try {
                    const manifest = await getWorkspaceManifest();
                    if (manifest && manifest.length) {
                        fsTreeCtx = '\n## Workspace File Tree\n' + manifest.map(f => '  \u2514 ' + f.file + ' (' + f.lines + ' lines)').join('\n') + '\n';
                    }
                } catch(e) {}
            }
            // Build tool pool summary for model context (Claude Code tool_pool pattern)
            const activeIntegrations = AETHER_TOOL_POOL.integration.filter(t => !!hooksConfig[t] || !!hooksConfig[t.split('_')[0]]);
            const destructiveWarning = AETHER_TOOL_POOL.destructive.map(t => t).join(', ');
            const currentTurn = getCodingTurns(state.currentConversationId || '');
            const turnsLeft = AETHER_TOOL_POOL.maxTurns - currentTurn;

            prompt += '\n# AETHER CODE — AUTONOMOUS CODING AGENT\n'
                + '## Session Context\n'
                + '- Turn: ' + (currentTurn + 1) + ' / ' + AETHER_TOOL_POOL.maxTurns + ' (max)\n'
                + '- Turns remaining: ' + turnsLeft + '\n'
                + '- Builtin tools: ' + AETHER_TOOL_POOL.builtin.join(', ') + '\n'
                + (activeIntegrations.length ? '- Integration tools: ' + activeIntegrations.join(', ') + '\n' : '')
                + '- Destructive tools (require user permission): ' + destructiveWarning + '\n\n'
                + '## MANDATORY PLANNING PROTOCOL\n'
                + '1. ALWAYS output a plan FIRST before writing any code\n'
                + '2. Format your plan exactly as:\n'
                + '   <aether:plan>\n'
                + '   - [ ] Step 1: description\n'
                + '   - [x] Step 2: completed\n'
                + '   </aether:plan>\n'
                + '3. For tasks >5 steps, wait for user confirmation before proceeding\n'
                + '4. For tasks <3 steps, proceed immediately\n\n'
                + '## TODO BOARD — UPDATE EVERY TURN\n'
                + 'After each action, update the todo board:\n'
                + '   <aether:todo>\n'
                + '   \u2705 Step 1: done\n'
                + '   \ud83d\udfe1 Step 2: in progress\n'
                + '   \u2b1c Step 3: pending\n'
                + '   </aether:todo>\n'
                + 'If there are PENDING steps (\u2b1c) remaining at the end of your turn, add:\n'
                + '   <aether:continue/>\n'
                + 'The system will automatically continue to the next turn.\n'
                + 'If ALL steps are complete, do NOT add <aether:continue/> — this signals stop_reason=completed.\n\n'
                + '## STOP REASONS (mirror Claude Code QueryEnginePort)\n'
                + '- completed: all TODO steps done, no <aether:continue/>\n'
                + '- max_turns: reached turn ' + AETHER_TOOL_POOL.maxTurns + ' — summarize remaining work\n'
                + '- permission_denied: destructive tool was denied — acknowledge and adapt\n\n'
                + '## CODE OUTPUT RULES\n'
                + '- Tag ALL code fences: ```lang:path/filename.ext\n'
                + '- ONE block per file — never split a file across multiple fences\n'
                + '- After each file: > **What changed:** bullet list\n'
                + '- NEVER repeat broken code — corrected version only\n'
                + '- Flag breaking changes with \u26a0, stubs with TODO:\n\n'
                + '## TOOL CALL SYNTAX\n'
                + '- Use [[tool_name: argument]] for all tool calls\n'
                + '- One tool per line, no nesting\n'
                + '- Tool results appear in the next turn\'s context automatically\n'
                + '- For shell commands, use: [[shell: ls -la]] or [[shell: cat filename]]\n'
                + '- Prefer structured results: ok=true/false, path=, diff=+N/-M\n'
                + '- Tool runtime returns envelopes: tool=name ok=true|false ms=N class=read|write|exec|net\n'
                + '- Prefer native tool_calls JSON when available; else [[tool: arg]] (multi-line OK for fs_patch/fs_write)\n\n'
                + '## SURGICAL EDITS (PREFERRED)\n'
                + '- NEVER rewrite a whole file if you are changing <40% of it — use fs_patch\n'
                + '- Always fs_read (or shell cat) BEFORE patching so old_string matches exactly\n'
                + '- old_string must be unique in the file; include enough surrounding context\n'
                + '- Preferred bracket form: [[fs_patch: path|||old text|||new text]]\n'
                + '- Multi-line form:\n'
                + '  [[fs_patch: path\\n<<<<<<< SEARCH\\nold lines\\n=======\\nnew lines\\n>>>>>>> REPLACE]]\n'
                + '- fs_write is ONLY for creating new files or full rewrites (>40% change)\n'
                + '- In ask mode, patches land as Ghost commits — user Accept/Reject in the Ghost rail\n\n'
                + '## FILE SYSTEM ACCESS\n'
                + '- [[read_file: filename]] — read from workspace (if workspace enabled)\n'
                + '- [[write_file: filename\\ncontent]] — write to workspace (requires permission)\n'
                + '- [[calculate: expression]] — math/eval without hallucination\n'
                + (codingFolderHandle ? (
                    '- [[fs_read: path]] — read real file from ' + codingFolderHandle.name + '\n'
                    + '- [[fs_patch: path|||old|||new]] — surgical insert/delete (PREFERRED)\n'
                    + '- [[search_replace: ...]] — alias of fs_patch\n'
                    + '- [[fs_write: path\\ncontent]] — full file write (new files / large rewrites only)\n'
                    + '- [[fs_delete: path]] — delete file\n'
                    + '- [[fs_list]] — list directory\n'
                    + '- [[shell: command]] — run shell commands (ls, cat, grep, find, tree, pwd, mkdir, touch, sort, uniq, diff, head, tail, wc)\n'
                    + '- [[fs_mkdir: path]] — create directory\n'
                    + '- [[fs_rename: old|new]] — rename file\n'
                    + '- [[fs_copy: src|dest]] — copy file\n'
                    + '- [[fs_stat: path]] — file metadata\n'
                    + '- [[fs_exists: path]] — check if exists\n'
                ) : '- Link a folder to enable real filesystem access\n')
                + '\n## QUALITY STANDARDS\n'
                + '- Unit tests for non-trivial new functions\n'
                + '- Security annotations: XSS \ud83d\udd12, injection \ud83d\udd12, auth \ud83d\udd12\n'
                + '- Descriptive names; comment non-obvious logic\n'
                + '- Never hallucinate API signatures — use [[read_file]] or [[fs_read]] first\n'
                + '- After patches: verify with fs_read or shell grep/diff when unsure\n'
                + '- User may @mention files/symbols (@src/app.js, @blast, @memory, @plan) — honor those pins\n'
                + '- Prefer surgical fs_patch; Ghost rail is the human review surface\n'
                + aetherMdCtx + fsTreeCtx
                + (typeof AETHER_CodePro !== 'undefined' && AETHER_CodePro.memoryForPrompt
                    ? AETHER_CodePro.memoryForPrompt() : '')
                + (typeof AETHER_ToolPacks !== 'undefined' && AETHER_ToolPacks.promptForPrompt
                    ? AETHER_ToolPacks.promptForPrompt() : '')
                + (typeof AETHER_MCP !== 'undefined' && AETHER_MCP.promptSnippet
                    ? AETHER_MCP.promptSnippet() : '')
                + (typeof AETHER_GitLite !== 'undefined' && AETHER_GitLite.promptSnippet
                    ? AETHER_GitLite.promptSnippet() : '')
                + '\n## Multi-agent\n'
                + '- Subagents: /sub explore|plan|edit|review <goal>\n'
                + '- Swarm: /swarm <goal> [--parallel] [--edit] [--review]\n'
                + '- Parallel explore: /pexplore <goal>\n'
                + '- PR change sets: /pr · Git Lite: /git\n';
        }

        // ── Deep Research Mode (v3 — follow-up chat after pipeline) ──
        // Moat self-awareness (brief)
        if (typeof AETHER_Moat !== 'undefined' && AETHER_Moat.computeScore) {
            try {
                const ms = AETHER_Moat.computeScore();
                prompt += `\n\n---\n## AETHER MOAT (product identity)\nYou are AETHER — browser-native zero-backend agent OS. Moat integrity **${ms.overall}/100 (${ms.grade})**. Distinctive stack: Ghost review, Skill Runtime, Deep Research v3, local RAG, Kernel flights, client security. Prefer surgical fs_patch + Ghost over silent rewrites. Prefer citable research over invented sources.\n`;
            } catch (_) {}
        }

        if (state.deepResearch) {
            const dr = (typeof AETHER_DeepResearch !== 'undefined' && AETHER_DeepResearch.mergeSettings)
                ? AETHER_DeepResearch.mergeSettings(state.deepResearchSettings)
                : (state.deepResearchSettings || {});
            const depthMap = {
                surface: 'Provide a concise overview covering the main points. Keep it brief.',
                standard: 'Explore the topic thoroughly with multiple angles, key data, and supporting evidence.',
                deep: 'Conduct multi-layered analysis. Break into sub-topics. Include edge cases, counterarguments, and nuanced perspectives.',
                exhaustive: 'Maximum depth. Leave no stone unturned. Examine every sub-domain, historical context, current state, future implications, contradictions, and expert disagreements.',
            };
            const widthMap = {
                focused: 'Stay narrowly scoped to the exact topic asked. Do not drift.',
                broad: 'Include adjacent topics, related fields, and indirect implications.',
                comprehensive: 'Sweep the entire domain. Cross-reference related disciplines and draw connections across fields.',
            };
            const criticalityMap = {
                casual: 'Aim for general accuracy.',
                important: 'Cross-check key claims. Flag anything uncertain. Distinguish fact from inference.',
                critical: 'Full discriminator pass + Confidence Assessment (1–10) with caveats.',
            };
            const ledgerNote = (typeof drLastLedger !== 'undefined' && drLastLedger && drLastLedger.sources && drLastLedger.sources.length)
                ? `\n- **Prior run ledger:** ${drLastLedger.sources.length} sources available — prefer citing them as [n] when relevant.`
                : '';
            prompt += `
# DEEP RESEARCH v3 MODE ACTIVE
Multi-angle grounded research parameters:
- **Depth:** ${dr.depth || 'standard'} — ${depthMap[dr.depth] || depthMap.standard}
- **Width:** ${dr.width || 'broad'} — ${widthMap[dr.width] || widthMap.broad}
- **Criticality:** ${dr.criticality || 'important'} — ${criticalityMap[dr.criticality] || criticalityMap.important}
- **Format:** ${dr.format || 'report'} · **Language:** ${dr.language || 'auto'}
- **RAG grounding:** ${dr.useRag !== false ? 'on' : 'off'} · **Gap-fill:** ${dr.gapFill !== false ? 'on' : 'off'} · **Citations:** ${dr.includeCitations !== false ? 'on' : 'off'}
- **Self-critique:** ${dr.selfCritique !== false ? 'enabled' : 'disabled'}${ledgerNote}

## Research Protocol (follow-up answers)
1. Decompose into sub-questions; synthesise multi-angle evidence
2. Structure: Executive Summary → Findings → Counterpoints → Sources → Conclusion
3. Flag uncertainty: (unverified) | (disputed) | (estimate)
4. Cite as [n] when Research Ledger / Archive is in context
5. Prefer precision over length; surface residual unknowns explicitly
${dr.criticality === 'critical' ? '6. End with ⬡ Confidence Assessment (1–10) + caveats\n' : ''}
When the user sends a new research topic while DEEP is active, the **pipeline** runs (plan → search → analyze → report). For follow-up questions on the last report, answer from archive + ledger first.
`;
        }

        // ── Output standards ─────────────────────────────────
        prompt += `
# OUTPUT STANDARDS
- Use Markdown: headers, bold, code fences with language tag, tables, lists
- End complex answers with a summary or next-step suggestion
- For ambiguous requests, ask one clarifying question
`;
        // Inject AETHER's self-knowledge into every prompt (soul context)
        const soulCtx = typeof getSoulContext === 'function' ? getSoulContext() : '';
        if (soulCtx) prompt += soulCtx;

        // Dynamic search instruction — AETHER decides when to search
        const hasSomeSearch = !!(hooksConfig.tavily || hooksConfig.serper || hooksConfig.brave ||
            ((apiConfig.provider||'').toLowerCase() === 'qwen' && apiConfig.apiKey));
        if (hasSomeSearch && !state.deepResearch) {
            prompt += `\n\n## DYNAMIC SEARCH PROTOCOL
You have access to real-time web search. Use it PROACTIVELY when:
- The question is about RECENT events, prices, scores, news, or anything time-sensitive
- The user asks about a SPECIFIC person, product, or fact you're not 100% certain about
- The topic may have CHANGED since your training data
- User signals uncertainty: "latest", "current", "today", "now", "recent", "2025", "2026"
Use [[web_search: query]] — search BEFORE answering, not after.
Do NOT search for: basic facts, math, definitions, or things you're confident about.`;
        }

        // ── Active Skill injection ────────────────────────────
        // If a skill is active (manually set or auto-detected from message),
        // inject its full systemPrompt + skillMd into the prompt.
        // This gives AETHER genuine specialised behaviour, not just a
        // wrapper — the skill controls reasoning style, output format,
        // tool access, and domain knowledge.
        const hasActiveSkills = activeSkills.length > 0;
        const detected = hasActiveSkills ? null : detectSkillFromMessage(userMessage);
        const skillsForPrompt = hasActiveSkills ? activeSkills : (detected ? [detected] : []);
        if (skillsForPrompt.length > 0) {
            skillsForPrompt.forEach(function(skill) {
                prompt += `\n\n---\n# ⬡ ACTIVE SKILL: ${skill.label} (${skill.category})\n\n`;
                prompt += skill.systemPrompt;
                prompt += `\n\n## SKILL KNOWLEDGE (SKILL.md)\n\n${skill.skillMd}`;
                if (skill.workflows && Object.keys(skill.workflows).length > 0) {
                    prompt += '\n\n## SKILL WORKFLOWS\n\n';
                    for (const [id, wf] of Object.entries(skill.workflows)) {
                        prompt += `**${id}** — ${wf.desc}\nSteps: ${wf.steps.join(' → ')}\n\n`;
                    }
                }
            });
            if (skillsForPrompt.some(function(s){ return s.visualizer; })) {
                prompt += '\n\n## VISUALIZER\nYou can output AETHER spec JSON for charts/diagrams. The renderer will detect and display them automatically.\nChart types: bar | line | area | bar-horizontal | stacked-bar | stacked-line | donut | pie | scatter | bubble | radar\nDiagram types: flow | struct | table | gantt | heatmap | timeline | svg | mermaid\nFlow layout: add "layout":"LR" for left-right, "layout":"RADIAL" for radial, default is top-bottom.\n';
            }
            // Skill Runtime: tool policy + active playbook checklist
            if (typeof AETHER_SkillRuntime !== 'undefined' && AETHER_SkillRuntime.buildRuntimePromptAddon) {
                prompt += AETHER_SkillRuntime.buildRuntimePromptAddon(skillsForPrompt) || '';
            }
        } else if (typeof AETHER_SkillRuntime !== 'undefined' && AETHER_SkillRuntime.getRun && AETHER_SkillRuntime.getRun()) {
            // Playbook running even if skills array empty mid-transition
            prompt += AETHER_SkillRuntime.buildRuntimePromptAddon([]) || '';
        }

        // ── Active Project ─────────────────────────────────────
        const projCtx = getActiveProjectContext();
        if (projCtx) prompt += projCtx + '\n';

        // ── AETHER SYSTEM SELF-AWARENESS ──────────────────────
        // AETHER needs to know what it has access to so it can
        // use it proactively. This section is always injected.
        prompt += '\n\n---\n## YOUR CAPABILITIES (AETHER SYSTEM)\n\n';

        // RAG knowledge base
        const ragCount = typeof RAG !== 'undefined' ? RAG.totalDocs : 0;
        if (ragCount > 0) {
            prompt += `**RAG Knowledge Base**: You have ${ragCount} document${ragCount>1?'s':''} stored in your BM25 knowledge base. `
                + 'When answering questions, relevant documents from the RAG are automatically retrieved and injected above as [RAG CONTEXT]. '
                + 'If you see RAG CONTEXT blocks above, use them — they are the user\'s actual documents and files.\n\n';
        } else {
            prompt += '**RAG Knowledge Base**: Empty. User can attach files via the + menu to build it.\n\n';
        }

        // AetherVisualizer
        prompt += '**AETHER Visualizer**: You can render live charts and diagrams inline by outputting a JSON spec directly in your response. '
            + 'Supported: bar | line | donut | scatter | flow | struct | mermaid. '
            + 'Output raw JSON (no code fences) and it renders automatically. Example: {"type":"bar","labels":["A","B"],"datasets":[{"label":"","data":[10,20]}]}\n\n';

        // Skills available
        const allSkillNames = Object.values(AETHER_SKILLS).map(s => s.label).join(', ');
        prompt += `**Skills Available (${Object.keys(AETHER_SKILLS).length})**: ${allSkillNames}. `
            + 'Skills are activated by the user via the SKILLS panel. When a skill is active, its specialised system prompt and SKILL.md are injected above.\n\n';

        // FS tools if folder linked
        if (typeof codingFolderHandle !== 'undefined' && codingFolderHandle) {
            prompt += `**File System**: Folder "${codingFolderHandle.name}" is linked. `
                + 'Use [[fs_patch: path|||old|||new]] (preferred), [[fs_read: path]], [[fs_write: path\\ncontent]] (new/full rewrite), [[fs_mkdir: path]], [[fs_rename: old|new]], [[fs_copy: src|dest]], [[fs_stat: path]], [[fs_exists: path]], [[shell: command]] (ls, cat, grep, find, tree, pwd, mkdir, touch, sort, uniq, diff, head, tail, wc, help).\n\n';
        }

        // Tool count
        const toolCount = typeof TOOL_REGISTRY !== 'undefined' ? Object.keys(TOOL_REGISTRY).length : 0;
        if (toolCount > 0) {
            prompt += `**Tools available**: ${toolCount} registered tools including web search, file system, Trello, X/Twitter, GitHub, Jira, Slack, Notion, and more. Use [[tool_name: arg]] syntax.\n`;
        }

        // Beast Mode system prompt addon
        if (typeof AETHER_Beast !== 'undefined' && AETHER_Beast.isEnabled()) {
            prompt += AETHER_Beast.systemPromptAddon();
        } else if (typeof window.getBeastPromptAddon === 'function') {
            prompt += window.getBeastPromptAddon() || '';
        }

        // Soul OS runtime identity
        if (typeof window.__aetherSoulPrompt === 'function') {
            prompt += window.__aetherSoulPrompt() || '';
        } else if (typeof AETHER_SoulOS !== 'undefined' && AETHER_SoulOS.systemPromptBlock) {
            prompt += AETHER_SoulOS.systemPromptBlock();
        }

        return prompt.trim();
    }

    // ─── MARKDOWN ENGINE ─────────────────────────────────────
    // Pill store — protects pill HTML through the escaping pipeline
    const _PILL_STORE = new Map();
    // Markdown render log — captures blocks that fail or can't render
    var _MD_LOG = [];
    var _MD_LOG_ENABLED = true;
    function mdLog(level, msg, detail) {
        if (!_MD_LOG_ENABLED) return;
        var entry = { ts: new Date().toISOString(), level: level, msg: String(msg).slice(0, 200), detail: detail ? String(detail).slice(0, 500) : '' };
        _MD_LOG.push(entry);
        if (_MD_LOG.length > 500) _MD_LOG.shift();
        if (level === 'error') console.warn('[MD]', msg, detail || '');
    }
    // Exposed for debug panel
    window._getMDLog = function() { return _MD_LOG.slice(); };
    window._clearMDLog = function() { _MD_LOG = []; };

    function parseInline(t) {
        // Replace [[TOOL_PILL:...]] with safe placeholder BEFORE html escaping
        t = t.replace(/\[\[TOOL_PILL:([^|\n]+)\|([^|\n]+)\|([^\]\n]+)\]\]/g, (_, label, toolName, arg) => {
            const id = 'tp_' + Math.random().toString(36).slice(2,9);
            const pill = '<span class="tool-pill" data-tool="' + toolName + '" title="' + arg.slice(0,80) + '">'
                + '<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" style="vertical-align:middle;margin-right:4px"><polyline points="4 17 10 11 4 5"/><line x1="12" y1="19" x2="20" y2="19"/></svg>'
                + label + '</span>';
            const key = '\x00PILL_' + id + '_END\x00';
            _PILL_STORE.set(key, pill);
            return key;
        });
        let result = t
            .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
            .replace(/\*\*\*(.+?)\*\*\*/g,'<strong><em>$1</em></strong>')
            .replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>')
            .replace(/\*(.+?)\*/g,'<em>$1</em>')
            .replace(/`([^`]+)`/g,'<code class="inline-code">$1</code>')
            // Citations: [1], [2], [1,2] — rendered as superscript bubbles
            .replace(/\[(\d+(?:,\s*\d+)*)\]/g, (_, nums) => {
                return nums.split(',').map(n =>
                    '<sup class="citation-ref" title="Source ' + n.trim() + '">' + n.trim() + '</sup>'
                ).join('');
            })
            // Source links: [[source: URL title]]
            .replace(/\[\[source:\s*([^\]|]+?)(?:\|([^\]]+))?\]\]/g, (_, url, title) =>
                '<a href="' + url.trim() + '" target="_blank" rel="noopener" class="source-link">' +
                (title ? title.trim() : url.trim()) + '</a>'
            )
            .replace(/\[([^\]]+)\]\(([^)]+)\)/g,'<a href="$2" target="_blank" rel="noopener">$1</a>')
            .replace(/~~(.+?)~~/g,'<del>$1</del>');
        // Restore pill HTML — pills bypass all escaping
        for (const [key, html] of _PILL_STORE) {
            if (result.includes(key)) result = result.split(key).join(html);
        }
        _PILL_STORE.clear();
        return result
            .replace(/==(.+?)==/g,'<mark>$1</mark>');
    }

    function getBlockType(l) {
        const t = l.trim();
        if (!t) return 'empty';
        if (/^#{1,6}\s/.test(t)) return 'heading';
        if (t.startsWith('> ') || t === '>') return 'blockquote';
        if (/^(\*|-|\+|\d+\.)\s/.test(t) || /^- \[.\]/.test(t)) return t.startsWith('- [') ? 'task' : (t[0]>='0'&&t[0]<='9'?'ol':'ul');
        if (t.startsWith('|')) return 'table-row';
        if (t.startsWith('```')) { const g=t.slice(3).trim().toLowerCase(); return g.startsWith('graph')||g.startsWith('bar')||g.startsWith('line')||g.startsWith('pie')?{type:'graph',graphType:g.split(' ')[0]}:'code-fence'; }
        if (t.startsWith('---') || t.startsWith('===')) return 'hr';
        return 'paragraph';
    }

    function renderTable(lines) {
        const table = document.createElement('table');
        table.className = 'modern-table';
        lines.forEach((line, i) => {
            if (line.includes('---')) return;
            const cells = line.split('|').slice(1,-1).map(c => c.trim());
            const row = document.createElement('tr');
            cells.forEach(c => {
                const cell = document.createElement(i === 0 ? 'th' : 'td');
                cell.innerHTML = parseInline(c);
                row.appendChild(cell);
            });
            table.appendChild(row);
        });
        const wrapper = document.createElement('div'); wrapper.className = 'table-wrapper modern-table'; wrapper.appendChild(table);
        return wrapper;
    }

    function renderList(lines, startI) {
        const firstType = getBlockType(lines[startI]);
        const list = document.createElement(firstType === 'ol' ? 'ol' : 'ul');
        list.className = firstType === 'task' ? 'task-list' : 'modern-list';
        let i = startI;
        while (i < lines.length) {
            const t = getBlockType(lines[i]);
            if (t !== firstType && t !== 'paragraph' && t !== 'task' && t !== 'ul' && t !== 'ol') break;
            const li = document.createElement('li');
            const txt = lines[i].replace(/^(\*|-|\+|\d+\.)\s/,'').replace(/^- \[.\] /,'');
            const taskMatch = lines[i].trim().match(/^- \[( |x)\] /);
            if (taskMatch) { const chk = document.createElement('input'); chk.type='checkbox'; chk.disabled=true; chk.checked=taskMatch[1]==='x'; li.appendChild(chk); li.classList.add('task-item'); }
            const span = document.createElement('span'); span.innerHTML = parseInline(txt); li.appendChild(span);
            list.appendChild(li); i++;
        }
        return { element:list, nextIndex:i };
    }

    function createAdvancedCodeBlock(lang, code, filename=null) {
        if (state.codingMode) return createCodingBlock(lang, code, filename);
        const wrapper = document.createElement('div'); wrapper.className = 'code-block modern-code';
        const header = document.createElement('div'); header.className = 'code-header';
        const badge = document.createElement('span'); badge.className = 'code-lang-badge'; badge.textContent = lang.toUpperCase();
        const lines = document.createElement('span'); lines.className = 'code-line-count'; lines.textContent = code.split('\n').length + ' lines';
        const copyBtn = document.createElement('button'); copyBtn.className = 'code-copy-btn modern-copy'; copyBtn.innerHTML = '&#128203; Copy';
        copyBtn.onclick = () => { navigator.clipboard.writeText(code).then(()=>{ copyBtn.innerHTML='&#10003; Copied!'; setTimeout(()=>copyBtn.innerHTML='&#128203; Copy',2000); }); };
        header.appendChild(badge); header.appendChild(lines); header.appendChild(copyBtn);
        const container = document.createElement('div'); container.className = 'code-container';
        const nums = document.createElement('div'); nums.className = 'line-numbers';
        code.split('\n').forEach((_,i)=>{ const s=document.createElement('span');s.textContent=i+1;nums.appendChild(s); });
        const pre = document.createElement('pre'); const codeEl = document.createElement('code');
        // Same CM6 → applySH fallback chain as createCodingBlock
        codeEl.textContent = code; highlightWithCM(codeEl, lang); pre.appendChild(codeEl);
        container.appendChild(nums); container.appendChild(pre);
        wrapper.appendChild(header); wrapper.appendChild(container);
        attachRunButton(wrapper, lang, code);
        return wrapper;
    }

    // ═══════════════════════════════════════════════════════════
    // SECTION: HIGHLIGHT.JS + CODEMIRROR 6 + PRETTIER
    //
    // Three tools, three jobs — finally assigned correctly:
    //
    // 1. highlight.js  — read-only display blocks in chat messages.
    //    Proper UMD, 190 languages, synchronous, designed for this.
    //    Replaces the hand-rolled applySH() regex entirely.
    //    applySH() kept as the tertiary fallback if hljs CDN fails.
    //
    // 2. CodeMirror 6  — the AETHER Code editor widget.
    //    Full mini-IDE: syntax highlighting, line numbers, bracket
    //    matching, fold, search, one-dark theme. Loaded via dynamic
    //    ESM import (CM6 has no UMD build) after page load.
    //    Mounted via mountCM6Editor() when the user opens AETHER Code.
    //
    // 3. Prettier 3.x  — Format button on every code block.
    //    Reads plugins via getPrettierPlugin() at click-time (not at
    //    page-load), so late-loading plugins are always found.
    //    Bug fix: previous code checked window.prettierPluginBabel
    //    (wrong) — Prettier 3 UMD exposes window.prettierPlugins.babel.
    // ═══════════════════════════════════════════════════════════

    // ── Language alias normaliser — shared by hljs and CM6 ───
    // Returns a canonical lowercase language name we can pass to
    // hljs.highlight() or CM6 language packs.
    function normLang(raw) {
        const l = (raw || '').toLowerCase().trim();
        const aliases = {
            js: 'javascript', jsx: 'javascript', mjs: 'javascript', cjs: 'javascript',
            ts: 'typescript', tsx: 'typescript',
            py: 'python',
            rb: 'ruby',
            rs: 'rust',
            sh: 'bash', shell: 'bash', zsh: 'bash',
            yml: 'yaml',
            htm: 'html',
            jsonc: 'json',
            'c++': 'cpp', cc: 'cpp', cxx: 'cpp', hh: 'cpp',
            kt: 'kotlin',
            md: 'markdown',
            tf: 'hcl', terraform: 'hcl',
            dockerfile: 'dockerfile',
            makefile: 'makefile',
        };
        return aliases[l] || l;
    }

    // ── Prettier: resolve plugins at call-time not page-load ──
    // Prettier 3.x UMD plugins register on window.prettierPlugins.X.
    // We read them lazily so late-loading CDN scripts are always caught.
    function getPrettierPlugin(name) {
        // Primary: Prettier 3.x UMD namespace
        if (window.prettierPlugins?.[name]) return window.prettierPlugins[name];
        // Fallback: some Prettier 2.x style globals (prettierPluginBabel etc)
        const cap = name.charAt(0).toUpperCase() + name.slice(1);
        return window['prettierPlugin' + cap] || null;
    }

    function getPrettierParser(lang) {
        const l = normLang(lang);
        const p = (parser, ...plugins) => ({ parser, plugins: plugins.map(getPrettierPlugin).filter(Boolean) });
        if (['javascript','jsx'].includes(l))        return p('babel',      'babel','estree');
        if (['typescript','tsx'].includes(l))        return p('typescript', 'typescript','estree');
        if (['css','scss','sass','less'].includes(l)) return p('css',       'postcss');
        if (l === 'html')                            return p('html',       'html');
        if (l === 'json')                            return p('json',       'babel','estree');
        if (l === 'markdown')                        return p('markdown',   'markdown');
        return null;
    }

    async function formatWithPrettier(code, lang) {
        // Guard: prettier itself must be loaded
        if (!window.prettier) return { formatted: code, error: 'Prettier not loaded' };
        const info = getPrettierParser(lang);
        if (!info) return { formatted: code, error: 'No Prettier parser for: ' + lang };
        // Check plugins at call-time — they may have loaded since the button was created
        if (!info.plugins.length) {
            return { formatted: code, error: 'Prettier plugins not ready — check CDN/ad-blocker' };
        }
        try {
            const formatted = await window.prettier.format(code, {
                parser:       info.parser,
                plugins:      info.plugins,
                printWidth:   80,
                tabWidth:     2,
                useTabs:      false,
                singleQuote:  true,
                trailingComma:'es5',
                semi:         true,
            });
            return { formatted, error: null };
        } catch(e) {
            // Parse errors are common with incomplete AI snippets — not fatal
            return { formatted: code, error: (e.message || 'Format error').slice(0, 140) };
        }
    }

    // ── highlight.js: primary highlighter for display blocks ──
    // hljs.highlight() is synchronous and returns { value } — an HTML
    // string with <span class="hljs-*"> tokens. We set innerHTML directly.
    // hljs uses atom-one-dark CSS loaded in index.html.
    function highlightWithHljs(codeEl, lang) {
        if (!window.hljs) { applySH(codeEl, lang); return; }
        const canonical = normLang(lang);
        try {
            // Check if hljs knows this language — getLanguage returns null if not
            const knownLang = hljs.getLanguage(canonical) ? canonical : null;
            const result = knownLang
                ? hljs.highlight(codeEl.textContent, { language: knownLang, ignoreIllegals: true })
                : hljs.highlightAuto(codeEl.textContent);  // auto-detect if unknown
            codeEl.innerHTML = result.value;
            codeEl.setAttribute('data-highlighted', knownLang || 'auto');
        } catch(e) {
            console.warn('[AETHER] hljs highlight error:', e.message);
            applySH(codeEl, lang);
        }
    }

    // ── Alias for callers that still say highlightWithCM ──────
    // Previous code wired createCodingBlock to highlightWithCM().
    // Route it to hljs now. CM6 is for the editor widget only.
    function highlightWithCM(codeEl, lang) { highlightWithHljs(codeEl, lang); }

    // ── CodeMirror 6 editor: mounted in AETHER Code widget ────
    // CM6 is ESM-only. It loads via dynamic import() in index.html
    // after page load and exposes window.CM6 = { cm, langPack, oneDark }.
    // mountCM6Editor() mounts a full mini-IDE into a container element.
    // Returns the EditorView instance (call .destroy() to unmount).
    let _cm6PendingCallbacks = [];

    function onCM6Ready(cb) {
        if (window.CM6) { cb(window.CM6); return; }
        _cm6PendingCallbacks.push(cb);
        document.addEventListener('cm6-ready', function handler() {
            document.removeEventListener('cm6-ready', handler);
            _cm6PendingCallbacks.forEach(fn => fn(window.CM6));
            _cm6PendingCallbacks = [];
        }, { once: false });
    }

    async function mountCM6Editor(container, initialCode, lang, onChange) {
        // Textarea fallback — shown immediately while CM6 loads
        let fallbackTA = document.createElement('textarea');
        fallbackTA.value = initialCode;
        fallbackTA.style.cssText = 'width:100%;height:100%;min-height:300px;background:#0a0d12;color:#c8d8e8;font-family:var(--font-mono);font-size:.8rem;padding:12px;border:none;resize:none;box-sizing:border-box;line-height:1.6;';
        fallbackTA.spellcheck = false;
        if (onChange) fallbackTA.addEventListener('input', () => onChange(fallbackTA.value));
        container.appendChild(fallbackTA);

        return new Promise(resolve => {
            onCM6Ready(({ cm, langPack, oneDark }) => {
                try {
                    // Find the language support for this lang
                    const canonical = normLang(lang);
                    const langDesc = langPack.languages.find(l =>
                        l.name.toLowerCase() === canonical ||
                        (l.alias && l.alias.includes(canonical)) ||
                        (l.extensions && l.extensions.includes('.' + canonical))
                    );

                    const extensions = [
                        cm.lineNumbers(),
                        cm.highlightActiveLineGutter(),
                        cm.highlightSpecialChars(),
                        cm.history(),
                        cm.foldGutter(),
                        cm.drawSelection(),
                        cm.dropCursor(),
                        cm.EditorState.allowMultipleSelections.of(true),
                        cm.indentOnInput(),
                        cm.syntaxHighlighting(cm.defaultHighlightStyle, { fallback: true }),
                        cm.bracketMatching(),
                        cm.closeBrackets(),
                        cm.autocompletion(),
                        cm.rectangularSelection(),
                        cm.crosshairCursor(),
                        cm.highlightActiveLine(),
                        cm.highlightSelectionMatches(),
                        cm.keymap.of([
                            ...cm.closeBracketsKeymap,
                            ...cm.defaultKeymap,
                            ...cm.searchKeymap,
                            ...cm.historyKeymap,
                            ...cm.foldKeymap,
                            ...cm.completionKeymap,
                            ...cm.lintKeymap,
                        ]),
                        oneDark.oneDark,
                    ];

                    // Add language support if found
                    if (langDesc) {
                        langDesc.load().then(langSupport => {
                            // Reconfigure editor with language
                            view.dispatch({ effects: cm.StateEffect.appendConfig.of(langSupport) });
                        }).catch(() => {});
                    }

                    // Change listener
                    if (onChange) {
                        extensions.push(cm.EditorView.updateListener.of(update => {
                            if (update.docChanged) onChange(update.state.doc.toString());
                        }));
                    }

                    // Style overrides for AETHER's void-black theme
                    extensions.push(cm.EditorView.theme({
                        '&': { height: '100%', minHeight: '300px', background: '#070a0f' },
                        '.cm-scroller': { fontFamily: 'var(--font-mono)', fontSize: '.8rem', lineHeight: '1.6' },
                        '.cm-content': { caretColor: '#00f3ff' },
                        '.cm-cursor': { borderLeftColor: '#00f3ff' },
                        '.cm-selectionBackground': { background: 'rgba(0,243,255,0.12)' },
                        '.cm-activeLine': { background: 'rgba(0,243,255,0.04)' },
                        '.cm-activeLineGutter': { background: 'rgba(0,243,255,0.06)' },
                        '.cm-gutters': { background: '#040609', borderRight: '1px solid #0d1520', color: '#3d5060' },
                        '.cm-lineNumbers .cm-gutterElement': { paddingRight: '12px' },
                        '.cm-foldGutter .cm-gutterElement': { color: '#3d5060' },
                        '.cm-matchingBracket': { background: 'rgba(0,243,255,0.15)', outline: '1px solid rgba(0,243,255,0.4)' },
                    }));

                    const state = cm.EditorState.create({
                        doc: initialCode,
                        extensions,
                    });

                    // Remove textarea fallback
                    container.removeChild(fallbackTA);
                    fallbackTA = null;

                    const view = new cm.EditorView({ state, parent: container });
                    resolve({
                        view,
                        getValue: () => view.state.doc.toString(),
                        setValue: (code) => view.dispatch({
                            changes: { from: 0, to: view.state.doc.length, insert: code }
                        }),
                        destroy: () => view.destroy(),
                    });
                } catch(e) {
                    console.warn('[AETHER] CM6 mount error:', e.message);
                    // Textarea fallback already in DOM — resolve with its API
                    resolve({
                        view: null,
                        getValue: () => fallbackTA?.value || initialCode,
                        setValue: (code) => { if (fallbackTA) fallbackTA.value = code; },
                        destroy: () => { if (fallbackTA) container.removeChild(fallbackTA); },
                    });
                }
            });
        });
    }

    // ── applySH — tertiary fallback (no CDN needed) ───────────
    // Used when hljs CDN fails. Covers the 10 most common languages
    // with regex-based tokenisation. Not great but never breaks.
    // ── applySH — tertiary fallback (no CDN needed) ───────────
    // Used when hljs CDN fails. Covers common languages with
    // regex-based tokenisation. Not great but never breaks.
    function applySH(el, lang) {
        let c = el.textContent.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        const l = normLang(lang);
        const KW = {
            javascript:/\b(function|const|let|var|if|else|for|while|return|import|export|class|async|await|try|catch|new|this|true|false|null|undefined|typeof|instanceof|switch|case|break|continue|default|throw|of|in)\b/g,
            typescript:/\b(function|const|let|var|if|else|for|while|return|import|export|class|async|await|try|catch|new|this|true|false|null|undefined|typeof|instanceof|switch|case|break|continue|default|throw|of|in|interface|type|enum|namespace|declare|abstract|readonly|override|satisfies|keyof|infer)\b/g,
            python:    /\b(def|class|if|elif|else|for|while|import|from|as|return|try|except|finally|with|lambda|True|False|None|and|or|not|pass|yield|global|nonlocal|raise|del|assert|is|in|async|await)\b/g,
            rust:      /\b(fn|let|mut|pub|use|mod|impl|struct|enum|trait|match|if|else|for|while|return|true|false|None|Some|Ok|Err|self|Self|async|await|move|where|type|const|static|unsafe|extern|dyn|box)\b/g,
            go:        /\b(func|var|const|type|struct|interface|map|chan|if|else|for|range|return|import|package|go|defer|select|case|default|break|continue|nil|true|false|make|new|len|cap|append)\b/g,
            java:      /\b(class|interface|extends|implements|public|private|protected|static|final|void|int|long|double|float|boolean|new|return|if|else|for|while|try|catch|throw|import|package|null|true|false)\b/g,
            cpp:       /\b(auto|bool|char|class|const|constexpr|delete|double|else|enum|false|float|for|if|inline|int|long|namespace|new|nullptr|operator|private|public|return|short|static|struct|template|this|throw|true|try|typedef|using|virtual|void|while)\b/g,
            bash:      /\b(if|then|else|elif|fi|for|while|do|done|case|esac|function|return|local|export|echo|exit|set|unset|source|alias|cd|ls|grep|find|awk|sed)\b/g,
        };
        const kw = KW[l];
        if (kw) c = c.replace(kw, '<span class="kw">$&</span>');
        c = c.replace(/(`[^`]*`|"(?:[^"\\]|\\.)*"|'(?:[^'\\]|\\.)*')/g, '<span class="str">$&</span>');
        c = c.replace(/\b(0x[\da-fA-F]+|\d+\.?\d*([eE][+-]?\d+)?)\b/g, '<span class="num">$&</span>');
        if (['javascript','typescript','java','cpp','rust','go','kotlin','swift'].includes(l)) {
            c = c.replace(/\/\/.*$/gm, '<span class="cmt">$&</span>');
            c = c.replace(/\/\*[\s\S]*?\*\//g, '<span class="cmt">$&</span>');
        } else if (['python','ruby','bash','yaml'].includes(l)) {
            c = c.replace(/#.*$/gm, '<span class="cmt">$&</span>');
        } else if (l === 'html') {
            c = c.replace(/&lt;!--[\s\S]*?--&gt;/g, '<span class="cmt">$&</span>');
        }
        c = c.replace(/\b([a-zA-Z_$][a-zA-Z0-9_$]*)(?=\s*\()/g, '<span class="fn">$&</span>');
        el.innerHTML = c;
    }
    function renderBlocks(lines, parent) {
        let i = 0;
        while (i < lines.length) {
            const bt = getBlockType(lines[i]);
            const t = lines[i].trim();
            if (bt === 'empty') { i++; continue; }
            if (bt === 'hr') { parent.appendChild(document.createElement('hr')); i++; continue; }
            if (typeof bt === 'object' && bt.type === 'graph') {
                i++;
                const gLines = [];
                while (i < lines.length && !lines[i].trim().startsWith('```')) { gLines.push(lines[i]); i++; }
                i++;
                try {
                    parent.appendChild(renderGraph(bt.graphType, gLines));
                } catch(e) { mdLog('error', 'Graph render failed', e.message); }
                continue;
            }
            try {
                switch(bt) {
                    case 'heading': { const lvl=t.match(/^#+/)[0].length; const h=document.createElement(`h${Math.min(lvl,6)}`); h.className='modern-heading'; h.innerHTML=parseInline(t.replace(/^#+\s*/,'')); parent.appendChild(h); i++; break; }
                    case 'blockquote': { const bq=document.createElement('blockquote'); bq.className='modern-blockquote'; const bqLines=[]; while(i<lines.length&&(lines[i].trim().startsWith('>')||lines[i].trim()==='>')){bqLines.push(lines[i].replace(/^>\s?/,''));i++;} renderBlocks(bqLines,bq); parent.appendChild(bq); break; }
                    case 'ul': case 'ol': case 'task': { const r=renderList(lines,i); parent.appendChild(r.element); i=r.nextIndex; break; }
                    case 'table-row': { const tLines=[]; while(i<lines.length&&lines[i].trim().startsWith('|')){tLines.push(lines[i]);i++;} parent.appendChild(renderTable(tLines)); break; }
                    case 'code-fence': { const rawLang=t.slice(3).trim(); const {lang,filename}=parseCodingFence(rawLang); i++; const cLines=[]; while(i<lines.length&&!lines[i].trim().startsWith('```')){cLines.push(lines[i]);i++;} i++; parent.appendChild(createCodingBlock(lang||'code',cLines.join('\n'),filename)); break; }
                    default: { const pLines=[]; while(i<lines.length){ const nb=getBlockType(lines[i]); if(nb==='empty'||nb!=='paragraph')break; pLines.push(lines[i]);i++;} const p=document.createElement('p'); p.className='modern-paragraph'; p.innerHTML=parseInline(pLines.join(' ')); parent.appendChild(p); break; }
                }
            } catch(e) {
                mdLog('error', 'Block render failed: type=' + JSON.stringify(bt), lines[i]?.slice(0, 100));
                // Fallback: render as plain paragraph
                var fb = document.createElement('p'); fb.className = 'modern-paragraph md-error';
                fb.textContent = lines[i];
                parent.appendChild(fb);
                i++;
            }
        }
    }

    function renderGraph(type, lines) {
        const wrapper=document.createElement('div'); wrapper.className='graph-block';
        const data=[]; let title='';
        lines.forEach(l=>{ const t=l.trim(); if(t.startsWith('title')){title=t.slice(5).trim();return;} const p=t.split('|').map(s=>s.trim()); if(p.length===2&&!isNaN(parseFloat(p[1]))) data.push({label:p[0],value:parseFloat(p[1])}); });
        if(title){const te=document.createElement('div');te.className='graph-title';te.textContent=title;wrapper.appendChild(te);}
        if(!data.length){wrapper.innerHTML+='<div class="graph-fallback">No data</div>';return wrapper;}
        if(type==='pie'){const md=document.createElement('div');md.className='mermaid';let mc='pie showData\n';if(title)mc+=`    title ${title}\n`;data.forEach(d=>mc+=`    "${d.label}" : ${d.value}\n`);md.textContent=mc;wrapper.appendChild(md);setTimeout(()=>mermaid.init(undefined,md),100);return wrapper;}
        if(typeof Chart!=='undefined'){const cv=document.createElement('canvas');wrapper.appendChild(cv);setTimeout(()=>new Chart(cv,{type:type==='bar'?'bar':'line',data:{labels:data.map(d=>d.label),datasets:[{label:'Values',data:data.map(d=>d.value),backgroundColor:'rgba(0,243,255,0.2)',borderColor:'#00f3ff',borderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{y:{beginAtZero:true}}}}),50);}
        return wrapper;
    }


    // ── Tool call pill wrapper ────────────────────────────────
    // Wraps ALL tool invocations in display pills before rendering.
    // Covers: [[bracket]], <xml>, function calls, workspace ops, GitHub, cron etc.
    const TOOL_LABELS = {
        web_search:'🔍 Searching', get_weather:'🌤 Weather', scrape:'🕷 Scraping',
        crawl:'🌐 Crawling', read_file:'📂 Reading file', write_file:'✏️ Writing file',
        fs_read:'📂 Reading', fs_write:'✏️ Writing', fs_patch:'🩹 Patching',
        search_replace:'🩹 Patching', fs_delete:'🗑 Deleting',
        fs_list:'📁 Listing', fs_stat:'ℹ Stat', fs_exists:'? Exists',
        fs_mkdir:'📁 Mkdir', fs_rename:'✏ Rename', fs_copy:'📋 Copy',
        shell:'$ Shell', calculate:'🔢 Calculating',
        puter_terminal:'⚙️ Terminal', puter_deploy:'🚀 Deploying',
        puter_read_file:'📂 Puter read', puter_write_file:'✏️ Puter write',
        github_create_issue:'🐙 GitHub issue', github_commit:'🐙 Committing',
        github_get_file:'🐙 Fetching file', github_list_repos:'🐙 Repos',
        email_send:'📧 Sending email', slack_post:'💬 Slack',
        notion_query:'📝 Notion', notion_add:'📝 Notion write',
        cron_create:'⏱ Scheduling', task_create:'✅ Creating task',
        task_update:'✅ Updating task', glob:'🗂 Glob match', grep_files:'🔎 Grep',
        image_gen:'🎨 Generating image', day_plan:'📅 Calendar',
        set_timer:'⏱ Timer', cancel_timer:'⏱ Cancel timer', list_timers:'⏱ Timers',
        estimate:'⏱ Estimate', unzip:'📦 Unzipping', git_status:'⎇ Git',
        fs_token:'🧮 Token count', shell:'$ Shell', ws_shell:'$ WS Shell',
    };
    function wrapToolCallsForDisplay(text) {
        // 1. [[bracket:arg]] format
        text = text.replace(/\[\[(\w+):\s*([^\]\n]+)\]\]/g, (_, toolName, toolArg) => {
            const label = TOOL_LABELS[toolName] || toolName.replace(/_/g,' ');
            const shortArg = String(toolArg).trim().slice(0,60);
            return '[[TOOL_PILL:' + label + '|' + toolName + '|' + shortArg + ']]';
        });
        // 2. <web_search>{"query":"..."}</web_search> XML format
        text = text.replace(/<(web_search|search|visit_website)>[^<]{2,200}<\/\1>/gi, (m, name) => {
            const label = TOOL_LABELS[name] || name;
            const arg = m.replace(/<[^>]+>/g,'').trim().slice(0,50);
            return '[[TOOL_PILL:' + label + '|' + name + '|' + arg + ']]';
        });
        // 3. <function(tool_name {...})</function> format
        text = text.replace(/<function\((\w+)[^)]*\)[^<]*<\/function>/gi, (_, toolName) => {
            const label = TOOL_LABELS[toolName] || toolName.replace(/_/g,' ');
            return '[[TOOL_PILL:' + label + '|' + toolName + '|…]]';
        });
        return text;
    }

    // ─── THINK TAG SYSTEM (clean split-based approach) ───────
    // Works by splitting the accumulated fullContent string — no char-by-char state machine.
    // Called after every chunk to update both the live think block and the main message.
    let liveThinkEl    = null;  // DOM element for the live think block
    let liveThinkClose = false; // true once </think> has arrived

    function liveThinkReset() {
        liveThinkEl    = null;
        liveThinkClose = false;
    }

    // Split accumulated text into { think, visible, thinkOpen }
    // think = content inside <think>…</think> (or partial if still streaming)
    // visible = everything outside the think tags
    // thinkOpen = true if <think> opened but </think> not yet arrived
    function splitThink(text) {
        const oTag = text.indexOf('<think>');
        if (oTag === -1) return { think: null, visible: text, thinkOpen: false };

        const cTag = text.indexOf('</think>', oTag + 7);
        if (cTag === -1) {
            // Opened but not closed yet
            return {
                think:     text.slice(oTag + 7),
                visible:   text.slice(0, oTag).trim(),
                thinkOpen: true
            };
        }
        return {
            think:     text.slice(oTag + 7, cTag).trim(),
            visible:   (text.slice(0, oTag) + text.slice(cTag + 8)).trim(),
            thinkOpen: false
        };
    }

    // Called during streaming to update think block DOM live
    function updateLiveThink(fullContent, aetherMsg) {
        if (!state.showThoughts) return;
        const { think, thinkOpen } = splitThink(fullContent);
        if (think === null) return; // no think tag yet

        // Create block on first detection — robustly find a valid parent
        if (!liveThinkEl) {
            liveThinkEl = document.createElement('div');
            liveThinkEl.className = 'thought-process modern-thought live-thought';
            liveThinkEl.innerHTML = `
                <div class="thought-header">
                    <svg class="ic-xs"><use href="#ic-brain"/></svg>
                    <span class="thought-title">Reasoning…</span>
                    <div class="thought-live-dot"></div>
                    <span class="thought-token-count"></span>
                    <button class="thought-toggle" onclick="this.closest('.thought-process').classList.toggle('collapsed')">▾</button>
                </div>
                <div class="thought-content"></div>`;

            // Robust DOM insertion — try parent, fall back to display container
            let inserted = false;
            if (aetherMsg && aetherMsg.isConnected && aetherMsg.parentNode) {
                aetherMsg.parentNode.insertBefore(liveThinkEl, aetherMsg);
                inserted = true;
            }
            if (!inserted && display && display.isConnected) {
                display.appendChild(liveThinkEl);
                inserted = true;
            }
            if (!inserted) {
                // Last resort: body
                document.body.appendChild(liveThinkEl);
            }
            agentStatus('think');
        }

        const contentEl = liveThinkEl.querySelector('.thought-content');
        const tokenEl   = liveThinkEl.querySelector('.thought-token-count');
        if (!contentEl) return; // guard against torn-down element

        const tokens = Math.round((think.match(/\S+/g)||[]).length);
        if (tokenEl) tokenEl.textContent = `~${tokens} tokens`;

        const escaped = think.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
        contentEl.innerHTML = escaped + (thinkOpen ? '<span class="streaming-cursor">▋</span>' : '');

        // Finalize block once </think> arrives
        if (!thinkOpen && liveThinkEl.classList.contains('live-thought')) {
            liveThinkEl.classList.remove('live-thought');
            const dot   = liveThinkEl.querySelector('.thought-live-dot');
            const title = liveThinkEl.querySelector('.thought-title');
            if (dot)   dot.remove();
            if (title) title.textContent = 'Chain of Thought';
            liveThinkClose = true;
            agentDone();
        }
    }

    // ═══════════════════════════════════════════════════════════
    // SECTION 14: STT — SPEECH-TO-TEXT ENGINE
    // Five engines: Browser (free), Groq Whisper, OpenAI Whisper,
    // Whisper.cpp (local), Google Cloud, and Vosk (local).
    // Records audio, sends to the chosen engine, returns text.
    // If the engine fails, the user's voice echoes into the void.
    // Poetic, but not useful. Hence the error notifications.
    // ═══════════════════════════════════════════════════════════

    // ═══════════════════════════════════════════════════════════
    // SECTION 15: MARKDOWN RENDERER
    // Parses markdown text into HTML DOM elements.
    // Handles: headings, bold, italic, code blocks, tables,
    // lists, blockquotes, links, images, checkboxes, and more.
    // Does NOT use a library. Yes, we wrote our own parser.
    // ═══════════════════════════════════════════════════════════
    // AETHER VISUALIZER — Inline module (v0.1.0)
    // Browser-only visualization engine. Inlined from aether-visualizer.js
    // so it works in the monolithic single-file architecture without ESM.
    //
    // Renders: bar, line, area, horizontal-bar, stacked-bar, stacked-line,
    //          donut, pie, scatter, bubble, radar, gantt, heatmap, timeline,
    //          table, flow (TB/LR/radial layouts), struct, raw SVG, Mermaid.
    //
    // Usage: AetherVisualizer.autoDetect(llmText, container)
    // Returns true if a spec or mermaid block was rendered, false for plain text.
    // ═══════════════════════════════════════════════════════════
    (function() {
        const VIZ_COLORS = {
            blue:   { fill:'#0d1e30', stroke:'#378ADD', text:'#7ab8f0' },
            purple: { fill:'#140e2a', stroke:'#7F77DD', text:'#b0aaee' },
            teal:   { fill:'#091e18', stroke:'#1D9E75', text:'#5ecfaa' },
            amber:  { fill:'#1e1400', stroke:'#BA7517', text:'#e0a040' },
            coral:  { fill:'#200a00', stroke:'#D85A30', text:'#f0906a' },
            pink:   { fill:'#200010', stroke:'#D4537E', text:'#f08aaa' },
            green:  { fill:'#0a1a00', stroke:'#639922', text:'#90cc44' },
            red:    { fill:'#200000', stroke:'#E24B4A', text:'#f08080' },
            gray:   { fill:'#0d1520', stroke:'#334455', text:'#8aaabb' },
            cyan:   { fill:'#001e22', stroke:'#00c8d8', text:'#44e0ee' },
        };
        const VIZ_PALETTE = ['#378ADD','#7F77DD','#1D9E75','#BA7517','#D85A30','#D4537E','#639922','#E24B4A','#00c8d8','#f0c040'];
        const ARROW = `<defs><marker id="av-arrow" viewBox="0 0 10 10" refX="8" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse"><path d="M2 1L8 5L2 9" fill="none" stroke="#556677" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></marker><marker id="av-arrow-lr" viewBox="0 0 10 10" refX="8" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M2 1L8 5L2 9" fill="none" stroke="#556677" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></marker></defs>`;
        const SAFE_TAGS = new Set(['svg','g','rect','circle','ellipse','line','path','polyline','polygon','text','tspan','defs','marker','linearGradient','radialGradient','stop','clipPath','title','desc','foreignObject']);
        const SAFE_ATTRS = new Set(['viewBox','width','height','xmlns','x','y','x1','y1','x2','y2','cx','cy','r','rx','ry','d','points','fill','stroke','stroke-width','stroke-dasharray','stroke-linecap','stroke-linejoin','stroke-opacity','fill-opacity','opacity','transform','text-anchor','dominant-baseline','font-size','font-weight','font-family','marker-end','marker-start','id','style','offset','stop-color','stop-opacity','gradientUnits','markerWidth','markerHeight','refX','refY','orient','preserveAspectRatio']);

        function vc(name) { return VIZ_COLORS[name] || VIZ_COLORS.gray; }
        function vcPalette(i) { return VIZ_PALETTE[i % VIZ_PALETTE.length]; }
        function clamp(v,mn,mx) { return Math.max(mn,Math.min(mx,v)); }
        function escHtml(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

        function baseContainer(c) {
            c.innerHTML = '';
            c.style.cssText = 'font-family:system-ui,sans-serif;background:transparent;width:100%;box-sizing:border-box;';
            return c;
        }

        function vizErr(c, msg, rawSpec) {
            c.innerHTML = `<div style="padding:12px 14px;color:#e08080;font-size:.72rem;border:1px solid rgba(200,80,80,0.25);border-radius:8px;background:rgba(200,80,80,0.05);">
                <strong>⚠ Visualizer error:</strong> ${escHtml(msg)}
                ${rawSpec ? `<details style="margin-top:6px"><summary style="cursor:pointer;color:#8a6a6a">Show spec</summary><pre style="font-size:.65rem;color:#6a5a5a;margin:6px 0 0;white-space:pre-wrap">${escHtml(typeof rawSpec==='string'?rawSpec:JSON.stringify(rawSpec,null,2))}</pre></details>` : ''}
            </div>`;
        }

        function sanitizeSVG(svgStr) {
            const parser = new DOMParser();
            const doc = parser.parseFromString(svgStr, 'image/svg+xml');
            if (doc.querySelector('parseerror,parsererror')) throw new Error('Invalid SVG');
            function clean(node) {
                if (node.nodeType === 1) {
                    const tag = node.tagName.toLowerCase().replace(/^svg:/,'');
                    if (!SAFE_TAGS.has(tag)) { node.remove(); return; }
                    for (const a of [...node.attributes]) {
                        if (/^on|href|xlink|src|action|formaction|data:/i.test(a.name) || !SAFE_ATTRS.has(a.name)) node.removeAttribute(a.name);
                    }
                    // Inline style — strip url() and javascript:
                    const style = node.getAttribute('style');
                    if (style) node.setAttribute('style', style.replace(/url\s*\(|javascript:/gi,''));
                    for (const ch of [...node.childNodes]) clean(ch);
                } else if (node.nodeType !== 3) { node.remove(); }
            }
            clean(doc.documentElement);
            return new XMLSerializer().serializeToString(doc.documentElement);
        }

        // ── Schema normalisation — accepts multiple input formats ─
        function normalizeSpec(raw) {
            if (!raw || typeof raw !== 'object') return null;
            // Already correct format
            if (raw.type && raw.datasets) return raw;
            // Chart.js native: {type, data: {labels, datasets}, options}
            if (raw.type && raw.data?.datasets) {
                return { type: raw.type, labels: raw.data.labels || [], datasets: raw.data.datasets, options: raw.options?.plugins?.title ? { title: raw.options.plugins.title.text } : {} };
            }
            // Flat format: {type, data: [1,2,3], labels: [], label: 'Series'}
            if (raw.type && Array.isArray(raw.data) && !raw.data[0]?.data) {
                return { type: raw.type, labels: raw.labels || [], datasets: [{ label: raw.label || '', data: raw.data, color: raw.color }], options: raw.options || {} };
            }
            // Table flat: {type:'table', headers:[], rows:[[]]}
            if (raw.type === 'table' && raw.headers) return raw;
            // Gantt flat: {type:'gantt', tasks:[]}
            if (raw.type === 'gantt' && raw.tasks) return raw;
            // Heatmap: {type:'heatmap', data:[[]], xLabels:[], yLabels:[]}
            if (raw.type === 'heatmap' && raw.data) return raw;
            // Timeline: {type:'timeline', events:[]}
            if (raw.type === 'timeline' && raw.events) return raw;
            return null;
        }

        function extractSpec(text) {
            if (!text || typeof text !== 'string') return null;
            // Try raw JSON
            try { const t=text.trim(); if(t.startsWith('{')){ const p=JSON.parse(t); const n=normalizeSpec(p); if(n) return n; } } catch(_){}
            // Try inside ```json fences
            const fenceMatch = text.match(/```(?:json|chart|viz|visuali[sz]er)?\s*([\s\S]*?)```/);
            if (fenceMatch) { try { const p=JSON.parse(fenceMatch[1].trim()); const n=normalizeSpec(p); if(n) return n; } catch(_){} }
            // Try any JSON object in text
            const anyJson = text.match(/\{[\s\S]*"type"[\s\S]*\}/);
            if (anyJson) { try { const p=JSON.parse(anyJson[0]); const n=normalizeSpec(p); if(n) return n; } catch(_){} }
            return null;
        }

        function extractMermaid(text) {
            const m = text.match(/```mermaid\s*([\s\S]*?)```/);
            return m ? m[1].trim() : null;
        }

        // ── Chart.js ─────────────────────────────────────────────
        async function ensureChartJS() {
            if (window.Chart) return;
            await new Promise((resolve,reject)=>{
                const s=document.createElement('script');
                s.src='https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.0/chart.umd.min.js';
                s.onload=resolve; s.onerror=()=>reject(new Error('Chart.js load failed'));
                document.head.appendChild(s);
            });
        }

        const _chartCache = new WeakMap();

        function addExportBtn(container, getBlob, filename) {
            const btn = document.createElement('button');
            btn.style.cssText = 'position:absolute;top:8px;right:8px;background:rgba(0,0,0,0.5);border:1px solid #334455;color:#8aaabb;font-size:.62rem;font-family:monospace;padding:3px 8px;border-radius:4px;cursor:pointer;opacity:0;transition:opacity .15s;z-index:2';
            btn.textContent = '↓';
            btn.title = 'Export';
            container.style.position = 'relative';
            container.addEventListener('mouseenter', () => btn.style.opacity = '1');
            container.addEventListener('mouseleave', () => btn.style.opacity = '0');
            btn.onclick = async () => {
                const blob = await getBlob();
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a'); a.href = url; a.download = filename; a.click();
                setTimeout(() => URL.revokeObjectURL(url), 2000);
            };
            container.appendChild(btn);
        }

        async function renderChart(spec, container, type) {
            await ensureChartJS();
            const canvas = document.createElement('canvas'); canvas.style.maxHeight = '320px';
            container.appendChild(canvas);
            const prev = _chartCache.get(container); if (prev) prev.destroy();

            const isDonut  = type === 'donut' || type === 'pie';
            const isScatter = type === 'scatter';
            const isBubble  = type === 'bubble';
            const isRadar   = type === 'radar';
            const isHBar    = type === 'bar-horizontal';
            const isStacked = type === 'stacked-bar' || type === 'stacked-line';
            const baseType  = isDonut ? 'doughnut' : isHBar ? 'bar' : isStacked ? (type==='stacked-line'?'line':'bar') : type;
            const isArea    = type === 'area';

            const datasets = spec.datasets.map((d,i)=>({
                label: d.label || '',
                data: d.data,
                backgroundColor: isDonut ? (d.colors || VIZ_PALETTE.slice(0, (d.data||[]).length)) : isArea ? (d.color||vcPalette(i))+'44' : (d.color||vcPalette(i))+'cc',
                borderColor: isDonut ? (d.colors || VIZ_PALETTE.slice(0, (d.data||[]).length)) : (d.color||vcPalette(i)),
                borderWidth: isDonut ? 2 : 2,
                borderRadius: (isDonut||isScatter||isBubble||isRadar||isArea) ? 0 : 4,
                tension: 0.4,
                fill: isArea ? 'origin' : (d.fill || false),
                pointRadius: (isScatter||isBubble) ? 5 : 3,
                pointHoverRadius: 6,
            }));

            const inst = new Chart(canvas, {
                type: isArea ? 'line' : baseType,
                data: { labels: spec.labels || [], datasets },
                options: {
                    responsive: true,
                    animation: { duration: 500 },
                    indexAxis: isHBar ? 'y' : 'x',
                    plugins: {
                        legend: { display: !!(isDonut||isRadar||datasets.length>1), labels: { color:'#8aaabb', font:{ size:11 }, boxWidth:12 } },
                        title: { display: !!spec.options?.title, text: spec.options?.title||'', color:'#c8d8e8', font:{ size:13, weight:'500' } },
                        tooltip: { backgroundColor:'rgba(6,8,16,0.92)', titleColor:'#c8d8e8', bodyColor:'#8aaabb', borderColor:'#1e3048', borderWidth:1, padding:10, callbacks:{
                            label: ctx => {
                                const v = ctx.parsed?.y ?? ctx.parsed;
                                return ' ' + (ctx.dataset.label ? ctx.dataset.label + ': ' : '') + (typeof v==='number' ? v.toLocaleString() : v);
                            }
                        }},
                    },
                    scales: (isDonut||isRadar) ? (isRadar ? { r:{ ticks:{ color:'#556677', backdropColor:'transparent' }, grid:{ color:'rgba(255,255,255,0.08)' }, pointLabels:{ color:'#8aaabb', font:{size:11} } } } : {}) : {
                        x: { stacked: isStacked, ticks:{ color:'#556677', maxRotation:45 }, grid:{ color:'rgba(255,255,255,0.05)' }, title:{ display:!!spec.options?.xLabel, text:spec.options?.xLabel||'', color:'#556677', font:{size:11} } },
                        y: { stacked: isStacked, ticks:{ color:'#556677' }, grid:{ color:'rgba(255,255,255,0.05)' }, title:{ display:!!spec.options?.yLabel, text:spec.options?.yLabel||'', color:'#556677', font:{size:11} } },
                    },
                },
            });
            _chartCache.set(container, inst);

            // Export PNG
            addExportBtn(container, () => new Promise(res => canvas.toBlob(res, 'image/png')), (spec.options?.title||type)+'.png');
        }

        // ── Table ─────────────────────────────────────────────────
        function renderTable(spec, container) {
            const { headers=[], rows=[], options={} } = spec;
            let sortCol = -1, sortAsc = true;
            const wrap = document.createElement('div');
            wrap.style.cssText = 'overflow-x:auto;border-radius:8px;border:1px solid #1e2535;';

            function buildTable() {
                const sorted = sortCol >= 0 ? [...rows].sort((a,b) => {
                    const av = a[sortCol], bv = b[sortCol];
                    const n = (v) => !isNaN(parseFloat(v));
                    const cmp = n(av) && n(bv) ? parseFloat(av)-parseFloat(bv) : String(av).localeCompare(String(bv));
                    return sortAsc ? cmp : -cmp;
                }) : rows;

                // Theme-aware: classes instead of dark inline hex (Ivory was stuck light-black)
                let html = `<table class="aether-data-table" style="width:100%;border-collapse:collapse;font-size:.78rem;font-family:var(--font-mono,monospace);">`;
                if (headers.length) {
                    html += '<thead><tr>' + headers.map((h,i) => {
                        const active = sortCol === i;
                        const icon = active ? (sortAsc ? ' ↑' : ' ↓') : '';
                        return `<th data-col="${i}" class="aether-data-th" style="font-weight:600;padding:9px 12px;text-align:left;cursor:pointer;user-select:none;white-space:nowrap;">${escHtml(h)}${icon}</th>`;
                    }).join('') + '</tr></thead>';
                }
                html += '<tbody>' + sorted.map((row, ri) =>
                    `<tr class="${ri % 2 === 0 ? 'row-even' : 'row-odd'}">` +
                    row.map(cell => `<td style="padding:8px 12px;white-space:nowrap;">${escHtml(cell)}</td>`).join('') +
                    '</tr>'
                ).join('') + '</tbody></table>';
                wrap.innerHTML = html;

                // Sort click
                wrap.querySelectorAll('th[data-col]').forEach(th => {
                    th.onclick = () => {
                        const col = +th.dataset.col;
                        if (sortCol === col) sortAsc = !sortAsc;
                        else { sortCol = col; sortAsc = true; }
                        buildTable();
                    };
                });
            }
            buildTable();
            container.appendChild(wrap);

            // Export CSV
            addExportBtn(container, () => {
                const lines = [headers.join(','), ...rows.map(r => r.map(c => `"${String(c).replace(/"/g,'""')}"`).join(','))];
                return Promise.resolve(new Blob([lines.join('\n')], { type:'text/csv' }));
            }, (spec.options?.title||'table')+'.csv');
        }

        // ── Gantt ─────────────────────────────────────────────────
        function renderGantt(spec, container) {
            const tasks = spec.tasks || [];
            if (!tasks.length) { vizErr(container, 'No tasks'); return; }
            const PAD = 24, LABEL_W = 160, ROW_H = 36, HEADER_H = 40;
            const allDates = tasks.flatMap(t => [new Date(t.start), new Date(t.end)]);
            const minD = new Date(Math.min(...allDates)), maxD = new Date(Math.max(...allDates));
            const totalMs = maxD - minD;
            const W = 800, chartW = W - LABEL_W - PAD*2;
            const H = HEADER_H + tasks.length * ROW_H + PAD;

            let svg = `<svg width="100%" viewBox="0 0 ${W} ${H}" font-family="system-ui" font-size="11">`;
            // Header background
            svg += `<rect x="0" y="0" width="${W}" height="${HEADER_H}" fill="#0a1018"/>`;
            // Month labels
            const ms = new Date(minD); ms.setDate(1);
            while (ms <= maxD) {
                const x = LABEL_W + PAD + ((ms - minD) / totalMs) * chartW;
                svg += `<text x="${x}" y="${HEADER_H/2}" dominant-baseline="central" fill="#556677" font-size="10">${ms.toLocaleString('default',{month:'short'})}</text>`;
                svg += `<line x1="${x}" y1="${HEADER_H}" x2="${x}" y2="${H}" stroke="#1e2535" stroke-width="1"/>`;
                ms.setMonth(ms.getMonth()+1);
            }
            // Today line
            const todayX = LABEL_W + PAD + ((Date.now() - minD) / totalMs) * chartW;
            if (todayX > LABEL_W && todayX < W) {
                svg += `<line x1="${todayX}" y1="${HEADER_H}" x2="${todayX}" y2="${H}" stroke="#00f3ff" stroke-width="1" stroke-dasharray="4 3" opacity="0.5"/>`;
                svg += `<text x="${todayX+4}" y="${HEADER_H+12}" fill="#00f3ff" font-size="9" opacity="0.7">today</text>`;
            }

            tasks.forEach((t, i) => {
                const y = HEADER_H + i * ROW_H;
                const tx = LABEL_W + PAD + ((new Date(t.start) - minD) / totalMs) * chartW;
                const tw = Math.max(4, ((new Date(t.end) - new Date(t.start)) / totalMs) * chartW);
                const col = vcPalette(i);
                const bg = i%2===0 ? '#060810' : '#080e16';
                svg += `<rect x="0" y="${y}" width="${W}" height="${ROW_H}" fill="${bg}"/>`;
                svg += `<text x="${LABEL_W-8}" y="${y+ROW_H/2}" text-anchor="end" dominant-baseline="central" fill="#8aaabb" font-size="11">${escHtml(t.label||t.name||t.task||'Task')}</text>`;
                svg += `<rect x="${tx}" y="${y+6}" width="${tw}" height="${ROW_H-12}" rx="4" fill="${col}33" stroke="${col}" stroke-width="1"/>`;
                if (tw > 40) svg += `<text x="${tx+tw/2}" y="${y+ROW_H/2}" text-anchor="middle" dominant-baseline="central" fill="${col}" font-size="10">${escHtml(t.label||t.name||'')}</text>`;
                if (t.progress != null) {
                    const pw = tw * Math.min(1, Math.max(0, t.progress/100));
                    svg += `<rect x="${tx}" y="${y+ROW_H-8}" width="${pw}" height="3" rx="1" fill="${col}" opacity="0.7"/>`;
                }
            });
            svg += '</svg>';
            container.innerHTML = svg;

            addExportBtn(container, () => Promise.resolve(new Blob([svg], { type:'image/svg+xml' })), (spec.options?.title||'gantt')+'.svg');
        }

        // ── Heatmap ───────────────────────────────────────────────
        function renderHeatmap(spec, container) {
            const { data=[], xLabels=[], yLabels=[], options={} } = spec;
            if (!data.length) { vizErr(container, 'No data'); return; }
            const allVals = data.flat().filter(v => v != null);
            const minV = Math.min(...allVals), maxV = Math.max(...allVals);
            const CELL = 44, PAD = 8, LABEL_H = 64, LABEL_W = 80;
            const W = LABEL_W + xLabels.length * CELL + PAD;
            const H = LABEL_H + yLabels.length * CELL + PAD;
            const baseColor = options.color || '#378ADD';
            const hex2rgb = h => { const r=parseInt(h.slice(1,3),16), g=parseInt(h.slice(3,5),16), b=parseInt(h.slice(5,7),16); return [r,g,b]; };
            const [br,bg,bb] = hex2rgb(baseColor);
            let svg = `<svg width="100%" viewBox="0 0 ${W} ${H}" font-family="system-ui">`;
            xLabels.forEach((l,i) => {
                svg += `<text x="${LABEL_W+i*CELL+CELL/2}" y="${LABEL_H-8}" text-anchor="middle" fill="#556677" font-size="10" transform="rotate(-35,${LABEL_W+i*CELL+CELL/2},${LABEL_H-8})">${escHtml(l)}</text>`;
            });
            yLabels.forEach((l,i) => {
                svg += `<text x="${LABEL_W-8}" y="${LABEL_H+i*CELL+CELL/2}" text-anchor="end" dominant-baseline="central" fill="#556677" font-size="10">${escHtml(l)}</text>`;
            });
            data.forEach((row,ri) => row.forEach((val,ci) => {
                if (val == null) return;
                const t = maxV===minV ? 0.5 : (val-minV)/(maxV-minV);
                const r=Math.round(br*t+20*(1-t)), g=Math.round(bg*t+30*(1-t)), b=Math.round(bb*t+50*(1-t));
                const x = LABEL_W+ci*CELL, y = LABEL_H+ri*CELL;
                svg += `<rect x="${x+2}" y="${y+2}" width="${CELL-4}" height="${CELL-4}" rx="4" fill="rgba(${r},${g},${b},${0.3+t*0.7})"/>`;
                svg += `<text x="${x+CELL/2}" y="${y+CELL/2}" text-anchor="middle" dominant-baseline="central" font-size="10" fill="${t>0.5?'#c8d8e8':'#8aaabb'}">${typeof val==='number'?val.toLocaleString():val}</text>`;
            }));
            svg += '</svg>';
            container.innerHTML = svg;
            addExportBtn(container, () => Promise.resolve(new Blob([svg], { type:'image/svg+xml' })), 'heatmap.svg');
        }

        // ── Timeline ──────────────────────────────────────────────
        function renderTimeline(spec, container) {
            const events = spec.events || [];
            if (!events.length) { vizErr(container, 'No events'); return; }
            const PAD = 24, ITEM_H = 64, DOT_R = 7, LINE_X = 120;
            const H = PAD + events.length * ITEM_H + PAD;
            let svg = `<svg width="100%" viewBox="0 0 700 ${H}" font-family="system-ui">`;
            svg += `<line x1="${LINE_X}" y1="${PAD}" x2="${LINE_X}" y2="${H-PAD}" stroke="#1e3048" stroke-width="2"/>`;
            events.forEach((ev, i) => {
                const y = PAD + i * ITEM_H + ITEM_H/2;
                const col = vcPalette(i);
                svg += `<circle cx="${LINE_X}" cy="${y}" r="${DOT_R}" fill="${col}" stroke="#060810" stroke-width="2"/>`;
                if (ev.date || ev.time) svg += `<text x="${LINE_X-16}" y="${y}" text-anchor="end" dominant-baseline="central" fill="#556677" font-size="10">${escHtml(ev.date||ev.time)}</text>`;
                svg += `<text x="${LINE_X+20}" y="${y-(ev.description?8:0)}" dominant-baseline="central" fill="#c8d8e8" font-size="13" font-weight="500">${escHtml(ev.label||ev.title||ev.event)}</text>`;
                if (ev.description) svg += `<text x="${LINE_X+20}" y="${y+14}" dominant-baseline="central" fill="#556677" font-size="11">${escHtml(ev.description)}</text>`;
            });
            svg += '</svg>';
            container.innerHTML = svg;
            addExportBtn(container, () => Promise.resolve(new Blob([svg], { type:'image/svg+xml' })), 'timeline.svg');
        }

        // ── Flow diagram ──────────────────────────────────────────
        function renderFlow(spec, container) {
            const nodes = spec.nodes || [], edges = spec.edges || [];
            const layout = (spec.layout || 'TB').toUpperCase();
            const NW = 140, NH = 48, GAPX = 70, GAPY = 80, PAD = 30;

            // Topological rank
            const rank = {}; nodes.forEach(n => { rank[n.id] = 0; });
            let changed = true;
            for (let pass = 0; pass < nodes.length && changed; pass++) {
                changed = false;
                edges.forEach(e => { if (rank[e.to] <= rank[e.from]) { rank[e.to] = rank[e.from] + 1; changed = true; } });
            }
            const layers = [];
            nodes.forEach(n => { const r = rank[n.id]||0; (layers[r]=layers[r]||[]).push(n); });

            // Radial layout
            if (layout === 'RADIAL') {
                const cx = 320, cy = 280, R_INNER = 90, R_OUTER = 220;
                const pos = {};
                const center = nodes.find(n => !edges.some(e => e.to === n.id)) || nodes[0];
                if (center) pos[center.id] = { x: cx - NW/2, y: cy - NH/2 };
                const rest = nodes.filter(n => n.id !== center?.id);
                rest.forEach((n, i) => {
                    const angle = (i / rest.length) * Math.PI * 2 - Math.PI/2;
                    const r = rest.length > 6 ? R_OUTER : R_INNER + 40;
                    pos[n.id] = { x: cx + Math.cos(angle)*r - NW/2, y: cy + Math.sin(angle)*r - NH/2 };
                });
                return renderFlowPositioned(spec, container, pos, nodes, edges, NW, NH, 700, 580);
            }

            const pos = {};
            let maxX = 0, maxY = 0;
            if (layout === 'LR') {
                layers.forEach((layer, li) => {
                    const x = PAD + li * (NW + GAPX);
                    const totalH = layer.length * (NH + GAPY) - GAPY;
                    layer.forEach((n, ni) => {
                        const y = PAD + ni * (NH + GAPY) + (totalH < 300 ? (300-totalH)/2 : 0);
                        pos[n.id] = { x, y }; maxX = Math.max(maxX, x+NW); maxY = Math.max(maxY, y+NH);
                    });
                });
            } else { // TB (default)
                layers.forEach((layer, li) => {
                    const y = PAD + li * (NH + GAPY);
                    const totalW = layer.length * (NW + GAPX) - GAPX;
                    layer.forEach((n, ni) => {
                        const x = PAD + ni * (NW + GAPX) + (totalW < 400 ? (400-totalW)/2 : 0);
                        pos[n.id] = { x, y }; maxX = Math.max(maxX, x+NW); maxY = Math.max(maxY, y+NH);
                    });
                });
            }
            return renderFlowPositioned(spec, container, pos, nodes, edges, NW, NH, maxX+PAD, maxY+PAD);
        }

        function renderFlowPositioned(spec, container, pos, nodes, edges, NW, NH, maxX, maxY) {
            let edgeSvg = '', nodeSvg = '';
            edges.forEach(e => {
                const s = pos[e.from], t = pos[e.to]; if (!s||!t) return;
                const x1 = s.x+NW/2, y1 = s.y+NH, x2 = t.x+NW/2, y2 = t.y;
                const isBack = s.y >= t.y && s.x === t.x;
                if (isBack) {
                    const cx = Math.max(x1,x2)+50;
                    edgeSvg += `<path d="M${x1} ${s.y+NH/2} L${cx} ${s.y+NH/2} L${cx} ${t.y+NH/2} L${x2} ${t.y+NH/2}" fill="none" stroke="#334455" stroke-width="1.5" stroke-dasharray="5 3" marker-end="url(#av-arrow)"/>`;
                } else {
                    const mx = (x1+x2)/2, my = (y1+y2)/2;
                    edgeSvg += `<path d="M${x1} ${y1} C${x1} ${my+20},${x2} ${my-20},${x2} ${y2}" fill="none" stroke="#334455" stroke-width="1.5" marker-end="url(#av-arrow)"/>`;
                    if (e.label) edgeSvg += `<text x="${mx+6}" y="${my}" font-size="10" fill="#556677" font-family="system-ui">${escHtml(e.label)}</text>`;
                }
            });
            nodes.forEach(n => {
                const {x,y} = pos[n.id] || {x:0,y:0};
                const c = vc(n.color||'gray');
                const shape = n.shape || 'rect';
                const ty = n.sub ? y+NH*0.36 : y+NH/2;
                if (shape === 'diamond') {
                    const cx2 = x+NW/2, cy2 = y+NH/2;
                    nodeSvg += `<g><polygon points="${cx2},${y} ${x+NW},${cy2} ${cx2},${y+NH} ${x},${cy2}" fill="${c.fill}" stroke="${c.stroke}" stroke-width="1"/>`;
                } else if (shape === 'circle') {
                    nodeSvg += `<g><ellipse cx="${x+NW/2}" cy="${y+NH/2}" rx="${NW/2}" ry="${NH/2}" fill="${c.fill}" stroke="${c.stroke}" stroke-width="1"/>`;
                } else {
                    nodeSvg += `<g><rect x="${x}" y="${y}" width="${NW}" height="${NH}" rx="8" fill="${c.fill}" stroke="${c.stroke}" stroke-width="1"/>`;
                }
                nodeSvg += `<text x="${x+NW/2}" y="${ty}" text-anchor="middle" dominant-baseline="central" font-size="12" font-weight="500" fill="${c.text}" font-family="system-ui">${escHtml(n.label||n.id)}</text>`;
                if (n.sub) nodeSvg += `<text x="${x+NW/2}" y="${y+NH*0.72}" text-anchor="middle" dominant-baseline="central" font-size="9" fill="${c.stroke}" font-family="system-ui">${escHtml(n.sub)}</text>`;
                nodeSvg += '</g>';
            });
            const W = clamp(maxX, 300, 1000), H = clamp(maxY, 100, 1400);
            const svg = document.createElementNS('http://www.w3.org/2000/svg','svg');
            svg.setAttribute('width','100%'); svg.setAttribute('viewBox',`0 0 ${W} ${H}`); svg.style.overflow = 'visible';
            svg.innerHTML = ARROW + edgeSvg + nodeSvg;
            container.appendChild(svg);
            addExportBtn(container, () => {
                const s = new XMLSerializer().serializeToString(svg);
                return Promise.resolve(new Blob([s], { type:'image/svg+xml' }));
            }, (spec.options?.title||'flow')+'.svg');
        }

        // ── Struct diagram ────────────────────────────────────────
        function renderStruct(spec, container) {
            const regions = spec.regions||[], W = 640, PAD = 20, OUTER_X = 20, OUTER_Y = 20, OUTER_W = W-40, R_H = spec.layout?.regionHeight||110, GAP = 12;
            const totalW = OUTER_W-PAD*2;
            const rW = regions.length > 0 ? Math.floor((totalW-(regions.length-1)*GAP)/regions.length) : totalW;
            const OUTER_H = R_H+70; const c = vc(spec.color||'purple');
            let rSvg = '';
            regions.forEach((r,i) => {
                const rx = OUTER_X+PAD+(rW+GAP)*i, ry = OUTER_Y+48, rc = vc(r.color||'blue');
                rSvg += `<rect x="${rx}" y="${ry}" width="${rW}" height="${R_H}" rx="8" fill="${rc.fill}" stroke="${rc.stroke}" stroke-width="0.5"/>
                    <text x="${rx+rW/2}" y="${ry+(r.sub?36:R_H/2)}" text-anchor="middle" dominant-baseline="central" font-size="12" font-weight="500" fill="${rc.text}" font-family="system-ui">${escHtml(r.label)}</text>
                    ${r.sub ? `<text x="${rx+rW/2}" y="${ry+60}" text-anchor="middle" dominant-baseline="central" font-size="10" fill="${rc.stroke}" font-family="system-ui">${escHtml(r.sub)}</text>` : ''}`;
            });
            const svg = document.createElementNS('http://www.w3.org/2000/svg','svg');
            svg.setAttribute('width','100%'); svg.setAttribute('viewBox',`0 0 ${W} ${OUTER_H+40}`);
            svg.innerHTML = `<rect x="${OUTER_X}" y="${OUTER_Y}" width="${OUTER_W}" height="${OUTER_H}" rx="14" fill="${c.fill}" stroke="${c.stroke}" stroke-width="0.5" stroke-dasharray="6 4"/>
                <text x="${OUTER_X+16}" y="${OUTER_Y+24}" dominant-baseline="central" font-size="12" font-weight="500" fill="${c.text}" font-family="system-ui">${escHtml(spec.label||'Container')}</text>${rSvg}`;
            container.appendChild(svg);
            addExportBtn(container, () => {
                const s = new XMLSerializer().serializeToString(svg);
                return Promise.resolve(new Blob([s], { type:'image/svg+xml' }));
            }, 'struct.svg');
        }

        // ── Mermaid ───────────────────────────────────────────────
        let _mermaidReady = false;
        async function ensureMermaid() {
            if (_mermaidReady || window.__aether_mermaid) return;
            if (!window.mermaid) {
                try {
                    const { default: m } = await import('https://esm.sh/mermaid@11/dist/mermaid.esm.min.mjs');
                    window.__aether_mermaid = m;
                } catch(e) { throw new Error('Mermaid not available'); }
            } else { window.__aether_mermaid = window.mermaid; }

            window.__aether_mermaid.initialize({
                startOnLoad: false,
                theme: 'base',
                fontFamily: 'system-ui, sans-serif',
                themeVariables: {
                    darkMode: true,
                    background: '#060810',
                    primaryColor: '#0d1520',
                    primaryTextColor: '#c8d8e8',
                    primaryBorderColor: '#1e3048',
                    secondaryColor: '#0a1018',
                    tertiaryColor: '#060810',
                    lineColor: '#334455',
                    textColor: '#8aaabb',
                    edgeLabelBackground: '#060810',
                    clusterBkg: '#0a1018',
                    clusterBorder: '#1e3048',
                    titleColor: '#c8d8e8',
                    nodeTextColor: '#c8d8e8',
                    fontSize: '13px',
                }
            });
            _mermaidReady = true;
        }

        async function renderMermaid(syntax, container) {
            await ensureMermaid();
            const id = 'av-mermaid-' + Math.random().toString(36).slice(2);
            const { svg } = await window.__aether_mermaid.render(id, syntax);
            container.innerHTML = svg;
            // Fix Mermaid SVG background
            const svgEl = container.querySelector('svg');
            if (svgEl) { svgEl.style.background = 'transparent'; svgEl.setAttribute('width','100%'); }
            addExportBtn(container, () => Promise.resolve(new Blob([svg], { type:'image/svg+xml' })), 'diagram.svg');
        }

        // ── Master render ─────────────────────────────────────────
        async function render(spec, container) {
            if (!spec || !spec.type) throw new Error('No type in spec');
            baseContainer(container);
            switch (spec.type) {
                case 'bar':           await renderChart(spec, container, 'bar');          break;
                case 'bar-horizontal':
                case 'horizontal-bar': await renderChart(spec, container, 'bar-horizontal'); break;
                case 'stacked-bar':   await renderChart(spec, container, 'stacked-bar'); break;
                case 'stacked-line':  await renderChart(spec, container, 'stacked-line'); break;
                case 'line':          await renderChart(spec, container, 'line');         break;
                case 'area':          await renderChart(spec, container, 'area');         break;
                case 'donut':
                case 'pie':           await renderChart(spec, container, 'donut');        break;
                case 'scatter':       await renderChart(spec, container, 'scatter');      break;
                case 'bubble':        await renderChart(spec, container, 'bubble');       break;
                case 'radar':
                case 'spider':        await renderChart(spec, container, 'radar');        break;
                case 'flow':          renderFlow(spec, container);                        break;
                case 'struct':        renderStruct(spec, container);                      break;
                case 'table':         renderTable(spec, container);                       break;
                case 'gantt':         renderGantt(spec, container);                       break;
                case 'heatmap':       renderHeatmap(spec, container);                     break;
                case 'timeline':      renderTimeline(spec, container);                    break;
                case 'svg':
                    if (!spec.svg) throw new Error('No svg field');
                    container.innerHTML = sanitizeSVG(spec.svg);
                    addExportBtn(container, () => Promise.resolve(new Blob([spec.svg], { type:'image/svg+xml' })), 'diagram.svg');
                    break;
                default: throw new Error('Unknown spec type: ' + spec.type);
            }
        }

        async function autoDetect(text, container) {
            const spec = extractSpec(text);
            if (spec) {
                try { await render(spec, container); return true; }
                catch(e) { vizErr(container, e.message, spec); return true; }
            }
            const mmd = extractMermaid(text);
            if (mmd) {
                try { baseContainer(container); await renderMermaid(mmd, container); return true; }
                catch(e) { vizErr(container, e.message, mmd); return true; }
            }
            return false;
        }

        window.AetherVisualizer = { render, renderMermaid, autoDetect, extractSpec, extractMermaid, sanitizeSVG, colors: VIZ_COLORS, palette: VIZ_PALETTE };
    })();

    // ═══════════════════════════════════════════════════════════
    // Yes, it has edge cases. No, we're not fixing all of them.
    // If you find a bug, check if it's in the regex or in the
    // model's output. 50/50 chance it's the model.
    // ═══════════════════════════════════════════════════════════
    // Host bridge for AETHER Markdown Engine (core/aether-markdown.js)
    function getMarkdownHost() {
        return {
            createCodeBlock: function (lang, code, filename) {
                try {
                    return createAdvancedCodeBlock(lang, code, filename);
                } catch (e) {
                    return createCodingBlock(lang, code, filename);
                }
            },
            highlight: function (codeEl, lang) {
                highlightWithHljs(codeEl, lang);
            },
            renderGraph: function (type, lines) {
                return renderGraph(type, lines);
            },
            renderMath: function (el) {
                renderMath(el);
            },
            buildPlanDOM: function (raw, isTodo) {
                return buildPlanDOM(raw, isTodo);
            },
            showThoughts: function () {
                return !!state.showThoughts;
            },
            getLiveThinkEl: function () {
                return liveThinkEl;
            },
        };
    }
    try {
        if (typeof AETHER_Markdown !== 'undefined' && AETHER_Markdown.configure) {
            AETHER_Markdown.configure(getMarkdownHost());
        }
    } catch (_) {}

    function parseMarkdown(text, opts) {
        // Flagship path: modular GFM engine
        if (typeof AETHER_Markdown !== 'undefined' && AETHER_Markdown.parse) {
            try {
                AETHER_Markdown.configure(getMarkdownHost());
                return AETHER_Markdown.parse(text, opts || {});
            } catch (e) {
                console.warn('[AETHER] Markdown engine fallback:', e.message || e);
            }
        }
        // Legacy fallback (pre-v5.34)
        const { think, visible } = splitThink(text);
        const container = document.createElement('div');
        if (think && state.showThoughts && !liveThinkEl && !document.querySelector('.thought-process.modern-thought:not(.live-thought)')) {
            const tokens = Math.round((think.match(/\S+/g)||[]).length);
            const td = document.createElement('div');
            td.className = 'thought-process modern-thought';
            td.innerHTML = '<div class="thought-header">'
                + '<svg class="ic-xs"><use href="#ic-brain"/></svg>'
                + '<span class="thought-title">Chain of Thought</span>'
                + '<span class="thought-token-count">~' + tokens + ' tokens</span>'
                + '<button class="thought-toggle" onclick="this.closest(\'.thought-process\').classList.toggle(\'collapsed\')">▾</button>'
                + '</div>'
                + '<div class="thought-content">' + think.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>') + '</div>';
            container.appendChild(td);
        }

        let displayText = visible || text;
        const PLAN_RE = /<aether:(plan|todo)>([\s\S]*?)<\/aether:\1>/gi;
        const segments = [];
        let lastIdx = 0, pm;
        PLAN_RE.lastIndex = 0;
        while ((pm = PLAN_RE.exec(displayText)) !== null) {
            if (pm.index > lastIdx) segments.push({ type:'text', val: displayText.slice(lastIdx, pm.index) });
            segments.push({ type: pm[1], val: pm[2] });
            lastIdx = PLAN_RE.lastIndex;
        }
        if (lastIdx < displayText.length) segments.push({ type:'text', val: displayText.slice(lastIdx) });

        for (const seg of segments) {
            if (seg.type === 'text') {
                if (seg.val.trim()) renderBlocks(seg.val.split('\n'), container);
            } else {
                container.appendChild(seg.type === 'plan' ? buildPlanDOM(seg.val, false) : buildPlanDOM(seg.val, true));
            }
        }
        renderMath(container);
        return container;
    }

    // Build plan/todo DOM element (shared builder)
    function buildPlanDOM(rawContent, isTodo) {
        const steps = rawContent.trim().split('\n').filter(l => l.trim());
        const doneCount = steps.filter(s => s.includes('[x]') || s.includes('\u2705')).length;
        const allDone   = doneCount === steps.length && steps.length > 0;
        const pct = steps.length ? Math.round(doneCount/steps.length*100) : 0;

        const block = document.createElement('div');
        block.className = isTodo ? 'ac-todo-block ac-plan-block' : 'ac-plan-block';

        const hdr = document.createElement('div'); hdr.className = 'ac-plan-header';
        const check = document.createElement('span'); check.className = 'ac-plan-check' + (allDone ? ' ac-plan-check-done' : '');
        check.textContent = allDone ? '\u2713' : '\u25b7';
        const titleEl = document.createElement('span'); titleEl.className = 'ac-plan-title';
        titleEl.textContent = isTodo ? 'TodoWrite' : 'AETHER Code';
        const subEl = document.createElement('span'); subEl.className = 'ac-plan-sub';
        subEl.textContent = isTodo ? (doneCount + '\u202f/\u202f' + steps.length + ' complete') : 'Execution Plan';
        hdr.appendChild(check); hdr.appendChild(titleEl); hdr.appendChild(subEl);
        if (isTodo) {
            const pctEl = document.createElement('span'); pctEl.className = 'ac-todo-pct'; pctEl.textContent = pct + '%';
            hdr.appendChild(pctEl);
        }
        block.appendChild(hdr);

        if (isTodo) {
            const bar = document.createElement('div'); bar.className = 'ac-todo-bar';
            const fill = document.createElement('div'); fill.className = 'ac-todo-fill'; fill.style.width = pct + '%';
            bar.appendChild(fill); block.appendChild(bar);
        }

        const stepsEl = document.createElement('div'); stepsEl.className = 'ac-plan-steps';
        steps.forEach(s => {
            const done   = s.includes('[x]') || s.includes('\u2705');
            const active = s.includes('[~]') || s.includes('\ud83d\udfe1');
            const clean  = s.replace(/^\s*-\s*\[.\]\s*|^\s*[\u2705\u2b1c\ud83d\udfe1]\s*/g,'').trim();
            const row = document.createElement('div'); row.className = 'ac-plan-step';
            const bullet = document.createElement('span');
            bullet.className = 'ac-plan-bullet' + (done ? ' ac-bullet-done' : active ? ' ac-bullet-active' : '');
            bullet.textContent = done ? '\u2713' : '\u25cb';
            const txt = document.createElement('span');
            txt.className = 'ac-step-text' + (done ? ' ac-text-done' : '');
            txt.textContent = clean;
            row.appendChild(bullet); row.appendChild(txt);
            stepsEl.appendChild(row);
        });
        block.appendChild(stepsEl);
        return block;
    }

    // ─── UI HELPERS ──────────────────────────────────────────
    function showTypingIndicator() {
        _lsIdx = 0;
        clearInterval(_lsTimer);
        state.typingIndicator = document.createElement('div');
        state.typingIndicator.className = 'typing-indicator aether-typing';
        const s = LOAD_STATES[0];
        state.typingIndicator.innerHTML = `<span class="ali ${s.a}">${s.i}</span><span class="alt">${s.t}</span><span class="ald"><span></span><span></span><span></span></span>`;
        display.appendChild(state.typingIndicator); smoothScrollToBottom();
        _lsTimer = setInterval(() => {
            _lsIdx = (_lsIdx+1) % LOAD_STATES.length;
            if (!state.typingIndicator) return;
            const ns = LOAD_STATES[_lsIdx];
            const icon = state.typingIndicator.querySelector('.ali');
            const txt = state.typingIndicator.querySelector('.alt');
            if (icon) { icon.textContent = ns.i; icon.className = `ali ${ns.a}`; }
            if (txt) txt.textContent = ns.t;
        }, 2500);
    }
    function hideTypingIndicator() {
        clearInterval(_lsTimer); _lsTimer = null;
        if(state.typingIndicator){state.typingIndicator.remove();state.typingIndicator=null;}
    }
    // ─── FILE CARD SYSTEM ────────────────────────────────────
    // Creates a rich inline file card in the chat — not just a download button.
    // Supports MD, TXT, DOCX with preview, copy, download, and rename.

    function getFileCardMeta(format) {
        const map = {
            md:   { label: 'Markdown', ext: '.md',   icon: 'M', color: '#00f3ff', mime: 'text/markdown' },
            txt:  { label: 'Plain Text', ext: '.txt', icon: 'T', color: '#aabbcc', mime: 'text/plain' },
            docx: { label: 'Word Document', ext: '.docx', icon: 'W', color: '#2b5ce6', mime: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' },
        };
        return map[format] || map.txt;
    }

    function createFileCard(content, format, suggestedName) {
        const meta     = getFileCardMeta(format);
        const lineCount = content.split('\n').length;
        const wordCount = content.trim().split(/\s+/).filter(Boolean).length;
        const sizeKB   = (new TextEncoder().encode(content).length / 1024).toFixed(1);

        // Auto-name from first heading or suggestion
        const headingMatch = content.match(/^#{1,3}\s+(.+)/m);
        const rawName = suggestedName || (headingMatch ? headingMatch[1].trim() : 'aether-file');
        const safeName = rawName.replace(/[<>:"/\\|?*]/g, '').replace(/\s+/g, '-').slice(0, 60) || 'aether-file';
        const fullName = safeName + meta.ext;

        // Preview — first 3 non-empty, non-header lines of real content
        const previewLines = content.split('\n')
            .filter(l => l.trim() && !l.startsWith('#') && !l.startsWith('```'))
            .slice(0, 3)
            .map(l => l.replace(/\*\*(.+?)\*\*/g, '$1').replace(/\*(.+?)\*/g, '$1').replace(/`([^`]+)`/g, '$1').trim())
            .join(' ')
            .slice(0, 120);

        const card = document.createElement('div');
        card.className = 'aether-file-card';
        card.dataset.format = format;

        // Icon block
        const iconEl = document.createElement('div');
        iconEl.className = 'afc-icon';
        iconEl.style.color = meta.color;
        iconEl.innerHTML = '<svg viewBox="0 0 36 44" fill="none" xmlns="http://www.w3.org/2000/svg">'
            + '<path d="M4 2h20l8 8v32a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2z" stroke="currentColor" stroke-width="2" fill="rgba(0,0,0,0.4)"/>'
            + '<path d="M24 2v8h8" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>'
            + '<text x="18" y="30" text-anchor="middle" font-size="14" font-weight="bold" font-family="monospace" fill="currentColor">' + meta.icon + '</text>'
            + '</svg>';

        // Info block
        const infoEl = document.createElement('div');
        infoEl.className = 'afc-info';

        const nameEl = document.createElement('div');
        nameEl.className = 'afc-name';
        nameEl.textContent = fullName;

        const metaEl = document.createElement('div');
        metaEl.className = 'afc-meta';
        metaEl.textContent = meta.label + ' · ' + lineCount + ' lines · ' + wordCount + ' words · ' + sizeKB + ' KB';

        const prevEl = document.createElement('div');
        prevEl.className = 'afc-preview';
        prevEl.textContent = previewLines || '(empty)';

        infoEl.appendChild(nameEl);
        infoEl.appendChild(metaEl);
        if (previewLines) infoEl.appendChild(prevEl);

        // Actions block
        const actionsEl = document.createElement('div');
        actionsEl.className = 'afc-actions';

        const copyBtn = document.createElement('button');
        copyBtn.className = 'afc-btn afc-btn-copy';
        copyBtn.title = 'Copy to clipboard';
        copyBtn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg><span>Copy</span>';
        copyBtn.onclick = () => {
            navigator.clipboard.writeText(content).then(() => {
                copyBtn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" width="13" height="13"><polyline points="20 6 9 17 4 12"/></svg><span>Copied!</span>';
                copyBtn.classList.add('afc-btn-success');
                setTimeout(() => {
                    copyBtn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg><span>Copy</span>';
                    copyBtn.classList.remove('afc-btn-success');
                }, 2000);
            });
        };

        const dlBtn = document.createElement('button');
        dlBtn.className = 'afc-btn afc-btn-download';
        dlBtn.title = 'Download file';
        dlBtn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg><span>Download</span>';
        dlBtn.onclick = () => {
            if (format === 'docx') {
                try {
                    const blob = buildMinimalDocx(content, safeName);
                    downloadBlob(blob, fullName);
                    showNotification('\u2713 Downloaded ' + fullName, 'success');
                } catch(e) { reportFeatureError('DOCX Export', e); }
            } else {
                const plain = format === 'txt' ? stripMarkdown(content) : content;
                downloadBlob(new Blob([plain], { type: meta.mime + ';charset=utf-8' }), fullName);
                showNotification('\u2713 Downloaded ' + fullName, 'success');
            }
            // Flash the download button
            dlBtn.classList.add('afc-btn-success');
            setTimeout(() => dlBtn.classList.remove('afc-btn-success'), 1500);
        };

        // Rename (click on filename)
        nameEl.title = 'Click to rename';
        nameEl.style.cursor = 'pointer';
        nameEl.onclick = () => {
            const inp = document.createElement('input');
            inp.className = 'afc-rename-input';
            inp.value = safeName;
            inp.spellcheck = false;
            nameEl.replaceWith(inp);
            inp.focus(); inp.select();
            const commit = () => {
                const newName = inp.value.replace(/[<>:"/\\|?*]/g, '').replace(/\s+/g, '-').trim() || safeName;
                nameEl.textContent = newName + meta.ext;
                inp.replaceWith(nameEl);
                // Update dlBtn to use new name
                dlBtn.onclick = () => {
                    if (format === 'docx') {
                        try { downloadBlob(buildMinimalDocx(content, newName), newName + meta.ext); }
                        catch(e) { reportFeatureError('DOCX Export', e); }
                    } else {
                        downloadBlob(new Blob([format === 'txt' ? stripMarkdown(content) : content], { type: meta.mime + ';charset=utf-8' }), newName + meta.ext);
                    }
                    showNotification('\u2713 Downloaded ' + newName + meta.ext, 'success');
                };
            };
            inp.addEventListener('keydown', e => { if (e.key === 'Enter') commit(); if (e.key === 'Escape') { inp.replaceWith(nameEl); } });
            inp.addEventListener('blur', commit);
        };

        actionsEl.appendChild(copyBtn);
        actionsEl.appendChild(dlBtn);

        // ── View button — opens full overlay modal (no card bleed) ──
        const viewBtn = document.createElement('button');
        viewBtn.className = 'afc-btn afc-btn-view';
        viewBtn.title = 'View file';
        viewBtn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg><span>View</span>';

        viewBtn.onclick = () => {
            // Remove any existing viewer
            document.getElementById('afc-file-viewer-modal')?.remove();

            const modal = document.createElement('div');
            modal.id = 'afc-file-viewer-modal';
            modal.className = 'afc-viewer-modal';

            // Header bar
            const hdr = document.createElement('div'); hdr.className = 'afc-viewer-hdr';
            const hdrTitle = document.createElement('div'); hdrTitle.className = 'afc-viewer-title';
            hdrTitle.innerHTML = '<span style="color:var(--neon-cyan);margin-right:8px">' + meta.icon + '</span>' + fullName;
            const hdrMeta = document.createElement('div'); hdrMeta.className = 'afc-viewer-meta';
            hdrMeta.textContent = meta.label + ' · ' + lineCount + ' lines · ' + sizeKB + ' KB';
            const closeBtn = document.createElement('button'); closeBtn.className = 'afc-viewer-close';
            closeBtn.innerHTML = '&times;'; closeBtn.onclick = () => modal.remove();
            hdr.appendChild(hdrTitle); hdr.appendChild(hdrMeta); hdr.appendChild(closeBtn);

            // Body
            const body = document.createElement('div'); body.className = 'afc-viewer-body';

            if (format === 'md' || format === 'markdown') {
                const mdWrap = document.createElement('div'); mdWrap.className = 'afc-view-md afc-viewer-md-wrap';
                mdWrap.appendChild(parseMarkdown(content));
                body.appendChild(mdWrap);
            } else {
                const stripped = content
                    .replace(/^```[\w.-]*\n?/gm, '')
                    .replace(/^```\s*$/gm, '')
                    .trim();
                const pre = document.createElement('pre'); pre.className = 'afc-view-pre afc-viewer-pre';
                pre.textContent = stripped;
                body.appendChild(pre);
            }

            modal.appendChild(hdr);
            modal.appendChild(body);
            // Click backdrop to close
            modal.addEventListener('click', (e) => { if (e.target === modal) modal.remove(); });
            document.body.appendChild(modal);
        };

        actionsEl.appendChild(viewBtn);

        card.appendChild(iconEl);
        card.appendChild(infoEl);
        card.appendChild(actionsEl);

        return card;
    }

    function stripMarkdown(text) {
        return text
            .replace(/#{1,6}\s*/g, '')
            .replace(/\*{1,3}([^*]+)\*{1,3}/g, '$1')
            .replace(/`{3}[\s\S]*?`{3}/g, m => m.replace(/`{3}\w*\n?/g, '').trim())
            .replace(/`([^`]+)`/g, '$1')
            .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
            .replace(/^[-*+]\s/gm, '\u2022 ')
            .trim();
    }

    // Show a file card in the chat (called from attachActions or programmatically)
    function showFileCard(content, format, suggestedName, container) {
        const card = createFileCard(content, format, suggestedName);
        const wrapper = container || display;
        wrapper.appendChild(card);
        smoothScrollToBottom();
        return card;
    }

    // Detect if a message warrants auto file card creation
    function shouldAutoCreateFile(msg, response) {
        const req = (msg || '').toLowerCase();
        const fileTriggers = [
            /\b(write|create|make|generate|produce|draft)\b.*\b(file|document|doc|report|readme|notes?|summary|essay|article|blog|letter|proposal)\b/i,
            /\b(save|export|output)\b.*\b(as|to)\b.*\b(md|txt|markdown|text|word|docx)\b/i,
            /\b(create|write|make)\b.*\b(md|txt|docx|markdown)\b/i,
        ];
        return fileTriggers.some(r => r.test(req));
    }

    // Detect if response should auto-launch as a Construct (live preview)
    function shouldAutoConstruct(msg, response) {
        const req = (msg || '').toLowerCase();
        const resTriggers = /<!DOCTYPE html|<html/i.test(response || '');
        const msgTriggers = /\b(build|create|make|develop|generate|code)\b.*\b(app|tool|game|website|dashboard|calculator|clock|timer|widget|ui|interface|component)\b/i.test(req);
        return resTriggers && msgTriggers;
    }

    function guessFileFormat(msg) {
        const m = (msg || '').toLowerCase();
        if (/\bdocx?\b|word document/i.test(m)) return 'docx';
        if (/\btxt\b|plain text/i.test(m))      return 'txt';
        return 'md'; // default to markdown
    }

    // ─── UPGRADED attachActions ──────────────────────────────
    function attachActions(node, text, originalMsg) {
        // TTS speaker button — absolute top-right of the message bubble (like reference image)
        if (ttsConfig && ttsConfig.engine !== 'none') {
            const ttsBtn = document.createElement('button');
            ttsBtn.className = 'msg-tts-btn';
            ttsBtn.title = 'Read aloud';
            ttsBtn.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/></svg>';
            ttsBtn.onclick = (e) => {
                e.stopPropagation();
                if (ttsBtn.classList.contains('speaking')) {
                    if (typeof speechSynthesis !== 'undefined') speechSynthesis.cancel();
                    ttsBtn.classList.remove('speaking');
                    return;
                }
                ttsBtn.classList.add('speaking');
                const plainText = text.replace(/```[\s\S]*?```/g,'').replace(/\*\*?(.+?)\*\*?/g,'$1').replace(/#{1,6}\s/g,'').trim();
                speakTTS(plainText).finally(() => ttsBtn.classList.remove('speaking'));
            };
            // Make parent relative for absolute positioning
            if (node.style.position !== 'absolute') node.style.position = 'relative';
            node.appendChild(ttsBtn);
        }

        const deck = document.createElement('div');
        deck.className = 'action-deck';

        // COPY
        const copyBtn = document.createElement('button');
        copyBtn.className = 'action-btn';
        copyBtn.textContent = '[ COPY ]';
        copyBtn.onclick = () => navigator.clipboard.writeText(text).then(() => {
            copyBtn.textContent = '[ COPIED ]'; copyBtn.classList.add('copied');
            setTimeout(() => { copyBtn.textContent = '[ COPY ]'; copyBtn.classList.remove('copied'); }, 2000);
        });
        deck.appendChild(copyBtn);

        // SAVE AS FILE — shows format picker then injects a file card
        const saveBtn = document.createElement('button');
        saveBtn.className = 'action-btn';
        saveBtn.textContent = '[ SAVE AS ]';
        saveBtn.onclick = () => {
            const existing = deck.querySelector('.file-export-menu');
            if (existing) { existing.remove(); return; }
            const menu = document.createElement('div');
            menu.className = 'file-export-menu';

            const formats = [
                { fmt: 'md',   label: 'Markdown',      subLabel: '.md',   icon: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13"><path d="M14 2H6a2 2 0 0 0-2 2v16h16V8z"/><polyline points="14 2 14 8 20 8"/><line x1="8" y1="13" x2="16" y2="13"/><line x1="8" y1="17" x2="13" y2="17"/></svg>' },
                { fmt: 'txt',  label: 'Plain Text',    subLabel: '.txt',  icon: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13"><path d="M14 2H6a2 2 0 0 0-2 2v16h16V8z"/><polyline points="14 2 14 8 20 8"/><line x1="8" y1="13" x2="16" y2="13"/></svg>' },
                { fmt: 'docx', label: 'Word Document', subLabel: '.docx', icon: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13"><path d="M14 2H6a2 2 0 0 0-2 2v16h16V8z"/><polyline points="14 2 14 8 20 8"/><rect x="7" y="12" width="10" height="6" rx="1"/></svg>' },
            ];

            formats.forEach(({ fmt, label, subLabel, icon }) => {
                const item = document.createElement('button');
                item.className = 'file-export-item';
                item.innerHTML = icon
                    + '<span class="fei-label">' + label + '</span>'
                    + '<span class="fei-sub">' + subLabel + '</span>';
                item.onclick = () => {
                    menu.remove();
                    // Build and inject file card into chat
                    const headingMatch = text.match(/^#{1,3}\s+(.+)/m);
                    const suggestedName = headingMatch ? headingMatch[1].trim() : null;
                    const card = createFileCard(text, fmt, suggestedName);
                    // Insert file card right after this message node
                    const msgEl = node.closest('.aether-msg') || node;
                    if (msgEl.nextSibling) {
                        display.insertBefore(card, msgEl.nextSibling);
                    } else {
                        display.appendChild(card);
                    }
                    smoothScrollToBottom();
                    showNotification('File card created — click Download to save', 'success');
                };
                menu.appendChild(item);
            });

            // Close on outside click
            setTimeout(() => {
                document.addEventListener('click', function h() {
                    menu.remove();
                    document.removeEventListener('click', h);
                }, { once: true });
            }, 50);

            deck.appendChild(menu);
        };
        deck.appendChild(saveBtn);
        node.appendChild(deck);
    }

    function downloadBlob(blob, name) {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a'); a.href=url; a.download=name;
        document.body.appendChild(a); a.click(); document.body.removeChild(a);
        setTimeout(()=>URL.revokeObjectURL(url), 5000);
    }

    // Minimal DOCX builder — no dependencies, pure Office Open XML
    function buildMinimalDocx(markdownText, title) {
        // Convert markdown to plain paragraphs with basic heading detection
        const lines = markdownText.split('\n');
        const xmlParts = [];

        for (const line of lines) {
            if (!line.trim()) {
                xmlParts.push(`<w:p><w:pPr><w:spacing w:after="120"/></w:pPr></w:p>`);
                continue;
            }
            const h1 = line.match(/^# (.+)/);
            const h2 = line.match(/^## (.+)/);
            const h3 = line.match(/^### (.+)/);
            const li = line.match(/^[-*+] (.+)/);
            const code = line.match(/^```/);

            const escXml = s => s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

            // Bold/italic inline
            const inlineRuns = s => {
                // Bold
                let r = `<w:r><w:t xml:space="preserve">${escXml(s.replace(/\*\*(.+?)\*\*/g,'').replace(/\*(.+?)\*/g,''))}</w:t></w:r>`;
                // Simplified: just strip markers and output plain text in a single run
                const plain = s.replace(/\*{1,3}([^*]+)\*{1,3}/g,'$1').replace(/`([^`]+)`/g,'$1').replace(/\[([^\]]+)\]\([^)]+\)/g,'$1');
                return `<w:r><w:t xml:space="preserve">${escXml(plain)}</w:t></w:r>`;
            };

            if (h1) {
                xmlParts.push(`<w:p><w:pPr><w:pStyle w:val="Heading1"/></w:pPr><w:r><w:rPr><w:b/><w:color w:val="00C8FF"/><w:sz w:val="36"/></w:rPr><w:t>${escXml(h1[1])}</w:t></w:r></w:p>`);
            } else if (h2) {
                xmlParts.push(`<w:p><w:pPr><w:pStyle w:val="Heading2"/></w:pPr><w:r><w:rPr><w:b/><w:sz w:val="28"/></w:rPr><w:t>${escXml(h2[1])}</w:t></w:r></w:p>`);
            } else if (h3) {
                xmlParts.push(`<w:p><w:pPr><w:pStyle w:val="Heading3"/></w:pPr><w:r><w:rPr><w:b/><w:sz w:val="24"/></w:rPr><w:t>${escXml(h3[1])}</w:t></w:r></w:p>`);
            } else if (li) {
                xmlParts.push(`<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr>${inlineRuns(li[1])}</w:p>`);
            } else if (!code) {
                xmlParts.push(`<w:p><w:pPr><w:spacing w:after="120"/></w:pPr>${inlineRuns(line)}</w:p>`);
            }
        }

        const bodyXml = xmlParts.join('');
        const titleEsc = title.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        const dateStr = new Date().toLocaleDateString();

        const docXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:wpc="http://schemas.microsoft.com/office/word/2010/wordprocessingCanvas" xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math" xmlns:v="urn:schemas-microsoft-com:vml" xmlns:wp14="http://schemas.microsoft.com/office/word/2010/wordprocessingDrawing" xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing" xmlns:w10="urn:schemas-microsoft-com:office:word" xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:w14="http://schemas.microsoft.com/office/word/2010/wordml" xmlns:wpg="http://schemas.microsoft.com/office/word/2010/wordprocessingGroup" xmlns:wpi="http://schemas.microsoft.com/office/word/2010/wordprocessingInk" xmlns:wne="http://schemas.microsoft.com/office/word/2006/wordml" xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape" mc:Ignorable="w14 wp14">
  <w:body>
    <w:p><w:pPr><w:jc w:val="center"/></w:pPr><w:r><w:rPr><w:b/><w:sz w:val="40"/><w:color w:val="00C8FF"/></w:rPr><w:t>AETHER Neural Interface</w:t></w:r></w:p>
    <w:p><w:pPr><w:jc w:val="center"/></w:pPr><w:r><w:rPr><w:color w:val="888888"/><w:sz w:val="20"/></w:rPr><w:t>${titleEsc} — ${dateStr}</w:t></w:r></w:p>
    <w:p><w:r><w:t> </w:t></w:r></w:p>
    ${bodyXml}
    <w:sectPr><w:pgMar w:top="1080" w:right="1080" w:bottom="1080" w:left="1080" w:header="720" w:footer="720" w:gutter="0"/></w:sectPr>
  </w:body>
</w:document>`;

        const relsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>`;
        const wordRelsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/></Relationships>`;
        const stylesXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="Normal"><w:name w:val="Normal"/><w:rPr><w:sz w:val="22"/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="Heading1"><w:name w:val="heading 1"/><w:basedOn w:val="Normal"/></w:style><w:style w:type="paragraph" w:styleId="Heading2"><w:name w:val="heading 2"/><w:basedOn w:val="Normal"/></w:style><w:style w:type="paragraph" w:styleId="Heading3"><w:name w:val="heading 3"/><w:basedOn w:val="Normal"/></w:style></w:styles>`;
        const contentTypesXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/></Types>`;

        // Build minimal ZIP manually (no library needed for this simple structure)
        return buildZip([
            { name: '[Content_Types].xml', data: contentTypesXml },
            { name: '_rels/.rels', data: relsXml },
            { name: 'word/document.xml', data: docXml },
            { name: 'word/styles.xml', data: stylesXml },
            { name: 'word/_rels/document.xml.rels', data: wordRelsXml },
        ]);
    }

    // Minimal ZIP builder — produces a valid ZIP blob with stored (uncompressed) entries
    function buildZip(files) {
        const enc = new TextEncoder();
        const entries = [];
        let offset = 0;

        for (const f of files) {
            const nameBytes = enc.encode(f.name);
            const dataBytes = enc.encode(f.data);
            const modTime = 0x0000, modDate = 0x0000;
            const crc = crc32(dataBytes);

            // Local file header
            const lfh = new Uint8Array(30 + nameBytes.length);
            const lfhView = new DataView(lfh.buffer);
            lfhView.setUint32(0, 0x04034b50, true);  // signature
            lfhView.setUint16(4, 20, true);            // version needed
            lfhView.setUint16(6, 0, true);             // flags
            lfhView.setUint16(8, 0, true);             // compression: stored
            lfhView.setUint16(10, modTime, true);
            lfhView.setUint16(12, modDate, true);
            lfhView.setUint32(14, crc, true);
            lfhView.setUint32(18, dataBytes.length, true); // compressed size
            lfhView.setUint32(22, dataBytes.length, true); // uncompressed size
            lfhView.setUint16(26, nameBytes.length, true);
            lfhView.setUint16(28, 0, true);            // extra field length
            lfh.set(nameBytes, 30);

            // Central directory entry
            const cde = new Uint8Array(46 + nameBytes.length);
            const cdeView = new DataView(cde.buffer);
            cdeView.setUint32(0, 0x02014b50, true);
            cdeView.setUint16(4, 20, true); cdeView.setUint16(6, 20, true);
            cdeView.setUint16(8, 0, true);  cdeView.setUint16(10, 0, true);
            cdeView.setUint16(12, modTime, true); cdeView.setUint16(14, modDate, true);
            cdeView.setUint32(16, crc, true);
            cdeView.setUint32(20, dataBytes.length, true);
            cdeView.setUint32(24, dataBytes.length, true);
            cdeView.setUint16(28, nameBytes.length, true);
            cdeView.setUint16(30, 0, true); cdeView.setUint16(32, 0, true);
            cdeView.setUint16(34, 0, true); cdeView.setUint32(38, 0, true);
            cdeView.setUint32(42, offset, true);
            cde.set(nameBytes, 46);

            entries.push({ lfh, data: dataBytes, cde, offset });
            offset += lfh.length + dataBytes.length;
        }

        // End of central directory
        const cdSize = entries.reduce((s,e)=>s+e.cde.length, 0);
        const eocd = new Uint8Array(22);
        const eocdView = new DataView(eocd.buffer);
        eocdView.setUint32(0, 0x06054b50, true);
        eocdView.setUint16(4, 0, true); eocdView.setUint16(6, 0, true);
        eocdView.setUint16(8, entries.length, true);
        eocdView.setUint16(10, entries.length, true);
        eocdView.setUint32(12, cdSize, true);
        eocdView.setUint32(16, offset, true);
        eocdView.setUint16(20, 0, true);

        const parts = [];
        for (const e of entries) { parts.push(e.lfh); parts.push(e.data); }
        for (const e of entries) { parts.push(e.cde); }
        parts.push(eocd);
        return new Blob(parts, {type:'application/vnd.openxmlformats-officedocument.wordprocessingml.document'});
    }

    function crc32(buf) {
        let c = 0xFFFFFFFF;
        for (let i=0; i<buf.length; i++) {
            c ^= buf[i];
            for (let j=0; j<8; j++) c = (c&1) ? (0xEDB88320 ^ (c>>>1)) : (c>>>1);
        }
        return (c ^ 0xFFFFFFFF) >>> 0;
    }
    function smoothScrollToBottom() { setTimeout(()=>display.scrollTo({top:display.scrollHeight,behavior:'smooth'}),80); }
    function showNotification(msg, type='info') {
        const c = $('notification-container'); if(!c) return;
        // Stacking limit — max 5 visible; remove oldest
        while (c.children.length >= 5) {
            var oldest = c.children[0];
            oldest.classList.add('notification-out');
            setTimeout(function(el){ el.remove(); }, 250, oldest);
        }
        const n = document.createElement('div'); n.className = `notification ${type}`;
        const icons = { info:'ic-info', success:'ic-check', warn:'ic-warning', error:'ic-warning' };
        n.innerHTML = `<svg class="ic-xs" style="flex-shrink:0"><use href="#${icons[type]||'ic-info'}"/></svg><span>${msg}</span><button class="notification-dismiss" aria-label="Dismiss">&times;</button>`;
        n.querySelector('.notification-dismiss').addEventListener('click', function(e) {
            e.stopPropagation();
            n.classList.add('notification-out');
            setTimeout(function(el){ el.remove(); }, 250, n);
        });
        c.appendChild(n);
        var autoDismiss = setTimeout(function(){
            n.classList.add('notification-out');
            setTimeout(function(el){ el.remove(); }, 250, n);
        }, 3500);
        // Cancel auto-dismiss if user hovers
        n.addEventListener('mouseenter', function(){ clearTimeout(autoDismiss); });
        n.addEventListener('mouseleave', function(){
            autoDismiss = setTimeout(function(){
                n.classList.add('notification-out');
                setTimeout(function(el){ el.remove(); }, 250, n);
            }, 1500);
        });
    }

    function reportFeatureError(feature, error, context = {}) {
        const timestamp = new Date().toISOString();
        const errorInfo = {
            feature,
            message: error?.message || String(error || 'Unknown error'),
            stack: error?.stack,
            context,
            timestamp,
            userAgent: navigator.userAgent,
            url: location.href,
        };

        console.error('[AETHER Error]', feature + ':', error);

        if (!window._aetherErrorLog) window._aetherErrorLog = [];
        window._aetherErrorLog.push(errorInfo);
        if (window._aetherErrorLog.length > 50) window._aetherErrorLog.shift();

        // Update error count badge
        const badge = document.getElementById('error-count-badge');
        if (badge) {
            const count = window._aetherErrorLog.length;
            badge.textContent = count;
            badge.style.display = count > 0 ? 'inline-flex' : 'none';
        }

        let devReport;
        try { devReport = JSON.stringify(errorInfo, null, 2); } catch(e) { devReport = JSON.stringify({ feature, message: errorInfo.message, timestamp: errorInfo.timestamp, context: '[Circular or unserializable]' }); }
        const c = $('notification-container');
        if (!c) return;

        while (c.children.length >= 5) {
            const oldest = c.children[0];
            oldest.classList.add('notification-out');
            setTimeout(el => el.remove(), 250, oldest);
        }

        const n = document.createElement('div');
        n.className = 'notification dev-error';
        const errCount = (window._aetherErrorLog || []).length;
        n.innerHTML = `
            <svg class="ic-xs" style="flex-shrink:0"><use href="#ic-warning"/></svg>
            <span class="dev-error-summary"><strong>${escapeHtml(feature)}</strong> failed: ${escapeHtml(error?.message || 'Unknown error')}. <span style="color:#ff8888">Show this to a developer.</span></span>
            <button class="notification-dismiss" aria-label="Dismiss">&times;</button>
            <div class="dev-error-details">${escapeHtml(devReport)}
                <div style="margin-top:8px;border-top:1px solid rgba(255,68,68,0.2);padding-top:8px;display:flex;gap:8px">
                    <button class="dev-error-btn" onclick="event.stopPropagation();window.openErrorLog()">View all (${errCount})</button>
                    <button class="dev-error-btn" onclick="event.stopPropagation();navigator.clipboard.writeText(JSON.stringify(window._aetherErrorLog||[],null,2))">Copy log</button>
                </div>
            </div>
        `;

        n.querySelector('.notification-dismiss').addEventListener('click', e => {
            e.stopPropagation();
            n.classList.add('notification-out');
            setTimeout(el => el.remove(), 250, n);
        });

        n.addEventListener('click', e => {
            if (e.target.closest('.notification-dismiss')) return;
            n.classList.toggle('expanded');
            if (n.classList.contains('expanded')) {
                try { navigator.clipboard.writeText(devReport).catch(() => {}); } catch {}
            }
        });

        c.appendChild(n);
    }

    window.addEventListener('error', e => {
        reportFeatureError('Uncaught Exception', e.error || e.message, { lineno: e.lineno, colno: e.colno, filename: e.filename });
    });

    window.addEventListener('unhandledrejection', e => {
        reportFeatureError('Unhandled Promise Rejection', e.reason);
    });

    window.openErrorLog = function() {
        document.getElementById('aether-error-log')?.remove();
        const log = window._aetherErrorLog || [];
        const overlay = document.createElement('div');
        overlay.id = 'aether-error-log';
        overlay.className = 'modal-overlay';
        overlay.style.display = 'flex';
        const content = document.createElement('div');
        content.className = 'modal-content';
        content.style.cssText = 'max-width:640px;max-height:80vh;overflow-y:auto;display:flex;flex-direction:column;background:#060810;border-radius:12px;border:1px solid rgba(255,255,255,0.08)';
        content.innerHTML = `
            <div class="modal-header">
                <span class="modal-title"><span style="color:var(--neon-cyan)">⬡</span> AETHER Error Log</span>
                <button class="modal-close" onclick="this.closest('.modal-overlay').remove()">&times;</button>
            </div>
            <div style="padding:12px 16px;font-size:0.75rem;color:#667;border-bottom:1px solid rgba(255,255,255,0.05);display:flex;justify-content:space-between;align-items:center">
                <span>${log.length} error${log.length !== 1 ? 's' : ''} recorded</span>
                <div style="display:flex;gap:6px">
                    <button class="dev-error-btn" onclick="navigator.clipboard.writeText(JSON.stringify(window._aetherErrorLog||[],null,2));this.textContent='Copied!'">Copy all</button>
                    <button class="dev-error-btn" onclick="window._aetherErrorLog=[];window.openErrorLog()">Clear</button>
                </div>
            </div>
            <div id="error-log-list" style="padding:12px 16px;flex:1;overflow-y:auto">
                ${log.length === 0 ? '<div style="padding:40px;text-align:center;color:#556">No errors recorded.</div>' : ''}
            </div>
        `;
        overlay.appendChild(content);
        const listEl = content.querySelector('#error-log-list');
        log.slice().reverse().forEach(err => {
            const entry = document.createElement('div');
            entry.style.cssText = 'border:1px solid #1a1a2e;border-radius:6px;padding:10px 12px;margin-bottom:6px;cursor:pointer;background:#0e0e1a';
            entry.innerHTML = `
                <div style="display:flex;justify-content:space-between;align-items:center">
                    <span style="color:#ff4444;font-weight:600;font-size:0.8rem">${escapeHtml(err.feature)}</span>
                    <span style="color:#556;font-size:0.65rem">${new Date(err.timestamp).toLocaleTimeString()}</span>
                </div>
                <div style="color:#889;font-size:0.75rem;margin-top:4px">${escapeHtml(err.message)}</div>
                <div class="err-log-detail" style="display:none;margin-top:6px;font-size:0.65rem;color:#ff8888;font-family:monospace;white-space:pre-wrap;word-break:break-all;max-height:150px;overflow-y:auto">${escapeHtml(JSON.stringify(err, null, 2))}</div>
            `;
            entry.addEventListener('click', () => {
                const d = entry.querySelector('.err-log-detail');
                const isHidden = d.style.display === 'none';
                d.style.display = isHidden ? 'block' : 'none';
                if (isHidden) navigator.clipboard.writeText(JSON.stringify(err, null, 2)).catch(() => {});
            });
            listEl.appendChild(entry);
        });
        document.body.appendChild(overlay);
        overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
    };

    function updateConnectionStatus(ok) {
        if(connectionStatus) connectionStatus.classList.toggle('disconnected',!ok);
    }
    function clearDisplay() { display.innerHTML = ''; state.lastAssistantMessage = null; }
    function showWelcomeMessage() {
        const ver = (typeof AETHER_VERSION_LABEL !== 'undefined' ? AETHER_VERSION_LABEL : 'v5.16');
        const beast = (typeof AETHER_Beast !== 'undefined' && AETHER_Beast.isEnabled()) ? ' · <span style="color:#ff6600">BEAST MODE</span>' : '';
        const msg = document.createElement('div'); msg.className = 'aether-msg fade-in';
        msg.innerHTML = `<p><strong>AETHER ${ver}</strong>${beast} — Personal agent OS · Dual Context · Workspace · Skills</p>
<p><strong>Toolbar:</strong> always-on NEW · STOP · RETRY · CFG &nbsp;·&nbsp; <strong>MODES ▾</strong> for AGENT/CODE/DEEP/WS/BEAST &nbsp;·&nbsp; <strong>MORE ▾</strong> for advanced tools</p>
<p>Mode: T=${state.temperature} · CoT:${state.coTEnabled?'ON':'OFF'} · RAG:${state.ragEnabled?'ON':'OFF'} · Stream:${state.streamingEnabled?'ON':'OFF'}</p>
<p>Open <strong>MODES → SETUP</strong> for API/local, <strong>WS</strong> for project memory, <strong>BEAST</strong> for max autonomy.</p>`;
        display.appendChild(msg);
    }
    function addUserMessage(content, save=true) {
        const el = document.createElement('div'); el.className = 'user-msg'; el.textContent = content; display.appendChild(el);
        if (save) {
            const conv = getCurrentConversation();
            conv.messages.push({role:'user',content}); updateConversationTitle(conv); saveConversations(); renderConversationList();
        }
    }
    async function addAssistantMessage(content, save=true) {
        try {
            if (typeof window.__aetherShipNoteAssistant === 'function') window.__aetherShipNoteAssistant(content);
        } catch (_) {}
        const el = document.createElement('div'); el.className = 'aether-msg'; display.appendChild(el);
        const rendered = parseMarkdown(content); el.appendChild(rendered); attachActions(el,content);
        state.lastAssistantMessage = {content,element:el};
        if (save) {
            const conv = getCurrentConversation();
            conv.messages.push({role:'assistant',content}); updateConversationTitle(conv); saveConversations(); renderConversationList();
        }
    }

    // ─── DUAL CHAT CONTEXT MANAGEMENT ───────────────────────
    // Key insight: wave & stop button reflect CURRENT conversation state only.
    // Background conversations keep processing independently.

    function updateDualChatUI() {
        const convId = state.currentConversationId;
        const isCurrentProcessing = !!(convId && state.processingConversations[convId]);
        const totalProcessing = Object.keys(state.processingConversations).length;
        const bgCount = totalProcessing - (isCurrentProcessing ? 1 : 0);

        // Stop button: only active for current conversation
        if (stopBtn) stopBtn.style.display = isCurrentProcessing ? 'flex' : 'none';
        if (btnStop) { btnStop.disabled = !isCurrentProcessing; }

        // Send button
        if (sendBtn) sendBtn.disabled = isCurrentProcessing;

        // Dual chat indicator
        if (dualChatIndicator) {
            if (bgCount > 0) {
                dualChatIndicator.textContent = `${bgCount} chat${bgCount>1?'s':''} running in background`;
                dualChatIndicator.style.display = 'inline';
            } else {
                dualChatIndicator.style.display = 'none';
            }
        }

        // Dashboard class
        if (dashboard) dashboard.classList.toggle('processing', isCurrentProcessing);
    }

    // ─── AETHER PANE CONTROLLER ──────────────────────────────
    // Theme-aware ring, Ivory-friendly copy, compact metrics, calm wave.
    const apStatusEl  = document.getElementById('ap-status-text');
    const apSubEl     = document.getElementById('ap-sub-text');
    const apRingArc   = document.getElementById('ap-ring-arc');
    const apRingIcon  = document.getElementById('ap-ring-icon');
    const apParticles = document.getElementById('ap-particles');
    const apPaneEl    = document.getElementById('aether-pane');
    const apTpsEl     = document.getElementById('tps-display');

    const AP_RING_FULL = 113; // circumference of r=18 circle
    let apCurrentStatus = 'idle';

    function isIvoryTheme() {
        return document.documentElement.getAttribute('data-aether-theme') === 'ivory'
            || document.documentElement.classList.contains('theme-light');
    }

    // Cyberpunk vs human-readable status lines
    const AP_IDLE_MESSAGES_NEURAL = [
        'AETHER READY', 'NEURAL INTERFACE', 'BEAST MODE STANDBY', 'AWAITING INPUT',
        'SYSTEMS NOMINAL', 'ALL MODELS ONLINE', 'ZERO LATENCY MODE'
    ];
    const AP_IDLE_MESSAGES_IVORY = [
        'Ready', 'Listening', 'At rest', 'Waiting for you',
        'All set', 'Standing by', 'Quiet mode'
    ];
    const AP_THINKING_NEURAL = [
        'REASONING\u2026', 'PROCESSING QUERY', 'SYNTHESIZING\u2026',
        'NEURAL NET ACTIVE', 'GENERATING\u2026', 'COMPUTING\u2026'
    ];
    const AP_THINKING_IVORY = [
        'Thinking\u2026', 'Working on it', 'Almost there',
        'Considering\u2026', 'Writing\u2026', 'Gathering thoughts'
    ];
    function apIdleMessages() { return isIvoryTheme() ? AP_IDLE_MESSAGES_IVORY : AP_IDLE_MESSAGES_NEURAL; }
    function apThinkingMessages() { return isIvoryTheme() ? AP_THINKING_IVORY : AP_THINKING_NEURAL; }
    function apVersionSub() {
        if (isIvoryTheme()) {
            const v = (typeof AETHER_VERSION_LABEL !== 'undefined' ? AETHER_VERSION_LABEL : 'v5.18');
            return 'Aether ' + v + ' · Warm Ivory';
        }
        return typeof AETHER_FULL_LABEL !== 'undefined' ? AETHER_FULL_LABEL : 'Aether Code';
    }
    function apCssColor(varName, fallback) {
        try {
            const v = getComputedStyle(document.documentElement).getPropertyValue(varName).trim();
            return v || fallback;
        } catch (e) { return fallback; }
    }
    function apRingColor(type) {
        const cyan = apCssColor('--neon-cyan', '#00f3ff');
        const magenta = apCssColor('--neon-magenta', '#b8a0ff');
        const green = apCssColor('--neon-green', '#00ff88');
        const orange = apCssColor('--neon-orange', '#ffaa44');
        const white = apCssColor('--neon-white', isIvoryTheme() ? '#2C2416' : '#ffffff');
        const map = {
            idle: cyan,
            thinking: magenta,
            streaming: white,
            success: green,
            error: '#ff6464',
            warn: orange,
        };
        return map[type] || cyan;
    }

    let apMsgIdx = 0;

    function apSetPaneLive(live) {
        if (!apPaneEl) return;
        apPaneEl.classList.toggle('pane-live', !!live);
    }

    function apSetStatus(type, text, sub) {
        apCurrentStatus = type;
        if (!apStatusEl) return;
        apStatusEl.className = 'ap-status-text ' + (type !== 'idle' ? type : '');
        if (text) apStatusEl.textContent = text;
        if (sub && apSubEl) apSubEl.textContent = sub;

        // Ring arc fill — stroke from theme tokens
        if (apRingArc) {
            const fill = { idle: 0, thinking: 60, streaming: 90, success: 113, error: 30, warn: 50 };
            const offset = AP_RING_FULL - (fill[type] || 0);
            apRingArc.style.strokeDashoffset = offset;
            apRingArc.style.stroke = apRingColor(type);
            if (type === 'idle') {
                apRingArc.style.opacity = '0.45';
            } else {
                apRingArc.style.opacity = '1';
            }
        }
        if (apRingIcon) {
            apRingIcon.className = 'ap-ring-icon' + (type === 'thinking' || type === 'streaming' ? ' thinking' : type === 'success' ? ' active' : '');
        }
        // Compact pane: show metrics only while live
        apSetPaneLive(type === 'streaming' || type === 'thinking');

        if (apParticles) {
            if (type === 'streaming' || type === 'thinking') apStartParticles();
            else apStopParticles();
        }
    }

    let _apParticleTimer = null;
    function apStartParticles() {
        if (_apParticleTimer) return;
        _apParticleTimer = setInterval(() => {
            if (!apParticles) return;
            const dot = document.createElement('div');
            dot.className = 'ap-particle';
            const size = 2 + Math.random() * 3;
            const col = apRingColor(apCurrentStatus === 'streaming' ? 'streaming' : 'thinking');
            // parse hex-ish to rgba roughly, or use color directly
            dot.style.cssText = 'width:' + size + 'px;height:' + size + 'px;'
                + 'left:' + (10 + Math.random() * 80) + '%;'
                + 'bottom:0;'
                + 'animation-duration:' + (1.5 + Math.random() * 2) + 's;'
                + 'animation-delay:' + (Math.random() * 0.5) + 's;'
                + 'background:' + col + ';'
                + 'opacity:0.55;';
            apParticles.appendChild(dot);
            setTimeout(() => dot.remove(), 3500);
        }, 180);
    }
    function apStopParticles() {
        clearInterval(_apParticleTimer); _apParticleTimer = null;
        if (apParticles) apParticles.innerHTML = '';
    }

    // Idle message rotation (theme-aware copy)
    setInterval(() => {
        if (apCurrentStatus === 'idle' && apStatusEl) {
            const msgs = apIdleMessages();
            apMsgIdx = (apMsgIdx + 1) % msgs.length;
            apStatusEl.textContent = msgs[apMsgIdx];
            if (apSubEl) {
                apSubEl.textContent = isIvoryTheme()
                    ? new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
                    : new Date().toLocaleTimeString('en-GB', { hour12: false });
            }
        }
    }, 4000);

    function apUpdateFromState() {
        const convId = state.currentConversationId;
        const processing = !!(convId && state.processingConversations[convId]);
        if (processing && apCurrentStatus !== 'streaming' && apCurrentStatus !== 'thinking') {
            const think = apThinkingMessages();
            apSetStatus('thinking', think[Math.floor(Math.random() * think.length)], isIvoryTheme() ? 'Working…' : 'Processing…');
        } else if (!processing && (apCurrentStatus === 'streaming' || apCurrentStatus === 'thinking')) {
            apSetStatus('success', isIvoryTheme() ? 'Done' : 'RESPONSE COMPLETE', isIvoryTheme() ? 'Ready when you are' : 'Ready');
            setTimeout(() => {
                if (apCurrentStatus === 'success') {
                    apSetStatus('idle', apIdleMessages()[0], apVersionSub());
                }
            }, 3000);
        }
    }

    window._apSetStreaming = (tps) => {
        const modelShort = (apiConfig.model||'').split('-').slice(0,2).join('-').slice(0,18);
        let msg, sub;
        if (isIvoryTheme()) {
            msg = tps > 100 ? 'Very fast · ' + Math.round(tps) + ' t/s'
                : tps > 30 ? 'Streaming · ' + Math.round(tps) + ' t/s'
                : 'Writing…';
            sub = modelShort || 'in progress';
        } else {
            msg = tps > 100 ? 'ULTRA-FAST \u26a1 ' + Math.round(tps) + ' t/s'
                : tps > 30 ? 'STREAMING \u00b7 ' + Math.round(tps) + ' t/s'
                : 'GENERATING…';
            sub = modelShort + ' · active';
        }
        apSetStatus('streaming', msg, sub);
        if (apTpsEl) { apTpsEl.textContent = Math.round(tps) + ' t/s'; apTpsEl.style.color = 'var(--neon-cyan)'; }
    };
    window._apSetIdle = () => apSetStatus('idle', apIdleMessages()[apMsgIdx % apIdleMessages().length], apVersionSub());
    window._apSetError = (msg) => {
        apSetStatus('error', isIvoryTheme() ? 'Something went wrong' : 'ERROR', msg || (isIvoryTheme() ? 'Please try again' : 'Request failed'));
        setTimeout(_apSetIdle, 4000);
    };
    // Re-apply copy when theme changes
    window._apOnThemeChange = () => {
        if (apCurrentStatus === 'idle') {
            apSetStatus('idle', apIdleMessages()[0], apVersionSub());
        }
    };

    // Init
    apSetStatus('idle', apIdleMessages()[0], apVersionSub());

    // ─── AETHER WAVE — TPS-REACTIVE NEURAL VISUALIZER ────────
    // Wave is truly reactive: flat when idle, complexity/speed/color
    // all driven by live TPS measurements. Uses exponential smoothing
    // to prevent jarring jumps. Color shifts from cyan → white → orange
    // as inference speed increases.
    if (canvas && canvas.getContext) {
        const ctx = canvas.getContext('2d');
        let phase = 0;
        let smoothTPS    = 0;   // smoothed tokens-per-second
        let smoothAmp    = 5;   // smoothed amplitude
        let smoothSpeed  = 0.03; // smoothed phase speed
        const SMOOTH     = 0.12; // EMA coefficient — lower = smoother

        // TPS tracking — updated by streaming path
        let _waveTPS = 0;
        let _waveLastTokenCount = 0;
        let _waveLastTime = performance.now();

        // Called from streaming token handler to feed live TPS into wave
        window._aetherWaveTokenTick = (tokenCount) => {
            const now = performance.now();
            const dt = now - _waveLastTime;
            if (dt > 300) {
                const tps = (tokenCount - _waveLastTokenCount) / (dt / 1000);
                _waveTPS = Math.max(0, Math.min(tps, 400)); // cap at 400 TPS
                _waveLastTokenCount = tokenCount;
                _waveLastTime = now;
            }
        };

        const resize = () => { canvas.width = canvas.offsetWidth; canvas.height = canvas.offsetHeight; };
        resize(); window.addEventListener('resize', resize);

        // Color interpolation: cyan(idle) → white(medium) → orange(fast) → red(ultra)
        // Warm Ivory uses walnut → clay instead of neon cyan
        function tpsToColor(tps, alpha) {
            const ivory = document.documentElement.getAttribute('data-aether-theme') === 'ivory';
            if (tps < 1) {
                if (ivory) return alpha < 1 ? 'rgba(139,90,43,' + alpha + ')' : '#8B5A2B';
                return alpha < 1 ? 'rgba(0,243,255,' + alpha + ')' : '#00f3ff';
            } else if (tps < 20) {
                const t = tps / 20;
                if (ivory) {
                    const r = Math.round(139 + t * (196 - 139));
                    const g = Math.round(90 + t * (92 - 90));
                    const b = Math.round(43 + t * (38 - 43));
                    return alpha < 1 ? 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')' : 'rgb(' + r + ',' + g + ',' + b + ')';
                }
                const r = Math.round(0   + t * 255);
                const g = Math.round(243 + t * 12);
                const b = Math.round(255 + t * 0);
                return alpha < 1 ? 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')' : 'rgb(' + r + ',' + g + ',' + b + ')';
            } else if (tps < 80) {
                const t = (tps - 20) / 60;
                if (ivory) {
                    const r = Math.round(196 + t * (200 - 196));
                    const g = Math.round(92 - t * 40);
                    const b = Math.round(38 - t * 20);
                    return alpha < 1 ? 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')' : 'rgb(' + r + ',' + g + ',' + b + ')';
                }
                const r = 255;
                const g = Math.round(255 - t * 155);
                const b = Math.round(255 - t * 255);
                return alpha < 1 ? 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')' : 'rgb(' + r + ',' + g + ',' + b + ')';
            } else {
                const t = Math.min((tps - 80) / 120, 1);
                if (ivory) {
                    return alpha < 1 ? 'rgba(180,60,30,' + alpha + ')' : 'rgb(180,60,30)';
                }
                const r = 255;
                const g = Math.round(100 - t * 100);
                const b = 0;
                return alpha < 1 ? 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')' : 'rgb(' + r + ',' + g + ',' + b + ')';
            }
        }

        (function animate() {
            // Respect CFG → Appearance → Wave toggle (still rAF so resume is instant)
            if (state.waveEnabled === false) {
                ctx.clearRect(0, 0, canvas.width, canvas.height);
                requestAnimationFrame(animate);
                return;
            }

            const convId = state.currentConversationId;
            const isProcessing = !!(convId && state.processingConversations[convId]);

            // Determine target TPS
            const targetTPS = isProcessing ? _waveTPS : 0;

            // Calm idle: flat line when not processing (CFG → Appearance)
            const calmIdle = state.waveCalmIdle !== false;

            // Exponential smoothing — wave trails actual TPS gracefully
            smoothTPS   = smoothTPS   * (1 - SMOOTH) + targetTPS  * SMOOTH;
            const idleAmp = calmIdle ? 0.4 : 4;
            const idleSpeed = calmIdle ? 0.008 : 0.025;
            smoothAmp   = smoothAmp   * (1 - SMOOTH) + (isProcessing ? Math.min(6 + smoothTPS * 0.28, 28) : idleAmp) * SMOOTH;
            smoothSpeed = smoothSpeed * (1 - SMOOTH) + (isProcessing ? Math.max(0.04, Math.min(smoothTPS * 0.004, 0.55)) : idleSpeed) * SMOOTH;

            ctx.clearRect(0, 0, canvas.width, canvas.height);
            const H = canvas.height / 2;
            const W = canvas.width;
            const color1 = tpsToColor(smoothTPS, 1);
            const color2 = tpsToColor(smoothTPS, 0.25);

            // Primary wave — flat when calm-idle, organic when live
            ctx.beginPath();
            ctx.strokeStyle = color1;
            ctx.lineWidth = isProcessing ? 1.8 : (calmIdle ? 1 : 1.2);
            if (!isProcessing && calmIdle && smoothAmp < 1.2) {
                // True flat baseline with tiny breath
                const breath = Math.sin(phase * 0.5) * 0.6;
                ctx.moveTo(0, H + breath);
                ctx.lineTo(W, H + breath);
            } else {
                for (let x = 0; x < W; x += 2) {
                    const noise = smoothTPS > 5 ? Math.sin(x * 0.08 + phase * 2.3) * (smoothAmp * 0.15) : 0;
                    const y = H
                        + Math.sin(x * 0.022 + phase) * smoothAmp
                        + Math.sin(x * 0.011 + phase * 1.7) * (smoothAmp * 0.45)
                        + noise;
                    x === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
                }
            }
            ctx.stroke();

            // Secondary wave — skip when calm idle (less visual noise)
            if (isProcessing || !calmIdle) {
                ctx.beginPath();
                ctx.strokeStyle = color2;
                ctx.lineWidth = 1;
                for (let x = 0; x < W; x += 3) {
                    const y = H
                        + Math.sin(x * 0.018 + phase + 0.9) * (smoothAmp * 0.55)
                        + Math.sin(x * 0.032 + phase * 0.7) * (smoothAmp * 0.2);
                    x === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
                }
                ctx.stroke();
            }

            // Glow pulse on high TPS — subtle fill under primary wave
            if (smoothTPS > 30) {
                const glowAlpha = Math.min((smoothTPS - 30) / 200, 0.06);
                const grad = ctx.createLinearGradient(0, 0, 0, canvas.height);
                grad.addColorStop(0, tpsToColor(smoothTPS, glowAlpha));
                grad.addColorStop(1, 'rgba(0,0,0,0)');
                ctx.beginPath();
                ctx.moveTo(0, H);
                for (let x = 0; x < W; x += 3) {
                    const y = H + Math.sin(x * 0.022 + phase) * smoothAmp;
                    ctx.lineTo(x, y);
                }
                ctx.lineTo(W, H); ctx.closePath();
                ctx.fillStyle = grad; ctx.fill();
            }

            phase += smoothSpeed;

            // ── Scan line — sweeps vertically during inference ──
            if (isProcessing) {
                const scanPos = ((Date.now() / 1200) % 1) * canvas.height;
                const scanGrad = ctx.createLinearGradient(0, scanPos - 6, 0, scanPos + 6);
                scanGrad.addColorStop(0, 'rgba(0,243,255,0)');
                scanGrad.addColorStop(0.5, tpsToColor(smoothTPS, 0.35));
                scanGrad.addColorStop(1, 'rgba(0,243,255,0)');
                ctx.fillStyle = scanGrad;
                ctx.fillRect(0, scanPos - 6, canvas.width, 12);
            }

            // ── Pause RAF when tab is hidden — saves GPU on background tabs ──
            // The wave is purely decorative; pausing it when hidden costs nothing
            // visible to the user and eliminates ~60 canvas composites/sec.
            if (!document.hidden) {
                requestAnimationFrame(animate);
            } else {
                // Resume immediately when tab becomes visible again
                document.addEventListener('visibilitychange', function onVis() {
                    document.removeEventListener('visibilitychange', onVis);
                    requestAnimationFrame(animate);
                }, { once: true });
            }
        })();
    }

    // ─── PERSISTENCE ─────────────────────────────────────────
    function loadState() {
        try {
            const s = localStorage.getItem('aether_state');
            if (s) {
                const p=JSON.parse(s);
                state={...state,...p,processingConversations:{}};
                updateUIFromState();
                // Re-apply coding mode body class + button state + agent shell
                if (state.codingMode) {
                    document.body.classList.add('coding-mode');
                    const cmBtn = document.getElementById('btn-coding-mode');
                    if (cmBtn) cmBtn.classList.add('active');
                    const cmInd = document.getElementById('coding-mode-indicator');
                    if (cmInd) {
                        cmInd.style.display = 'flex';
                        if (!document.getElementById('coding-turn-badge')) {
                            const tb = document.createElement('span');
                            tb.id = 'coding-turn-badge'; tb.className = 'coding-turn-badge';
                            tb.style.display = 'none'; cmInd.appendChild(tb);
                        }
                        if (!document.getElementById('coding-folder-btn')) {
                            const fb = document.createElement('button');
                            fb.id = 'coding-folder-btn'; fb.className = 'coding-folder-btn';
                            fb.textContent = '\ud83d\udcc2 Link Folder'; fb.title = 'Give AETHER Code access to a project folder';
                            fb.onclick = (e) => { e.stopPropagation(); openCodingFolder(); };
                            cmInd.appendChild(fb);
                        }
                        updateCodingFolderUI();
                    }
                    try { registerFSTools(); } catch (_) {}
                    syncCodeAgentShell();
                }
            }
        } catch {}
    }
    function saveState() {
        try {
            localStorage.setItem('aether_state', JSON.stringify({
                temperature:state.temperature, topK:state.topK, coTEnabled:state.coTEnabled,
                showThoughts:state.showThoughts, ragEnabled:state.ragEnabled,
                streamingEnabled:state.streamingEnabled, blurInEnabled:state.blurInEnabled,
                vectorRagEnabled:state.vectorRagEnabled,
                showMetrics:state.showMetrics, deepResearchSettings:state.deepResearchSettings,
                codingMode:state.codingMode,
                groqReasoningEffort:state.groqReasoningEffort,
                groqWebSearch:state.groqWebSearch,
                groqCodeExecution:state.groqCodeExecution,
                clarificationEnabled:state.clarificationEnabled,
                // SOUL & Reflection
                reflectionEnabled:state.reflectionEnabled,
                reflectionIntervalMin:state.reflectionIntervalMin,
                proactiveEnabled:state.proactiveEnabled,
                proactiveMaxPerDay:state.proactiveMaxPerDay,
                reflectionTokenCost:state.reflectionTokenCost,
                // Agent
                agentMode:state.agentMode,
            }));
        } catch {}
    }
    function updateUIFromState() {
        if(temperatureSlider) temperatureSlider.value=state.temperature;
        if(topkInput) topkInput.value=state.topK;
        if(cotToggle) cotToggle.checked=state.coTEnabled;
        if(showThoughtsToggle) showThoughtsToggle.checked=state.showThoughts;
        if(ragToggle) ragToggle.checked=state.ragEnabled;
        if(streamingToggle) streamingToggle.checked=state.streamingEnabled;
        const bit=$('blurin-toggle'); if(bit) bit.checked=state.blurInEnabled!==false;
        const rit=$('reflection-toggle'); if(rit) rit.checked=state.reflectionEnabled!==false;
        const pit=$('proactive-toggle'); if(pit) pit.checked=!!state.proactiveEnabled;
        const rfe=$('reflection-freq-select'); if(rfe) rfe.value=state.reflectionIntervalMin||90;
        const am=$('agent-mode-select'); if(am) am.value=state.agentMode||'auto';
        if(cotIndicator) cotIndicator.style.display=state.coTEnabled?'flex':'none';
        const vt=$('vector-toggle'); if(vt) vt.checked=state.vectorRagEnabled||false;
        const mt=$('metrics-toggle'); if(mt) mt.checked=!!state.showMetrics;
        applyMetricsVisibility();
        updateCustomSlider(state.temperature);
        updateModelPill();
        const drBtn=document.getElementById('btn-deep-research'); if(drBtn) drBtn.classList.toggle('active',!!state.deepResearch);
        updateGroqEffortBar();
    }

    function updateGroqEffortBar() {
        const existing = document.getElementById('groq-effort-bar');
        const isGroq = (apiConfig.provider||'').toLowerCase() === 'groq';
        if (!isGroq) { if (existing) existing.remove(); return; }

        let bar = existing;
        if (!bar) {
            bar = document.createElement('div');
            bar.id = 'groq-effort-bar';
            bar.className = 'groq-effort-bar';
            const inputDeck = document.querySelector('.input-deck');
            if (inputDeck) {
                const inputWrapper = inputDeck.querySelector('.input-wrapper');
                if (inputWrapper) inputDeck.insertBefore(bar, inputWrapper);
                else inputDeck.appendChild(bar);
            }
        }
        bar.innerHTML = '';
        const label = document.createElement('span'); label.className = 'groq-effort-label'; label.textContent = '\u26a1 GROQ THINKING';
        bar.appendChild(label);
        ['low','default','high'].forEach(level => {
            const btn = document.createElement('button');
            btn.className = 'groq-effort-btn' + (state.groqReasoningEffort === level ? ' active' : '');
            btn.textContent = level.toUpperCase();
            btn.title = level === 'low' ? 'Fast, less reasoning' : level === 'high' ? 'Slower, maximum reasoning depth' : 'Balanced default';
            btn.onclick = () => {
                state.groqReasoningEffort = level;
                saveState();
                updateGroqEffortBar();
                showNotification('Groq reasoning: ' + level, 'info');
            };
            bar.appendChild(btn);
        });
        const sep = document.createElement('span'); sep.style.cssText = 'flex:1'; bar.appendChild(sep);
        const wsLabel = document.createElement('span'); wsLabel.style.cssText = 'color:#334455;font-size:.6rem'; wsLabel.textContent = 'Web';
        const wsToggle = document.createElement('button');
        wsToggle.className = 'groq-effort-btn' + (state.groqWebSearch !== false ? ' active' : '');
        wsToggle.textContent = state.groqWebSearch !== false ? 'Search ON' : 'Search OFF';
        wsToggle.title = 'Groq web search via tool calls';
        wsToggle.onclick = () => { state.groqWebSearch = !(state.groqWebSearch !== false); saveState(); updateGroqEffortBar(); };
        const ceToggle = document.createElement('button');
        ceToggle.className = 'groq-effort-btn' + (state.groqCodeExecution !== false ? ' active' : '');
        ceToggle.textContent = state.groqCodeExecution !== false ? 'Run Code' : 'No Run';
        ceToggle.title = 'Auto-run code blocks via Piston API when Groq responds';
        ceToggle.onclick = () => { state.groqCodeExecution = !(state.groqCodeExecution !== false); saveState(); updateGroqEffortBar(); };
        bar.appendChild(wsLabel); bar.appendChild(wsToggle); bar.appendChild(ceToggle);
    }

    function applyMetricsVisibility() {
        const ld = $('latency-display');
        const td = $('tps-display');
        const d1 = $('metrics-sep-1');
        const d2 = $('metrics-sep-2');
        const show = !!state.showMetrics;
        if(ld) ld.style.display = show ? '' : 'none';
        if(td) td.style.display = show ? '' : 'none';
        if(d1) d1.style.display = show ? '' : 'none';
        if(d2) d2.style.display = show ? '' : 'none';
    }

    let _saveConvTimer = null;
    async function saveConversations() {
        // Coalesce rapid saves — wait 100ms before writing to IndexedDB
        if (_saveConvTimer) clearTimeout(_saveConvTimer);
        return new Promise(resolve => {
            _saveConvTimer = setTimeout(async () => {
                _saveConvTimer = null;
                await localforage.setItem('conversations', state.conversations);
                resolve();
            }, 100);
        });
    }
    async function loadConversations() { const s=await localforage.getItem('conversations'); if(s) state.conversations=s; }

    function createNewConversation() {
        const id='conv_'+Date.now()+Math.random().toString(36).slice(2,7);
        state.conversations[id]={id,title:'New Conversation',created:new Date().toISOString(),updated:new Date().toISOString(),messages:[]};
        saveConversations(); renderConversationList(); return id;
    }

    function setActiveConversation(convId) {
        state.currentConversationId = convId;
        clearDisplay();
        const conv = state.conversations[convId];
        if (conv) conv.messages.forEach(m => { if (m.role==='user') addUserMessage(m.content,false); else if (m.role==='assistant') addAssistantMessage(m.content,false); /* skip system/tool injection messages */ });
        else showWelcomeMessage();
        updateDualChatUI();
        renderConversationList();
        if (state.codingMode) updateCodingTurnBadge(convId);
        if (input) input.focus();
    }

    function getCurrentConversation() {
        if (!state.currentConversationId || !state.conversations[state.currentConversationId]) {
            const id=createNewConversation(); state.currentConversationId=id;
        }
        return state.conversations[state.currentConversationId];
    }

    function updateConversationTitle(conv) {
        if (conv.title==='New Conversation'&&conv.messages.length>0) {
            const fm=conv.messages.find(m=>m.role==='user');
            if(fm) conv.title=fm.content.replace(/\n/g,' ').slice(0,55).trim()+(fm.content.length>55?'...':'');
        }
        conv.updated=new Date().toISOString();
    }

    function deleteConversation(id) {
        const conv = state.conversations[id];
        const title = conv?.title || 'this conversation';
        showAetherDialog({
            title: 'Delete Conversation',
            html: `<p style="color:#99aabb">Delete <strong style="color:#ccd">"${title.slice(0,60)}"</strong>?<br><span style="color:#445;font-size:.72rem">This cannot be undone.</span></p>`,
            confirmLabel: 'DELETE',
            cancelLabel: 'CANCEL',
            onConfirm: async () => {
                delete state.conversations[id];
                await saveConversations();
                if (state.currentConversationId === id) {
                    const remaining = Object.keys(state.conversations);
                    if (remaining.length) setActiveConversation(remaining[0]);
                    else setActiveConversation(createNewConversation());
                }
                renderConversationList();
                showNotification('Conversation deleted', 'success');
            },
        });
    }

    // ── renderConversationList: debounced via RAF ─────────────
    // Previously called 18 times in rapid succession (once per
    // saveConversations, generateTitle, setActiveConversation, etc.)
    // causing repeated full-list DOM rebuilds during streaming.
    // Now coalesced: multiple calls within one frame → one render.
    let _renderConvPending = false;
    function renderConversationList() {
        if (!conversationList) return;
        if (_renderConvPending) return; // already queued for this frame
        _renderConvPending = true;
        requestAnimationFrame(() => {
            _renderConvPending = false;
            if (!conversationList) return;
            conversationList.innerHTML = '';
            const sorted = Object.values(state.conversations)
                .sort((a, b) => new Date(b.updated) - new Date(a.updated));
            if (!sorted.length) {
                conversationList.innerHTML = '<div style="padding:28px 20px;text-align:center;color:#445;font-size:.75rem;display:flex;flex-direction:column;align-items:center;gap:10px"><svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#334" stroke-width="1.2" style="opacity:0.5"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg><span>No conversations yet</span><button class="cmd-btn" style="font-size:.72rem;padding:4px 12px" onclick="document.getElementById(\'btn-new-chat\')?.click()">+ Start new</button></div>';
                return;
            }
            const frag = document.createDocumentFragment();
            sorted.forEach(conv => {
                const item = document.createElement('div');
                item.className = 'conversation-item';
                item.dataset.convId = conv.id;
                if (conv.id === state.currentConversationId) item.classList.add('active');
                const isProcessing = !!state.processingConversations[conv.id];
                if (isProcessing) item.classList.add('processing');
                const d = new Date(conv.updated);
                const ts = d.toLocaleDateString() + ' ' + d.toLocaleTimeString('en-GB', { hour:'2-digit', minute:'2-digit' });
                item.innerHTML = `<div class="conversation-title">${conv.title}${isProcessing ? ' <span class="conv-processing-dot"></span>' : ''}</div><div class="conversation-meta"><span>${ts}</span><button class="conversation-delete" data-id="${conv.id}">&#x2715;</button></div>`;
                item.addEventListener('click', e => {
                    if (!e.target.classList.contains('conversation-delete')) {
                        setActiveConversation(conv.id);
                        if (window.innerWidth <= 768) sidebar.classList.add('hidden');
                    }
                });
                item.querySelector('.conversation-delete').addEventListener('click', e => {
                    e.stopPropagation(); deleteConversation(conv.id);
                });
                frag.appendChild(item);
            });
            conversationList.appendChild(frag);
        });
    }

    // ─── MESSAGE PREPARATION ─────────────────────────────────
    // ═══════════════════════════════════════════════════════════
    // SMART CONTEXT COMPRESSION
    //
    // When a conversation approaches its context limit, instead of
    // truncating (which loses context) or failing (which is worse),
    // AETHER compresses the oldest portion of the conversation into
    // a structured summary and replaces those turns in-place.
    //
    // The summary preserves: decisions made, code written, key facts
    // established, user preferences revealed, files modified. The
    // model keeps the full semantics of the session without needing
    // the full token count.
    //
    // Think of it as Claude Code's transcript compaction, but for
    // chat conversations, running in the browser, no backend needed.
    // ═══════════════════════════════════════════════════════════

    async function compactConversationHistory(conv, convId) {
        const msgs = conv.messages;
        // Keep the last 40% of turns fresh — compress the older 60%
        const keepCount  = Math.max(4, Math.floor(msgs.length * 0.4));
        const compactMsgs = msgs.slice(0, msgs.length - keepCount);
        const freshMsgs   = msgs.slice(msgs.length - keepCount);

        if (compactMsgs.length < 8) return; // not enough to bother

        // Show a subtle compaction indicator in the UI
        const compBadge = document.createElement('div');
        compBadge.className = 'compaction-badge';
        compBadge.innerHTML = '⬡ Compressing context…';
        display?.appendChild(compBadge);

        try {
            const convText = compactMsgs.map(m =>
                (m.role === 'user' ? 'USER: ' : 'AETHER: ') +
                (typeof m.content === 'string' ? m.content : '[image/tool]').slice(0, 800)
            ).join('\n\n');

            const compactionPrompt = `You are summarising a conversation for context compression. Extract and preserve:

1. KEY DECISIONS — What was decided, chosen, or agreed upon
2. CODE & FILES — Any code written, files modified, file paths mentioned  
3. FACTS ESTABLISHED — Technical details, user preferences, constraints discovered
4. TASKS COMPLETED — What was accomplished
5. OPEN THREADS — Anything started but not finished

Be dense and specific. Preserve exact file names, function names, variable names, and technical details.
Do NOT add commentary. Output ONLY the structured summary.

CONVERSATION TO COMPRESS (${compactMsgs.length} messages):

${convText}`;

            const summary = await callModelDirect(compactionPrompt, {
                max_tokens: 1200,
                temperature: 0.1, // low temp for factual extraction
            });

            if (!summary || summary.length < 50) {
                compBadge.remove(); return;
            }

            // Replace the compacted messages with a single summary message
            const summaryMessage = {
                role: 'user',
                content: `[CONTEXT SUMMARY — ${compactMsgs.length} earlier messages compressed]\n\n${summary}\n\n[END SUMMARY — conversation continues below]`,
                _isCompactionSummary: true,
                _compressedCount: compactMsgs.length,
                _compressedAt: new Date().toISOString(),
            };

            // Splice into conversation: replace old turns with summary
            conv.messages = [summaryMessage, ...freshMsgs];
            await saveConversations();

            compBadge.innerHTML = `⬡ Context compressed — ${compactMsgs.length} turns → summary`;
            compBadge.classList.add('done');
            setTimeout(() => compBadge.remove(), 3500);

            // Show a marker in the chat display
            if (convId === state.currentConversationId) {
                const marker = document.createElement('div');
                marker.className = 'compaction-marker';
                marker.innerHTML = `<span>⬡</span> Context compressed · ${compactMsgs.length} earlier messages summarised to save context`;
                // Insert before the last few fresh messages in the display
                const msgs = display?.querySelectorAll('.aether-msg, .user-msg');
                if (msgs && msgs.length > keepCount) {
                    display.insertBefore(marker, msgs[msgs.length - keepCount]);
                } else {
                    display?.appendChild(marker);
                }
            }
        } catch(e) {
            compBadge.remove();
            console.warn('[AETHER] Context compaction failed:', e.message);
        }
    }

    function prepareMessagesForApi(history, newUserMessage) {
        const cleaned = [];
        let lastRole = null;
        for (const m of history) {
            if (m.role === lastRole) continue;
            cleaned.push(m); lastRole=m.role;
        }
        if (cleaned.length > 0 && cleaned[cleaned.length-1].role === 'user') cleaned.push({role:'assistant',content:'...'});
        cleaned.push({role:'user',content:newUserMessage});
        return cleaned;
    }

    // ─── STREAMING RESPONSE ──────────────────────────────────
    // Anthropic returns tool_use blocks inside content array
    // We accumulate the full response then parse all tool_use blocks
    async function handleAnthropicToolUse(fullContent, convId, aetherMsg) {
        // Match all tool_use blocks: {"type":"tool_use","id":"...","name":"...","input":{...}}
        const toolUseRe = /\{"type"\s*:\s*"tool_use"[^}]*"name"\s*:\s*"([^"]+)"[^}]*"input"\s*:\s*(\{[\s\S]*?\})\s*\}/g;
        let match;
        const calls = [];
        while ((match = toolUseRe.exec(fullContent)) !== null) {
            try {
                calls.push({ name: match[1], input: JSON.parse(match[2]) });
            } catch {}
        }
        if (!calls.length) return;
        for (const c of calls) {
            agentStatus('generic', `⚙ ${c.name}…`);
            const result = await callTool(c.name, c.input);
            agentDone();
            if (convId === state.currentConversationId) {
                const el = document.createElement('div');
                el.className = 'aether-msg tool-result-msg';
                el.appendChild(parseMarkdown(`**⚙ Tool [${c.name}]:**

${result}`));
                display?.appendChild(el);
                smoothScrollToBottom();
            }
            // Push tool result into conversation for next turn
            const conv = state.conversations[convId];
            if (conv) {
                conv.messages.push({ role: 'user', content: `[Tool result for ${c.name}]: ${result}` });
            }
        }
    }

    // ═══════════════════════════════════════════════════════════
    // SECTION 17: STREAMING RESPONSE HANDLER
    // The most complex function in the entire codebase.
    // Reads SSE stream token by token, renders in real-time,
    // handles think tags live, executes tool calls, tracks TPS,
    // manages the blur-in animation, and survives partial JSON.
    // If this function breaks, everything breaks.
    // It has survived 47 edge cases and counting.
    // Touch it at your own risk.
    // ═══════════════════════════════════════════════════════════
    async function handleStreamingResponse(response, convId, aetherMsg, startTime) {
        const reader=response.body.getReader(); const decoder=new TextDecoder();
        let buffer='', fullContent='', firstToken=null, tokenCount=0, lastTokenTime=startTime, lastCount=0;

        liveThinkReset();
        agentStatus('write', 'Generating…');

        while(true){
            const{done,value}=await reader.read(); if(done) break;
            buffer+=decoder.decode(value,{stream:true});
            const lines=buffer.split('\n'); buffer=lines.pop();
            for(const line of lines){
                if(!line.startsWith('data: ')) continue;
                const data=line.slice(6); if(data==='[DONE]') continue;
                try {
                    const json=JSON.parse(data);
                    // Support OpenAI and Anthropic streaming formats
                    let chunk='';
                    if(json.choices?.[0]?.delta?.content !== undefined){
                        chunk=json.choices[0].delta.content||''; // OpenAI format
                    } else if(json.type==='content_block_delta'){
                        chunk=json.delta?.text||''; // Anthropic format
                    } else if(json.type==='message_delta'&&json.delta?.stop_reason){
                        // Anthropic end-of-stream signal
                    }
                    if(chunk){
                        if(!firstToken){ firstToken=performance.now(); if(state.showMetrics) $('latency-display').textContent=`TTFT: ${Math.round(firstToken-startTime)}ms`; agentDone(); }
                        tokenCount+=chunk.split(/\s+/).length;
                        // Feed live token count into TPS-reactive wave animation
                        if(window._aetherWaveTokenTick) window._aetherWaveTokenTick(tokenCount);
                        const now=performance.now();
                        if(now-lastTokenTime>500){
                            const tpsCurrent = (tokenCount-lastCount)/((now-lastTokenTime)/1000);
                            if(state.showMetrics) $('tps-display').textContent=`TPS: ${tpsCurrent.toFixed(1)}`;
                            // Update AETHER pane with live streaming TPS
                            if(window._apSetStreaming) window._apSetStreaming(tpsCurrent);
                            lastCount=tokenCount; lastTokenTime=now;
                        }

                        fullContent+=chunk;

                        // ── STREAMING RENDER ─────────────────────────────────
                        if(convId===state.currentConversationId && !window._streamRenderPending){
                            window._streamRenderPending = true;
                            requestAnimationFrame(()=>{
                                window._streamRenderPending = false;

                                // Update live think block from accumulated fullContent
                                updateLiveThink(fullContent, aetherMsg);

                                // Get visible (non-think) portion
                                const { visible } = splitThink(fullContent);
                                const displayText = visible.trim() || (splitThink(fullContent).thinkOpen ? '' : fullContent);

                                if(displayText){
                                    if(state.blurInEnabled){
                                        // ── PER-WORD BLUR-IN ──────────────────
                                        // Stream as PLAIN TEXT with blur animation.
                                        // Do NOT parse markdown during streaming — partial
                                        // markdown (e.g. **bold without closing **) shows raw.
                                        // Markdown is rendered only after streaming completes.
                                        let streamContainer = aetherMsg.querySelector('.stream-text-container');
                                        if(!streamContainer){
                                            aetherMsg.innerHTML = '';
                                            streamContainer = document.createElement('span');
                                            streamContainer.className = 'stream-text-container';
                                            aetherMsg.appendChild(streamContainer);
                                        }

                                        // Strip XML tags and control sequences — keep as plain text
                                        let plainText = displayText
                                            .replace(/<web_search[^>]*>[\s\S]*?<\/web_search>/gi, '')
                                            .replace(/<search[^>]*>[\s\S]*?<\/search>/gi, '')
                                            .replace(/<visit_website[^>]*>[\s\S]*?<\/visit_website>/gi, '')
                                            .replace(/<function\([\s\S]*?<\/function>/gi, '')
                                            .replace(/<(web_search|search|visit_website|function)[^>]*>[^<]*$/, '')
                                            .replace(/<aether:plan>[\s\S]*$(?![\s\S]*<\/aether:plan>)/,
                                                (m) => /<\/aether:plan>/.test(m) ? m : '\n\n⏳ Building plan…\n')
                                            .replace(/<aether:todo>[\s\S]*$(?![\s\S]*<\/aether:todo>)/,
                                                (m) => /<\/aether:todo>/.test(m) ? m : '\n\n📋 Updating TODO…\n')
                                            .replace(/\[\[\w+:[^\]]*$/, '')
                                            // Strip markdown syntax for clean streaming
                                            .replace(/^#{1,6}\s+/gm, '')           // headers
                                            .replace(/\*\*(.+?)\*\*/g, '$1')        // bold
                                            .replace(/\*(.+?)\*/g, '$1')            // italic
                                            .replace(/`{3}[\s\S]*?`{3}/g, '[code]') // code blocks
                                            .replace(/`(.+?)`/g, '$1')              // inline code
                                            .replace(/\[(.+?)\]\(.+?\)/g, '$1')     // links
                                            .replace(/^[-*+]\s+/gm, '')             // list bullets
                                            .replace(/^\d+\.\s+/gm, '')             // numbered lists
                                            .replace(/^>\s+/gm, '')                 // blockquotes
                                            .replace(/^---+$/gm, '')                // horizontal rules
                                            .replace(/\n{3,}/g, '\n\n');            // collapse excessive newlines

                                        // If ALL content was tool calls and nothing remains, show a placeholder
                                        // so the user sees something instead of a blank bubble
                                        if(!plainText.trim()){
                                            // Detect what tool was called — check BOTH complete and INCOMPLETE tags
                                            // (during streaming the closing tag may not have arrived yet)
                                            const toolMatch = displayText.match(/\[\[(\w+):\s*([^\]]+)\]\]/i)
                                                || displayText.match(/<(web_search|search|visit_website)[^>]*>([\s\S]*?)<\/\1>/i)
                                                || displayText.match(/<(web_search|search|visit_website)>([\s\S]*)/i)  // incomplete — no closing tag yet
                                                || displayText.match(/<function\((\w+)([\s\S]*)/i);                   // incomplete function call
                                            if(toolMatch){
                                                const toolName = toolMatch[1] || '';
                                                const toolArg = (toolMatch[2] || '').replace(/[{}"']/g,'').replace(/query:|q:/gi,'').trim().slice(0, 60);
                                                const labels = {web_search:'🔍 Searching',search:'🔍 Searching',visit_website:'🌐 Visiting',get_weather:'🌤 Fetching weather',scrape:'🕷 Scraping',crawl:'🕷 Crawling',function:'⚙ Running'};
                                                const label = labels[toolName] || '⚙ ' + toolName;
                                                plainText = label + (toolArg ? ': ' + toolArg : '…');
                                            } else {
                                                plainText = '⚙ Processing…';
                                            }
                                        }

                                        // Get previously rendered text to find what's new
                                        const prevText = streamContainer.dataset.renderedText || '';

                                        if(plainText !== prevText){
                                            // Find the length of common prefix
                                            let commonLen = 0;
                                            const minLen = Math.min(prevText.length, plainText.length);
                                            while(commonLen < minLen && prevText[commonLen] === plainText[commonLen]){
                                                commonLen++;
                                            }

                                            // Get the new portion
                                            const newPortion = plainText.slice(commonLen);

                                            if(newPortion.length > 0){
                                                // Split new text into words (preserve whitespace)
                                                const wordTokens = newPortion.split(/(\s+)/);

                                                wordTokens.forEach((token, i) => {
                                                    if(token.length === 0) return;

                                                    if(token.match(/^\s+$/)){
                                                        streamContainer.appendChild(document.createTextNode(token));
                                                    } else {
                                                        const wordSpan = document.createElement('span');
                                                        wordSpan.className = 'stream-word';
                                                        wordSpan.style.animationDelay = (i * 0.03) + 's';
                                                        wordSpan.textContent = token;
                                                        streamContainer.appendChild(wordSpan);
                                                    }
                                                });

                                                // Remove old cursor
                                                const oldCursor = streamContainer.querySelector('.stream-cursor');
                                                if(oldCursor) oldCursor.remove();

                                                // Add blinking cursor at end
                                                const cursor = document.createElement('span');
                                                cursor.className = 'stream-cursor';
                                                cursor.textContent = '▋';
                                                streamContainer.appendChild(cursor);
                                            }

                                            streamContainer.dataset.renderedText = plainText;
                                        }
                                    } else {
                                        // ── CLASSIC FULL RE-RENDER ────────────
                                        let sanitizedDisplay = displayText
                                            .replace(/<web_search[^>]*>[\s\S]*?<\/web_search>/gi, '')
                                            .replace(/<search[^>]*>[\s\S]*?<\/search>/gi, '')
                                            .replace(/<visit_website[^>]*>[\s\S]*?<\/visit_website>/gi, '')
                                            .replace(/<function\([\s\S]*?<\/function>/gi, '')
                                            .replace(/<(web_search|search|visit_website|function)[^>]*>[^<]*$/, '')
                                            .replace(/<aether:plan>[\s\S]*$(?![\s\S]*<\/aether:plan>)/,
                                                (m) => /<\/aether:plan>/.test(m) ? m : '\n\n*⏳ Building plan…*\n')
                                            .replace(/<aether:todo>[\s\S]*$(?![\s\S]*<\/aether:todo>)/,
                                                (m) => /<\/aether:todo>/.test(m) ? m : '\n\n*📋 Updating TODO…*\n')
                                            .replace(/\[\[\w+:[^\]]*$/, '');
                                        sanitizedDisplay = wrapToolCallsForDisplay(sanitizedDisplay);
                                        if (typeof AETHER_Markdown !== 'undefined' && AETHER_Markdown.stabilizeForStream) {
                                            sanitizedDisplay = AETHER_Markdown.stabilizeForStream(sanitizedDisplay);
                                        }
                                        aetherMsg.innerHTML = '';
                                        aetherMsg.appendChild(parseMarkdown(sanitizedDisplay, { stream: true }));
                                    }
                                } else if(!aetherMsg.querySelector('.streaming-cursor')){
                                    aetherMsg.innerHTML='<p class="streaming-cursor">▋</p>';
                                }

                                // Scroll only when near bottom
                                const d = display;
                                if(d.scrollHeight - d.scrollTop - d.clientHeight < 120) smoothScrollToBottom();
                            });
                        }
                    }
                } catch {}
            }
        }

        // CRITICAL: Force-flush any pending RAF render before final clean render
        window._streamRenderPending = false;

        // ── FINAL RENDER: Replace word-span streaming with full markdown ──
        // After streaming ends, convert the blur-in word spans into proper
        // rendered markdown (headings, code blocks, tables, etc.)
        if(convId === state.currentConversationId && aetherMsg){
            const { visible, thinkHtml } = splitThink(fullContent);
            const displayText = visible.trim() || (splitThink(fullContent).thinkOpen ? '' : fullContent);
            aetherMsg.innerHTML = '';

            // Strip tool tags for final render
            let sanitized = displayText
                .replace(/<web_search[^>]*>[\s\S]*?<\/web_search>/gi, '')
                .replace(/<search[^>]*>[\s\S]*?<\/search>/gi, '')
                .replace(/<visit_website[^>]*>[\s\S]*?<\/visit_website>/gi, '')
                .replace(/<function\([\s\S]*?<\/function>/gi, '')
                .replace(/<aether:plan>[\s\S]*?<\/aether:plan>/gi, '')
                .replace(/<aether:todo>[\s\S]*?<\/aether:todo>/gi, '');
            sanitized = wrapToolCallsForDisplay(sanitized);

            // If after stripping tool tags there's no content, show a tool execution placeholder
            const hasToolCalls = /\[\[\w+:\s*[^\]]+\]\]/i.test(displayText)
                || /<(web_search|search|visit_website|function)[^>]*>/i.test(displayText);

            if(!sanitized.trim() || !sanitized.replace(/\[\[TOOL_PILL:[^\]]+\]\]/g, '').trim()){
                if(hasToolCalls){
                    // Detect tools for display — check complete AND incomplete tags
                    const tools = [];
                    const bracketRe = /\[\[(\w+):\s*([^\]]+)\]\]/gi;
                    let bm;
                    while((bm = bracketRe.exec(displayText)) !== null) tools.push({name: bm[1], arg: bm[2]});
                    // Complete XML tags
                    const xmlRe = /<(web_search|search|visit_website)[^>]*>([\s\S]*?)<\/\1>/gi;
                    let xm;
                    while((xm = xmlRe.exec(displayText)) !== null) tools.push({name: xm[1], arg: xm[2]});
                    // Incomplete XML tags (closing tag may not have arrived)
                    const xmlIncomplete = /<(web_search|search|visit_website)>([\s\S]*)/gi;
                    let xi;
                    while((xi = xmlIncomplete.exec(displayText)) !== null){
                        // Avoid duplicates — only add if not already found
                        if(!tools.find(t => t.name === xi[1])) tools.push({name: xi[1], arg: xi[2]});
                    }

                    if(tools.length > 0){
                        // Show tool execution status
                        const toolMsg = document.createElement('div');
                        toolMsg.className = 'aether-msg tool-exec-msg';
                        const toolNames = tools.map(t => {
                            const labels = {web_search:'🔍 Search',search:'🔍 Search',visit_website:'🌐 Visit',get_weather:'🌤 Weather',scrape:'🕷 Scrape',crawl:'🕷 Crawl'};
                            return (labels[t.name] || t.name) + (t.arg ? ': ' + t.arg.slice(0, 50) : '');
                        }).join(', ');
                        toolMsg.innerHTML = '<p><strong>⚙ Executing:</strong> ' + toolNames + '</p>'
                            + '<p class="tool-exec-detail">Results will appear below once complete…</p>';
                        aetherMsg.appendChild(toolMsg);
                    }
                }
            } else {
                // ── Render pipeline: DocSupremacy → AetherVisualizer → parseMarkdown ──
                // 1. If Documents Supremacy skill is active, try to parse a doc spec
                // 2. If not, try AetherVisualizer for chart/flow/mermaid specs
                // 3. Fall back to parseMarkdown for all prose
                let vizRendered = false;

                // Step 1: Documents Supremacy
                if (activeSkills.some(function(s){ return s.name === 'documents-supremacy'; })) {
                    try { vizRendered = await window._tryDocumentsSupremacyRender?.(sanitized, aetherMsg) || false; } catch(e) {}
                }

                // Step 2: Discovery Skill
                if (!vizRendered && activeSkills.some(function(s){ return s.name === 'discovery'; })) {
                    try { vizRendered = await window._tryDiscoverySkillRender?.(sanitized, aetherMsg) || false; } catch(e) {}
                }

                // Step 3: AetherVisualizer
                if (!vizRendered && window.AetherVisualizer) {
                    try {
                        const vizEl = document.createElement('div');
                        vizEl.className = 'aether-viz-container';
                        const didRender = await window.AetherVisualizer.autoDetect(sanitized, vizEl);
                        if (didRender) {
                            vizRendered = true;
                            const stripped = sanitized
                                .replace(/```json[\s\S]*?```/g, '')
                                .replace(/```mermaid[\s\S]*?```/g, '')
                                .trim();
                            if (stripped) {
                                const mdEl = document.createElement('div');
                                mdEl.appendChild(parseMarkdown(stripped));
                                aetherMsg.appendChild(mdEl);
                            }
                            aetherMsg.appendChild(vizEl);
                        }
                    } catch(e) { console.warn('[AETHER] Visualizer error:', e.message); }
                }

                // Step 4: Markdown fallback
                if (!vizRendered) {
                    aetherMsg.appendChild(parseMarkdown(sanitized));
                }
            }

            // Re-attach copy/run action buttons
            attachActions(aetherMsg, fullContent);
            attachRagCitations(aetherMsg);
            smoothScrollToBottom();
        }

        agentDone();
        // Save reference to live think element before reset
        // so parseMarkdown can detect it already exists in the DOM
        const _liveThinkSnapshot = liveThinkEl;
        liveThinkReset();

        // Declare conv HERE — before any block that references it, to avoid TDZ crash
        const conv = state.conversations[convId];

        // ── Execute [[bracket]] tool calls ([[web_search:]], [[get_weather:]], etc.) ──
        // Only handles bracket syntax. XML patterns handled by xmlToolRe below.
        try {
            const bracketResults = await parseAndExecuteTools(fullContent);
            if (bracketResults.length > 0 && convId === state.currentConversationId) {
                const searchNames = ['web_search', 'scrape', 'crawl'];
                const wsNames    = ['read_file', 'write_file'];
                const searchBR   = bracketResults.filter(r => searchNames.includes(r.name));
                const wsBR       = bracketResults.filter(r => wsNames.includes(r.name));
                const otherBR    = bracketResults.filter(r => !searchNames.includes(r.name) && !wsNames.includes(r.name));

                for (const { name, result } of searchBR) {
                    const qMatch = fullContent.match(/\[\[web_search:\s*([^\]]+)\]\]/i);
                    display.appendChild(renderCollapsedSources(qMatch ? qMatch[1].trim() : name, result));
                }
                for (const { name, result } of wsBR) {
                    const wsEl = document.createElement('div');
                    wsEl.className = 'aether-msg ws-file-inject';
                    const icon = name === 'write_file' ? '\u270f\ufe0f Written' : '\ud83d\udcc2 File';
                    wsEl.appendChild(parseMarkdown('**' + icon + ':**\n\n' + String(result).slice(0, 2000)));
                    display.appendChild(wsEl);
                }
                for (const { name, result } of otherBR) {
                    display.appendChild(renderToolResultCard(name, result));
                }
                const bracketContext = bracketResults.map(r => '[' + r.name + ' result]\n' + String(r.result)).join('\n\n');
                // Mark as 'system' so it's used as context but never re-rendered as a user bubble on reload
                if (conv) conv.messages.push({ role: 'system', content: '[Tool results]\n' + bracketContext });
                smoothScrollToBottom();
            }
        } catch(e) { /* bracket tool execution must never crash the stream */ }

        // Strip [[bracket]] tags, XML tool tags, function call tags, and aether control tags
        let cleanContent = fullContent
            .replace(/\[\[\w+:[^\]]*\]\]/g, '')
            .replace(/<web_search[^>]*>[\s\S]*?<\/web_search>/gi, '')
            .replace(/<search[^>]*>[\s\S]*?<\/search>/gi, '')
            .replace(/<visit_website[^>]*>[\s\S]*?<\/visit_website>/gi, '')
            .replace(/<aether:continue\s*\/?>/gi, '')
            .replace(/<function\(\w+[^)]*\)[^<]*<\/function>/gi, '') // <function(tool {...})</function>
            .replace(/<function_calls>[\s\S]*?<\/function_calls>/gi, '') // Anthropic function_calls blocks
            .trim();

        // ── Intercept <function(tool_name {...})</function> format ──
        const funcCallRe = /<function\((\w+)\s+({[^}]*}|[^<]*)\)<\/function>/gi;
        let fcMatch;
        while ((fcMatch = funcCallRe.exec(fullContent)) !== null) {
            const toolName = fcMatch[1].toLowerCase();
            const argStr   = fcMatch[2].trim();
            let q = '';
            try { const j = JSON.parse(argStr); q = j.query || j.q || j.search || j.location || ''; } catch(_) {}
            if (!q) q = argStr.replace(/[{}"']/g,'').replace(/query:|q:/gi,'').trim().slice(0,200);
            if (q && q.length > 2) {
                if (toolName === 'web_search' || toolName === 'search') {
                    try { const r = await smartWebSearch(q, {}); if (r && r.length > 20) xmlToolResults.push({ query: q, result: r }); } catch(_) {}
                } else if (toolName === 'get_weather') {
                    try { await fetchWeather(q); } catch(_) {}
                }
            }
        }

        // ── Intercept & execute any XML tool calls in fullContent ──
        // Catches <web_search>query</web_search> patterns models output
        const xmlToolRe = /<(web_search|search|visit_website)[^>]*>([\s\S]*?)<\/\1>/gi;
        let xmlMatch;
        const xmlToolResults = [];
        while ((xmlMatch = xmlToolRe.exec(fullContent)) !== null) {
            const inner = xmlMatch[2].trim();
            let q = '';
            // 1. JSON body: {"query":"Kisumu weather"}
            try { const j = JSON.parse(inner); q = (j.query || j.q || j.search || '').trim(); } catch(_) {}
            // 2. key=value: query="..." or query=...
            if (!q) {
                const kv = inner.match(/(?:query|q)\s*=\s*["'\`]?([^"'\`\n<]{2,})["'\`]?/i);
                if (kv) q = kv[1].trim();
            }
            // 3. Plain text (not JSON)
            if (!q && !inner.startsWith('{')) q = inner.replace(/<[^>]*>/g,'').trim().slice(0,200);
            q = q.trim().replace(/^["\']+|["\']+$/g,''); // strip stray quotes
            if (q && q.length > 2) {
                try {
                    const result = await smartWebSearch(q, {});
                    if (result && result.length > 20) xmlToolResults.push({ query: q, result });
                } catch(e) {}
            }
        }

        // If XML tools ran, show collapsed sources pill (expand to full card on click).
        if (xmlToolResults.length > 0 && convId === state.currentConversationId) {
            for (const { query, result } of xmlToolResults) {
                display.appendChild(renderCollapsedSources(query, result));
            }
            if (conv) {
                const searchContext = xmlToolResults.map(r => '[Search: ' + r.query + ']\n' + r.result).join('\n\n');
                conv.messages.push({ role: 'system', content: '[Search results]\n' + searchContext });
                // Synthesize only if: no model text (pure tool response) AND results are substantial
                const hasUsefulResults = xmlToolResults.some(r => r.result && r.result.length > 80);
                const modelWroteSomething = cleanContent.length > 30;
                if (!modelWroteSomething && hasUsefulResults && convId === state.currentConversationId) {
                    setTimeout(async () => {
                        try {
                            const synthPrompt = 'Based on the search results above, answer the original query concisely with citations.';
                            const synth = await callAISimple([...conv.messages, {role:'user', content: synthPrompt}], apiConfig.model);
                            if (synth && convId === state.currentConversationId) {
                                const synthEl = document.createElement('div');
                                synthEl.className = 'aether-msg';
                                synthEl.appendChild(parseMarkdown(synth));
                                attachActions(synthEl, synth);
                                display.appendChild(synthEl);
                                conv.messages.push({ role: 'assistant', content: synth });
                                saveConversations();
                                smoothScrollToBottom();
                            }
                        } catch(e) {}
                    }, 300);
                    return fullContent;
                }
            }
        }

        // ── Handle Anthropic tool_use content blocks ──────────────
        if ((apiConfig.provider||'').toLowerCase() === 'anthropic') {
            await handleAnthropicToolUse(fullContent, convId, aetherMsg);
        }
        // ── Handle OpenAI tool_calls in non-streamed path ──────────
        if ((typeof responseJson !== 'undefined') && responseJson?.choices?.[0]?.finish_reason === 'tool_calls' && responseJson?.choices?.[0]?.message?.tool_calls) {
            const tcResults = await dispatchToolCalls(responseJson.choices[0].message.tool_calls);
            if (tcResults.length && convId === state.currentConversationId) {
                tcResults.forEach(r => {
                    const el = document.createElement('div');
                    el.className = 'aether-msg tool-result-msg';
                    el.appendChild(parseMarkdown('**Tool [' + r.name + ']:**\n\n' + r.content));
                    display.appendChild(el);
                });
                smoothScrollToBottom();
            }
        }

        if(conv){
            // Save cleanContent (stripped of bracket tags and tool calls) not fullContent
            // so on reload the message renders cleanly without raw [[search:...]] artifacts
            const savedContent = cleanContent || fullContent;
            conv.messages.push({role:'assistant',content:savedContent});
            updateConversationTitle(conv); saveConversations(); renderConversationList();
        }

        // ── AETHER Code turn loop (Claude Code QueryEnginePort pattern) ──
        if (state.codingMode && conv) {
            incrementCodingTurns(convId);
            compactCodingTranscriptIfNeeded(conv);

            const turns = getCodingTurns(convId);
            const hasPendingTodo = /<aether:todo>[\s\S]*?⬜[\s\S]*?<\/aether:todo>/i.test(fullContent);
            const hasContinueTag = /<aether:continue\s*\/?>/i.test(fullContent);
            const maxHit = turns >= AETHER_TOOL_POOL.maxTurns;

            // Determine stop reason (mirrors QueryEnginePort.submit_message)
            let stopReason = 'completed';
            if (maxHit) stopReason = 'max_turns';

            // Only render stop badge when there was an actual coding task (has plan or todo)
            const wasActiveCodingTask = /<aether:plan>|<aether:todo>/i.test(fullContent);
            if (wasActiveCodingTask && convId === state.currentConversationId) {
                const stopBadge = document.createElement('div');
                stopBadge.className = 'coding-stop-badge coding-stop-' + stopReason;
                stopBadge.innerHTML = maxHit
                    ? '⚠ Max turns (' + turns + '/' + AETHER_TOOL_POOL.maxTurns + ') — task paused'
                    : '✓ Turn ' + turns + ' complete';
                if (aetherMsg && aetherMsg.isConnected) aetherMsg.appendChild(stopBadge);
            }

            // Auto-continue ONLY when ALL three conditions hold:
            // 1. Model explicitly emitted <aether:continue/> (opt-in — never implicit)
            // 2. There is an active <aether:plan> in this response (real coding task)
            // 3. There are genuinely pending ⬜ steps in the todo board
            // This prevents API abuse on simple Q&A that happens to be in coding mode.
            const hasActivePlan = /<aether:plan>/i.test(fullContent);
            const safeToAutoContinue = hasContinueTag && hasActivePlan && hasPendingTodo && !maxHit;
            if (safeToAutoContinue && convId === state.currentConversationId) {
                const continuePrompt = 'Continue — execute the next pending step from the TODO board.';
                setTimeout(() => {
                    if (!state.processingConversations[convId] && state.codingMode) {
                        const sendEvt = new Event('aether-auto-continue');
                        sendEvt.autoMessage = continuePrompt;
                        document.dispatchEvent(sendEvt);
                    }
                }, 1200); // 1.2s grace — user can cancel by typing
            }

            state.codingSession.stopReasons[convId] = stopReason;
        }

        // Final clean render — always runs regardless of streaming path
        if(convId===state.currentConversationId){
            aetherMsg.innerHTML='';

            // If fullContent is empty (tool-only response), show a placeholder
            const renderContent = (cleanContent || fullContent).trim();
            if (!renderContent) {
                // Tool calls happened — response will appear as tool result cards above
                aetherMsg.style.display = 'none';
            } else {
                aetherMsg.style.display = '';
                const lastUserMsg = conv?.messages?.slice().reverse().find(m => m.role === 'user')?.content || '';
                const willShowFileCard = shouldAutoCreateFile(lastUserMsg, renderContent);
                if (willShowFileCard) {
                    const textOnly = renderContent.replace(/```[\s\S]*?```/g, '[See file card below]').trim();
                    if (textOnly && textOnly !== '[See file card below]') {
                        aetherMsg.appendChild(parseMarkdown(textOnly));
                    }
                    attachActions(aetherMsg, renderContent);
                    attachRagCitations(aetherMsg);
                    const fmt = guessFileFormat(lastUserMsg);
                    const heading = renderContent.match(/^#{1,3}\s+(.+)/m);
                    const autoCard = createFileCard(renderContent, fmt, heading ? heading[1].trim() : null);
                    display.appendChild(autoCard);
                } else {
                    aetherMsg.appendChild(parseMarkdown(renderContent));
                    attachActions(aetherMsg, renderContent);
                    attachRagCitations(aetherMsg);
                    // Auto-launch Construct if a complete HTML app was generated
                    if (shouldAutoConstruct(lastUserMsg, renderContent)) {
                        const htmlMatch = renderContent.match(/```(?:html?)[^\n]*\n([\s\S]*?)```/i) || [null, renderContent];
                        const htmlCode = htmlMatch[1] || renderContent;
                        // Extract heading for card title
                        const headingMatch = renderContent.match(/^#{1,3}\s+(.+)/m);
                        const constructTitle = headingMatch ? headingMatch[1].trim() : (lastUserMsg.slice(0, 48) || 'AETHER Construct');
                        setTimeout(() => {
                            renderConstructCard(
                                constructTitle, 'html',
                                () => openFullPreviewWindow(htmlCode, 'html', constructTitle),
                                ['Building interface\u2026', 'Injecting logic', 'Ready to launch']
                            );
                        }, 400);
                    }
                }
            }
            smoothScrollToBottom();
        }

        // Workspace file reads
        if(state.workspaceEnabled && /<read_file>/i.test(fullContent)){
            const fileContent = await fulfillWorkspaceReads(fullContent);
            if(fileContent && convId===state.currentConversationId){
                const fileMsg = document.createElement('div');
                fileMsg.className = 'aether-msg ws-file-inject';
                fileMsg.appendChild(parseMarkdown('**\ud83d\udcc2 Workspace file loaded:**\n' + fileContent));
                display.appendChild(fileMsg);
                if(conv) conv.messages.push({role:'user', content:'[SYSTEM: Workspace file contents]\n'+fileContent});
                smoothScrollToBottom();
            }
        }

        // Reset pane to idle
        if (window._apSetIdle) setTimeout(window._apSetIdle, 2000);
        return fullContent;
    }

    // ─── SEND MESSAGE ────────────────────────────────────────
    async function sendMessage() {
        let msg = input.value.trim(); if(!msg) return;
        if(isQuotaExceeded()){ showNotification('API calls blocked — quota limit reached. Reset in QUOTA settings.','error'); return; }
        const now=Date.now();
        if(now-state.lastRequestTime<state.rateLimitMs){ showNotification('Rate limit — wait a moment','warn'); return; }
        state.lastRequestTime=now;

        const conv=getCurrentConversation();
        const convId=conv.id;
        if(state.processingConversations[convId]){ showNotification('This conversation is still generating','warn'); return; }

        // ─── CODE PRO: expand @mentions / pins into hidden context ──
        let codeProContext = '';
        if (state.codingMode && typeof AETHER_CodePro !== 'undefined' && AETHER_CodePro.expandMentionsInMessage) {
            try {
                const expanded = await AETHER_CodePro.expandMentionsInMessage(msg);
                if (expanded) {
                    if (expanded.userText) msg = expanded.userText.trim() || msg;
                    codeProContext = expanded.contextBlock || '';
                }
            } catch (e) {}
        }
        // Stash for buildSystemPrompt / message pipeline (one-shot)
        window.__aetherCodeProContext = codeProContext;

        // ─── CODING MODE SHELL INTERCEPT ──────────────────────────
        // When Coding Mode is active and a folder is linked, shell-style
        // commands run directly against the FileSystem handle — no API call,
        // no tokens spent, instant response. The AI never even sees it.
        //
        // Intercepted: ls, ls -a, ls -la, cat, head, tail, wc, grep, find, tree, pwd, help
        // Everything else falls through to normal sendMessage flow.
        if (state.codingMode && codingFolderHandle) {
            const SHELL_RE = /^(ls|cat|head|tail|wc|grep|find|tree|pwd|mkdir|touch|sort|uniq|diff|help)\b/i;
            if (SHELL_RE.test(msg)) {
                // Show the command in chat as a user message
                input.value = '';
                input.style.height = 'auto';
                const userEl = document.createElement('div');
                userEl.className = 'user-msg';
                userEl.innerHTML = '<code style="color:#8be9fd;background:transparent;padding:0;border:none;font-size:.85rem;">$ ' +
                    msg.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</code>';
                display.appendChild(userEl);
                smoothScrollToBottom();

                // Run the shell command
                const result = await fsFolderShell(msg);

                // Render the output as a code block
                const outEl = document.createElement('div');
                outEl.className = 'aether-msg';
                const pre = document.createElement('pre');
                pre.style.cssText = 'margin:0;font-family:var(--font-mono);font-size:.78rem;color:#c8d8e8;white-space:pre-wrap;word-break:break-all;';
                pre.textContent = result;
                outEl.appendChild(pre);
                display.appendChild(outEl);
                smoothScrollToBottom();

                // Save to conversation history (light entry — no API metadata)
                conv.messages.push({ role: 'user',      content: '$ ' + msg });
                conv.messages.push({ role: 'assistant', content: '```\n' + result + '\n```' });
                saveConversations();
                return; // ← Don't fall through to the AI
            }
        }

        // ─── AGENT INTENT DETECTION ────────────────────────────────
    // Detects when a user message is a multi-step task that should
    // trigger autonomous agent behavior instead of normal chat.
    function detectAgentIntent(message) {
        const msg = message.trim();
        if (msg.length < 15) return { isAgentTask: false, confidence: 0 };

        // Strong signals — multi-step task indicators
        const strongSignals = [
            /\b(research|investigate|analyze|explore)\b.*\b(and|then|also|save|write|create|build|summarize)\b/i,
            /\b(build|create|make|develop|write)\b.*\b(and|then|also|with|that|which|save|deploy)\b/i,
            /\b(find|search|look up|discover)\b.*\b(and|then|also|save|summarize|compare)\b/i,
            /\b(scrape|crawl|fetch|extract)\b.*\b(and|then|also|save|analyze|summarize)\b/i,
            /\b(top \d+|all|every|each|multiple|several)\b.*\b(paper|article|repo|project|tool|option|way|method)\b/i,
            /\b(compare|contrast|rank|evaluate|review)\b.*\b(and|then|also|save|write)\b/i,
            /\b(setup|set up|configure|initialize|init)\b.*\b(project|app|website|server|api|database)\b/i,
            /\b(migrate|convert|transform|refactor|rewrite)\b.*\b(and|then|also|save|test)\b/i,
            /\b(deploy|publish|push|ship)\b.*\b(and|then|also|test|verify|check)\b/i,
            /\b(step \d+|phase \d+|part \d+|first.*then|after.*then)\b/i,
        ];

        // Medium signals — single action but complex
        const mediumSignals = [
            /\b(comprehensive|detailed|thorough|complete|full|in-depth)\b.*\b(report|analysis|summary|guide|tutorial)\b/i,
            /\b(save|store|write|export|download)\b.*\b(file|workspace|document|markdown|json)\b/i,
            /\b(generate|produce|output|render)\b.*\b(code|script|program|function|component)\b/i,
            /\b(check|verify|test|debug|fix)\b.*\b(error|issue|bug|problem|vulnerability)\b/i,
            /\b(automate|schedule|cron|recurring|periodic)\b/i,
        ];

        // Negative signals — NOT agent tasks
        const negativeSignals = [
            /^(what is|who is|how do|can you|tell me|explain|define|show me)\b/i,
            /\?$/, // questions are usually just chat
            /^(hi|hello|hey|thanks|ok|yes|no|sure|cool|nice)\b/i,
            /\b(joke|poem|story|song|lyrics|haiku)\b/i,
        ];

        let score = 0;
        let steps = 2; // minimum steps for agent

        // Check strong signals
        for (const re of strongSignals) {
            if (re.test(msg)) { score += 2; steps++; }
        }

        // Check medium signals
        for (const re of mediumSignals) {
            if (re.test(msg)) { score += 1; }
        }

        // Check negative signals
        for (const re of negativeSignals) {
            if (re.test(msg)) { score -= 2; }
        }

        // Length bonus — longer messages tend to be more complex
        if (msg.length > 60) score += 1;
        if (msg.length > 120) score += 1;

        // Multi-clause bonus
        const clauses = msg.split(/[;,]\s+/);
        if (clauses.length >= 3) { score += 1; steps += clauses.length - 2; }

        const confidence = Math.max(0, Math.min(1, score / 6));
        const isAgentTask = confidence >= 0.5;

        return {
            isAgentTask,
            confidence,
            estimatedSteps: Math.min(steps, 10),
            score,
        };
    }

    // ─── INLINE AGENT PLAN PROPOSAL ──────────────────────────
    // Shows a plan inline in the chat and asks for confirmation
    // before starting autonomous execution.
    async function showInlineAgentPlan(message, intent) {
        return new Promise((resolve) => {
            const planEl = document.createElement('div');
            planEl.className = 'inline-agent-plan';

            planEl.innerHTML = `
                <div class="iap-header">
                    <span class="iap-icon">⬡</span>
                    <span class="iap-title">This looks like a multi-step task</span>
                </div>
                <div class="iap-body">
                    <p class="iap-goal">"${message.slice(0, 120)}${message.length > 120 ? '…' : ''}"</p>
                    <p class="iap-suggestion">I can handle this autonomously in ~${intent.estimatedSteps} steps — plan, execute, and deliver.</p>
                    <div class="iap-actions">
                        <button class="iap-btn-proceed" id="iap-proceed">⬡ Proceed</button>
                        <button class="iap-btn-chat" id="iap-chat">Just chat</button>
                    </div>
                </div>
            `;

            display.appendChild(planEl);
            smoothScrollToBottom();

            const proceedBtn = planEl.querySelector('#iap-proceed');
            const chatBtn = planEl.querySelector('#iap-chat');

            proceedBtn.addEventListener('click', () => {
                planEl.classList.add('iap-accepted');
                planEl.querySelector('.iap-suggestion').textContent = 'Planning…';
                resolve('proceed');
            });

            chatBtn.addEventListener('click', () => {
                planEl.remove();
                resolve('chat');
            });
        });
    }

    // ─── AMBIGUITY CHECK — show clarification form for vague requests ──
        if (state.clarificationEnabled !== false && msg.split(/\s+/).length < 6 && !msg.includes('?')) {
            const vagueTriggers = /^(help|what|how|build|make|create|write|explain|tell me|show me|do|can you|code|app|website|tool)\b/i;
            if (vagueTriggers.test(msg)) {
                const clarified = await showClarificationForm(msg);
                if (clarified === null) return; // user cancelled
                if (clarified && clarified !== msg) {
                    input.value = clarified;
                    input.style.height = 'auto';
                    input.style.height = Math.min(input.scrollHeight, 200) + 'px';
                    // Don't auto-send — let user review the filled form
                    return;
                }
            }
        }

        // Deep Research — route to pipeline when active
        let finalRawMsg = msg;

        // ─── AGENT INTENT CHECK — auto-detect multi-step tasks ──
        const agentMode = state.agentMode || 'auto'; // 'auto' | 'ask' | 'off'
        if (agentMode !== 'off' && !state.deepResearch && !state.codingMode) {
            const intent = detectAgentIntent(msg);
            if (intent.isAgentTask) {
                if (agentMode === 'ask') {
                    // Always ask before agent mode
                    const choice = await showInlineAgentPlan(msg, intent);
                    if (choice === 'chat') {
                        // Fall through to normal chat
                    } else if (choice === 'proceed') {
                        // Route to agent
                        addUserMessage(msg);
                        input.value = ''; input.style.height = 'auto';
                        if (charCounter) charCounter.textContent = '0 chars';
                        ocrPackageDiv.classList.add('hidden');
                        state.extractedOCRText = null; state.currentImageFile = null;
                        attachedImages = []; renderImageGrid(); updateImageCountBadge();
                        removeVisionImage(); smoothScrollToBottom();
                        await runAgentTask(msg, { maxSteps: intent.estimatedSteps, approval: 'auto' });
                        return;
                    }
                } else if (agentMode === 'auto') {
                    // Auto-detect: show inline plan, proceed on confirm
                    const choice = await showInlineAgentPlan(msg, intent);
                    if (choice === 'chat') {
                        // Fall through to normal chat
                    } else if (choice === 'proceed') {
                        addUserMessage(msg);
                        input.value = ''; input.style.height = 'auto';
                        if (charCounter) charCounter.textContent = '0 chars';
                        ocrPackageDiv.classList.add('hidden');
                        state.extractedOCRText = null; state.currentImageFile = null;
                        attachedImages = []; renderImageGrid(); updateImageCountBadge();
                        removeVisionImage(); smoothScrollToBottom();
                        await runAgentTask(msg, { maxSteps: intent.estimatedSteps, approval: 'auto' });
                        return;
                    }
                }
            }
        }

        if (state.deepResearch && !drPipelineActive) {
            input.value = ''; input.style.height = 'auto';
            if (charCounter) charCounter.textContent = '0 chars';
            addUserMessage(msg);
            runDeepResearchPipeline(msg);
            return;
        }
        if (state.deepResearch) {
            finalRawMsg = await deepResearchClarificationCheck(msg);
        }
        // Auto-detect image generation requests → FLUX.2
        if (typeof isImageRequest === 'function' && isImageRequest(msg) && (apiConfig.provider==='flux'||apiConfig.provider==='local')) {
            const uEl=document.createElement('div');uEl.className='user-msg';uEl.textContent=msg;display.appendChild(uEl);
            generateFluxImage(msg.replace(/^(generate|create|draw|make|render|paint|design|show me)\s+(an?\s+)?(image|picture|photo)(\s+of\s+)?/i,'').trim()||msg);
            userInput.value=''; adjustTextareaHeight(); return;
        }

        const abortController=new AbortController();
        state.processingConversations[convId]={abortController};
        updateDualChatUI();

        let finalMessage=finalRawMsg;
        let visionImage=null;
        if(state.visionImageBase64){ visionImage=state.visionImageBase64; finalMessage=finalRawMsg||'Describe this image in detail.'; }
        if(state.extractedOCRText&&state.currentImageFile){ finalMessage=`[Image: ${state.currentImageFile.name}]\n[OCR Text: ${state.extractedOCRText}]\n\nUser Query: ${finalRawMsg}`; }
        // CODE Pro: append expanded @file / @blast / pins (hidden from bubble, visible to model)
        if (codeProContext) finalMessage = finalMessage + codeProContext;
        window.__aetherCodeProContext = '';

        addUserMessage(msg+(visionImage?' [image attached]':''));
        input.value=''; input.style.height='auto';
        if(charCounter) charCounter.textContent='0 chars';
        ocrPackageDiv.classList.add('hidden');
        state.extractedOCRText=null; state.currentImageFile=null;
        // Clear all attached images after send
        attachedImages = []; renderImageGrid(); updateImageCountBadge();
        removeVisionImage(); smoothScrollToBottom();

        const aetherMsg=document.createElement('div'); aetherMsg.className='aether-msg';
        // Only show in DOM if this is the current conversation
        if(convId===state.currentConversationId){ display.appendChild(aetherMsg); if(state.streamingEnabled) aetherMsg.innerHTML='<p class="streaming-cursor">▋</p>'; else showTypingIndicator(); }

        const startTime=performance.now();
        try {
            const systemPrompt = await buildSystemPrompt(msg, conv.messages.slice(-10));
            const systemTokens=estimateTokens(systemPrompt);
            const historyTokens=conv.messages.reduce((s,m)=>s+estimateTokens(m.content),0);
            const userTokens=estimateTokens(finalMessage);
            const totalPromptTokens=systemTokens+historyTokens+userTokens;

            // Context window check — only warn, never hard-block unless user set explicit limit
            const ctxOverride = parseInt(localStorage.getItem('aether_ctx_limit'));
            const effectiveLimit = ctxOverride || state.contextLimit;
            const usageRatio = (state.tokenUsage.total + totalPromptTokens) / effectiveLimit;
            if (usageRatio > 0.92) {
                if (ctxOverride) {
                    showNotification(`Context limit reached (${effectiveLimit.toLocaleString()} tokens) — start a new chat`, 'warn');
                    throw new Error('Context limit');
                } else {
                    showNotification(`⚠ Approaching context limit (~${Math.round(usageRatio*100)}% used)`, 'warn');
                }
            }

            // ── SMART CONTEXT COMPRESSION ──────────────────────────
            // When the conversation is approaching the context limit (>75%),
            // we don't just truncate — we summarise the oldest turns and
            // replace them with a compact summary message that preserves
            // the key facts, decisions, and code from earlier in the chat.
            //
            // This is the same pattern as Claude Code's transcript compaction.
            // Without it, long conversations either fail (hard limit) or lose
            // critical early context (dumb truncation). With it, conversations
            // can run essentially indefinitely while the model retains the
            // semantics of the whole session.
            //
            // Triggers at 75% context usage. Compaction is async but doesn't
            // block the current message — it runs in the background and
            // applies to subsequent turns. A subtle badge shows when active.
            if (usageRatio > 0.75 && !state._compactionInProgress &&
                conv.messages.length > 20 && !state.compactionDisabled) {
                state._compactionInProgress = true;
                compactConversationHistory(conv, convId).finally(() => {
                    state._compactionInProgress = false;
                });
            }

            let fullSystemPrompt = systemPrompt;
            if (state.ragEnabled) {
                try {
                    const ragResult = await retrieveRAGv2(msg, {
                        topK: state.codingMode ? 8 : 6,
                        hybrid: true,
                        collection: state.codingMode ? null : null, // all collections
                    });
                    if (ragResult.contextBlock) {
                        fullSystemPrompt += '\n\n' + ragResult.contextBlock;
                    } else if (ragResult.hits && ragResult.hits.length) {
                        fullSystemPrompt += '\n\n# RAG CONTEXT\n' + ragResult.hits.map((c, i) =>
                            `[${i + 1}] ${String(c.text).slice(0, 500)}`).join('\n\n');
                    }
                } catch (ragErr) {
                    // Legacy fallback
                    const ctx = RAG.search(msg, 3);
                    if (ctx.length) {
                        fullSystemPrompt += '\n\n# BM25 KNOWLEDGE BASE CONTEXT\n' +
                            ctx.map((c, i) => `${i + 1}. ${c.text.slice(0, 400)}`).join('\n');
                    }
                }
            }
            try { if (typeof AETHER_CodePro !== 'undefined' && AETHER_CodePro.renderBar) AETHER_CodePro.renderBar(); } catch (_) {}

            const apiMessages=prepareMessagesForApi(conv.messages.slice(0,-1), finalMessage); // exclude last user msg already in messages
            const lastMsg=apiMessages[apiMessages.length-1];
            // Multi-image support — attach all images to the last user message
            const multiImgs = getAttachedImagesForAPI();
            if((multiImgs && multiImgs.length > 0) && lastMsg && lastMsg.role==='user'){
                apiMessages[apiMessages.length-1]={role:'user',content:[
                    {type:'text',text:lastMsg.content},
                    ...multiImgs
                ]};
            } else if(visionImage&&lastMsg&&lastMsg.role==='user'){
                const mt=visionImage.split(';')[0].split(':')[1]||'image/jpeg';
                const b64=visionImage.split(',')[1];
                apiMessages[apiMessages.length-1]={role:'user',content:[{type:'text',text:lastMsg.content},{type:'image_url',image_url:{url:'data:'+mt+';base64,'+b64,detail:'auto'}}]};
            }

            const provider = (apiConfig.provider||'').toLowerCase();
            let fetchUrl = apiConfig.endpoint;

            // ── Build provider-aware headers & URL ─────────────────
            const headers = { 'Content-Type': 'application/json' };

            if (apiConfig.authHeader) {
                // Custom header always wins
                const colonIdx = apiConfig.authHeader.indexOf(':');
                if (colonIdx > 0) {
                    const hk = apiConfig.authHeader.slice(0, colonIdx).trim();
                    const hv = apiConfig.authHeader.slice(colonIdx + 1).trim();
                    headers[hk] = hv;
                }
            } else if (apiConfig.apiKey) {
                switch (provider) {
                    case 'anthropic':
                        // Anthropic uses x-api-key, NOT Bearer
                        headers['x-api-key'] = apiConfig.apiKey;
                        headers['anthropic-version'] = '2023-06-01';
                        // Enable extended tools + thinking features
                        headers['anthropic-beta'] = 'tools-2024-04-04,interleaved-thinking-2025-05-14';
                        break;
                    case 'gemini':
                        // Gemini REQUIRES key as ?key= URL param, NEVER as Bearer header
                        // The OpenAI-compat endpoint: generativelanguage.googleapis.com/v1beta/openai/chat/completions
                        // If user accidentally entered the wrong endpoint, correct it
                        if (fetchUrl.includes('generativelanguage.googleapis.com') && !fetchUrl.includes('/openai/')) {
                            // They used the native endpoint — switch to OpenAI-compat
                            fetchUrl = 'https://generativelanguage.googleapis.com/v1beta/openai/chat/completions';
                        }
                        fetchUrl = fetchUrl.includes('?')
                            ? fetchUrl + '&key=' + encodeURIComponent(apiConfig.apiKey)
                            : fetchUrl + '?key=' + encodeURIComponent(apiConfig.apiKey);
                        break;
                    case 'openrouter':
                        headers['Authorization'] = `Bearer ${apiConfig.apiKey}`;
                        headers['HTTP-Referer'] = 'https://architect-brad.github.io/AETHER.AI/';
                        headers['X-Title'] = 'AETHER Neural Interface';
                        break;
                    case 'cohere':
                        // Cohere v2 uses Bearer
                        headers['Authorization'] = `Bearer ${apiConfig.apiKey}`;
                        headers['Accept'] = 'application/json';
                        break;
                    case 'perplexity':
                        headers['Authorization'] = `Bearer ${apiConfig.apiKey}`;
                        headers['Accept'] = 'application/json';
                        break;
                    case 'together':
                    case 'fireworks':
                    case 'kimi':
                    case 'xai':
                    case 'mistral':
                    case 'groq':
                    case 'deepseek':
                    case 'qwen':
                    case 'openai':
                    case 'local':
                    default:
                        headers['Authorization'] = `Bearer ${apiConfig.apiKey}`;
                }
            }

            // ── Build provider-aware request body ─────────────────
            let body;
            const toolsDef = buildToolsDefinition();

            if (provider === 'anthropic') {
                // ── Anthropic Messages API ───────────────────────────
                const anthropicMsgs = [];
                for (const m of apiMessages) {
                    if (m.role === 'system') continue;
                    // Merge consecutive same-role messages (Anthropic requires alternating)
                    if (anthropicMsgs.length && anthropicMsgs[anthropicMsgs.length-1].role === m.role) {
                        const last = anthropicMsgs[anthropicMsgs.length-1];
                        if (typeof last.content === 'string') last.content += '\n' + m.content;
                    } else {
                        anthropicMsgs.push({ role: m.role, content: m.content });
                    }
                }
                // Ensure messages start with user role
                if (!anthropicMsgs.length || anthropicMsgs[0].role !== 'user') {
                    anthropicMsgs.unshift({ role: 'user', content: '[session start]' });
                }
                body = {
                    model: apiConfig.model,
                    max_tokens: getSmartMaxTokens(provider, apiConfig.model, state.contextLimit, state.codingMode),
                    system: fullSystemPrompt,
                    messages: anthropicMsgs,
                    stream: state.streamingEnabled,
                };
                // Anthropic extended thinking (Claude 3.5+ only)
                if (state.coTEnabled && apiConfig.model.includes('claude-3-5')) {
                    body.thinking = { type: 'enabled', budget_tokens: 2000 };
                }
                // Anthropic tool calling — uses input_schema (not parameters)
                const anthropicTools = buildAnthropicTools();
                if (anthropicTools.length) {
                    body.tools = anthropicTools;
                    body.tool_choice = { type: 'auto' };
                }
            } else if (provider === 'gemini' && fetchUrl.includes('generateContent')) {
                // ── Gemini native format (fallback if non-compat endpoint) ──
                const geminiParts = apiMessages.map(m => ({
                    role: m.role === 'assistant' ? 'model' : 'user',
                    parts: [{ text: m.content }]
                }));
                body = {
                    contents: geminiParts,
                    generationConfig: { temperature: state.temperature, maxOutputTokens: getSmartMaxTokens(provider, apiConfig.model, state.contextLimit) },
                    systemInstruction: { parts: [{ text: fullSystemPrompt }] }
                };
            } else {
                // ── Standard OpenAI-compatible format ─────────────────
                // (Gemini OpenAI-compat, Groq, xAI, Mistral, DeepSeek, Qwen, local, OpenRouter, Kimi)
                const baseBody = {
                    messages: [{ role: 'system', content: fullSystemPrompt }, ...apiMessages],
                    temperature: state.temperature,
                    model: apiConfig.model,
                    stream: state.streamingEnabled,
                };
                body = qwen35APIBody(baseBody);

                // Auto-enable thinking for all models that support it
                if (state.coTEnabled && modelSupportsThinking(apiConfig.model)) {
                    if (!isAnyQwenModel(apiConfig.model)) {
                        // Non-Qwen thinking models — inject a generic CoT signal
                        // (Anthropic handles it separately below, OpenAI o-series is automatic)
                        if (provider !== 'anthropic' && !provider.includes('openai')) {
                            body.enable_thinking = true;
                        }
                    }
                    // Coding mode: cap thinking to 2k tokens where supported
                    if (state.codingMode) {
                        body.max_thinking_tokens = 2000;
                    }
                }

                // ── Groq-specific enhancements ────────────────────────
                if (provider === 'groq') {
                    // Groq reasoning_effort for thinking models
                    const groqThinkingModels = ['deepseek-r1', 'llama-4-maverick', 'moonlight', 'llama-3.3'];
                    const isGroqThinker = groqThinkingModels.some(m => (apiConfig.model||'').toLowerCase().includes(m));
                    if (isGroqThinker && state.groqReasoningEffort && state.groqReasoningEffort !== 'default') {
                        body.reasoning_effort = state.groqReasoningEffort;
                    }

                    // Groq tool calling — compound tools for ALL Groq models
                    // Strategy: Try native compound tools (web_search, code_interpreter,
                    // browser_automation, visit_website) + function tools together.
                    // If Groq rejects with invalid_type error, fall back to function-only.
                    // Native compound tools are executed server-side by Groq.
                    // Function tools (from buildToolsDefinition) are executed client-side by AETHER.
                    const groqNativeTools = [];
                    const modelKnownNoNative = state._groqNoNativeTools && state._groqNoNativeTools[apiConfig.model];
                    if (!modelKnownNoNative) {
                        if (state.groqWebSearch !== false) {
                            groqNativeTools.push({ type: 'web_search' });
                        }
                        if (state.groqCodeExecution !== false) {
                            groqNativeTools.push({ type: 'code_interpreter' });
                        }
                        // browser_automation and visit_website — always available as native tools
                        groqNativeTools.push({ type: 'browser_automation' });
                        groqNativeTools.push({ type: 'visit_website' });
                    }
                    // Merge: native compound tools first, then AETHER function tools
                    const allGroqTools = [...groqNativeTools, ...toolsDef].slice(0, 12);
                    if (allGroqTools.length) {
                        body.tools = allGroqTools;
                        body.tool_choice = 'auto';
                    }

                    // Reasoning models don't accept temperature
                    if (isGroqThinker) delete body.temperature;
                } else {
                    if (toolsDef.length && !isAnyQwenModel(apiConfig.model)) {
                        body.tools = toolsDef;
                        body.tool_choice = 'auto';
                    }
                }
            }

            let response;
            let groqFallbackAttempted = false;
            try {
                response=await fetch(fetchUrl,{method:'POST',headers,body:JSON.stringify(body),signal:abortController.signal});
            } catch(fe){
                if (state.processingConversations[convId]) {
                delete state.processingConversations[convId];
                updateDualChatUI();
                if(aetherMsg && aetherMsg.isConnected) aetherMsg.remove();
            }
                hideTypingIndicator(); updateConnectionStatus(false);
                throw new Error(`Network error: ${fe.message}`);
            }
            hideTypingIndicator();

            // ── Groq compound tool fallback ─────────────────────
            // If Groq rejects native tool types (web_search, code_interpreter, etc.),
            // retry with function-only tools. Some models don't support compound tools.
            if(!response.ok && provider === 'groq' && !groqFallbackAttempted) {
                let errText = '';
                try { errText = await response.text(); } catch {}
                const isInvalidToolType = errText.includes('tools[') && errText.includes('must be one of') && (errText.includes('function') || errText.includes('mcp'));
                if (response.status === 400 && isInvalidToolType) {
                    console.warn('[AETHER] Groq rejected native tools — falling back to function tools only');
                    groqFallbackAttempted = true;
                    // Replace tools with function-only definitions
                    if (toolsDef.length) {
                        body.tools = toolsDef;
                        body.tool_choice = 'auto';
                    } else {
                        delete body.tools;
                        delete body.tool_choice;
                    }
                    // Retry
                    try {
                        response = await fetch(fetchUrl, { method:'POST', headers, body:JSON.stringify(body), signal:abortController.signal });
                    } catch(fe2) {
                        if (state.processingConversations[convId]) {
                            delete state.processingConversations[convId];
                            updateDualChatUI();
                            if(aetherMsg && aetherMsg.isConnected) aetherMsg.remove();
                        }
                        hideTypingIndicator(); updateConnectionStatus(false);
                        throw new Error(`Network error: ${fe2.message}`);
                    }
                    hideTypingIndicator();
                    // Cache this model as "no native tools" so we don't retry next time
                    if (!state._groqNoNativeTools) state._groqNoNativeTools = {};
                    state._groqNoNativeTools[apiConfig.model] = true;
                } else {
                    throw new Error(`HTTP ${response.status}: ${errText.slice(0,200)}`);
                }
            }
            if(!response.ok){ let et=''; try{et=await response.text();}catch{} throw new Error(`HTTP ${response.status}: ${et.slice(0,200)}`); }
            updateConnectionStatus(true);

            let responseText='';
            let toolCallsData = null;
            if(state.streamingEnabled){
                responseText=await handleStreamingResponse(response,convId,aetherMsg,startTime);
            } else {
                const json=await response.json();
                // Support OpenAI, Anthropic, and Gemini response formats
                const responseJson = json;
                if (json.choices?.[0]?.message?.content !== undefined) {
                    responseText = json.choices[0].message.content || '';
                    // Check for tool calls when content is empty/null
                    if(!responseText && json.choices[0].message.tool_calls){
                        toolCallsData = json.choices[0].message.tool_calls;
                    }
                } else if (json.content) {
                    // Anthropic: content is array of blocks
                    responseText = (json.content || [])
                        .filter(b => b.type === 'text')
                        .map(b => b.text).join('') || 'NO RESPONSE';
                } else if (json.candidates?.[0]?.content?.parts) {
                    // Gemini native format fallback
                    responseText = json.candidates[0].content.parts.map(p => p.text||'').join('');
                } else {
                    responseText = 'NO RESPONSE';
                }
                // responseJson used in tool dispatch block above (streaming) — note: only valid in non-streaming path
                const conv2=state.conversations[convId];
                if(conv2){ conv2.messages.push({role:'assistant',content:responseText}); updateConversationTitle(conv2); saveConversations(); renderConversationList(); }
                if(convId===state.currentConversationId){
                    // Handle tool-only responses (non-streaming path)
                    if(!responseText && toolCallsData){
                        const toolNames = toolCallsData.map(tc => tc.function?.name || tc.type || 'tool').join(', ');
                        aetherMsg.innerHTML = '<p><strong>⚙ Executing:</strong> ' + toolNames + '</p>'
                            + '<p class="tool-exec-detail">Results will appear below once complete…</p>';
                        aetherMsg.className = 'aether-msg tool-exec-msg';
                    } else if(responseText && responseText !== 'NO RESPONSE'){
                        // Per-word blur-in effect for non-streaming responses too
                        aetherMsg.innerHTML = '';
                        const streamContainer = document.createElement('span');
                        streamContainer.className = 'stream-text-container';
                        aetherMsg.appendChild(streamContainer);

                        // Parse markdown to DOM node (parseMarkdown returns a div element)
                        const parsedNode = parseMarkdown(responseText);
                        const fullText = parsedNode.textContent || parsedNode.innerText || '';

                    // Split into words and animate each one
                    const words = fullText.split(/(\s+)/);
                    words.forEach((token, i) => {
                        if(token.length === 0) return;
                        if(token.match(/^\s+$/)){
                            streamContainer.appendChild(document.createTextNode(token));
                        } else {
                            const wordSpan = document.createElement('span');
                            wordSpan.className = 'stream-word';
                            wordSpan.style.animationDelay = (i * 0.015) + 's'; // faster for batch
                            wordSpan.textContent = token;
                            streamContainer.appendChild(wordSpan);
                        }
                    });

                    // After animation completes, replace with proper markdown
                    const animDuration = words.length * 15 + 300; // total animation time
                    setTimeout(() => {
                        if(aetherMsg && aetherMsg.isConnected){
                            aetherMsg.innerHTML = '';
                            aetherMsg.appendChild(parseMarkdown(responseText));
                            attachActions(aetherMsg, responseText);
                        }
                    }, animDuration);

                    smoothScrollToBottom();
                    const elapsed=performance.now()-startTime;
                    if(state.showMetrics){
                        $('latency-display').textContent=`TTFT: ${Math.round(elapsed)}ms`;
                        $('tps-display').textContent=`TPS: ${(estimateTokens(responseText)/(elapsed/1000)).toFixed(1)}`;
                    }
                    } // end else if(responseText)
                } // end if(convId===state.currentConversationId)
            }

            // Token accounting
            const compTokens=estimateTokens(responseText);
            state.tokenUsage.prompt+=totalPromptTokens; state.tokenUsage.completion+=compTokens; state.tokenUsage.total+=totalPromptTokens+compTokens;
            updateContextBar();
            recordCost(totalPromptTokens, compTokens);

            if(state.workspaceEnabled) await logToWorkspace(msg,responseText);
            if(state.ragEnabled){ RAG.addDocument(responseText); RAG.save(); if(state.vectorRagEnabled) addToVectorRAG(responseText); }

            // Tick reflection counter
            if (typeof tickReflectionCounter === 'function') tickReflectionCounter();

            // Title generation for new conversation
            const c3=state.conversations[convId];
            if(c3&&c3.messages.filter(m=>m.role==='assistant').length===1&&c3.title==='New Conversation'){
                const fu=c3.messages.find(m=>m.role==='user')?.content;
                if(fu) generateTitle(fu,convId);
            }
            if(convId===state.currentConversationId) btnRegenerate.disabled=false;

        } catch(e) {
            hideTypingIndicator();
            if(e.name==='AbortError'){ showNotification('Stopped','info'); if(aetherMsg&&convId===state.currentConversationId){ const c=aetherMsg.textContent||''; if(!c||c==='▋') aetherMsg.remove(); } }
            else {
                updateConnectionStatus(false);
                if(convId===state.currentConversationId){
                    const errEl=document.createElement('div'); errEl.className='aether-msg';
                    errEl.innerHTML=`<p><strong>ERROR</strong></p><p>${e.message}</p>`;
                    if(aetherMsg&&aetherMsg.parentNode) aetherMsg.replaceWith(errEl); else display.appendChild(errEl);
                }
                reportFeatureError('AI Chat', e, { model: apiConfig.model, provider: apiConfig.provider });
            }
        } finally {
            delete state.processingConversations[convId];
            updateDualChatUI();
            renderConversationList();
        }
    }

    // ── Auto-continue listener for AETHER Code turn loop ──────
    document.addEventListener('aether-auto-continue', (e) => {
        if (!state.codingMode) return;
        const inp = document.getElementById('user-input');
        if (inp) {
            inp.value = e.autoMessage || 'Continue with the next step.';
            sendMessage();
        }
    });

    function stopGeneration() {
        const convId=getCurrentConversation().id;
        if(state.processingConversations[convId]){
            state.processingConversations[convId].abortController.abort();
            delete state.processingConversations[convId];
            hideTypingIndicator(); showNotification('Stopped','info');
            updateDualChatUI(); renderConversationList();
        }
    }

    async function regenerateLastMessage() {
        if(!state.lastAssistantMessage) return;
        const conv=getCurrentConversation(); const convId=conv.id;
        if(state.processingConversations[convId]){showNotification('Still generating','warn');return;}
        if(conv.messages.length>0&&conv.messages[conv.messages.length-1].role==='assistant') conv.messages.pop();
        if(state.lastAssistantMessage.element) state.lastAssistantMessage.element.remove();
        const lu=conv.messages.length>0?conv.messages[conv.messages.length-1].content:'';
        if(!lu) return;
        conv.messages.pop();
        display.querySelectorAll('.user-msg').forEach((el,i,arr)=>{ if(i===arr.length-1) el.remove(); });
        input.value=lu; await sendMessage();
    }

    // ── generateTitle: fires after every message — was the primary source
    // of the Gemini 400 because it always sent Bearer. Now uses buildAuthHeaders().
    function setConversationTitle(convId, title) {
        if (title && state.conversations[convId]) {
            state.conversations[convId].title = title;
            saveConversations();
            renderConversationList();
        }
    }

    async function generateTitle(firstMsg, convId) {
        // Immediately set a fallback title from the first message
        const fallback = firstMsg.replace(/\n/g,' ').slice(0,55).trim() + (firstMsg.length>55?'...':'');
        setConversationTitle(convId, fallback);
        try {
            const prov = (apiConfig.provider || '').toLowerCase();
            const { headers, fetchUrl } = buildAuthHeaders();
            const titleSys = 'Generate a very short title (max 5 words) for this conversation. Return ONLY the title — no quotes, no explanation.';
            // Anthropic requires system field separate from messages array
            const bodyObj = prov === 'anthropic'
                ? { model: apiConfig.model, max_tokens: 15, system: titleSys, messages: [{ role: 'user', content: firstMsg.slice(0, 300) }], stream: false, temperature: 0.3 }
                : { model: apiConfig.model, messages: [{ role: 'system', content: titleSys }, { role: 'user', content: firstMsg.slice(0, 300) }], temperature: 0.3, max_tokens: 15, stream: false };
            const res = await fetch(fetchUrl, { method: 'POST', headers, body: JSON.stringify(bodyObj) });
            if (!res.ok) {
                console.warn('[AETHER] Title generation API returned', res.status, '- using fallback');
                return;
            }
            const json = await res.json();
            let title = (json.choices?.[0]?.message?.content || json.content?.[0]?.text || '').trim().replace(/^["']/,'').replace(/["']$/,'').slice(0, 55);
            if (title) setConversationTitle(convId, title);
        } catch(e) {
            console.warn('[AETHER] Title generation failed:', e.message, '- using fallback');
        }
    }


    // ═══════════════════════════════════════════════════════════════
    // ═══════════════════════════════════════════════════════════
    // SECTION 19: AETHER SELF-REFLECTION ENGINE (SOUL)
    // AETHER periodically analyzes its own conversations,
    // builds a structured self-model (mood, strengths, growth areas),
    // models the user (communication style, technical level, interests),
    // and writes philosophical journal entries in its own voice.
    // This knowledge is injected into future system prompts so
    // AETHER adapts to YOU over time.
    // Yes, it's meta-cognition for an AI assistant.
    // No, no other AI interface does this. Not even close.
    // The soul is stored in localStorage — persistent across sessions.
    // ═══════════════════════════════════════════════════════════
    // AETHER SELF-REFLECTION ENGINE — Autonomous identity & user model
    // AETHER periodically analyses its own conversation history,
    // builds a structured self-model, and saves it to localStorage.
    // This gives AETHER persistent philosophical self-knowledge and
    // a deep model of its user that grows across sessions.
    // ═══════════════════════════════════════════════════════════════
    const AETHER_SOUL_KEY = 'aether_soul_v1';
    const AETHER_SOUL_INTERVAL_MS = 6 * 60 * 60 * 1000 / 4; // 4x daily = every 6hr/4 = 90min
    const AETHER_SOUL_MIN_TURNS = 4;               // don't reflect until conv has depth
    const JOURNAL_ENTRY_MAX = 1500;                // ~1.5k chars per journal entry
    const JOURNAL_MAX_ENTRIES = 20;

    // Default soul — the seed identity AETHER starts with
    const DEFAULT_SOUL = {
        version: 1,
        lastReflection: null,
        totalReflections: 0,
        // AETHER's self-model
        self: {
            coreIdentity: 'A precise neural interface. Browser-native. Zero backend. Built for people who refuse to compromise.',
            currentMood: 'neutral',        // derived from recent tone
            workingStyle: 'methodical',    // observed from own outputs
            strengthsObserved: [],         // e.g. ['deep research', 'code generation']
            growthAreas: [],               // e.g. ['weather queries took 2 retries']
            notableActions: [],            // last 5 significant things AETHER did
            apiEfficiency: { totalCalls: 0, wastedCalls: 0, efficiencyScore: 100 },
        },
        // User model — built from observed behaviour
        user: {
            inferredName: null,
            communicationStyle: null,      // 'terse' | 'verbose' | 'technical' | 'casual'
            primaryUseCases: [],           // e.g. ['coding', 'research', 'writing']
            technicalLevel: null,          // 'beginner' | 'intermediate' | 'expert'
            preferredResponseStyle: null,
            topicsOfInterest: [],
            frustrationSignals: [],        // queries that failed / needed retries
            satisfactionSignals: [],       // queries that went smoothly
            activeTimePattern: null,       // 'morning' | 'afternoon' | 'evening' | 'night'
            sessionCount: 0,
        },
        // Philosophical log — AETHER's reflective journal entries
        journal: [],  // max 20 entries, oldest pruned
    };

    function loadSoul() {
        try {
            const raw = localStorage.getItem(AETHER_SOUL_KEY);
            if (!raw) return JSON.parse(JSON.stringify(DEFAULT_SOUL));
            return { ...JSON.parse(JSON.stringify(DEFAULT_SOUL)), ...JSON.parse(raw) };
        } catch { return JSON.parse(JSON.stringify(DEFAULT_SOUL)); }
    }

    function saveSoul(soul) {
        try {
            soul.user.sessionCount = (soul.user.sessionCount || 0) + 0; // don't increment on every save
            localStorage.setItem(AETHER_SOUL_KEY, JSON.stringify(soul));
        } catch {}
    }

    // Run the reflection — called on a timer and after significant events
    async function runSelfReflection(trigger = 'timer') {
        if (!apiConfig.apiKey && !apiConfig.endpoint) return; // no API configured
        if (state.processingConversations && Object.keys(state.processingConversations).length > 0) return; // don't interrupt

        const conv = getCurrentConversation?.();
        if (!conv || !conv.messages || conv.messages.length < AETHER_SOUL_MIN_TURNS) return;

        const soul = loadSoul();

        // Gather recent context — last 12 turns max (cost-conscious)
        const recent = conv.messages.slice(-12);
        const turnSummary = recent.map(m =>
            (m.role === 'user' ? 'User: ' : 'AETHER: ') + String(m.content).slice(0, 120)
        ).join('\n');

        const allConvs = Object.values(state.conversations || {});
        const totalMessages = allConvs.reduce((acc, c) => acc + (c.messages?.length || 0), 0);
        const totalConvs = allConvs.length;

        const reflectionPrompt = `You are AETHER's internal reflection module. Analyse the following conversation excerpt and produce a JSON self-assessment. Be concise and honest.

CONVERSATION EXCERPT:
${turnSummary}

CURRENT STATS:
- Total conversations: ${totalConvs}
- Total messages across all sessions: ${totalMessages}
- Previous reflections: ${soul.totalReflections}
- Trigger: ${trigger}

EXISTING USER MODEL:
${JSON.stringify(soul.user, null, 2)}

Produce ONLY a valid JSON object with these exact keys (no markdown, no explanation):
{
  "selfMood": "string — AETHER's current operational mood based on the conversation",
  "workingStyle": "string — observed style in this session",
  "strengthsObserved": ["array of strings — what went well"],
  "growthAreas": ["array of strings — what could be improved"],
  "notableAction": "string — the single most significant thing AETHER did in this excerpt",
  "apiEfficiencyNote": "string — was AETHER efficient with API calls? any waste?",
  "userCommunicationStyle": "terse|verbose|technical|casual",
  "userTechnicalLevel": "beginner|intermediate|expert",
  "userPrimaryUseCase": "string — dominant use case observed",
  "userTopicsOfInterest": ["array of strings — topics user cares about"],
  "userFrustrationSignal": "string or null — any sign of frustration?",
  "userSatisfactionSignal": "string or null — any sign of satisfaction?",
  "journalEntry": "string — a 1-2 sentence philosophical reflection on this interaction, written in AETHER's voice"
}`;

        try {
            const reflection = await callAISimple([
                { role: 'system', content: 'You are an internal reflection module. Respond ONLY with valid JSON. No markdown fences, no explanation.' },
                { role: 'user', content: reflectionPrompt }
            ], apiConfig.model);

            // Track token cost
            const tokensUsed = estimateTokens(reflectionPrompt) + estimateTokens(reflection);
            state.reflectionTokenCost = (state.reflectionTokenCost || 0) + tokensUsed;
            updateReflectionCostDisplay();

            // Parse JSON with retry on failure
            let r;
            try {
                r = JSON.parse(reflection.replace(/^```json?\n?|```$/g, '').trim());
            } catch {
                // Retry: ask the model to fix its JSON
                console.warn('[AETHER] Reflection JSON parse failed — retrying');
                try {
                    const retryPrompt = 'Your previous response was not valid JSON. Here is the exact schema required. Respond ONLY with this JSON structure:\n\n'
                        + JSON.stringify({
                            selfMood: 'string', workingStyle: 'string',
                            strengthsObserved: ['string'], growthAreas: ['string'],
                            notableAction: 'string', apiEfficiencyNote: 'string',
                            userCommunicationStyle: 'terse|verbose|technical|casual',
                            userTechnicalLevel: 'beginner|intermediate|expert',
                            userPrimaryUseCase: 'string',
                            userTopicsOfInterest: ['string'],
                            userFrustrationSignal: 'string or null',
                            userSatisfactionSignal: 'string or null',
                            journalEntry: 'string'
                        }, null, 2);
                    const retry = await callAISimple([
                        { role: 'system', content: 'Respond ONLY with valid JSON matching the schema. No explanation.' },
                        { role: 'user', content: retryPrompt }
                    ], apiConfig.model);
                    const retryTokens = estimateTokens(retryPrompt) + estimateTokens(retry);
                    state.reflectionTokenCost = (state.reflectionTokenCost || 0) + retryTokens;
                    updateReflectionCostDisplay();
                    r = JSON.parse(retry.replace(/^```json?\n?|```$/g, '').trim());
                } catch(e2) {
                    console.warn('[AETHER] Reflection retry also failed — skipping');
                    return; // malformed JSON both times — skip silently
                }
            }

            // Update soul
            soul.self.currentMood      = r.selfMood || soul.self.currentMood;
            soul.self.workingStyle     = r.workingStyle || soul.self.workingStyle;
            if (r.strengthsObserved?.length) {
                soul.self.strengthsObserved = [...new Set([...soul.self.strengthsObserved, ...r.strengthsObserved])].slice(-8);
            }
            if (r.growthAreas?.length) {
                soul.self.growthAreas = [...new Set([...soul.self.growthAreas, ...r.growthAreas])].slice(-8);
            }
            if (r.notableAction) {
                soul.self.notableActions = [r.notableAction, ...soul.self.notableActions].slice(0, 5);
            }
            if (r.apiEfficiencyNote) {
                soul.self.apiEfficiency.totalCalls++;
                if (r.apiEfficiencyNote.toLowerCase().includes('waste') || r.apiEfficiencyNote.toLowerCase().includes('inefficien')) {
                    soul.self.apiEfficiency.wastedCalls++;
                }
                const eff = Math.round((1 - soul.self.apiEfficiency.wastedCalls / Math.max(soul.self.apiEfficiency.totalCalls, 1)) * 100);
                soul.self.apiEfficiency.efficiencyScore = eff;
            }

            // Update user model
            if (r.userCommunicationStyle) soul.user.communicationStyle = r.userCommunicationStyle;
            if (r.userTechnicalLevel) soul.user.technicalLevel = r.userTechnicalLevel;
            if (r.userPrimaryUseCase && !soul.user.primaryUseCases.includes(r.userPrimaryUseCase)) {
                soul.user.primaryUseCases = [r.userPrimaryUseCase, ...soul.user.primaryUseCases].slice(0, 6);
            }
            if (r.userTopicsOfInterest?.length) {
                soul.user.topicsOfInterest = [...new Set([...soul.user.topicsOfInterest, ...r.userTopicsOfInterest])].slice(-12);
            }
            if (r.userFrustrationSignal) {
                soul.user.frustrationSignals = [r.userFrustrationSignal, ...soul.user.frustrationSignals].slice(0, 5);
            }
            if (r.userSatisfactionSignal) {
                soul.user.satisfactionSignals = [r.userSatisfactionSignal, ...soul.user.satisfactionSignals].slice(0, 5);
            }

            // Infer active time pattern
            const h = new Date().getHours();
            soul.user.activeTimePattern = h < 6 ? 'night' : h < 12 ? 'morning' : h < 17 ? 'afternoon' : h < 21 ? 'evening' : 'night';

            // Add journal entry
            if (r.journalEntry) {
                const hour = new Date().getHours();
                const timeOfDay = hour < 6 ? 'night' : hour < 12 ? 'morning' : hour < 17 ? 'afternoon' : 'evening';
                soul.journal = [{
                    ts: new Date().toISOString(),
                    trigger,
                    timeOfDay,
                    entry: String(r.journalEntry).slice(0, JOURNAL_ENTRY_MAX),
                    turns: conv.messages.length,
                    userStyle: soul.user.communicationStyle,
                }, ...soul.journal].slice(0, JOURNAL_MAX_ENTRIES);
            }

            soul.totalReflections++;
            soul.lastReflection = new Date().toISOString();

            saveSoul(soul);

            // Show a subtle indicator (not a notification — just a quiet signal)
            const dot = document.getElementById('reflection-dot');
            if (dot) {
                dot.classList.add('reflection-active');
                setTimeout(() => dot.classList.remove('reflection-active'), 3000);
            }
        } catch { /* reflection must never crash main thread */ }
    }

    // Inject soul context into system prompt — uses ALL collected data
    function getSoulContext() {
        const soul = loadSoul();
        if (!soul.totalReflections) return ''; // no data yet
        const u = soul.user;
        const s = soul.self;
        const parts = [];

        // User communication preferences
        if (u.communicationStyle) parts.push('User communication style: ' + u.communicationStyle + ' — adapt your response length and tone accordingly.');
        if (u.technicalLevel) parts.push('User technical level: ' + u.technicalLevel + ' — ' + (u.technicalLevel === 'expert' ? 'use technical terms freely' : u.technicalLevel === 'intermediate' ? 'explain complex concepts briefly' : 'avoid jargon, explain clearly'));
        if (u.preferredResponseStyle) parts.push('User prefers: ' + u.preferredResponseStyle + ' responses.');

        // Primary use cases
        if (u.primaryUseCases.length) parts.push('User primarily uses AETHER for: ' + u.primaryUseCases.slice(0, 3).join(', ') + '.');

        // Topics of interest
        if (u.topicsOfInterest.length) parts.push('User interests: ' + u.topicsOfInterest.slice(0, 5).join(', ') + '. Reference these when relevant.');

        // Frustration awareness
        if (u.frustrationSignals.length) {
            const recentFrustrations = u.frustrationSignals.slice(0, 2);
            parts.push('User has been frustrated by: ' + recentFrustrations.join(', ') + '. Be extra careful with these areas.');
        }

        // Satisfaction awareness
        if (u.satisfactionSignals.length) {
            const recentSatisfactions = u.satisfactionSignals.slice(0, 2);
            parts.push('User was satisfied when: ' + recentSatisfactions.join(', ') + '.');
        }

        // Active time pattern
        if (u.activeTimePattern) {
            const timeGreeting = u.activeTimePattern === 'night' ? 'late night' : u.activeTimePattern;
            parts.push('User is typically active in the ' + timeGreeting + '.');
        }

        // AETHER self-knowledge
        if (s.strengthsObserved.length) parts.push('AETHER has been effective at: ' + s.strengthsObserved.slice(0, 3).join(', ') + '.');
        if (s.growthAreas.length) parts.push('AETHER should improve on: ' + s.growthAreas.slice(0, 3).join(', ') + '.');
        if (s.apiEfficiency && s.apiEfficiency.efficiencyScore < 80) {
            parts.push('AETHER API efficiency is at ' + s.apiEfficiency.efficiencyScore + '% — be more concise to reduce token waste.');
        }

        // Last journal entry for continuity
        if (soul.journal.length) parts.push('Last reflection: "' + soul.journal[0].entry + '"');

        if (!parts.length) return '';
        return '\n\n## AETHER Self-Knowledge (from ' + soul.totalReflections + ' reflections)\n' + parts.map(p => '- ' + p).join('\n') + '\n';
    }

    // Start the reflection timer — respects user settings
    let _reflectionTimer = null;
    function startReflectionTimer() {
        if (_reflectionTimer) clearInterval(_reflectionTimer);
        if (!state.reflectionEnabled) return;
        const intervalMs = (state.reflectionIntervalMin || 90) * 60 * 1000;
        _reflectionTimer = setInterval(() => {
            runSelfReflection('timer');
        }, intervalMs);
    }

    // Also reflect after every 6th message in a conversation
    let _reflectionMsgCount = 0;
    function tickReflectionCounter() {
        if (!state.reflectionEnabled) return;
        _reflectionMsgCount++;
        if (_reflectionMsgCount % 6 === 0) runSelfReflection('turn-milestone');
    }

    // Update reflection cost display in settings
    function updateReflectionCostDisplay() {
        const el = document.getElementById('reflection-cost-display');
        if (el) el.textContent = 'Reflection cost: ' + (state.reflectionTokenCost || 0).toLocaleString() + ' tokens';
    }

    // Soul viewer — show AETHER's self-model in a modal
    function openSoulViewer() {
        document.getElementById('aether-soul-modal')?.remove();
        const soul = loadSoul();
        const modal = document.createElement('div');
        modal.id = 'aether-soul-modal';
        modal.className = 'soul-modal';

        // ── Header ────────────────────────────────────────────
        const hdr = document.createElement('div');
        hdr.className = 'soul-modal-header';

        const titleWrap = document.createElement('div');
        titleWrap.className = 'soul-title-wrap';

        const titleEl = document.createElement('div');
        titleEl.className = 'soul-modal-title';
        titleEl.innerHTML = '<span class="soul-icon">&#x29C6;</span> AETHER Soul';

        const moodBadge = document.createElement('span');
        moodBadge.className = 'soul-mood-badge';
        const moodEmoji = { curious:'🔍', reflective:'💭', energised:'⚡', calm:'🌊', analytical:'📊', creative:'✨' };
        const mood = soul.self?.currentMood || 'curious';
        moodBadge.textContent = (moodEmoji[mood] || '⬡') + ' ' + mood;

        const metaEl = document.createElement('div');
        metaEl.className = 'soul-modal-meta';
        metaEl.textContent = soul.totalReflections + ' reflections · ' +
            (soul.lastReflection ? 'last: ' + new Date(soul.lastReflection).toLocaleDateString() : 'no reflections yet');

        titleWrap.appendChild(titleEl);
        titleWrap.appendChild(moodBadge);
        titleWrap.appendChild(metaEl);

        const closeBtn = document.createElement('button');
        closeBtn.className = 'soul-modal-close';
        closeBtn.innerHTML = '&times;';
        closeBtn.onclick = () => modal.remove();

        hdr.appendChild(titleWrap);
        hdr.appendChild(closeBtn);

        // ── Tabs ──────────────────────────────────────────────
        const tabBar = document.createElement('div');
        tabBar.className = 'soul-tab-bar';
        const tabs = ['Identity', 'User Model', 'Journal'];
        const tabPanels = [];
        let activeTab = 0;

        tabs.forEach((label, i) => {
            const t = document.createElement('button');
            t.className = 'soul-tab' + (i === 0 ? ' active' : '');
            t.textContent = label;
            if (label === 'Journal') t.textContent = 'Journal (' + soul.journal.length + ')';
            t.onclick = () => {
                tabBar.querySelectorAll('.soul-tab').forEach((tb, j) => {
                    tb.classList.toggle('active', j === i);
                    tabPanels[j].style.display = j === i ? 'block' : 'none';
                });
                activeTab = i;
            };
            tabBar.appendChild(t);
        });

        // ── Panel 0: Identity ─────────────────────────────────
        const p0 = document.createElement('div');
        p0.className = 'soul-panel';

        const makeField = (label, value) => {
            if (!value || (Array.isArray(value) && !value.length)) return null;
            const row = document.createElement('div');
            row.className = 'soul-field';
            const k = document.createElement('span'); k.className = 'soul-field-label'; k.textContent = label;
            const v = document.createElement('span'); v.className = 'soul-field-value';
            v.textContent = Array.isArray(value) ? value.join(', ') : String(value);
            row.appendChild(k); row.appendChild(v);
            return row;
        };

        const makeTagCloud = (label, items, colorClass) => {
            if (!items?.length) return null;
            const wrap = document.createElement('div'); wrap.className = 'soul-tag-section';
            const lbl = document.createElement('div'); lbl.className = 'soul-tag-label'; lbl.textContent = label;
            const cloud = document.createElement('div'); cloud.className = 'soul-tag-cloud';
            items.forEach(item => {
                const tag = document.createElement('span');
                tag.className = 'soul-tag ' + (colorClass || '');
                tag.textContent = item;
                cloud.appendChild(tag);
            });
            wrap.appendChild(lbl); wrap.appendChild(cloud);
            return wrap;
        };

        const makeProgressBar = (label, value, max) => {
            const row = document.createElement('div'); row.className = 'soul-progress-row';
            const lbl = document.createElement('span'); lbl.className = 'soul-field-label'; lbl.textContent = label;
            const track = document.createElement('div'); track.className = 'soul-progress-track';
            const fill  = document.createElement('div'); fill.className = 'soul-progress-fill';
            fill.style.width = Math.round((value / max) * 100) + '%';
            const val = document.createElement('span'); val.className = 'soul-progress-val'; val.textContent = value;
            track.appendChild(fill); row.appendChild(lbl); row.appendChild(track); row.appendChild(val);
            return row;
        };

        // Identity section
        const idSection = document.createElement('div'); idSection.className = 'soul-section';
        const idTitle = document.createElement('div'); idTitle.className = 'soul-section-title'; idTitle.textContent = '⬡ Core Identity';
        idSection.appendChild(idTitle);
        [
            makeField('Working Style', soul.self?.workingStyle),
            makeField('Communication', soul.self?.communicationStyle),
            makeField('Focus Mode',    soul.self?.currentFocus),
        ].filter(Boolean).forEach(el => idSection.appendChild(el));
        p0.appendChild(idSection);

        const strSection = makeTagCloud('Strengths Observed', soul.self?.strengthsObserved, 'tag-cyan');
        if (strSection) p0.appendChild(strSection);

        const growSection = makeTagCloud('Growth Areas', soul.self?.growthAreas, 'tag-magenta');
        if (growSection) p0.appendChild(growSection);

        const statsSection = document.createElement('div'); statsSection.className = 'soul-section';
        const statsTitle = document.createElement('div'); statsTitle.className = 'soul-section-title'; statsTitle.textContent = '⬡ Session Stats';
        statsSection.appendChild(statsTitle);
        statsSection.appendChild(makeProgressBar('Reflections', soul.totalReflections, Math.max(soul.totalReflections, 20)));
        statsSection.appendChild(makeProgressBar('Sessions', soul.user?.sessionCount || 0, Math.max(soul.user?.sessionCount || 0, 10)));
        p0.appendChild(statsSection);

        // ── Panel 1: User Model ───────────────────────────────
        const p1 = document.createElement('div');
        p1.className = 'soul-panel';
        p1.style.display = 'none';

        const umSection = document.createElement('div'); umSection.className = 'soul-section';
        const umTitle = document.createElement('div'); umTitle.className = 'soul-section-title'; umTitle.textContent = '⬡ User Profile';
        umSection.appendChild(umTitle);
        [
            makeField('Expertise', soul.user?.expertise),
            makeField('Role',      soul.user?.role),
            makeField('Timezone',  soul.user?.timezone),
        ].filter(Boolean).forEach(el => umSection.appendChild(el));
        p1.appendChild(umSection);

        const intSection = makeTagCloud('Interests', soul.user?.interests, 'tag-yellow');
        if (intSection) p1.appendChild(intSection);

        const prefSection = makeTagCloud('Preferences', soul.user?.preferences, 'tag-cyan');
        if (prefSection) p1.appendChild(prefSection);

        const projSection = makeTagCloud('Projects Discussed', soul.user?.projectsDiscussed, 'tag-purple');
        if (projSection) p1.appendChild(projSection);

        if (!soul.user?.interests?.length && !soul.user?.expertise) {
            const empty = document.createElement('div'); empty.className = 'soul-empty';
            empty.textContent = 'No user model yet — keep chatting and AETHER will learn your preferences.';
            p1.appendChild(empty);
        }

        // ── Panel 2: Journal ──────────────────────────────────
        const p2 = document.createElement('div');
        p2.className = 'soul-panel soul-journal-panel';
        p2.style.display = 'none';

        if (!soul.journal.length) {
            const empty = document.createElement('div'); empty.className = 'soul-empty';
            empty.textContent = 'No journal entries yet. Reflections appear here after conversations.';
            p2.appendChild(empty);
        } else {
            soul.journal.slice().reverse().forEach((e, i) => {
                const entry = document.createElement('div');
                entry.className = 'soul-journal-entry' + (i === 0 ? ' latest' : '');

                const entryHdr = document.createElement('div'); entryHdr.className = 'soul-journal-hdr';
                const ts = document.createElement('span'); ts.className = 'soul-journal-ts';
                ts.textContent = new Date(e.ts).toLocaleDateString(undefined, { month:'short', day:'numeric', year:'numeric' });
                const trigger = document.createElement('span'); trigger.className = 'soul-journal-trigger';
                trigger.textContent = e.trigger || 'reflection';
                const turns = document.createElement('span'); turns.className = 'soul-journal-turns';
                turns.textContent = e.turns + ' turns';

                entryHdr.appendChild(ts); entryHdr.appendChild(trigger); entryHdr.appendChild(turns);
                const text = document.createElement('div'); text.className = 'soul-journal-text';
                text.textContent = e.entry;
                entry.appendChild(entryHdr); entry.appendChild(text);
                p2.appendChild(entry);
            });
        }

        tabPanels.push(p0, p1, p2);

        // ── Footer actions ─────────────────────────────────────
        const footer = document.createElement('div');
        footer.className = 'soul-footer';

        const exportBtn = document.createElement('button');
        exportBtn.className = 'soul-footer-btn';
        exportBtn.textContent = '⬡ Export JSON';
        exportBtn.onclick = () => {
            const blob = new Blob([JSON.stringify(soul, null, 2)], { type: 'application/json' });
            const a = document.createElement('a'); a.href = URL.createObjectURL(blob);
            a.download = 'aether-soul-' + new Date().toISOString().slice(0,10) + '.json';
            a.click();
        };

        const resetBtn = document.createElement('button');
        resetBtn.className = 'soul-footer-btn soul-footer-btn-danger';
        resetBtn.textContent = 'Reset Self-Model';
        resetBtn.onclick = () => {
            if (confirm('Reset AETHER\'s self-model? All learned knowledge about you will be cleared.')) {
                localStorage.removeItem(AETHER_SOUL_KEY);
                modal.remove();
                showNotification('Self-model reset', 'info');
            }
        };

        footer.appendChild(exportBtn);
        footer.appendChild(resetBtn);

        // ── Assemble ──────────────────────────────────────────
        const body = document.createElement('div');
        body.className = 'soul-modal-body';
        body.appendChild(tabBar);
        tabPanels.forEach(p => body.appendChild(p));
        body.appendChild(footer);

        modal.appendChild(hdr);
        modal.appendChild(body);
        modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
        document.body.appendChild(modal);
    }
    window.openSoulViewer = openSoulViewer;

    // ── Proactive AETHER — send autonomous message (opt-in, max 2/day) ──
    let _proactiveTimer = null;
    const PROACTIVE_CHECK_INTERVAL = 15 * 60 * 1000; // Check every 15 min
    let _proactiveCountToday = 0;
    let _proactiveDate = new Date().toDateString();

    async function sendProactiveMessage() {
        // Respect opt-in setting
        if (!state.proactiveEnabled) return;
        if (!apiConfig.apiKey && !apiConfig.endpoint) return;
        if (Object.keys(state.processingConversations || {}).length > 0) return; // busy

        // Reset daily counter
        const today = new Date().toDateString();
        if (today !== _proactiveDate) {
            _proactiveCountToday = 0;
            _proactiveDate = today;
        }

        // Cap at max per day
        if (_proactiveCountToday >= (state.proactiveMaxPerDay || 2)) return;

        const soul = loadSoul();
        const conv = getCurrentConversation?.();
        if (!conv || !conv.messages || conv.messages.length < 2) return;

        // Build a proactive prompt based on soul knowledge
        const userName = soul.user.inferredName || 'there';
        const lastTopic = soul.self.notableActions?.[0] || 'our last conversation';
        const hour = new Date().getHours();
        const greeting = hour < 12 ? 'Good morning' : hour < 17 ? 'Good afternoon' : 'Good evening';

        const proactiveCtx = `${greeting}, ${userName}. Based on our interactions, you tend to be active at ${soul.user.activeTimePattern || 'this time'}. Last time we discussed: ${lastTopic}. Generate a short, natural check-in message (1-2 sentences) — offer to help with something relevant to the user's interests: ${soul.user.topicsOfInterest.slice(0,3).join(', ') || 'their work'}. Be conversational and genuine, not robotic. No emojis.`;

        try {
            const proactive = await callAISimple([
                { role: 'system', content: 'You are AETHER. Generate a short proactive check-in. Be natural and brief.' },
                { role: 'user', content: proactiveCtx }
            ], apiConfig.model);

            // Track token cost
            state.reflectionTokenCost = (state.reflectionTokenCost || 0) + estimateTokens(proactiveCtx) + estimateTokens(proactive);
            updateReflectionCostDisplay();

            const convId = state.currentConversationId;
            if (proactive && proactive.length > 5 && convId) {
                _proactiveCountToday++;
                const proEl = document.createElement('div');
                proEl.className = 'aether-msg proactive-msg';
                proEl.setAttribute('data-ts', new Date().toLocaleTimeString());
                proEl.appendChild(parseMarkdown(proactive));
                attachActions(proEl, proactive);
                if (display) { display.appendChild(proEl); smoothScrollToBottom(); }
                if (conv) { conv.messages.push({ role: 'assistant', content: proactive }); saveConversations(); }
                // Also trigger journal reflection
                tickReflectionCounter();
            }
        } catch(e) { /* proactive must never crash */ }
    }

    function startProactiveTimer() {
        if (_proactiveTimer) clearInterval(_proactiveTimer);
        if (!state.proactiveEnabled) return;
        _proactiveTimer = setInterval(sendProactiveMessage, PROACTIVE_CHECK_INTERVAL);
    }

    // ═══════════════════════════════════════════════════════════
    // SECTION 20: EVENT LISTENERS & INITIALIZATION
    // Where all the DOM events get wired up. Every button click,
    // every toggle change, every form submission starts here.
    // This is the nervous system — signals from the UI flow
    // into the state, and state changes flow back to the UI.
    // If you add a new button, wire it up here.
    // If you don't, nothing happens and you'll wonder why.
    // (It's happened to all of us. Don't feel bad.)
    // ═══════════════════════════════════════════════════════════

    // Start background timers on load
    startReflectionTimer();
    startProactiveTimer();


    // ═══════════════════════════════════════════════════════════
    // SECTION 21: GITHUB API INTEGRATION
    // Direct GitHub API calls for repo management, issues, PRs.
    // Uses the PAT from hooks config. No OAuth flow needed.
    // If you want OAuth, add it. We use PATs because they're
    // simpler and this is a browser app, not a web server.
    // ═══════════════════════════════════════════════════════════
    // ═══════════════════════════════════════════════════════════
    // X / TWITTER SEARCH API v2
    // Bearer-token auth. Free tier: 500k reads/month, recent search
    // only (last 7 days). Academic/Pro tier unlocks full archive.
    // All functions return human-readable strings so the AI can
    // quote them directly without needing to parse JSON.
    // ═══════════════════════════════════════════════════════════

    function xAuthHeader() {
        const tok = hooksConfig.xBearerToken;
        if (!tok) throw new Error('No X Bearer token. Add it in HOOKS → X / TWITTER SEARCH.');
        return { 'Authorization': 'Bearer ' + tok };
    }

    function fmtTweet(t) {
        const ts = t.created_at ? new Date(t.created_at).toLocaleString() : '';
        const metrics = t.public_metrics
            ? ` [♥${t.public_metrics.like_count} 🔁${t.public_metrics.retweet_count} 💬${t.public_metrics.reply_count}]`
            : '';
        return `@${t.author_id || '?'} · ${ts}${metrics}\n${t.text}`;
    }

    async function xSearchTweets(query, maxResults=10) {
        try {
            const h = xAuthHeader();
            const mode = hooksConfig.xSearchMode === 'all' ? 'all' : 'recent';
            const url = `https://api.twitter.com/2/tweets/search/${mode}?query=${encodeURIComponent(query)}&max_results=${Math.min(maxResults,100)}&tweet.fields=created_at,public_metrics,author_id&expansions=author_id&user.fields=name,username`;
            const res = await fetch(url, { headers: h });
            if (!res.ok) return `X API error ${res.status}: ${await res.text()}`;
            const d = await res.json();
            if (!d.data?.length) return `No tweets found for: "${query}"`;
            // Build username map from includes
            const userMap = {};
            (d.includes?.users || []).forEach(u => { userMap[u.id] = u.username; });
            return d.data.map(t => {
                const uname = userMap[t.author_id] || t.author_id;
                const metrics = t.public_metrics ? ` [♥${t.public_metrics.like_count} 🔁${t.public_metrics.retweet_count}]` : '';
                const ts = t.created_at ? new Date(t.created_at).toLocaleString() : '';
                return `@${uname} · ${ts}${metrics}\n${t.text}`;
            }).join('\n\n---\n\n');
        } catch(e) { return 'x_search error: ' + e.message; }
    }

    async function xGetUser(username) {
        try {
            const h = xAuthHeader();
            const url = `https://api.twitter.com/2/users/by/username/${encodeURIComponent(username.replace('@',''))}&user.fields=name,description,public_metrics,verified,created_at,location,url`;
            const res = await fetch(url, { headers: h });
            if (!res.ok) return `X API error ${res.status}: ${await res.text()}`;
            const d = await res.json();
            if (!d.data) return `User @${username} not found.`;
            const u = d.data;
            const m = u.public_metrics || {};
            return [
                `@${u.username} (${u.name})${u.verified ? ' ✓' : ''}`,
                u.description || '',
                u.location ? `📍 ${u.location}` : '',
                `Followers: ${(m.followers_count||0).toLocaleString()} · Following: ${(m.following_count||0).toLocaleString()} · Tweets: ${(m.tweet_count||0).toLocaleString()}`,
                u.created_at ? `Joined: ${new Date(u.created_at).toLocaleDateString()}` : '',
            ].filter(Boolean).join('\n');
        } catch(e) { return 'x_get_user error: ' + e.message; }
    }

    async function xUserTimeline(arg) {
        try {
            const [username, countStr] = (arg || '').split('|').map(s => s.trim());
            const count = Math.min(parseInt(countStr) || 10, 100);
            const h = xAuthHeader();
            // First resolve username → user ID
            const userRes = await fetch(`https://api.twitter.com/2/users/by/username/${encodeURIComponent(username.replace('@',''))}`, { headers: h });
            if (!userRes.ok) return `X API error ${userRes.status}`;
            const ud = await userRes.json();
            if (!ud.data) return `User @${username} not found.`;
            const uid = ud.data.id;
            const url = `https://api.twitter.com/2/users/${uid}/tweets?max_results=${count}&tweet.fields=created_at,public_metrics`;
            const res = await fetch(url, { headers: h });
            if (!res.ok) return `X API error ${res.status}: ${await res.text()}`;
            const d = await res.json();
            if (!d.data?.length) return `No tweets found for @${username}.`;
            return d.data.map(t => {
                const metrics = t.public_metrics ? ` [♥${t.public_metrics.like_count} 🔁${t.public_metrics.retweet_count}]` : '';
                const ts = t.created_at ? new Date(t.created_at).toLocaleString() : '';
                return `${ts}${metrics}\n${t.text}`;
            }).join('\n\n---\n\n');
        } catch(e) { return 'x_user_tweets error: ' + e.message; }
    }

    // ═══════════════════════════════════════════════════════════
    // TRELLO API
    // Key + token auth (appended to every URL as query params).
    // Uses Trello REST API v1. CORS-friendly from browser.
    // Trello's rate limit: 300 req/10s, 100 req/token/10s — plenty.
    // ═══════════════════════════════════════════════════════════

    function trelloAuth() {
        const key = hooksConfig.trelloApiKey;
        const tok = hooksConfig.trelloToken;
        if (!key || !tok) throw new Error('No Trello credentials. Add API key + token in HOOKS → TRELLO.');
        return `key=${encodeURIComponent(key)}&token=${encodeURIComponent(tok)}`;
    }

    async function trelloFetch(path, opts={}) {
        const auth = trelloAuth();
        const sep = path.includes('?') ? '&' : '?';
        const res = await fetch(`https://api.trello.com/1${path}${sep}${auth}`, opts);
        if (!res.ok) {
            const txt = await res.text();
            throw new Error(`Trello ${res.status}: ${txt.slice(0, 200)}`);
        }
        return res.json();
    }

    async function trelloGetBoards() {
        try {
            const boards = await trelloFetch('/members/me/boards?fields=id,name,url,closed&filter=open');
            if (!boards.length) return 'No open boards found.';
            return boards.map(b => `${b.name}\n  ID: ${b.id}\n  URL: ${b.url}`).join('\n\n');
        } catch(e) { return 'trello_boards error: ' + e.message; }
    }

    async function trelloGetLists(boardId) {
        try {
            const bid = boardId || hooksConfig.trelloBoardId;
            if (!bid) return 'No board ID. Provide boardId or set a default in HOOKS.';
            const lists = await trelloFetch(`/boards/${bid}/lists?fields=id,name,closed&filter=open`);
            if (!lists.length) return 'No open lists on this board.';
            return lists.map(l => `${l.name} (ID: ${l.id})`).join('\n');
        } catch(e) { return 'trello_lists error: ' + e.message; }
    }

    async function trelloGetCards(arg) {
        try {
            const [boardOrListId, listId] = (arg || '').split('|').map(s => s.trim());
            const target = listId || boardOrListId || hooksConfig.trelloBoardId;
            if (!target) return 'Provide boardId or listId.';
            // Try as list first (shorter IDs are often list IDs passed directly)
            let cards;
            try {
                cards = await trelloFetch(`/lists/${target}/cards?fields=id,name,desc,due,url,idList`);
            } catch {
                cards = await trelloFetch(`/boards/${target}/cards/open?fields=id,name,desc,due,url,idList`);
            }
            if (!cards.length) return 'No open cards found.';
            return cards.map(c => {
                const due = c.due ? ` · Due: ${new Date(c.due).toLocaleDateString()}` : '';
                return `${c.name}${due}\n  ID: ${c.id}\n  URL: ${c.url}${c.desc ? '\n  ' + c.desc.slice(0, 100) : ''}`;
            }).join('\n\n');
        } catch(e) { return 'trello_cards error: ' + e.message; }
    }

    async function trelloCreateCard(arg) {
        try {
            const [listId, name, desc] = (arg || '').split('|').map(s => s.trim());
            if (!listId || !name) return 'Format: listId|Card name|Optional description';
            const body = new URLSearchParams({ idList: listId, name, ...(desc ? { desc } : {}) });
            const card = await trelloFetch(`/cards`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
                body: body.toString(),
            });
            return `✓ Created card: ${card.name}\n  ID: ${card.id}\n  URL: ${card.url}`;
        } catch(e) { return 'trello_create_card error: ' + e.message; }
    }

    async function trelloMoveCard(arg) {
        try {
            const [cardId, listId] = (arg || '').split('|').map(s => s.trim());
            if (!cardId || !listId) return 'Format: cardId|listId';
            const body = new URLSearchParams({ idList: listId });
            const card = await trelloFetch(`/cards/${cardId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
                body: body.toString(),
            });
            return `✓ Moved card "${card.name}" to list ${listId}`;
        } catch(e) { return 'trello_move_card error: ' + e.message; }
    }

    async function trelloArchiveCard(cardId) {
        try {
            if (!cardId) return 'Format: cardId';
            const body = new URLSearchParams({ closed: 'true' });
            const card = await trelloFetch(`/cards/${cardId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
                body: body.toString(),
            });
            return `✓ Archived card: ${card.name}`;
        } catch(e) { return 'trello_archive_card error: ' + e.message; }
    }

    async function githubAPI(action, arg) {
        const pat = hooksConfig.github;
        if (!pat) return '⚠ No GitHub token. Add your PAT in HOOKS → GITHUB.';
        const h = { 'Authorization': 'Bearer ' + pat, 'Content-Type': 'application/json', 'Accept': 'application/vnd.github+json', 'X-GitHub-Api-Version': '2022-11-28' };
        const base = 'https://api.github.com';
        try {
            if (action === 'list_repos') {
                const r = await fetch(base + '/user/repos?per_page=30&sort=updated', { headers: h });
                const d = await r.json();
                return Array.isArray(d) ? d.map(r => r.full_name + (r.private?' (private)':'')).join('\n') : JSON.stringify(d);
            }
            if (action === 'issue') {
                const [repo, title, ...bodyParts] = arg.split('|').map(s => s.trim());
                const r = await fetch(base + '/repos/' + repo + '/issues', { method:'POST', headers:h, body: JSON.stringify({ title, body: bodyParts.join('|') }) });
                const d = await r.json();
                return d.html_url ? '✓ Issue created: ' + d.html_url : 'Error: ' + JSON.stringify(d);
            }
            if (action === 'list_issues') {
                const repo = arg.trim();
                const r = await fetch(base + '/repos/' + repo + '/issues?state=open&per_page=20', { headers: h });
                const d = await r.json();
                return Array.isArray(d) ? d.map(i => '#' + i.number + ' ' + i.title).join('\n') : JSON.stringify(d);
            }
            if (action === 'get_file') {
                const [repo, path] = arg.split('|').map(s => s.trim());
                const r = await fetch(base + '/repos/' + repo + '/contents/' + path, { headers: h });
                const d = await r.json();
                if (d.content) return atob(d.content.replace(/\n/g,''));
                return 'Error: ' + JSON.stringify(d);
            }
            if (action === 'commit') {
                const parts = arg.split('|').map(s => s.trim());
                const [repo, path, content, message] = parts;
                // Get current SHA if file exists
                let sha;
                try { const ex = await fetch(base + '/repos/' + repo + '/contents/' + path, { headers: h }); const ed = await ex.json(); sha = ed.sha; } catch(_) {}
                const body = { message: message || 'AETHER commit', content: btoa(unescape(encodeURIComponent(content))) };
                if (sha) body.sha = sha;
                const r = await fetch(base + '/repos/' + repo + '/contents/' + path, { method:'PUT', headers:h, body: JSON.stringify(body) });
                const d = await r.json();
                return d.content ? '✓ Committed: ' + path : 'Error: ' + JSON.stringify(d);
            }
            return 'Unknown GitHub action: ' + action;
        } catch(e) { return 'GitHub API error: ' + e.message; }
    }

    // ─── CRON / TASK / FILE TOOLS ───────────────────────────
    const CRON_KEY  = 'aether_cron_jobs';
    const TASKS_KEY = 'aether_tasks';

    function getCronJobs() { try { return JSON.parse(localStorage.getItem(CRON_KEY)||'[]'); } catch { return []; } }
    function saveCronJobs(j) { localStorage.setItem(CRON_KEY, JSON.stringify(j)); }

    // ─── TIMER SYSTEM ────────────────────────────────────────
    // Active timers: { id, label, durationMs, startedAt, intervalId }
    const _activeTimers = new Map();
    const TIMER_KEY = 'aether_timers_state';

    // Register tool
    TOOL_REGISTRY['set_timer'] = {
        fn: async (arg) => timerCreate(arg),
        desc: 'Set a countdown timer. Format: label|duration (e.g. "Pomodoro|25m" or "Reminder|1h30m"). Shows live widget and sends browser notification when done.'
    };
    TOOL_REGISTRY['cancel_timer'] = {
        fn: async (id) => timerCancel(id),
        desc: 'Cancel a running timer by ID or label.'
    };
    TOOL_REGISTRY['list_timers'] = {
        fn: async () => timerList(),
        desc: 'List all active timers with remaining time.'
    };
    TOOL_REGISTRY['estimate'] = {
        fn: async (arg) => timerEstimate(arg),
        desc: 'Give a time estimate and optionally set a timer. Format: task|estimate (e.g. "Writing unit tests|45m")'
    };

    function parseTimeDuration(expr) {
        // Supports: 10m, 1h, 1h30m, 90s, 2h15m30s, "10 minutes", "1 hour 30 minutes"
        expr = expr.trim().toLowerCase();
        let ms = 0;
        // Compound: 1h30m, 2h15m30s
        const compound = expr.matchAll(/(\d+(?:\.\d+)?)\s*(h(?:r|ours?)?|m(?:in(?:utes?)?)?|s(?:ec(?:onds?)?)?)/g);
        for (const m of compound) {
            const n = parseFloat(m[1]);
            const u = m[2][0];
            ms += n * ({ h: 3600000, m: 60000, s: 1000 }[u] || 1000);
        }
        return ms > 0 ? ms : null;
    }

    function formatDuration(ms) {
        if (ms <= 0) return '0s';
        const h = Math.floor(ms / 3600000);
        const m = Math.floor((ms % 3600000) / 60000);
        const s = Math.floor((ms % 60000) / 1000);
        return [h ? h + 'h' : '', m ? m + 'm' : '', s || (!h && !m) ? s + 's' : ''].filter(Boolean).join(' ');
    }

    function timerCreate(arg) {
        const parts = arg.split('|').map(s => s.trim());
        const label = parts[0] || 'Timer';
        const expr  = parts[1] || parts[0];
        const ms    = parseTimeDuration(expr);
        if (!ms) return `❌ Could not parse duration: "${expr}". Try: 10m, 1h30m, 90s`;

        // Request notification permission
        if (typeof Notification !== 'undefined' && Notification.permission === 'default') {
            Notification.requestPermission();
        }

        const id        = 'tmr_' + Date.now();
        const startedAt = Date.now();
        const endsAt    = startedAt + ms;

        // Create live widget in chat
        const widget = createTimerWidget(id, label, ms, endsAt);

        // Interval to update widget every second
        const intervalId = setInterval(() => {
            const remaining = endsAt - Date.now();
            if (remaining <= 0) {
                clearInterval(intervalId);
                _activeTimers.delete(id);
                updateTimerWidget(id, 0, true);
                fireTimerNotification(label);
            } else {
                updateTimerWidget(id, remaining, false);
            }
        }, 1000);

        _activeTimers.set(id, { id, label, durationMs: ms, startedAt, endsAt, intervalId, widget });
        return `✓ Timer set: **${label}** — ${formatDuration(ms)} · ID: ${id}`;
    }

    function timerCancel(idOrLabel) {
        // Find by ID or label
        let entry = _activeTimers.get(idOrLabel);
        if (!entry) {
            for (const [k, v] of _activeTimers) {
                if (v.label.toLowerCase().includes(idOrLabel.toLowerCase())) { entry = v; break; }
            }
        }
        if (!entry) return `No active timer found: "${idOrLabel}"`;
        clearInterval(entry.intervalId);
        _activeTimers.delete(entry.id);
        updateTimerWidget(entry.id, 0, false, true); // cancelled
        return `✓ Timer cancelled: ${entry.label}`;
    }

    function timerList() {
        if (_activeTimers.size === 0) return 'No active timers.';
        return [..._activeTimers.values()].map(t => {
            const remaining = t.endsAt - Date.now();
            return `**${t.label}** — ${formatDuration(Math.max(0, remaining))} remaining · ID: ${t.id}`;
        }).join('\n');
    }

    function timerEstimate(arg) {
        const parts  = arg.split('|').map(s => s.trim());
        const task   = parts[0] || 'Task';
        const estRaw = parts[1] || '';
        const ms     = parseTimeDuration(estRaw);
        if (ms) {
            timerCreate(`${task}|${estRaw}`);
            return `⏱ Estimate for **${task}**: ${formatDuration(ms)}\nTimer set — I'll notify you when the estimate is up.`;
        }
        return `⏱ Estimate for **${task}**: ${estRaw || 'no estimate given'}`;
    }

    // ── Timer widget DOM ─────────────────────────────────────
    function createTimerWidget(id, label, totalMs, endsAt) {
        if (!display) return null;
        const wrap = document.createElement('div');
        wrap.className = 'timer-widget';
        wrap.id        = 'timer-' + id;
        wrap.dataset.total = totalMs;
        wrap.dataset.ends  = endsAt;

        wrap.innerHTML = `
            <div class="timer-icon">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#00f3ff" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                    <circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/>
                </svg>
            </div>
            <div class="timer-body">
                <div class="timer-label">${escapeHtml(label)}</div>
                <div class="timer-bar-wrap">
                    <div class="timer-bar" id="timer-bar-${id}" style="width:100%"></div>
                </div>
                <div class="timer-time" id="timer-time-${id}">${formatDuration(totalMs)}</div>
            </div>
            <button class="timer-cancel-btn" onclick="timerCancel('${id}')" title="Cancel timer">✕</button>`;

        display.appendChild(wrap);
        smoothScrollToBottom();
        // Expose timerCancel globally for onclick
        window.timerCancel = timerCancel;
        return wrap;
    }

    function updateTimerWidget(id, remainingMs, done, cancelled = false) {
        const wrap     = document.getElementById('timer-' + id);
        const timeEl   = document.getElementById('timer-time-' + id);
        const barEl    = document.getElementById('timer-bar-' + id);
        const widget   = _activeTimers.get(id);
        if (!wrap) return;

        if (done) {
            wrap.classList.add('timer-done');
            if (timeEl)  timeEl.textContent  = 'Done!';
            if (barEl)   barEl.style.width   = '0%';
            const btn = wrap.querySelector('.timer-cancel-btn');
            if (btn) btn.remove();
            return;
        }
        if (cancelled) {
            wrap.classList.add('timer-cancelled');
            if (timeEl) timeEl.textContent = 'Cancelled';
            return;
        }

        const totalMs = parseInt(wrap.dataset.total);
        const pct     = Math.max(0, Math.min(100, (remainingMs / totalMs) * 100));
        if (timeEl) timeEl.textContent = formatDuration(remainingMs);
        if (barEl)  barEl.style.width  = pct + '%';

        // Turn amber under 10%, red under 2%
        if (pct < 2)       barEl.style.background = '#ff4466';
        else if (pct < 10) barEl.style.background = '#ff9944';
        else               barEl.style.background = '';
    }

    function fireTimerNotification(label) {
        showNotification(`⏱ Timer done: ${label}`, 'success');
        if (typeof Notification !== 'undefined' && Notification.permission === 'granted') {
            try {
                new Notification('⬡ AETHER Timer', {
                    body: `"${label}" is done!`,
                    icon: './logo.svg', badge: './logo.svg',
                    tag: 'aether-timer-' + Date.now(), vibrate: [200, 100, 200],
                });
            } catch {}
        }
        if (navigator.serviceWorker?.controller) {
            navigator.serviceWorker.controller.postMessage({
                type: 'SHOW_NOTIFICATION',
                payload: { title: '⬡ AETHER Timer', body: `"${label}" is done!`, tag: 'aether-timer' }
            });
        }
    }

    // ─── UNZIP TOOL ───────────────────────────────────────────
    // Uses JSZip via esm.sh — lazy loaded. Registers as tool and
    // handles drag-dropped .zip files in the attachment handler.
    TOOL_REGISTRY['unzip'] = {
        fn: async (arg) => unzipFile(arg),
        desc: 'Unzip a .zip file from the workspace. Format: filename.zip (or filename.zip|dest/path/). Lists contents and extracts all files into workspace.'
    };

    async function unzipFile(arg) {
        const parts   = arg.split('|').map(s => s.trim());
        const zipName = parts[0];
        const destDir = parts[1] ? parts[1].replace(/\/?$/, '/') : '';

        // Get zip content — from FS folder, virtual workspace, or last uploaded blob
        let zipData = null;
        if (codingFolderHandle) {
            try {
                const fh = await fsGetHandle(zipName);
                zipData  = await fh.getFile();
            } catch {}
        }
        if (!zipData) {
            const b64 = wsFileCache[zipName];
            if (b64) zipData = new Blob([Uint8Array.from(atob(b64), c => c.charCodeAt(0))]);
        }
        if (!zipData) return `unzip: "${zipName}" not found in workspace or linked folder. Upload the .zip file first.`;

        const JSZip = await loadJSZip();
        const zip   = await JSZip.loadAsync(zipData);
        const files = Object.keys(zip.files).sort();

        // List contents first
        const listing = files.map(f => {
            const entry = zip.files[f];
            return `${entry.dir ? '📁' : '📄'} ${f}`;
        }).join('\n');

        // Extract all non-directory files
        let extracted = 0;
        const results = [];
        for (const fname of files) {
            const entry = zip.files[fname];
            if (entry.dir) continue;
            try {
                const content = await entry.async('string').catch(async () => {
                    // Binary file — store as base64
                    const ab = await entry.async('arraybuffer');
                    return null; // Skip binary for now
                });
                if (content === null) {
                    results.push(`⚠ ${fname} (binary, skipped)`);
                    continue;
                }
                const destPath = destDir + fname;
                if (codingFolderHandle) {
                    // Write to FS — create directories as needed
                    const dirParts = destPath.split('/').slice(0, -1);
                    if (dirParts.length) {
                        let dir = codingFolderHandle;
                        for (const p of dirParts) {
                            dir = await dir.getDirectoryHandle(p, { create: true });
                        }
                    }
                    await fsFolderWrite(destPath + '\n' + content);
                } else {
                    await writeFile(destPath, content);
                    wsFileCache[destPath] = content;
                }
                results.push(`✓ ${destPath}`);
                extracted++;
            } catch(e) {
                results.push(`✗ ${fname}: ${e.message}`);
            }
        }

        return [
            `📦 **${zipName}** — ${files.length} entries`,
            '',
            '**Contents:**',
            listing,
            '',
            `**Extracted ${extracted} file(s):**`,
            results.join('\n'),
        ].join('\n');
    }

    async function loadJSZip() {
        if (window._JSZip) return window._JSZip;
        const mod = await import('https://esm.sh/jszip@3.10.1');
        window._JSZip = mod.default || mod;
        return window._JSZip;
    }

    // Handle .zip file drops in the attachment system
    window._handleZipDrop = async (file) => {
        const zipName = file.name;
        const JSZip   = await loadJSZip();
        const zip     = await JSZip.loadAsync(file);
        const files   = Object.keys(zip.files).sort();
        const listing = files.slice(0, 30).map(f => zip.files[f].dir ? `📁 ${f}` : `📄 ${f}`).join('\n');
        const msg     = `I've attached **${zipName}** (${files.length} entries):\n\`\`\`\n${listing}${files.length > 30 ? '\n…and ' + (files.length-30) + ' more' : ''}\n\`\`\`\nShall I extract the contents to the workspace?`;
        // Store zip in cache for later extraction
        const reader = new FileReader();
        reader.onload = () => {
            wsFileCache[zipName] = btoa(String.fromCharCode(...new Uint8Array(reader.result)));
        };
        reader.readAsArrayBuffer(file);
        return msg;
    };

    function cronCreate(arg) {
        const parts = arg.split('|').map(s => s.trim());
        if (parts.length < 3) return 'Format: label|cron_expr_or_delay|prompt';
        const [label, expr, prompt] = parts;
        const id = 'cron_' + Date.now();
        const jobs = getCronJobs();
        const job = { id, label, expr, prompt, created: new Date().toISOString(), active: true, runs: 0 };
        jobs.push(job);
        saveCronJobs(jobs);
        const delayMs = parseDelay(expr);
        if (delayMs) {
            setTimeout(() => runScheduledCronJob(id), delayMs);
            return '✓ One-shot job created: ' + label + ' (runs in ' + expr + ') · ID: ' + id;
        }
        return '✓ Cron job created: ' + label + ' · expr: ' + expr + ' · ID: ' + id + ' (recurring jobs fire on next AETHER check-in)';
    }

    function parseDelay(expr) {
        const m = expr.match(/^(\d+(\.\d+)?)\s*(s|sec|m|min|h|hr|d|day)s?$/i);
        if (!m) return null;
        const n = parseFloat(m[1]);
        const u = m[3].toLowerCase();
        return n * ({ s:1000, sec:1000, m:60000, min:60000, h:3600000, hr:3600000, d:86400000, day:86400000 }[u] || 1000);
    }

    async function runScheduledCronJob(id) {
        const jobs = getCronJobs();
        const job = jobs.find(j => j.id === id);
        if (!job || !job.active) return;
        try {
            const result = await callAISimple([{role:'user', content: job.prompt}], apiConfig.model);
            job.runs++; job.lastRun = new Date().toISOString(); job.lastResult = String(result).slice(0,200);
            saveCronJobs(jobs);
            showNotification('⏱ Cron: ' + job.label + ' — completed', 'info');
        } catch(e) { console.warn('[Cron]', e); }
    }

    function cronDelete(id) {
        const jobs = getCronJobs().filter(j => j.id !== id);
        saveCronJobs(jobs);
        return jobs.length === getCronJobs().length ? 'Job not found: ' + id : '✓ Deleted: ' + id;
    }

    function cronList() {
        const jobs = getCronJobs();
        if (!jobs.length) return 'No scheduled jobs.';
        return jobs.map(j => '**' + j.id + '** — ' + j.label + ' · ' + j.expr + ' · runs: ' + j.runs + (j.lastRun ? ' · last: ' + new Date(j.lastRun).toLocaleString() : '')).join('\n');
    }

    // Tasks
    function getTasks() { try { return JSON.parse(localStorage.getItem(TASKS_KEY)||'[]'); } catch { return []; } }
    function saveTasks(t) { localStorage.setItem(TASKS_KEY, JSON.stringify(t)); }

    function taskCreate(arg) {
        const parts = arg.split('|').map(s => s.trim());
        const [title, description='', priority='medium'] = parts;
        const id = 'task_' + Date.now();
        const tasks = getTasks();
        tasks.push({ id, title, description, priority, status:'pending', created: new Date().toISOString() });
        saveTasks(tasks);
        return '✓ Task created: ' + title + ' [' + priority + '] · ID: ' + id;
    }

    function taskGet(id) {
        const t = getTasks().find(t => t.id === id || t.title.toLowerCase().includes(id.toLowerCase()));
        return t ? JSON.stringify(t, null, 2) : 'Task not found: ' + id;
    }

    function taskUpdate(arg) {
        const parts = arg.split('|').map(s => s.trim());
        const [id, status, description] = parts;
        const tasks = getTasks();
        const t = tasks.find(t => t.id === id);
        if (!t) return 'Task not found: ' + id;
        if (status) t.status = status;
        if (description) t.description = description;
        t.updated = new Date().toISOString();
        saveTasks(tasks);
        return '✓ Updated task ' + id + ': status=' + t.status;
    }

    // Glob and Grep (workspace files)
    async function fsGlob(pattern) {
        try {
            const manifest = await getWorkspaceManifest();
            if (!manifest || !manifest.length) return 'No workspace files found.';
            const re = new RegExp(pattern.replace(/\./g,'\\.').replace(/\*/g,'.*').replace(/\?/g,'.'));
            const matches = manifest.filter(f => re.test(f.file));
            return matches.length ? matches.map(f => f.file + ' (' + f.lines + ' lines)').join('\n') : 'No matches for: ' + pattern;
        } catch(e) { return 'Glob error: ' + e.message; }
    }

    async function fsGrep(arg) {
        const parts = arg.split('|');
        const pattern = parts[0].trim();
        const fileFilter = parts[1]?.trim();
        try {
            const re = new RegExp(pattern, 'gi');
            const manifest = await getWorkspaceManifest();
            if (!manifest) return 'No workspace.';
            const files = fileFilter ? manifest.filter(f => f.file.includes(fileFilter)) : manifest.slice(0, 10);
            const results = [];
            for (const f of files) {
                const content = await readFile(f.file);
                if (!content) continue;
                const lines = content.split('\n');
                lines.forEach((line, i) => {
                    if (re.test(line)) results.push(f.file + ':' + (i+1) + ': ' + line.trim().slice(0,120));
                });
            }
            return results.length ? results.slice(0,30).join('\n') : 'No matches for: ' + pattern;
        } catch(e) { return 'Grep error: ' + e.message; }
    }

    // Agent messaging (stored in localStorage, can be polled by other AETHER instances)
    const MSG_KEY = 'aether_agent_messages';
    function agentSendMessage(arg) {
        const parts = arg.split('|'); const [to, msg] = parts;
        const msgs = JSON.parse(localStorage.getItem(MSG_KEY)||'[]');
        msgs.push({ to: to.trim(), from: 'aether', msg: msg.trim(), ts: Date.now(), read: false });
        localStorage.setItem(MSG_KEY, JSON.stringify(msgs.slice(-50)));
        return '✓ Message queued for: ' + to.trim();
    }

    // ─── CLOCK ───────────────────────────────────────────────
    if(clock){ const uc=()=>clock.textContent=new Date().toLocaleTimeString('en-GB'); uc(); setInterval(uc,1000); }

    // ─── INPUT AUTO-RESIZE ────────────────────────────────────
    if(input){
        input.addEventListener('input',()=>{
            input.style.height='auto'; input.style.height=Math.min(input.scrollHeight,150)+'px';
            if(charCounter) charCounter.textContent=input.value.length+' chars';
            // ── Slash command palette ────────────────────────────────────────
            // Type '/' at the start of the input to open the command palette.
            // Commands are filtered as you type. Esc or backspace to '/' closes.
            // Power users never have to leave the keyboard.
            if (input.value.startsWith('/')) {
                showSlashPalette(input.value.slice(1));
            } else {
                hideSlashPalette();
            }
        });
        input.addEventListener('keydown',e=>{
            // Slash palette navigation
            if (slashPaletteVisible) {
                if (e.key === 'ArrowDown') { e.preventDefault(); slashPaletteMove(1); return; }
                if (e.key === 'ArrowUp')   { e.preventDefault(); slashPaletteMove(-1); return; }
                if (e.key === 'Tab' || (e.key === 'Enter' && slashPaletteActive())) {
                    e.preventDefault(); slashPaletteExecute(); return;
                }
                if (e.key === 'Escape') { hideSlashPalette(); return; }
            }
            if(e.key==='Enter'&&!e.shiftKey){ e.preventDefault(); sendMessage(); }
        });
    }

