    let slashPaletteVisible = false;
    let slashPaletteIndex   = 0;
    let slashPaletteFiltered = [];
    let slashPaletteEl = null;

    function showSlashPalette(query) {
        const q = query.toLowerCase();
        slashPaletteFiltered = q
            ? SLASH_COMMANDS.filter(c => c.id.startsWith(q) || c.label.slice(1).startsWith(q) || c.desc.toLowerCase().includes(q))
            : SLASH_COMMANDS;

        if (!slashPaletteFiltered.length) { hideSlashPalette(); return; }

        if (!slashPaletteEl) {
            slashPaletteEl = document.createElement('div');
            slashPaletteEl.id = 'slash-palette';
            slashPaletteEl.className = 'slash-palette';
            // Position above the input bar
            const inputBar = document.querySelector('.input-area, .chat-input-wrapper, #input-wrapper') || input.parentElement;
            inputBar.style.position = 'relative';
            inputBar.appendChild(slashPaletteEl);
        }

        slashPaletteIndex = 0;
        renderSlashPalette();
        slashPaletteVisible = true;
    }

    function renderSlashPalette() {
        if (!slashPaletteEl) return;
        let lastGroup = '';
        slashPaletteEl.innerHTML = '';
        slashPaletteFiltered.slice(0, 12).forEach((cmd, i) => {
            if (cmd.group !== lastGroup) {
                const grpEl = document.createElement('div');
                grpEl.className = 'slash-group';
                grpEl.textContent = cmd.group;
                slashPaletteEl.appendChild(grpEl);
                lastGroup = cmd.group;
            }
            const item = document.createElement('div');
            item.className = 'slash-item' + (i === slashPaletteIndex ? ' active' : '');
            item.innerHTML = `<span class="slash-label">${escapeHtml(cmd.label)}</span><span class="slash-desc">${escapeHtml(cmd.desc)}</span>`;
            item.addEventListener('mousedown', e => { e.preventDefault(); slashPaletteIndex = i; slashPaletteExecute(); });
            slashPaletteEl.appendChild(item);
        });
        if (slashPaletteFiltered.length > 12) {
            const more = document.createElement('div'); more.className = 'slash-more';
            more.textContent = '+' + (slashPaletteFiltered.length - 12) + ' more — keep typing to filter';
            slashPaletteEl.appendChild(more);
        }
    }

    function hideSlashPalette() {
        slashPaletteVisible = false;
        slashPaletteEl?.remove();
        slashPaletteEl = null;
    }

    function slashPaletteMove(dir) {
        slashPaletteIndex = Math.max(0, Math.min(slashPaletteFiltered.length - 1, slashPaletteIndex + dir));
        renderSlashPalette();
    }

    function slashPaletteActive() {
        return slashPaletteVisible && slashPaletteFiltered.length > 0;
    }

    function slashPaletteExecute() {
        const cmd = slashPaletteFiltered[slashPaletteIndex];
        if (!cmd) return;
        hideSlashPalette();
        // Extract arg from input: everything after the command id
        const raw = input.value.slice(1); // strip leading /
        const argMatch = raw.match(new RegExp('^' + cmd.id + '\\s*(.*)$', 'i'));
        const arg = argMatch ? argMatch[1].trim() : '';
        input.value = '';
        input.style.height = 'auto';
        try { cmd.action(arg); } catch(e) { reportFeatureError('Command', e); }
    }

    function addSystemMessage(md) {
        const div = document.createElement('div'); div.className = 'aether-msg slash-result';
        div.innerHTML = parseMarkdown(md);
        display.appendChild(div); smoothScrollToBottom();
    }
    window.addSystemMessage = addSystemMessage;

