            if (_md) console.log('%c Markdown fixtures ' + _md.passed + '/' + _md.total + (_md.ok ? ' PASS' : ' FAIL'), 'color:' + (_md.ok ? '#1d9e75' : '#e24b4a') + ';font-family:monospace');
