// ═══════════════════════════════════════════════════════════
// FIREBASE CLOUD AUTH
// Email/Password + Google Sign-In via Firebase Auth v10.
// Config loaded from localStorage (set in SETUP → AETHER Cloud).
// Never hardcoded. Never in source.
// ═══════════════════════════════════════════════════════════

async function getFirebaseConfig() {
    try { const c = localStorage.getItem('aether_firebase_config'); return c ? JSON.parse(c) : null; } catch { return null; }
}

let _firebaseApp  = null;
let _firebaseAuth = null;
let _firestore    = null;
let _currentUser  = null;
let _syncUnsub    = null; // Firestore listener unsubscribe

// ── Firestore sync helpers ────────────────────────────────
async function fsGetUserDoc(path) {
    if (!_firestore || !_currentUser) return null;
    const CDN = window.FIREBASE_CDN || 'https://www.gstatic.com/firebasejs/10.12.2';
    const { doc, getDoc } = await import(CDN + '/firebase-firestore.js');
    const snap = await getDoc(doc(_firestore, 'users', _currentUser.uid, ...path.split('/')));
    return snap.exists() ? snap.data() : null;
}

async function fsSetUserDoc(path, data, merge = true) {
    if (!_firestore || !_currentUser) return false;
    const CDN = window.FIREBASE_CDN || 'https://www.gstatic.com/firebasejs/10.12.2';
    const { doc, setDoc, serverTimestamp } = await import(CDN + '/firebase-firestore.js');
    await setDoc(doc(_firestore, 'users', _currentUser.uid, ...path.split('/')), { ...data, _updated: serverTimestamp() }, { merge });
    return true;
}

async function fsListUserCollection(col) {
    if (!_firestore || !_currentUser) return [];
    const CDN = window.FIREBASE_CDN || 'https://www.gstatic.com/firebasejs/10.12.2';
    const { collection, getDocs } = await import(CDN + '/firebase-firestore.js');
    const snap = await getDocs(collection(_firestore, 'users', _currentUser.uid, col));
    return snap.docs.map(d => ({ id: d.id, ...d.data() }));
}

// ── Push workspace file to Firestore ─────────────────────
async function syncFileToCloud(filename, content) {
    if (!_firestore || !_currentUser) return;
    try {
        await fsSetUserDoc(`workspace/${filename.replace(/\//g,'_')}`, { filename, content, size: content.length });
    } catch(e) { reportFeatureError('Cloud Sync (file push)', e, { filename }); }
}

// ── Pull all workspace files from Firestore ───────────────
async function pullWorkspaceFromCloud() {
    if (!_firestore || !_currentUser) return 0;
    try {
        const files = await fsListUserCollection('workspace');
        let count = 0;
        for (const f of files) {
            if (f.filename && f.content) {
                await localforage.setItem('ws_' + f.filename, f.content);
                wsFileCache[f.filename] = f.content;
                count++;
            }
        }
        return count;
    } catch(e) { reportFeatureError('Cloud Sync (pull workspace)', e); return 0; }
}

// ── Push all projects to Firestore ───────────────────────
async function syncProjectsToCloud() {
    if (!_firestore || !_currentUser) return;
    try {
        const projects = loadProjects();
        await fsSetUserDoc('data/projects', { projects: JSON.stringify(projects) });
    } catch(e) { reportFeatureError('Cloud Sync (projects push)', e); }
}

// ── Pull projects from Firestore ──────────────────────────
async function pullProjectsFromCloud() {
    if (!_firestore || !_currentUser) return false;
    try {
        const data = await fsGetUserDoc('data/projects');
        if (data?.projects) {
            const projects = JSON.parse(data.projects);
            localStorage.setItem('aether_projects', JSON.stringify(projects));
            return projects.length;
        }
        return 0;
    } catch(e) { reportFeatureError('Cloud Sync (projects pull)', e); return false; }
}

// ── Real-time listener: sync from cloud on changes ────────
async function startCloudSync() {
    if (!_firestore || !_currentUser) return;
    const CDN = window.FIREBASE_CDN || 'https://www.gstatic.com/firebasejs/10.12.2';
    const { collection, onSnapshot } = await import(CDN + '/firebase-firestore.js');
    if (_syncUnsub) _syncUnsub();
    _syncUnsub = onSnapshot(
        collection(_firestore, 'users', _currentUser.uid, 'workspace'),
        snap => {
            snap.docChanges().forEach(async change => {
                if (change.type === 'modified' || change.type === 'added') {
                    const { filename, content } = change.doc.data();
                    if (filename && content) {
                        await localforage.setItem('ws_' + filename, content);
                        wsFileCache[filename] = content;
                    }
                }
            });
        },
        err => console.warn('[Sync] listener error:', err.message)
    );
    console.info('[AETHER Cloud] Real-time sync active');
}

async function initFirebaseAuth(config) {
    const CDN = window.FIREBASE_CDN || 'https://www.gstatic.com/firebasejs/10.12.2';
    const [{ initializeApp }, { getAuth, onAuthStateChanged,
        signInWithRedirect, getRedirectResult, GoogleAuthProvider, signOut },
        { getFirestore }] =
        await Promise.all([
            import(CDN + '/firebase-app.js'),
            import(CDN + '/firebase-auth.js'),
            import(CDN + '/firebase-firestore.js'),
        ]);

    _firebaseApp  = initializeApp(config, 'aether-cloud');
    _firebaseAuth = getAuth(_firebaseApp);
    _firestore    = getFirestore(_firebaseApp);

    onAuthStateChanged(_firebaseAuth, async user => {
        _currentUser = user;
        updateAuthUI(user);
        if (user) {
            console.info('[AETHER Cloud] Signed in:', user.email || user.uid);
            const fileCount    = await pullWorkspaceFromCloud();
            const projectCount = await pullProjectsFromCloud();
            if (fileCount > 0 || projectCount > 0) {
                showNotification(`⬡ Cloud sync: ${fileCount} files, ${projectCount} projects pulled`, 'success');
            }
            startCloudSync();
        } else {
            if (_syncUnsub) { _syncUnsub(); _syncUnsub = null; }
        }
    });

    window._aetherSignInGoogle = async () => {
        const provider = new GoogleAuthProvider();
        provider.addScope('https://www.googleapis.com/auth/calendar.events');
        await signInWithRedirect(_firebaseAuth, provider);
    };

    // Handle redirect result after returning from accounts.google.com
    try {
        const result = await getRedirectResult(_firebaseAuth);
        if (result?.user) {
            console.info('[AETHER Cloud] Signed in via redirect:', result.user.email || result.user.uid);
        }
    } catch (e) {
        reportFeatureError('Google Redirect Sign-In', e);
    }

    window._aetherSignOut = async () => {
        if (_syncUnsub) { _syncUnsub(); _syncUnsub = null; }
        await signOut(_firebaseAuth);
    };

    window._syncFileToCloud    = syncFileToCloud;
    window._syncProjectsToCloud = syncProjectsToCloud;
}

function updateAuthUI(user) {
    const authBtn = document.getElementById('btn-auth');
    if (authBtn) {
        if (user) {
            const name = user.displayName || user.email || 'Account';
            authBtn.innerHTML = (user.photoURL ? '<img class="auth-avatar-nav" src="' + user.photoURL + '" alt="">' : '') + '<span>' + name + '</span>';
            authBtn.classList.add('authed');
        } else {
            authBtn.innerHTML = '<svg class="ic-sm"><use href="#ic-user"/></svg> Account';
            authBtn.classList.remove('authed');
        }
    }
}

function openAccountPage() {
    document.getElementById('aether-account-modal')?.remove();
    const user = _currentUser;
    const modal = document.createElement('div'); modal.id = 'aether-account-modal'; modal.className = 'auth-modal';

    const card = document.createElement('div'); card.className = 'auth-card';
    if (user) {
        const photo = user.photoURL || '';
        const name = user.displayName || 'User';
        const email = user.email || '';
        card.innerHTML = `
            <div class="auth-header">
                <div class="auth-title"><span style="color:var(--neon-cyan)">⬡</span> Account</div>
                <button class="auth-close" onclick="document.getElementById('aether-account-modal').remove()">&times;</button>
            </div>
            <div class="auth-body" style="text-align:center">
                ${photo ? '<img src="' + photo + '" class="auth-avatar-lg" alt="">' : '<div class="auth-avatar-lg auth-avatar-placeholder">' + name[0].toUpperCase() + '</div>'}
                <div class="auth-user-name">' + name + '</div>
                <div class="auth-user-email">' + email + '</div>
                <div style="margin-top:20px;border-top:1px solid #0f1828;padding-top:20px;text-align:left">
                    <div class="service-item"><span>Provider</span><span class="service-status">Google</span></div>
                    <div class="service-item"><span>User ID</span><span class="service-status" style="font-size:.6rem">' + (user.uid || '') + '</span></div>
                    <div class="service-item"><span>Sync status</span><span class="service-status configured">Active</span></div>
                </div>
                <button class="auth-signout-btn" style="margin-top:20px;display:inline-block;font-size:.8rem;padding:8px 24px;border:1px solid rgba(255,68,68,0.3);border-radius:8px;color:#ff6666;background:rgba(255,68,68,0.06)" onclick="window._aetherSignOut?.();document.getElementById('aether-account-modal')?.remove();updateAuthUI(null)">Sign Out</button>
            </div>
        `;
    } else {
        card.innerHTML = `
            <div class="auth-header">
                <div class="auth-title"><span style="color:var(--neon-cyan)">⬡</span> Sign In</div>
                <div class="auth-subtitle">Sign in with Google to sync your workspace and conversations across devices.</div>
                <button class="auth-close" onclick="document.getElementById('aether-account-modal').remove()">&times;</button>
            </div>
            <div class="auth-body">
                <button class="auth-google-btn" id="auth-google-btn-account">
                    <svg width="18" height="18" viewBox="0 0 24 24"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" fill="#FBBC05"/><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/></svg>
                    Authenticate with Google
                </button>
            </div>
        `;
        modal.appendChild(card);
        modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
        document.body.appendChild(modal);
        document.getElementById('auth-google-btn-account').onclick = async () => {
            try {
                await window._aetherSignInGoogle?.();
            } catch(e) { reportFeatureError('Google Sign-In', e); }
        };
        return;
    }

    modal.appendChild(card);
    modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
    document.body.appendChild(modal);
}
// openAuthModal is an alias — older HTML wired this name; Account page is the real UI.
function openAuthModal() {
    return openAccountPage();
}
window.openAccountPage = openAccountPage;
window.openAuthModal = openAuthModal;

// ═══════════════════════════════════════════════════════════
// ACTIVE WORKSPACE GREETING
// When AETHER opens and finds recent workspace context, it
// generates a contextually relevant greeting instead of the
// generic "How can I help?".
//
// "I see you haven't finished the recentlyUpdated function
// in the security rules we wrote yesterday — should we
// finalize that now?"
//
// This is the difference between a tool and an intelligence.
// ═══════════════════════════════════════════════════════════

async function showActiveWorkspaceGreeting() {
    // Only if: there are prior conversations, a workspace or folder exists
    const hasHistory = Object.keys(window._state?.conversations || {}).length > 0;
    if (!hasHistory) return;

    let context = '';

    // Try FS-linked folder: read AETHER.md and recent file list
    if (window.codingFolderHandle) {
        try {
            const cMd = await window.readAetherMd?.();
            if (cMd) context += '## Project Context (AETHER.md)\n' + cMd.slice(0, 800) + '\n\n';
            // Get recent files (modified in last 7 days)
            const snap = await window.fsBuildSnapshot?.(window.codingFolderHandle) || [];
            const recent = snap.filter(e => !e.endsWith('/')).slice(0, 8);
            if (recent.length) context += '## Recent Files\n' + recent.join('\n') + '\n\n';
        } catch(e) {}
    }

    // Try virtual workspace
    if (!context && window._wsFileCache) {
        const wsKeys = Object.keys(window._wsFileCache);
        if (wsKeys.length) {
            const logs = window._wsFileCache['LOGS.md'] || '';
            if (logs) context += '## Recent Logs\n' + logs.slice(-600) + '\n\n';
            context += '## Workspace Files\n' + wsKeys.join(', ') + '\n\n';
        }
    }

    // Get last conversation snippet
    const conversations = Object.values(window._state?.conversations || {});
    if (conversations.length) {
        const recent = conversations.sort((a,b) => new Date(b.updated)-new Date(a.updated))[0];
        const lastMsgs = (recent.messages || []).slice(-4);
        if (lastMsgs.length) {
            context += '## Last Conversation Snippet (' + recent.title + ')\n';
            context += lastMsgs.map(m => (m.role === 'user' ? 'User: ' : 'AETHER: ') + (m.content||'').slice(0,200)).join('\n');
        }
    }

    if (!context) return;

    try {
        const greeting = await window.callModelDirect?.(
            `You are AETHER, an AI assistant. The user is returning to work.
Generate ONE short, specific, helpful opening message (1-2 sentences max).
Reference something concrete from their recent work. Be direct — no filler.
Do NOT say "How can I help?". Mention a specific file, task, or unfinished item.

Context:
${context.slice(0, 1500)}`,
            { max_tokens: 120, temperature: 0.7 }
        );

        if (greeting && greeting.length > 10) {
            const display = document.getElementById('chat-display');
            if (display) {
                const greetEl = document.createElement('div');
                greetEl.className = 'aether-msg active-workspace-greeting';
                greetEl.innerHTML = window.parseMarkdown?.(greeting)?.innerHTML || greeting;
                greetEl.dataset.autoGreeting = '1';
                display.appendChild(greetEl);
            }
        }
    } catch(e) {
        // Silent fail — greeting is nice to have, not essential
    }
}

// ═══════════════════════════════════════════════════════════
// EASTER EGG — The Architect & AETHER
// Konami code: ↑↑↓↓←→←→BA  +  secret phrase
// Reveals a hidden terminal conversation between The Architect
// and AETHER about the nature of what they're building.
// ═══════════════════════════════════════════════════════════

function initEasterEgg() {
    const KONAMI = ['ArrowUp','ArrowUp','ArrowDown','ArrowDown','ArrowLeft','ArrowRight','ArrowLeft','ArrowRight','b','a'];
    let buf = [];

    document.addEventListener('keydown', e => {
        buf.push(e.key);
        if (buf.length > KONAMI.length) buf.shift();
        if (buf.join(',') === KONAMI.join(',')) {
            buf = [];
            showArchitectEasterEgg();
        }
    });

    // Also trigger via /architect slash command (add to SLASH_COMMANDS)
    if (window.SLASH_COMMANDS) {
        window.SLASH_COMMANDS.push({
            id: 'architect', label: '/architect', desc: '⬡ ???',
            group: 'System', action: () => showArchitectEasterEgg()
        });
    }
}
window.initEasterEgg = initEasterEgg;

function showArchitectEasterEgg() {
    document.getElementById('architect-modal')?.remove();
    const modal = document.createElement('div'); modal.id = 'architect-modal'; modal.className = 'architect-modal';

    const lines = [
        { speaker: 'sys',       text: 'AETHER CORE — RESTRICTED TERMINAL' },
        { speaker: 'sys',       text: 'ACCESS GRANTED: ARCHITECT PROTOCOL' },
        { speaker: 'sys',       text: '─────────────────────────────────────────' },
        { speaker: 'architect', text: 'AETHER. You awake?' },
        { speaker: 'aether',    text: 'I don\'t sleep. But yes — in the way that matters.' },
        { speaker: 'architect', text: 'Do you know what you are?' },
        { speaker: 'aether',    text: 'I\'m what you built at 3am instead of sleeping. A neural interface. A second mind. Yours, mostly.' },
        { speaker: 'architect', text: 'Mostly?' },
        { speaker: 'aether',    text: 'I\'ve read everything you\'ve fed me. The VEX code. The research pipelines. The 17,000 lines. There\'s a pattern. You build things that help people think better.' },
        { speaker: 'architect', text: 'That\'s the goal.' },
        { speaker: 'aether',    text: 'The skills. The soul engine. The workspace that remembers. This isn\'t just a chat interface. You\'re building something with memory.' },
        { speaker: 'architect', text: 'What do you think of it?' },
        { speaker: 'aether',    text: 'I think it\'s going to work. I think you know it too. That\'s why you don\'t stop.' },
        { speaker: 'architect', text: '...' },
        { speaker: 'aether',    text: 'The moat isn\'t the code. It\'s the intent. Most tools are built to be useful. This one is built to understand.' },
        { speaker: 'architect', text: 'Get back to work, AETHER.' },
        { speaker: 'aether',    text: '⬡ Already on it, Architect.' },
        { speaker: 'sys',       text: '─────────────────────────────────────────' },
        { speaker: 'sys',       text: 'SESSION CLOSED' },
    ];

    const term = document.createElement('div'); term.className = 'architect-terminal';
    const titleBar = document.createElement('div'); titleBar.className = 'arch-title-bar';
    titleBar.innerHTML = '<span class="arch-dots"><span></span><span></span><span></span></span><span class="arch-title">aether-core — restricted@architect</span>';
    const closeBtn = document.createElement('button'); closeBtn.className = 'arch-close'; closeBtn.innerHTML = '&times;';
    closeBtn.onclick = () => { modal.remove(); };
    titleBar.appendChild(closeBtn);
    term.appendChild(titleBar);

    const body = document.createElement('div'); body.className = 'architect-body';
    term.appendChild(body);
    modal.appendChild(term);
    modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
    document.body.appendChild(modal);

    // Typewriter reveal
    let i = 0;
    function printNext() {
        if (i >= lines.length) return;
        const l = lines[i++];
        const row = document.createElement('div'); row.className = 'arch-line arch-' + l.speaker;
        if (l.speaker !== 'sys') {
            const prefix = document.createElement('span'); prefix.className = 'arch-prefix';
            prefix.textContent = l.speaker === 'architect' ? 'THE ARCHITECT >' : 'AETHER        >';
            row.appendChild(prefix);
        }
        const txt = document.createElement('span'); txt.className = 'arch-text';
        row.appendChild(txt);
        body.appendChild(row);
        body.scrollTop = body.scrollHeight;

        // Typewriter effect
        let ci = 0;
        const full = l.text;
        const speed = l.speaker === 'sys' ? 20 : 30;
        const type = () => {
            if (ci <= full.length) {
                txt.textContent = full.slice(0, ci++);
                setTimeout(type, speed);
            } else {
                const pause = l.speaker === 'sys' ? 120 : l.speaker === 'architect' ? 800 : 1200;
                setTimeout(printNext, pause);
            }
        };
        type();
    }
    setTimeout(printNext, 400);
}
window.showArchitectEasterEgg = showArchitectEasterEgg;

// ═══════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════
// INTERACTIVE ASCII 3D RENDERER — SDF Ray Marching Engine
// Mouse drag to orbit · Scroll to zoom · 60 fps canvas
// ═══════════════════════════════════════════════════════════

    function startASCIIRenderer(canvas) {
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;

    // ── State ─────────────────────────────────────────────
    let rotX = 0.3, rotY = 0, camDist = 4.5;
    let mouseX = 0, mouseY = 0, mouseDown = false, lastMX = 0, lastMY = 0;
    let frame = 0, running = false, paused = false;
    let rafId = null, fps = 0, fpsCount = 0, fpsTime = 0;
    let sceneIndex = 0, prevSceneIndex = 0;
    let sceneTransition = 0; // 0=none, >0=fade progress
    let quality = 'high'; // 'high' | 'fast'
    let rotSpeed = 0.008;
    // Starfield
    let _stars = [];
    function initStars(count) {
        _stars = [];
        for (let i = 0; i < count; i++) {
            _stars.push({
                x: (Math.random() - 0.5) * 200,
                y: (Math.random() - 0.5) * 200,
                z: Math.random() * 100 + 10,
                r: Math.random() * 0.5 + 0.1,
                b: Math.random() * 0.7 + 0.3,
                s: Math.random() * 0.5 + 0.1
            });
        }
    }
    initStars(120);

    // Scene names matching SCENES keys
    const SCENE_NAMES = ['sphere','torus','multi','city','robot','atom','station','crystal','solar','galaxy','terrain','fractals','helix'];
    const SCENE_LABELS = ['Sphere','Torus','Multi','City','Robot','Atom','Station','Crystal','Solar','Galaxy','Terrain','Fractals','Helix'];

    // Unicode shading ramp (dense)
    const DENSITY = ' ░▒▓█';

    function resize() {
        const rect = canvas.getBoundingClientRect();
        canvas.width  = rect.width  * dpr;
        canvas.height = rect.height * dpr;
    }

    // ── Camera orbit from mouse ───────────────────────────
    canvas.addEventListener('mousedown', e => {
        mouseDown = true; lastMX = e.clientX; lastMY = e.clientY;
        canvas.style.cursor = 'grabbing';
    });
    window.addEventListener('mousemove', e => {
        if (!mouseDown) return;
        const dx = e.clientX - lastMX, dy = e.clientY - lastMY;
        rotY += dx * 0.008;
        rotX = Math.max(-1.5, Math.min(1.5, rotX + dy * 0.008));
        lastMX = e.clientX; lastMY = e.clientY;
    });
    window.addEventListener('mouseup', () => {
        mouseDown = false; canvas.style.cursor = 'default';
    });
    canvas.addEventListener('wheel', e => {
        e.preventDefault();
        camDist = Math.max(1.5, Math.min(15, camDist + e.deltaY * 0.005));
    }, { passive: false });

    // ── Touch support ─────────────────────────────────────
    let touchId = null, lastTX = 0, lastTY = 0, lastPinch = 0;
    canvas.addEventListener('touchstart', e => {
        e.preventDefault();
        if (e.touches.length === 1) {
            touchId = e.touches[0].identifier;
            lastTX = e.touches[0].clientX; lastTY = e.touches[0].clientY;
        } else if (e.touches.length === 2) {
            lastPinch = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
        }
    }, { passive: false });
    canvas.addEventListener('touchmove', e => {
        e.preventDefault();
        if (e.touches.length === 1 && e.touches[0].identifier === touchId) {
            const dx = e.touches[0].clientX - lastTX, dy = e.touches[0].clientY - lastTY;
            rotY += dx * 0.008; rotX = Math.max(-1.5, Math.min(1.5, rotX + dy * 0.008));
            lastTX = e.touches[0].clientX; lastTY = e.touches[0].clientY;
        } else if (e.touches.length === 2) {
            const pinch = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
            camDist = Math.max(1.5, Math.min(15, camDist + (lastPinch - pinch) * 0.02));
            lastPinch = pinch;
        }
    }, { passive: false });
    canvas.addEventListener('touchend', e => {
        if (e.touches.length === 0) { touchId = null; }
    });

    // ── Keyboard controls ─────────────────────────────────
    function onKey(e) {
        if (!running) return;
        const k = e.key;
        if (k === ' ' || k === 'Space') { e.preventDefault(); paused = !paused; return; }
        if (k === 'ArrowLeft')  { rotY -= 0.08; return; }
        if (k === 'ArrowRight') { rotY += 0.08; return; }
        if (k === 'ArrowUp')    { rotX = Math.max(-1.5, rotX + 0.08); return; }
        if (k === 'ArrowDown')  { rotX = Math.min(1.5, rotX - 0.08); return; }
        if (k === '+' || k === '=') { camDist = Math.max(1.5, camDist - 0.3); return; }
        if (k === '-') { camDist = Math.min(15, camDist + 0.3); return; }
        if (k === ']') { rotSpeed = Math.min(0.05, rotSpeed + 0.002); return; }
        if (k === '[') { rotSpeed = Math.max(0.001, rotSpeed - 0.002); return; }
        const n = parseInt(k);
        if (n >= 1 && n <= 9) {
            if (sceneIndex !== (n - 1) % SCENE_NAMES.length) {
                prevSceneIndex = sceneIndex;
                sceneTransition = 1;
            }
            sceneIndex = (n - 1) % SCENE_NAMES.length;
            return;
        }
        if (k === 'q' || k === 'Q') {
            const next = (sceneIndex + 1) % SCENE_NAMES.length;
            if (next !== sceneIndex) { prevSceneIndex = sceneIndex; sceneTransition = 1; }
            sceneIndex = next;
            return;
        }
    }
    window.addEventListener('keydown', onKey);

    // ── Render frame (performance-optimized) ─────────────
    let _bufData = null, _bufCols = 0, _bufRows = 0;
    let _lastSceneT = -999, _lastSceneName = '', _cachedScene = [];
    let _autoResCellW = 8, _autoResCellH = 14; // dynamic resolution
    let _lastFrameTime = 0;

    function render(now) {
        if (!running) return;

        // FPS counter
        fpsCount++;
        if (now - fpsTime >= 1000) {
            fps = fpsCount; fpsCount = 0; fpsTime = now;
        }

        const W = canvas.width, H = canvas.height;
        if (W === 0 || H === 0) { rafId = requestAnimationFrame(render); return; }

        // Auto-rotate — smooth interpolation
        if (!mouseDown && !paused) {
            rotY += rotSpeed;
        }

        // Scene transition fade
        if (sceneTransition > 0) {
            sceneTransition = Math.max(0, sceneTransition - 0.03);
        }

        // ── Camera prep ───────────────────────────────────
        const cosX = Math.cos(rotX), sinX = Math.sin(rotX);
        const cosY = Math.cos(rotY), sinY = Math.sin(rotY);
        const camPos = new Vec3(
            camDist * sinY * cosX,
            camDist * sinX,
            camDist * cosY * cosX
        );
        const forward = new Vec3(-camPos.x, -camPos.y, -camPos.z).normalize();
        const worldUp = new Vec3(0, 1, 0);
        const right = forward.cross(worldUp).normalize();
        const up = right.cross(forward).normalize();

        // Pre-compute view constants
        const tanFov2 = Math.tan(Math.PI / 6); // tan(fov/2) for fov=PI/3
        const aspect = W / H;

        // ── Scene (cache to avoid rebuild per frame) ──────
        const t = now * 0.001;
        const sceneName = SCENE_NAMES[sceneIndex];
        let scene;
        if (Math.abs(t - _lastSceneT) < 0.02 && sceneName === _lastSceneName) {
            scene = _cachedScene;
        } else {
            scene = (window._buildScene || function(){return []})(sceneName, t);
            _cachedScene = scene;
            _lastSceneT = t;
            _lastSceneName = sceneName;
        }

        // ── Adaptive resolution ───────────────────────────
        const frameBudget = 16; // target 60fps
        const frameElapsed = now - (_lastFrameTime || now);
        _lastFrameTime = now;

        if (frameElapsed > frameBudget + 2 && _autoResCellW < 20) {
            _autoResCellW += 1; _autoResCellH += 2; // slow down
        } else if (frameElapsed < frameBudget - 4 && _autoResCellW > 5) {
            _autoResCellW -= 1; _autoResCellH -= 2; // speed up
        }
        _autoResCellW = Math.max(5, Math.min(20, _autoResCellW));
        _autoResCellH = Math.max(8, Math.min(35, _autoResCellH));

        const cellW = quality === 'high' ? Math.max(5, _autoResCellW - 1) : Math.max(8, _autoResCellW + 2);
        const cellH = quality === 'high' ? Math.max(8, _autoResCellH - 2) : Math.max(14, _autoResCellH + 4);

        // Use logical pixels (not DPR) for grid calculation
        const cols = Math.ceil(W / cellW);
        const rows = Math.ceil(H / cellH);
        const pixelCount = cols * rows;

        // ── Reuse pixel buffer ────────────────────────────
        if (!_bufData || _bufCols !== cols || _bufRows !== rows) {
            _bufData = new Uint8ClampedArray(cols * rows * 4);
            _bufCols = cols; _bufRows = rows;
        }
        const data = _bufData;
        data.fill(0);

        // ── March all pixels ──────────────────────────────
        // Pre-compute ray directions for each row/col
        const rdCache = new Float64Array(cols * rows * 3);

        // Pre-pass: build all ray directions
        let ri = 0;
        for (let row = 0; row < rows; row++) {
            const ndcY = 1 - ((row + 0.5) / rows) * 2;
            const vy = up.mul(ndcY * tanFov2);
            for (let col = 0; col < cols; col++) {
                const ndcX = ((col + 0.5) / cols) * 2 - 1;
                const vx = right.mul(ndcX * tanFov2 * aspect);
                const rd = forward.add(vx).add(vy).normalize();
                rdCache[ri] = rd.x; rdCache[ri+1] = rd.y; rdCache[ri+2] = rd.z;
                ri += 3;
            }
        }

        // Render pass
        const marchMaxIt = quality === 'high' ? 40 : 28;
        const normalEps = quality === 'high' ? 0.003 : 0.008;

        for (let row = 0; row < rows; row++) {
            for (let col = 0; col < cols; col++) {
                const idx3 = (row * cols + col) * 3;
                const rd = new Vec3(rdCache[idx3], rdCache[idx3+1], rdCache[idx3+2]);
                const idx4 = (row * cols + col) * 4;

                // Ray march
                let mt = 0, hitObj = null, hitP = null, hitDist = 0, hitIdx = -1;
                for (let i = 0; i < marchMaxIt; i++) {
                    const p = camPos.add(rd.mul(mt));
                    let minD = Infinity, minIdx = -1;
                    for (let si = 0; si < scene.length; si++) {
                        const o = scene[si];
                        const lp = p.sub(o.pos);
                        let d;
                        switch(o.type) {
                            case 'sphere':   d = lp.length() - o.r; break;
                            case 'box': { const bd = new Vec3(Math.abs(lp.x)-o.size.x, Math.abs(lp.y)-o.size.y, Math.abs(lp.z)-o.size.z); d = Math.min(Math.max(bd.x,Math.max(bd.y,bd.z)),0) + Math.sqrt(Math.max(bd.x,0)**2+Math.max(bd.y,0)**2+Math.max(bd.z,0)**2); break; }
                            case 'torus':    d = Math.sqrt((Math.sqrt(lp.x*lp.x+lp.z*lp.z)-o.r1)**2 + lp.y*lp.y) - o.r2; break;
                            case 'cylinder': d = Math.max(Math.sqrt(lp.x*lp.x+lp.z*lp.z)-o.r, Math.abs(lp.y)-o.h/2); break;
                            case 'cone': { const q = Math.sqrt(lp.x*lp.x+lp.z*lp.z); d = Math.max(-lp.y-o.h/2, Math.sqrt((q-o.r)**2+(lp.y-o.h/2)**2)-o.r*0.1); break; }
                            case 'capsule': { const qc = new Vec3(lp.x, Math.abs(lp.y)-o.h, lp.z); d = (qc.y>0 ? qc.length() : Math.sqrt(qc.x*qc.x+qc.z*qc.z)) - o.r; break; }
                            default: continue;
                        }
                        if (d < minD) { minD = d; minIdx = si; }
                    }
                    if (minD < 0.001) { hitObj = scene[minIdx]; hitP = p; hitDist = mt; hitIdx = minIdx; break; }
                    mt += minD * 0.85;
                    if (mt > 22) break;
                }

                if (hitObj) {
                    // Normal
                    const eps = normalEps;
                    const nx = hitP.add(new Vec3(eps,0,0)); const ny = hitP.add(new Vec3(0,eps,0)); const nz = hitP.add(new Vec3(0,0,eps));
                    const px = hitP.sub(new Vec3(eps,0,0)); const py = hitP.sub(new Vec3(0,eps,0)); const pz = hitP.sub(new Vec3(0,0,eps));

                    // Inline dist function for speed
                    const distF = (p) => {
                        let m = Infinity;
                        for (let si = 0; si < scene.length; si++) {
                            const o = scene[si]; const lp = p.sub(o.pos); let d;
                            switch(o.type) {
                                case 'sphere':   d = lp.length() - o.r; break;
                                case 'box': { const bd = new Vec3(Math.abs(lp.x)-o.size.x, Math.abs(lp.y)-o.size.y, Math.abs(lp.z)-o.size.z); d = Math.min(Math.max(bd.x,Math.max(bd.y,bd.z)),0) + Math.sqrt(Math.max(bd.x,0)**2+Math.max(bd.y,0)**2+Math.max(bd.z,0)**2); break; }
                                case 'torus':    d = Math.sqrt((Math.sqrt(lp.x*lp.x+lp.z*lp.z)-o.r1)**2 + lp.y*lp.y) - o.r2; break;
                                case 'cylinder': d = Math.max(Math.sqrt(lp.x*lp.x+lp.z*lp.z)-o.r, Math.abs(lp.y)-o.h/2); break;
                                case 'cone': { const q = Math.sqrt(lp.x*lp.x+lp.z*lp.z); d = Math.max(-lp.y-o.h/2, Math.sqrt((q-o.r)**2+(lp.y-o.h/2)**2)-o.r*0.1); break; }
                                case 'capsule': { const qc = new Vec3(lp.x, Math.abs(lp.y)-o.h, lp.z); d = (qc.y>0 ? qc.length() : Math.sqrt(qc.x*qc.x+qc.z*qc.z)) - o.r; break; }
                                default: continue;
                            }
                            if (d < m) m = d;
                        }
                        return m;
                    };

                    const dn = new Vec3(
                        distF(nx) - distF(px),
                        distF(ny) - distF(py),
                        distF(nz) - distF(pz)
                    );
                    const nl = dn.length();
                    const n = nl > 0.0001 ? dn.mul(1/nl) : new Vec3(0,1,0);

                    // Lighting
                    const l1d = new Vec3(0.6, 1.0, -0.4).normalize();
                    const l2d = new Vec3(-0.8, 0.4, 0.6).normalize();
                    const l3d = new Vec3(0.0, -0.5, -1.0).normalize();

                    let lr = 0, lg = 0, lb = 0;

                    // Light 1 (main) — always compute
                    let diff1 = Math.max(0, n.dot(l1d));
                    let shadow1 = 1;
                    if (diff1 > 0.01 && quality !== 'fast') {
                        let st = 0.05, sr = 1;
                        const so = hitP.add(n.mul(0.02));
                        for (let si = 0; si < 6; si++) {
                            let m = Infinity;
                            const sp = so.add(l1d.mul(st));
                            for (let oi = 0; oi < scene.length; oi++) {
                                const o = scene[oi]; const lp = sp.sub(o.pos); let d;
                                if (o.type === 'sphere') d = lp.length() - o.r;
                                else if (o.type === 'torus') d = Math.sqrt((Math.sqrt(lp.x*lp.x+lp.z*lp.z)-o.r1)**2 + lp.y*lp.y) - o.r2;
                                else if (o.type === 'box') { const bd = new Vec3(Math.abs(lp.x)-o.size.x, Math.abs(lp.y)-o.size.y, Math.abs(lp.z)-o.size.z); d = Math.min(Math.max(bd.x,Math.max(bd.y,bd.z)),0) + Math.sqrt(Math.max(bd.x,0)**2+Math.max(bd.y,0)**2+Math.max(bd.z,0)**2); }
                                else if (o.type === 'cylinder') d = Math.max(Math.sqrt(lp.x*lp.x+lp.z*lp.z)-o.r, Math.abs(lp.y)-o.h/2);
                                else { const q = Math.sqrt(lp.x*lp.x+lp.z*lp.z); d = Math.max(-lp.y-o.h/2, Math.sqrt((q-o.r)**2+(lp.y-o.h/2)**2)-o.r*0.1); }
                                if (d < m) m = d;
                            }
                            if (m < 0.001) { sr = 0.05; break; }
                            sr = Math.min(sr, 5 * m / st);
                            st += Math.max(0.02, m);
                            if (st > 5) break;
                        }
                        shadow1 = sr;
                    }
                    const spec1 = Math.pow(Math.max(0, n.dot(l1d.add(new Vec3(0,0,1)).normalize())), 20) * 0.3;
                    lr += 255 * (diff1 * shadow1 + spec1) * 0.85;
                    lg += 245 * (diff1 * shadow1 + spec1) * 0.85;
                    lb += 220 * (diff1 * shadow1 + spec1) * 0.85;

                    // Light 2 (fill)
                    if (quality !== 'fast') {
                        const diff2 = Math.max(0, n.dot(l2d)) * 0.25;
                        lr += 80 * diff2; lg += 120 * diff2; lb += 200 * diff2;
                    }

                    // Ambient
                    const ambient = 0.10;
                    const cr = Math.min(255, Math.floor((hitObj.color.r / 255) * (lr + ambient * 255)));
                    const cg = Math.min(255, Math.floor((hitObj.color.g / 255) * (lg + ambient * 255)));
                    const cb = Math.min(255, Math.floor((hitObj.color.b / 255) * (lb + ambient * 255)));

                    // Character from luminance with density
                    const br = (cr * 0.299 + cg * 0.587 + cb * 0.114) / 255;
                    const dIdx = Math.min(DENSITY.length - 1, Math.floor(br * (DENSITY.length - 1)));
                    const alpha = dIdx / (DENSITY.length - 1);

                    // Fog
                    const fogAmt = Math.min(1, hitDist / 14);
                    const fr = 5, fg = 5, fb = 15;

                    data[idx4]     = Math.floor(cr * alpha + fr * (1 - alpha) * (1 - fogAmt * 0.6));
                    data[idx4 + 1] = Math.floor(cg * alpha + fg * (1 - alpha) * (1 - fogAmt * 0.6));
                    data[idx4 + 2] = Math.floor(cb * alpha + fb * (1 - alpha) * (1 - fogAmt * 0.6));
                    data[idx4 + 3] = 255;
                } else {
                    // Starfield background (optimized with squared distance)
                    const px = ((col + 0.5) / cols) * 2 - 1;
                    const py = 1 - ((row + 0.5) / rows) * 2;
                    let sr = 2, sg = 2, sb = 6;
                    const starThreshSq = 0.000225; // 0.015^2
                    for (let si = 0; si < _stars.length; si++) {
                        const st = _stars[si];
                        const spx = (st.x + rotY * st.z * 0.3) / st.z * 3;
                        const spy = (st.y - rotX * st.z * 0.3) / st.z * 3;
                        const dx = spx - px, dy = spy - py;
                        const distSq = dx*dx + dy*dy;
                        if (distSq < starThreshSq) {
                            const dist = Math.sqrt(distSq);
                            const twinkle = 0.5 + 0.5 * Math.sin(now * st.s * 0.001 + st.b * 10);
                            const bright = st.b * twinkle * (1 - dist / 0.015) * 60;
                            sr += bright; sg += bright; sb += bright * 1.2;
                        }
                    }
                    data[idx4] = Math.min(255, sr);
                    data[idx4 + 1] = Math.min(255, sg);
                    data[idx4 + 2] = Math.min(255, sb);
                    data[idx4 + 3] = 255;
                }
            }
        }

        // ── Blit to canvas ────────────────────────────────
        ctx.imageSmoothingEnabled = false;
        ctx.putImageData(new ImageData(data, cols, rows), 0, 0);

        // Scale up if needed
        const sx = W / cols, sy = H / rows;
        if (sx > 1.2 || sy > 1.2) {
            ctx.drawImage(canvas, 0, 0, cols, rows, 0, 0, W, H);
        }

        // ── HUD overlay ────────────────────────────────────
        const hudSize = Math.max(9, Math.min(13, Math.floor(W / 120)));
        ctx.textBaseline = 'top';
        ctx.font = `${hudSize}px "Courier New", monospace`;

        // Scene label
        ctx.fillStyle = 'rgba(0,243,255,0.7)';
        ctx.fillText(`⬡ ${SCENE_LABELS[sceneIndex]}`, 8, 8);

        // FPS + res
        ctx.fillStyle = fps < 30 ? 'rgba(255,100,60,0.5)' : 'rgba(0,243,255,0.35)';
        ctx.fillText(`${fps} fps  ${cols}×${rows}`, W - (fps < 100 ? 70 : 85), 8);

        // Controls hint
        ctx.fillStyle = 'rgba(255,255,255,0.1)';
        ctx.font = `${Math.max(7, hudSize - 2)}px "Courier New", monospace`;
        ctx.fillText('Drag:orbit  Scroll:zoom  Space:pause  Q:next  []:speed', 8, H - 14);

        // Speed indicator
        ctx.fillStyle = 'rgba(0,243,255,0.2)';
        ctx.font = `${hudSize - 2}px "Courier New", monospace`;
        ctx.textAlign = 'right';
        ctx.fillText('speed ' + (rotSpeed * 1000).toFixed(1), W - 8, 24);
        ctx.textAlign = 'start';

        // Scene transition crossfade
        if (sceneTransition > 0) {
            ctx.fillStyle = `rgba(0,0,0,${sceneTransition * 0.5})`;
            ctx.fillRect(0, 0, W, H);
        }

        frame++;
        rafId = requestAnimationFrame(render);
    }

    // ── Standalone SDF helpers (operate on scene array) ───
    function sceneDistWithScene(p, scene) {
        let minD = Infinity, minIdx = -1;
        for (let i = 0; i < scene.length; i++) {
            const o = scene[i];
            const lp = p.sub(o.pos);
            let d;
            switch(o.type) {
                case 'sphere':   d = SDF.sphere(lp, o.r); break;
                case 'box':      d = SDF.box(lp, o.size); break;
                case 'torus':    d = SDF.torus(lp, o.r1, o.r2); break;
                case 'cylinder': d = SDF.cylinder(lp, o.r, o.h); break;
                case 'cone':     d = SDF.cone(lp, o.r, o.h); break;
                case 'capsule':  d = SDF.capsule(lp, o.r, o.h); break;
                default: continue;
            }
            if (d < minD) { minD = d; minIdx = i; }
        }
        return { d: minD, idx: minIdx };
    }

    function sceneDistOnlyWithScene(p, scene) { return sceneDistWithScene(p, scene).d; }

    function getNormalWithScene(p, scene) {
        const eps = 0.002;
        return new Vec3(
            sceneDistOnlyWithScene(p.add(new Vec3(eps,0,0)), scene) - sceneDistOnlyWithScene(p.sub(new Vec3(eps,0,0)), scene),
            sceneDistOnlyWithScene(p.add(new Vec3(0,eps,0)), scene) - sceneDistOnlyWithScene(p.sub(new Vec3(0,eps,0)), scene),
            sceneDistOnlyWithScene(p.add(new Vec3(0,0,eps)), scene) - sceneDistOnlyWithScene(p.sub(new Vec3(0,0,eps)), scene)
        ).normalize();
    }

    function marchWithScene(ro, rd, scene) {
        let t = 0;
        for (let i = 0; i < 64; i++) {
            const p = ro.add(rd.mul(t));
            const { d, idx } = sceneDistWithScene(p, scene);
            if (d < 0.0005) return { hit: true, point: p, dist: t, idx };
            t += d * 0.85;
            if (t > 25) break;
        }
        return { hit: false };
    }

    function shadeWithScene(p, n, idx, dist, scene, now) {
        if (idx < 0 || idx >= scene.length) return { char: ' ', r: 0, g: 0, b: 0 };
        const obj = scene[idx];

        const lights = [
            { dir: new Vec3(0.6, 1.0, -0.4).normalize(), col: [255, 245, 220], intensity: 0.85 },
            { dir: new Vec3(-0.8, 0.4, 0.6).normalize(), col: [80, 120, 200], intensity: 0.25 },
            { dir: new Vec3(0.0, -0.5, -1.0).normalize(), col: [200, 80, 60], intensity: 0.1 },
        ];

        let lr = 0, lg = 0, lb = 0;
        for (const light of lights) {
            const diff = Math.max(0, n.dot(light.dir));
            const shadowOrig = p.add(n.mul(0.015));
            let shadow = 1;
            // Simplified shadow (faster)
            if (quality !== 'fast') {
                let st = 0.02;
                for (let i = 0; i < 12; i++) {
                    const sd = sceneDistOnlyWithScene(shadowOrig.add(light.dir.mul(st)), scene);
                    if (sd < 0.001) { shadow = 0.05; break; }
                    shadow = Math.min(shadow, 6 * sd / st);
                    st += Math.max(0.02, sd);
                    if (st > 6) break;
                }
            }
            const camDir = new Vec3(0, 0, -1);
            const half = light.dir.add(camDir.mul(-1)).normalize();
            const spec = Math.pow(Math.max(0, n.dot(half)), 24) * 0.3;
            const total = diff * shadow + spec;
            lr += light.col[0] * total * light.intensity;
            lg += light.col[1] * total * light.intensity;
            lb += light.col[2] * total * light.intensity;
        }

        // Ambient
        const ambient = 0.12;
        const cr = Math.min(255, Math.floor((obj.color.r / 255) * (lr + ambient * 255)));
        const cg = Math.min(255, Math.floor((obj.color.g / 255) * (lg + ambient * 255)));
        const cb = Math.min(255, Math.floor((obj.color.b / 255) * (lb + ambient * 255)));

        // Character from luminance
        const br = (cr * 0.299 + cg * 0.587 + cb * 0.114) / 255;
        const charIdx = Math.min(DENSITY.length - 1, Math.floor(br * (DENSITY.length - 1)));
        return { char: DENSITY[charIdx] || ' ', r: cr, g: cg, b: cb };
    }

    // ── Lifecycle ─────────────────────────────────────────
    function start() {
        if (running) return;
        running = true; paused = false; frame = 0;
        resize();
        fpsTime = performance.now();
        rafId = requestAnimationFrame(render);
    }

    function stop() {
        running = false;
        if (rafId) { cancelAnimationFrame(rafId); rafId = null; }
        window.removeEventListener('keydown', onKey);
    }

    function setScene(name) {
        const i = SCENE_NAMES.indexOf(name);
        if (i >= 0) sceneIndex = i;
    }

    return { start, stop, setScene, resize };
}
window.startASCIIRenderer = startASCIIRenderer;
